class KitError(Exception):
    pass


def now_iso() -> str:
    return dt.datetime.now(dt.timezone.utc).astimezone().isoformat(timespec="seconds")


def project_root(project_dir: str | Path) -> Path:
    return Path(project_dir).expanduser().resolve()


def state_root(project_dir: str | Path) -> Path:
    return project_root(project_dir) / STATE_DIR


def ensure_state(project_dir: str | Path, *, create: bool = False) -> Path:
    project = project_root(project_dir)
    state = project / STATE_DIR
    if create:
        project.mkdir(parents=True, exist_ok=True)
        state.mkdir(parents=True, exist_ok=True)
    if not state.exists():
        raise KitError(f"Novel agent state not found: {state}")
    return state


@contextmanager
def state_write_lock(state: Path, operation: str, *, timeout: float = LOCK_TIMEOUT_SECONDS):
    lock_dir = state / LOCK_DIR_NAME
    deadline = time.monotonic() + timeout
    token = uuid.uuid4().hex
    while True:
        try:
            lock_dir.mkdir()
            lock_payload = {
                "token": token,
                "operation": operation,
                "pid": os.getpid(),
                "created_at": now_iso(),
                "created_at_ts": time.time(),
            }
            (lock_dir / "lock.json").write_text(json.dumps(lock_payload, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
            break
        except FileExistsError:
            if stale_lock(lock_dir):
                remove_lock(lock_dir)
                continue
            if time.monotonic() >= deadline:
                detail = read_lock_detail(lock_dir)
                raise KitError(f"Novel agent state is locked by another writer: {detail}")
            time.sleep(0.1)
    try:
        yield
    finally:
        try:
            payload = read_lock_payload(lock_dir)
            if payload.get("token") == token:
                remove_lock(lock_dir)
        except OSError:
            pass


def read_lock_payload(lock_dir: Path) -> dict[str, Any]:
    path = lock_dir / "lock.json"
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
        return payload if isinstance(payload, dict) else {}
    except (OSError, json.JSONDecodeError):
        return {}


def read_lock_detail(lock_dir: Path) -> str:
    payload = read_lock_payload(lock_dir)
    if payload:
        return json.dumps({key: payload.get(key) for key in ("operation", "pid", "created_at")}, ensure_ascii=False)
    return str(lock_dir)


def stale_lock(lock_dir: Path) -> bool:
    payload = read_lock_payload(lock_dir)
    created = payload.get("created_at_ts")
    try:
        created_ts = float(created)
    except (TypeError, ValueError):
        try:
            created_ts = lock_dir.stat().st_mtime
        except OSError:
            return True
    return time.time() - created_ts > LOCK_STALE_SECONDS


def remove_lock(lock_dir: Path) -> None:
    shutil.rmtree(lock_dir, ignore_errors=True)


