def read_text_value(value: str | None, base_dir: str | Path | None = None) -> str:
    if not value:
        return ""
    candidates = [Path(value).expanduser()]
    if base_dir and not Path(value).expanduser().is_absolute():
        candidates.append(project_root(base_dir) / value)
    for maybe_path in candidates:
        if maybe_path.exists() and maybe_path.is_file():
            return maybe_path.read_text(encoding="utf-8")
    return value


def read_json(path: Path, default: Any) -> Any:
    if not path.exists():
        return default
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise KitError(f"Invalid JSON: {path}: {exc}") from exc


def write_json(path: Path, payload: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_suffix(path.suffix + ".tmp")
    tmp.write_text(json.dumps(payload, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    tmp.replace(path)


def read_jsonl(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    rows: list[dict[str, Any]] = []
    for line_no, line in enumerate(path.read_text(encoding="utf-8").splitlines(), 1):
        stripped = line.strip()
        if not stripped:
            continue
        try:
            row = json.loads(stripped)
        except json.JSONDecodeError as exc:
            raise KitError(f"Invalid JSONL: {path}:{line_no}: {exc}") from exc
        if isinstance(row, dict):
            rows.append(row)
    return rows


def write_jsonl(path: Path, rows: list[dict[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    text = "".join(json.dumps(row, ensure_ascii=False) + "\n" for row in rows)
    tmp = path.with_suffix(path.suffix + ".tmp")
    tmp.write_text(text, encoding="utf-8")
    tmp.replace(path)


def append_jsonl(path: Path, row: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(row, ensure_ascii=False) + "\n")


def current_state_schema_version(state: Path) -> int:
    manifest = read_json(state / "manifest.json", {})
    try:
        return int(manifest.get("state_schema_version") or 1) if isinstance(manifest, dict) else 1
    except (TypeError, ValueError):
        return 1


def deterministic_project_id(project: Path, manifest: dict[str, Any]) -> str:
    existing = str(manifest.get("project_id") or "").strip()
    if existing:
        return existing
    seed = {
        "project_dir": str(project.resolve()),
        "title": str(manifest.get("title") or project.name),
        "created_at": str(manifest.get("created_at") or ""),
        "gaoxia_project_id": str(manifest.get("gaoxia_project_id") or ""),
    }
    raw = json.dumps(seed, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return "novel-" + hashlib.sha256(raw).hexdigest()[:16]


def project_identity_payload(project_dir: str | Path, manifest: dict[str, Any] | None = None) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    manifest_payload = manifest if isinstance(manifest, dict) else read_json(state / "manifest.json", {})
    if not isinstance(manifest_payload, dict):
        manifest_payload = {}
    return {
        "type": "project_identity",
        "project_id": deterministic_project_id(project, manifest_payload) if manifest_payload else "",
        "title": str(manifest_payload.get("title") or project.name),
        "project_dir": str(project),
        "state_dir": str(state),
        "gaoxia_project_id": str(manifest_payload.get("gaoxia_project_id") or ""),
    }


def migrate_state(state: Path, *, operation: str = "migrate_state") -> dict[str, Any]:
    changes: list[str] = []
    for name in REQUIRED_JSONL_FILES:
        path = state / name
        if not path.exists():
            ensure_jsonl(path)
            changes.append(f"created:{name}")
    json_defaults = {
        "manifest.json": {},
        "rules.json": {"required_phrases": [], "forbidden_phrases": [], "future_markers": [], "forbidden_renames": [], "notes": []},
        "characters.json": {"characters": []},
        "debts.json": {"debts": []},
        "style_profile.json": {"samples": [], "profile": {}},
    }
    for name in REQUIRED_JSON_FILES:
        path = state / name
        if not path.exists():
            write_json(path, json_defaults.get(name, {}))
            changes.append(f"created:{name}")
    for name in REQUIRED_TEXT_FILES:
        path = state / name
        if not path.exists():
            path.write_text("", encoding="utf-8")
            changes.append(f"created:{name}")
    manifest_path = state / "manifest.json"
    manifest = read_json(manifest_path, {})
    if not isinstance(manifest, dict):
        manifest = {}
    previous_version = current_state_schema_version(state)
    if manifest.get("state_schema_version") != STATE_SCHEMA_VERSION:
        manifest["state_schema_version"] = STATE_SCHEMA_VERSION
        manifest["kit_version"] = KIT_VERSION
        manifest["updated_at"] = now_iso()
        if not manifest.get("title"):
            manifest["title"] = state.parent.name
        changes.append(f"state_schema_version:{previous_version}->{STATE_SCHEMA_VERSION}")
    if not manifest.get("project_id"):
        manifest["project_id"] = deterministic_project_id(state.parent, manifest)
        manifest["updated_at"] = now_iso()
        changes.append("manifest_project_id:created")
    if changes:
        write_json(manifest_path, manifest)
    if changes:
        append_jsonl(
            state / "audit.jsonl",
            {
                "id": make_id("audit"),
                "created_at": now_iso(),
                "operation": "migrate_state",
                "triggered_by": operation,
                "kit_version": KIT_VERSION,
                "from_state_schema_version": previous_version,
                "to_state_schema_version": STATE_SCHEMA_VERSION,
                "changes": changes,
            },
        )
    return {"changed": bool(changes), "changes": changes, "from": previous_version, "to": STATE_SCHEMA_VERSION}


def normalize_author_confirmation(value: Any) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def author_confirmation_record(value: str) -> dict[str, Any]:
    return {
        "provided": True,
        "summary": value[:240],
        "hash": text_hash(value),
    }


def require_author_confirmation(operation: str, value: Any) -> str:
    confirmation = normalize_author_confirmation(value)
    if operation in AUTHOR_CONFIRMATION_OPERATIONS and len(confirmation) < 8:
        raise KitError(
            f"{operation} requires author confirmation before writing long-term novel state. "
            "Use --author-confirmation for CLI or author_confirmation for MCP."
        )
    return confirmation


def audit_state_change(
    state: Path,
    operation: str,
    result: Any,
    *,
    migration: dict[str, Any] | None = None,
    author_confirmation: str = "",
) -> dict[str, Any]:
    ensure_jsonl(state / "audit.jsonl")
    row: dict[str, Any] = {
        "id": make_id("audit"),
        "created_at": now_iso(),
        "operation": operation,
        "kit_version": KIT_VERSION,
        "state_schema_version": current_state_schema_version(state),
        "affected_files": affected_files_for_operation(operation, result),
        "result": summarize_result_for_audit(result),
    }
    if migration and migration.get("changed"):
        row["migration"] = migration
    if author_confirmation:
        row["author_confirmation"] = author_confirmation_record(author_confirmation)
    append_jsonl(state / "audit.jsonl", row)
    return row


def affected_files_for_operation(operation: str, result: Any) -> list[str]:
    mapping = {
        "init": list(STATE_SNAPSHOT_FILES),
        "init_project": list(STATE_SNAPSHOT_FILES),
        "init-wizard": list(STATE_SNAPSHOT_FILES),
        "init_wizard": list(STATE_SNAPSHOT_FILES),
        "quickstart": list(STATE_SNAPSHOT_FILES),
        "quickstart_project": list(STATE_SNAPSHOT_FILES),
        "import-gaoxia": ["manifest.json", "sources.jsonl", "chapters.jsonl", "characters.json", "debts.json", "contracts.jsonl", "facts.jsonl", "handoff.md"],
        "import_gaoxia_project": ["manifest.json", "sources.jsonl", "chapters.jsonl", "characters.json", "debts.json", "contracts.jsonl", "facts.jsonl", "handoff.md"],
        "add-source": ["sources.jsonl"],
        "add_source_summary": ["sources.jsonl"],
        "add-research": ["research.jsonl"],
        "add_research_note": ["research.jsonl"],
        "resolve-conflict": ["conflicts.jsonl"],
        "resolve_conflict": ["conflicts.jsonl"],
        "add-fact": ["facts.jsonl"],
        "add_fact": ["facts.jsonl"],
        "update-fact": ["facts.jsonl"],
        "update_fact": ["facts.jsonl"],
        "supersede-fact": ["facts.jsonl"],
        "supersede_fact": ["facts.jsonl"],
        "record-chapter": ["chapters.jsonl", "manifest.json"],
        "record_chapter": ["chapters.jsonl", "manifest.json"],
        "update-after-write": ["handoff.md"],
        "update_after_write": ["handoff.md"],
        "propose-after-write": ["proposals.jsonl"],
        "propose_after_write_updates": ["proposals.jsonl"],
        "apply-after-write": ["facts.jsonl", "characters.json", "debts.json", "handoff.md", "proposals.jsonl", "snapshots/"],
        "apply_after_write_updates": ["facts.jsonl", "characters.json", "debts.json", "handoff.md", "proposals.jsonl", "snapshots/"],
        "reject-proposal": ["proposals.jsonl"],
        "reject_proposal": ["proposals.jsonl"],
        "create-snapshot": ["snapshots/"],
        "create_snapshot": ["snapshots/"],
        "restore-snapshot": list(STATE_SNAPSHOT_FILES) + ["snapshots/"],
        "restore_snapshot": list(STATE_SNAPSHOT_FILES) + ["snapshots/"],
        "record-desktop-check": ["desktop_verifications.jsonl"],
        "record_desktop_client_check": ["desktop_verifications.jsonl"],
        "record-agent-activity": ["agent_activity.jsonl"],
        "record_agent_activity": ["agent_activity.jsonl"],
    }
    files = mapping.get(operation, [])
    if isinstance(result, dict):
        snapshot = result.get("snapshot")
        if isinstance(snapshot, dict) and snapshot.get("id"):
            files.append(f"snapshots/{snapshot['id']}/")
        backup = result.get("backup_snapshot")
        if isinstance(backup, dict) and backup.get("id"):
            files.append(f"snapshots/{backup['id']}/")
    return unique_strings([*files, "audit.jsonl"])


def summarize_result_for_audit(result: Any) -> dict[str, Any]:
    if not isinstance(result, dict):
        return {"type": type(result).__name__}
    summary: dict[str, Any] = {"ok": result.get("ok")}
    for key in ("proposal_id", "audit_id"):
        if result.get(key):
            summary[key] = result.get(key)
    for key in ("entry", "proposal", "snapshot", "backup_snapshot"):
        value = result.get(key)
        if isinstance(value, dict) and value.get("id"):
            summary[f"{key}_id"] = value.get("id")
    if isinstance(result.get("counts"), dict):
        summary["counts"] = result["counts"]
    if isinstance(result.get("applied"), dict):
        summary["applied"] = result["applied"]
    if isinstance(result.get("restored_files"), list):
        summary["restored_files"] = result["restored_files"]
    return summary


def write_if_missing(path: Path, content: str, *, force: bool = False) -> None:
    if force or not path.exists():
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")


def write_json_if_missing(path: Path, payload: Any, *, force: bool = False) -> None:
    if force or not path.exists():
        write_json(path, payload)


def ensure_jsonl(path: Path, *, force: bool = False) -> None:
    if force or not path.exists():
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text("", encoding="utf-8")


def split_list(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, list):
        items: list[str] = []
        for item in value:
            items.extend(split_list(item))
        return items
    text = str(value)
    parts = re.split(r"[,，、;；\n]+", text)
    return [part.strip() for part in parts if part.strip()]


def parse_ranges(raw: str | list[Any] | None) -> list[dict[str, Any]]:
    if not raw:
        return []
    if isinstance(raw, list):
        ranges: list[dict[str, Any]] = []
        for item in raw:
            if isinstance(item, dict):
                ranges.append(item)
            else:
                ranges.extend(parse_ranges(str(item)))
        return ranges
    ranges = []
    for part in split_list(raw):
        normalized = part.strip()
        match = re.search(r"(\d+)\s*(?:-|~|～|—|至|到)\s*(\d+)", normalized)
        if match:
            start = int(match.group(1))
            end = int(match.group(2))
            ranges.append({"start": min(start, end), "end": max(start, end), "raw": normalized})
            continue
        match = re.search(r"(\d+)\s*\+", normalized)
        if match:
            ranges.append({"start": int(match.group(1)), "end": None, "raw": normalized})
            continue
        match = re.search(r"(\d+)", normalized)
        if match:
            chapter = int(match.group(1))
            ranges.append({"start": chapter, "end": chapter, "raw": normalized})
    return ranges


def range_visible(ranges: list[dict[str, Any]], chapter: int) -> bool:
    if not ranges:
        return True
    for item in ranges:
        start = item.get("start")
        end = item.get("end")
        if start is not None and chapter < int(start):
            continue
        if end is not None and chapter > int(end):
            continue
        return True
    return False


def entry_visible(entry: dict[str, Any], chapter: int) -> bool:
    reveal_after = entry.get("reveal_after_chapter")
    if reveal_after is not None:
        try:
            if chapter <= int(reveal_after):
                return False
        except (TypeError, ValueError):
            pass
    effective_until = entry.get("effective_until_chapter")
    if effective_until is not None:
        try:
            if chapter > int(effective_until):
                return False
        except (TypeError, ValueError):
            pass
    ranges = parse_ranges(entry.get("chapter_ranges") or entry.get("chapter_range"))
    return range_visible(ranges, chapter)


def entry_future_markers(entry: dict[str, Any], chapter: int) -> list[str]:
    if entry_visible(entry, chapter):
        return []
    markers = []
    for key in ("title", "source_path", "url"):
        value = str(entry.get(key) or "").strip()
        if value:
            markers.append(value)
    markers.extend(split_list(entry.get("future_markers")))
    return unique_strings(markers)


def unique_strings(values: list[str]) -> list[str]:
    seen: set[str] = set()
    result: list[str] = []
    for value in values:
        cleaned = value.strip()
        if cleaned and cleaned not in seen:
            seen.add(cleaned)
            result.append(cleaned)
    return result


def text_hash(text: str) -> str:
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def payload_hash(value: Any) -> str:
    return text_hash(json.dumps(value, ensure_ascii=False, sort_keys=True, default=str))


def count_text_units(text: str) -> int:
    cjk = re.findall(r"[\u3400-\u9fff]", text)
    words = re.findall(r"[A-Za-z0-9_]+", text)
    return len(cjk) + len(words)


def sentence_count(text: str) -> int:
    parts = [part for part in re.split(r"[。！？!?]+", text) if part.strip()]
    return max(1, len(parts))


def style_metrics(text: str) -> dict[str, Any]:
    paragraphs = [part for part in re.split(r"\n\s*\n", text.strip()) if part.strip()]
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    dialogue_lines = [line for line in lines if line.startswith(("“", "\"", "「", "'")) or "：" in line[:12] or ":" in line[:12]]
    units = count_text_units(text)
    sentences = sentence_count(text)
    abstract_markers = ["意识到", "感受到", "明白", "情绪", "内心", "意义", "命运", "复杂"]
    return {
        "text_units": units,
        "paragraphs": len(paragraphs),
        "sentences": sentences,
        "avg_sentence_units": round(units / sentences, 2),
        "dialogue_line_ratio": round(len(dialogue_lines) / max(1, len(lines)), 3),
        "model_marker_hits": [marker for marker in AI_MARKERS if marker in text],
        "abstract_marker_hits": [marker for marker in abstract_markers if marker in text],
    }


def merge_style_profile(samples: list[dict[str, Any]]) -> dict[str, Any]:
    metrics = [sample.get("metrics") for sample in samples if isinstance(sample.get("metrics"), dict)]
    if not metrics:
        return {}
    avg_sentence = sum(float(item.get("avg_sentence_units") or 0) for item in metrics) / len(metrics)
    dialogue_ratio = sum(float(item.get("dialogue_line_ratio") or 0) for item in metrics) / len(metrics)
    return {
        "sample_count": len(metrics),
        "avg_sentence_units": round(avg_sentence, 2),
        "dialogue_line_ratio": round(dialogue_ratio, 3),
        "model_markers_seen": unique_strings([marker for item in metrics for marker in item.get("model_marker_hits", [])]),
        "abstract_markers_seen": unique_strings([marker for item in metrics for marker in item.get("abstract_marker_hits", [])]),
        "updated_at": now_iso(),
    }


def tail_text(text: str, limit: int = TAIL_CHARS) -> str:
    compact = text.strip()
    if len(compact) <= limit:
        return compact
    return compact[-limit:]


def make_id(prefix: str) -> str:
    return f"{prefix}-{uuid.uuid4().hex[:12]}"


def snapshot_slug(value: str) -> str:
    text = re.sub(r"[^A-Za-z0-9]+", "-", value.strip().lower()).strip("-")
    return text[:32] or "snapshot"


def create_state_snapshot(state: Path, *, reason: str = "", metadata: dict[str, Any] | None = None) -> dict[str, Any]:
    snapshots = state / SNAPSHOT_DIR_NAME
    snapshots.mkdir(parents=True, exist_ok=True)
    created_at = now_iso()
    stamp = dt.datetime.now(dt.timezone.utc).strftime("%Y%m%dT%H%M%SZ")
    snapshot_id = f"{stamp}-{snapshot_slug(reason)}-{uuid.uuid4().hex[:8]}"
    target = snapshots / snapshot_id
    target.mkdir()
    copied: list[str] = []
    for name in STATE_SNAPSHOT_FILES:
        source = state / name
        if not source.exists():
            continue
        shutil.copy2(source, target / name)
        copied.append(name)
    payload: dict[str, Any] = {
        "id": snapshot_id,
        "created_at": created_at,
        "reason": reason or "manual",
        "kit_version": KIT_VERSION,
        "state_files": copied,
    }
    if metadata:
        payload["metadata"] = metadata
    (target / SNAPSHOT_METADATA_NAME).write_text(json.dumps(payload, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    return payload


def snapshot_metadata(path: Path) -> dict[str, Any]:
    payload = read_json(path / SNAPSHOT_METADATA_NAME, {})
    if not isinstance(payload, dict):
        payload = {}
    payload.setdefault("id", path.name)
    payload.setdefault("path", str(path))
    return payload


def create_snapshot(project_dir: str | Path, *, reason: str = "manual") -> dict[str, Any]:
    state = ensure_state(project_dir)
    snapshot = create_state_snapshot(state, reason=reason)
    return {"ok": True, "snapshot": snapshot}


def list_snapshots(project_dir: str | Path) -> dict[str, Any]:
    state = ensure_state(project_dir)
    root = state / SNAPSHOT_DIR_NAME
    rows: list[dict[str, Any]] = []
    if root.exists():
        for path in sorted(root.iterdir()):
            if path.is_dir():
                rows.append(snapshot_metadata(path))
    rows.sort(key=lambda row: str(row.get("created_at") or row.get("id") or ""), reverse=True)
    return {"ok": True, "snapshots": rows}


def list_audit(project_dir: str | Path, *, limit: int = 20) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "audit.jsonl")
    safe_limit = max(1, int(limit or 20))
    return {"ok": True, "audit": rows[-safe_limit:]}


def declare_agent_capabilities(
    project_dir: str | Path,
    *,
    agent_id: str,
    platform: str = "",
    capabilities: Any = None,
    notes: str = "",
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "agents.jsonl")
    agent_id = str(agent_id or "").strip()
    if not agent_id:
        raise KitError("agent_id is required")
    entry = {
        "id": agent_id,
        "platform": platform.strip(),
        "capabilities": split_list(capabilities),
        "notes": notes.strip(),
        "updated_at": now_iso(),
    }
    updated = False
    for index, row in enumerate(rows):
        if row.get("id") == agent_id:
            rows[index] = {**row, **entry}
            updated = True
            break
    if not updated:
        entry["created_at"] = entry["updated_at"]
        rows.append(entry)
    write_jsonl(state / "agents.jsonl", rows)
    return {"ok": True, "agent": entry, "updated": updated}


def list_agent_capabilities(project_dir: str | Path) -> dict[str, Any]:
    state = ensure_state(project_dir)
    return {"ok": True, "agents": read_jsonl(state / "agents.jsonl")}


def restore_snapshot(project_dir: str | Path, *, snapshot_id: str) -> dict[str, Any]:
    state = ensure_state(project_dir)
    snapshot_path = state / SNAPSHOT_DIR_NAME / snapshot_id
    if not snapshot_path.exists() or not snapshot_path.is_dir():
        raise KitError(f"Snapshot not found: {snapshot_id}")
    snapshot = snapshot_metadata(snapshot_path)
    backup = create_state_snapshot(state, reason="before_restore", metadata={"restore_target": snapshot_id})
    files = snapshot.get("state_files")
    if not isinstance(files, list) or not files:
        files = [name for name in STATE_SNAPSHOT_FILES if (snapshot_path / name).exists()]
    restored: list[str] = []
    for name in files:
        safe_name = str(name)
        if safe_name not in STATE_SNAPSHOT_FILES:
            continue
        source = snapshot_path / safe_name
        if source.exists():
            shutil.copy2(source, state / safe_name)
            restored.append(safe_name)
    return {"ok": True, "restored": snapshot, "restored_files": restored, "backup_snapshot": backup}


def export_state_package(project_dir: str | Path, *, output: str = "") -> dict[str, Any]:
    state = ensure_state(project_dir)
    project = project_root(project_dir)
    if output:
        package_path = Path(output).expanduser()
        if not package_path.is_absolute():
            package_path = project / package_path
    else:
        package_path = project / f"{project.name}.novel-agent.zip"
    package_path.parent.mkdir(parents=True, exist_ok=True)
    exported: list[str] = []
    manifest = {
        "package_type": "long-novel-agent-state",
        "kit_version": KIT_VERSION,
        "state_schema_version": STATE_SCHEMA_VERSION,
        "created_at": now_iso(),
        "source_project": str(project),
    }
    with zipfile.ZipFile(package_path, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        archive.writestr("package_manifest.json", json.dumps(manifest, ensure_ascii=False, indent=2) + "\n")
        for path in sorted(state.rglob("*")):
            if path.is_dir() or path.name == "lock.json" or LOCK_DIR_NAME in path.parts:
                continue
            rel = path.relative_to(state)
            archive.write(path, f"{STATE_DIR}/{rel.as_posix()}")
            exported.append(rel.as_posix())
    return {"ok": True, "package": str(package_path), "files": exported, "manifest": manifest}


def import_state_package(project_dir: str | Path, *, package: str, force: bool = False) -> dict[str, Any]:
    project = project_root(project_dir)
    package_path = Path(package).expanduser()
    if not package_path.is_absolute():
        package_path = project / package_path
    if not package_path.exists():
        raise KitError(f"State package not found: {package_path}")
    state = project / STATE_DIR
    if state.exists() and not force:
        raise KitError(f"State already exists: {state}. Use --force to replace it.")
    backup_dir: Path | None = None
    with tempfile_extract_state_package(package_path) as extracted_state:
        project.mkdir(parents=True, exist_ok=True)
        if state.exists():
            stamp = dt.datetime.now(dt.timezone.utc).strftime("%Y%m%dT%H%M%SZ")
            backup_dir = project / f"{STATE_DIR}.backup-{stamp}"
            shutil.move(str(state), str(backup_dir))
        shutil.copytree(extracted_state, state, ignore=shutil.ignore_patterns(LOCK_DIR_NAME, "__pycache__", "*.pyc"))
    migration = migrate_state(state, operation="import_state_package")
    result = {"ok": True, "state_dir": str(state), "backup_dir": str(backup_dir) if backup_dir else "", "migration": migration}
    audit = audit_state_change(state, "import-state", result, migration=migration)
    result["audit_id"] = audit["id"]
    return result


@contextmanager
def tempfile_extract_state_package(package_path: Path):
    import tempfile

    with tempfile.TemporaryDirectory(prefix="long-novel-state-import-") as tmp:
        tmp_path = Path(tmp)
        with zipfile.ZipFile(package_path) as archive:
            names = archive.namelist()
            if "package_manifest.json" not in names:
                raise KitError("State package missing package_manifest.json")
            for name in names:
                parts = Path(name).parts
                if not parts or parts[0] not in {"package_manifest.json", STATE_DIR}:
                    raise KitError(f"Unsafe state package entry: {name}")
                if ".." in parts:
                    raise KitError(f"Unsafe state package entry: {name}")
            archive.extractall(tmp_path)
        extracted_state = tmp_path / STATE_DIR
        if not extracted_state.exists():
            raise KitError("State package missing .novel-agent directory")
        yield extracted_state


def load_state(project_dir: str | Path) -> dict[str, Any]:
    state = ensure_state(project_dir)
    return {
        "state": state,
        "manifest": read_json(state / "manifest.json", {}),
        "rules": read_json(state / "rules.json", {}),
        "chapters": read_jsonl(state / "chapters.jsonl"),
        "characters": read_json(state / "characters.json", {"characters": []}),
        "debts": read_json(state / "debts.json", {"debts": []}),
        "style_profile": read_json(state / "style_profile.json", {"samples": [], "profile": {}}),
        "contracts": read_jsonl(state / "contracts.jsonl"),
        "sources": read_jsonl(state / "sources.jsonl"),
        "research": read_jsonl(state / "research.jsonl"),
        "conflicts": read_jsonl(state / "conflicts.jsonl"),
        "facts": read_jsonl(state / "facts.jsonl"),
        "proposals": read_jsonl(state / "proposals.jsonl"),
        "agents": read_jsonl(state / "agents.jsonl"),
        "desktop_verifications": read_jsonl(state / "desktop_verifications.jsonl"),
        "agent_activity": read_jsonl(state / "agent_activity.jsonl"),
        "style": (state / "style.md").read_text(encoding="utf-8") if (state / "style.md").exists() else "",
        "handoff": (state / "handoff.md").read_text(encoding="utf-8") if (state / "handoff.md").exists() else "",
    }


def init_project(
    project_dir: str | Path,
    *,
    title: str | None = None,
    target_chapters: int | None = None,
    target_words: int | None = None,
    force: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = ensure_state(project, create=True)
    created_at = now_iso()
    manifest = {
        "kit_version": KIT_VERSION,
        "state_schema_version": STATE_SCHEMA_VERSION,
        "title": title or project.name,
        "target_chapters": target_chapters,
        "target_words": target_words,
        "current_chapter": 0,
        "created_at": created_at,
        "updated_at": created_at,
    }
    manifest["project_id"] = deterministic_project_id(project, manifest)
    rules = {
        "required_phrases": [],
        "forbidden_phrases": [],
        "future_markers": [],
        "forbidden_renames": [],
        "notes": [],
    }
    write_json_if_missing(state / "manifest.json", manifest, force=force)
    write_json_if_missing(state / "rules.json", rules, force=force)
    write_json_if_missing(state / "characters.json", {"characters": []}, force=force)
    write_json_if_missing(state / "debts.json", {"debts": []}, force=force)
    write_json_if_missing(state / "style_profile.json", {"samples": [], "profile": {}}, force=force)
    for name in REQUIRED_JSONL_FILES:
        ensure_jsonl(state / name, force=force)
    write_if_missing(
        state / "style.md",
        "# Style\n\n- Record voice, rhythm, de-AI preferences, and project-specific prose constraints here.\n",
        force=force,
    )
    write_if_missing(
        state / "handoff.md",
        "# Handoff\n\nNo accepted chapter has been recorded yet.\n",
        force=force,
    )
    return {"ok": True, "project_dir": str(project), "state_dir": str(state), "manifest": read_json(state / "manifest.json", {})}


def merge_rule_list(rules: dict[str, Any], key: str, values: Any) -> bool:
    before = split_list(rules.get(key))
    after = unique_strings(before + split_list(values))
    if after == before:
        return False
    rules[key] = after
    return True


def append_style_note(state: Path, note: str) -> bool:
    text = note.strip()
    if not text:
        return False
    path = state / "style.md"
    current = path.read_text(encoding="utf-8") if path.exists() else "# Style\n"
    addition = "\n\n## Init Wizard Note\n\n" + text + "\n"
    if text in current:
        return False
    path.write_text(current.rstrip() + addition, encoding="utf-8")
    return True


def init_wizard_plan(
    project_dir: str | Path,
    *,
    title: str | None = None,
    target_chapters: int | None = None,
    target_words: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
    rule_notes: Any = None,
    style_note: str = "",
    source_summary: str = "",
    source_path: str = "",
    chapter_range: str = "",
    agent_id: str = "",
    platform: str = "",
    capabilities: Any = None,
    import_gaoxia: bool = False,
    append_import: bool = False,
    force: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    operations: list[str] = []
    warnings: list[str] = []
    if import_gaoxia:
        operations.append("import-gaoxia")
        if not (project / "project.json").exists():
            warnings.append(f"Gaoxia project.json not found: {project / 'project.json'}")
    else:
        operations.append("init")
        if (project / "project.json").exists():
            warnings.append("project.json exists; use --import-gaoxia to import Gaoxia continuity state.")
    if split_list(required_phrases) or split_list(forbidden_phrases) or split_list(future_markers) or split_list(rule_notes):
        operations.append("update-rules")
    if style_note.strip():
        operations.append("update-style")
    if source_summary.strip():
        operations.append("add-source")
    if agent_id.strip():
        operations.append("declare-agent")
    return {
        "project_dir": str(project),
        "state_dir": str(project / STATE_DIR),
        "title": title or project.name,
        "target_chapters": target_chapters,
        "target_words": target_words,
        "operations": operations,
        "warnings": warnings,
        "rules": {
            "required_phrases": split_list(required_phrases),
            "forbidden_phrases": split_list(forbidden_phrases),
            "future_markers": split_list(future_markers),
            "notes": split_list(rule_notes),
        },
        "source": {
            "has_summary": bool(source_summary.strip()),
            "source_path": source_path,
            "chapter_range": chapter_range,
        },
        "agent": {
            "agent_id": agent_id,
            "platform": platform,
            "capabilities": split_list(capabilities),
        },
        "import_gaoxia": import_gaoxia,
        "append_import": append_import,
        "force": force,
        "next_steps": [
            "Run build-context before drafting any chapter.",
            "Run chapter-readiness before presenting a chapter as ready; use check-chapter and diff-contract when the combined report is unavailable.",
            "After author acceptance, run record-chapter and propose-after-write/apply-after-write with --author-confirmation.",
        ],
    }


def init_wizard(
    project_dir: str | Path,
    *,
    title: str | None = None,
    target_chapters: int | None = None,
    target_words: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
    rule_notes: Any = None,
    style_note: str = "",
    source_summary: str = "",
    source_path: str = "",
    chapter_range: str = "",
    agent_id: str = "",
    platform: str = "",
    capabilities: Any = None,
    agent_notes: str = "",
    import_gaoxia: bool = False,
    append_import: bool = False,
    dry_run: bool = False,
    force: bool = False,
) -> dict[str, Any]:
    plan = init_wizard_plan(
        project_dir,
        title=title,
        target_chapters=target_chapters,
        target_words=target_words,
        required_phrases=required_phrases,
        forbidden_phrases=forbidden_phrases,
        future_markers=future_markers,
        rule_notes=rule_notes,
        style_note=style_note,
        source_summary=source_summary,
        source_path=source_path,
        chapter_range=chapter_range,
        agent_id=agent_id,
        platform=platform,
        capabilities=capabilities,
        import_gaoxia=import_gaoxia,
        append_import=append_import,
        force=force,
    )
    if dry_run:
        return {"ok": True, "dry_run": True, "plan": plan}
    if import_gaoxia:
        bootstrap = import_gaoxia_project(project_dir, append=append_import)
    else:
        bootstrap = init_project(
            project_dir,
            title=title,
            target_chapters=target_chapters,
            target_words=target_words,
            force=force,
        )
    state = ensure_state(project_dir)
    rules = read_json(state / "rules.json", {})
    if not isinstance(rules, dict):
        rules = {}
    changed_rules: list[str] = []
    for key, values in (
        ("required_phrases", required_phrases),
        ("forbidden_phrases", forbidden_phrases),
        ("future_markers", future_markers),
        ("notes", rule_notes),
    ):
        if merge_rule_list(rules, key, values):
            changed_rules.append(key)
    if changed_rules:
        write_json(state / "rules.json", rules)
    style_updated = append_style_note(state, style_note)
    source_result = None
    if source_summary.strip():
        source_result = add_source_summary(
            project_dir,
            summary=source_summary,
            source_path=source_path,
            title=source_path or "init-wizard-source",
            chapter_range=chapter_range,
            credibility="init-wizard",
        )
    agent_result = None
    if agent_id.strip():
        agent_result = declare_agent_capabilities(
            project_dir,
            agent_id=agent_id,
            platform=platform,
            capabilities=capabilities,
            notes=agent_notes,
        )
    return {
        "ok": True,
        "dry_run": False,
        "plan": plan,
        "bootstrap": bootstrap,
        "changed_rules": changed_rules,
        "style_updated": style_updated,
        "source": source_result,
        "agent": agent_result,
    }


def import_gaoxia_project(
    project_dir: str | Path,
    *,
    include_chapters: bool = True,
    include_vault: bool = True,
    include_narrative_state: bool = True,
    max_vault_notes: int = 120,
    append: bool = False,
    dry_run: bool = False,
    report_path: str = "",
) -> dict[str, Any]:
    project = project_root(project_dir)
    meta_path = project / "project.json"
    meta = read_json(meta_path, None)
    if not isinstance(meta, dict):
        raise KitError(f"Gaoxia project.json not found or invalid: {meta_path}")
    if dry_run:
        report = scan_gaoxia_project(
            project,
            include_chapters=include_chapters,
            include_vault=include_vault,
            include_narrative_state=include_narrative_state,
            max_vault_notes=max_vault_notes,
        )
        write_import_report(report_path, report)
        return report

    init_project(
        project,
        title=str(meta.get("name") or project.name),
        target_chapters=coerce_optional_int(meta.get("target_chapters")),
        target_words=coerce_optional_int(meta.get("target_words")),
    )
    state = ensure_state(project)
    if not append:
        remove_imported_state(state)

    imported_at = now_iso()
    counts = {
        "architecture_sources": 0,
        "chapters": 0,
        "vault_notes": 0,
        "narrative_debts": 0,
        "character_arcs": 0,
        "chapter_contracts": 0,
        "chapter_cards": 0,
        "project_memory_entries": 0,
        "facts": 0,
    }
    fact_rows = read_jsonl(state / "facts.jsonl")

    source_rows = read_jsonl(state / "sources.jsonl")
    for filename, title in ARCHITECTURE_FILES.items():
        path = project / filename
        if not path.exists():
            continue
        text = path.read_text(encoding="utf-8").strip()
        if not text:
            continue
        source_hash = text_hash(text)
        source_rows.append(
            imported_row(
                {
                    "id": f"gaoxia-architecture-{Path(filename).stem}",
                    "kind": "gaoxia_architecture",
                    "title": title,
                    "source_path": filename,
                    "source_hash": source_hash,
                    "summary": limit_text(text, 16000),
                    "chapter_ranges": [],
                    "required_phrases": [],
                    "forbidden_phrases": [],
                    "credibility": "gaoxia-project-file",
                },
                imported_at,
            )
        )
        fact_rows.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind="rule",
                        subject=title,
                        predicate="source_summary",
                        object_value=limit_text(text, 1200),
                        source_ids=[f"gaoxia-architecture-{Path(filename).stem}"],
                        source_path=filename,
                        confidence="imported",
                    ),
                    source_hash=source_hash,
                ),
                imported_at,
            )
        )
        counts["architecture_sources"] += 1

    memory_entries, memory_facts = import_project_memory(project, imported_at)
    source_rows.extend(memory_entries)
    fact_rows.extend(memory_facts)
    counts["project_memory_entries"] = len(memory_entries)

    if include_vault:
        vault_entries, vault_facts = import_gaoxia_vault(project, imported_at, max_notes=max_vault_notes)
        source_rows.extend(vault_entries)
        fact_rows.extend(vault_facts)
        counts["vault_notes"] = len(vault_entries)
    write_jsonl(state / "sources.jsonl", source_rows)

    if include_chapters:
        chapter_count, chapter_facts = import_gaoxia_chapters(project, state, imported_at)
        counts["chapters"] = chapter_count
        fact_rows.extend(chapter_facts)

    if include_narrative_state:
        narrative_counts, narrative_facts = import_gaoxia_narrative_state(project, state, imported_at)
        counts.update(narrative_counts)
        fact_rows.extend(narrative_facts)

    counts["facts"] = len([row for row in fact_rows if row.get("import_source") == IMPORT_SOURCE])
    write_jsonl(state / "facts.jsonl", fact_rows)

    manifest = read_json(state / "manifest.json", {})
    manifest["kit_version"] = KIT_VERSION
    manifest["title"] = str(meta.get("name") or manifest.get("title") or project.name)
    manifest["target_chapters"] = coerce_optional_int(meta.get("target_chapters")) or manifest.get("target_chapters")
    manifest["target_words"] = coerce_optional_int(meta.get("target_words")) or manifest.get("target_words")
    manifest["gaoxia_project_id"] = meta.get("id")
    manifest["gaoxia_project_path"] = str(project)
    manifest["updated_at"] = now_iso()
    write_json(state / "manifest.json", manifest)

    update_handoff_from_latest_chapter(state)
    result = {
        "ok": True,
        "project_dir": str(project),
        "state_dir": str(state),
        "append": append,
        "counts": counts,
    }
    write_import_report(report_path, result)
    return result


def coerce_optional_int(value: Any) -> int | None:
    try:
        if value is None or value == "":
            return None
        parsed = int(value)
        return parsed if parsed > 0 else None
    except (TypeError, ValueError):
        return None


def scan_gaoxia_project(
    project: Path,
    *,
    include_chapters: bool,
    include_vault: bool,
    include_narrative_state: bool,
    max_vault_notes: int,
) -> dict[str, Any]:
    counts = {
        "architecture_sources": 0,
        "chapters": 0,
        "vault_notes": 0,
        "narrative_debts": 0,
        "character_arcs": 0,
        "chapter_contracts": 0,
        "chapter_cards": 0,
        "project_memory_entries": 0,
        "estimated_facts": 0,
    }
    files: list[str] = []
    for filename in ARCHITECTURE_FILES:
        path = project / filename
        if path.exists() and path.read_text(encoding="utf-8").strip():
            counts["architecture_sources"] += 1
            counts["estimated_facts"] += 1
            files.append(filename)
    memory_payload = read_json(project / "project_memory.json", {})
    if isinstance(memory_payload, dict) and isinstance(memory_payload.get("entries"), list):
        counts["project_memory_entries"] = len([item for item in memory_payload["entries"] if isinstance(item, dict)])
        counts["estimated_facts"] += counts["project_memory_entries"]
        files.append("project_memory.json")
    if include_vault:
        vault = project / "Vault"
        if vault.exists():
            vault_paths = [path for path in sorted(vault.rglob("*.md")) if not is_ignored_vault_path(path.relative_to(project).as_posix())]
            counts["vault_notes"] = min(len(vault_paths), max_vault_notes)
            counts["estimated_facts"] += counts["vault_notes"]
            files.extend(path.relative_to(project).as_posix() for path in vault_paths[: min(5, max_vault_notes)])
    if include_chapters:
        chapters_dir = project / "chapters"
        if chapters_dir.exists():
            chapter_paths = [path for path in sorted(chapters_dir.glob("*.md")) if path.stem.isdigit() and path.read_text(encoding="utf-8").strip()]
            counts["chapters"] = len(chapter_paths)
            counts["estimated_facts"] += len(chapter_paths)
            files.extend(path.relative_to(project).as_posix() for path in chapter_paths[:5])
    if include_narrative_state:
        narrative = read_json(project / ".gaoxia" / "learning" / "narrative_state.json", {})
        if isinstance(narrative, dict):
            counts["narrative_debts"] = len(narrative.get("debts") or []) if isinstance(narrative.get("debts"), list) else 0
            counts["character_arcs"] = len(narrative.get("character_arcs") or []) if isinstance(narrative.get("character_arcs"), list) else 0
            counts["chapter_contracts"] = len(narrative.get("chapter_contracts") or []) if isinstance(narrative.get("chapter_contracts"), list) else 0
            counts["chapter_cards"] = len(narrative.get("chapter_cards") or []) if isinstance(narrative.get("chapter_cards"), list) else 0
            counts["estimated_facts"] += counts["narrative_debts"] + counts["character_arcs"] + counts["chapter_contracts"] + counts["chapter_cards"]
            files.append(".gaoxia/learning/narrative_state.json")
    return {
        "ok": True,
        "dry_run": True,
        "project_dir": str(project),
        "would_write": str(project / STATE_DIR),
        "counts": counts,
        "sample_files": unique_strings(files),
    }


def project_relative_or_absolute_path(project: Path, value: Any) -> Path | None:
    text = str(value or "").strip()
    if not text:
        return None
    path = Path(text).expanduser()
    if not path.is_absolute():
        path = project / text
    return path


def existing_or_first_path(candidates: list[Path]) -> Path | None:
    seen: set[str] = set()
    unique: list[Path] = []
    for path in candidates:
        key = str(path)
        if key not in seen:
            seen.add(key)
            unique.append(path)
    for path in unique:
        if path.exists():
            return path
    return unique[0] if unique else None


def imported_chapter_source_path(project: Path, row: dict[str, Any]) -> Path | None:
    candidates: list[Path] = []
    for key in ("source_path", "file"):
        candidate = project_relative_or_absolute_path(project, row.get(key))
        if candidate is not None:
            candidates.append(candidate)
    chapter = coerce_optional_int(row.get("chapter"))
    chapters_dir = project / "chapters"
    if chapter:
        candidates.extend(
            [
                chapters_dir / f"{chapter:03d}.md",
                chapters_dir / f"{chapter:04d}.md",
                chapters_dir / f"{chapter}.md",
            ]
        )
        if chapters_dir.exists():
            for path in sorted(chapters_dir.glob("*.md")):
                if path.stem.isdigit() and int(path.stem) == chapter:
                    candidates.append(path)
    return existing_or_first_path(candidates)


def safe_file_text_hash(path: Path, *, strip: bool = False) -> tuple[str, str]:
    try:
        text = path.read_text(encoding="utf-8")
    except OSError as exc:
        return "", str(exc)
    return text_hash(text.strip() if strip else text), ""


def import_row_ref(row: dict[str, Any], *, state_file: str) -> dict[str, Any]:
    ref = {
        "state_file": state_file,
        "id": row.get("id"),
        "kind": row.get("kind"),
        "source_path": row.get("source_path") or row.get("file"),
    }
    if row.get("chapter") is not None:
        ref["chapter"] = row.get("chapter")
    return {key: value for key, value in ref.items() if value not in (None, "", [], {})}


def current_project_memory_payload_hashes(project: Path) -> dict[str, str]:
    payload = read_json(project / "project_memory.json", {})
    rows = payload.get("entries", []) if isinstance(payload, dict) else []
    if not isinstance(rows, list):
        return {}
    hashes: dict[str, str] = {}
    for index, item in enumerate(rows, 1):
        if isinstance(item, dict):
            hashes[f"gaoxia-memory-{index}"] = payload_hash(item)
    return hashes


def current_narrative_payload_hashes(project: Path) -> dict[str, dict[str, str]]:
    payload = read_json(project / ".gaoxia" / "learning" / "narrative_state.json", {})
    if not isinstance(payload, dict):
        return {"narrative_debt": {}, "character_arc": {}, "chapter_contract": {}, "chapter_card": {}}
    groups = {
        "narrative_debt": ("debts", "gaoxia-debt"),
        "character_arc": ("character_arcs", "gaoxia-character"),
        "chapter_contract": ("chapter_contracts", "gaoxia-contract"),
        "chapter_card": ("chapter_cards", "gaoxia-card"),
    }
    result: dict[str, dict[str, str]] = {}
    for group, (payload_key, fallback_prefix) in groups.items():
        rows = payload.get(payload_key, [])
        hashes: dict[str, str] = {}
        if isinstance(rows, list):
            for index, item in enumerate(rows, 1):
                if isinstance(item, dict):
                    hashes[str(item.get("id") or f"{fallback_prefix}-{index}")] = payload_hash(item)
        result[group] = hashes
    return result


def compare_payload_hash_rows(
    rows: list[dict[str, Any]],
    *,
    current_hashes: dict[str, str],
    state_file: str,
    group: str,
    unknown_hashes: list[dict[str, Any]],
    changed_payloads: list[dict[str, Any]],
    missing_payloads: list[dict[str, Any]],
) -> None:
    for row in rows:
        row_id = str(row.get("id") or "")
        expected = str(row.get("source_payload_hash") or "")
        ref = import_row_ref(row, state_file=state_file)
        ref["payload_group"] = group
        if not expected:
            unknown_hashes.append(ref)
        if not row_id or row_id not in current_hashes:
            missing_payloads.append(ref)
            continue
        actual = current_hashes[row_id]
        if expected and actual != expected:
            changed_payloads.append({**ref, "expected": expected, "actual": actual})


def build_gaoxia_import_freshness(
    project: Path,
    *,
    imported_sources: list[dict[str, Any]],
    imported_chapters: list[dict[str, Any]],
    imported_debts: list[dict[str, Any]],
    imported_characters: list[dict[str, Any]],
    imported_contracts: list[dict[str, Any]],
) -> dict[str, Any]:
    changed_chapters: list[dict[str, Any]] = []
    missing_chapter_files: list[dict[str, Any]] = []
    changed_source_files: list[dict[str, Any]] = []
    missing_source_files: list[dict[str, Any]] = []
    changed_payloads: list[dict[str, Any]] = []
    missing_payloads: list[dict[str, Any]] = []
    unknown_hashes: list[dict[str, Any]] = []

    for row in imported_chapters:
        expected = str(row.get("hash") or "")
        ref = import_row_ref(row, state_file="chapters.jsonl")
        if not expected:
            unknown_hashes.append(ref)
        path = imported_chapter_source_path(project, row)
        if path is None or not path.exists():
            missing_chapter_files.append({**ref, "resolved_path": str(path) if path else ""})
            continue
        actual, error = safe_file_text_hash(path)
        if error:
            missing_chapter_files.append({**ref, "resolved_path": str(path), "error": error})
            continue
        if expected and actual != expected:
            changed_chapters.append({**ref, "resolved_path": str(path), "expected": expected, "actual": actual})

    for row in imported_sources:
        kind = str(row.get("kind") or "")
        if kind != "gaoxia_architecture" and not kind.startswith("gaoxia_vault:"):
            continue
        expected = str(row.get("source_hash") or "")
        ref = import_row_ref(row, state_file="sources.jsonl")
        if not expected:
            unknown_hashes.append(ref)
        path = project_relative_or_absolute_path(project, row.get("source_path"))
        if path is None or not path.exists():
            missing_source_files.append({**ref, "resolved_path": str(path) if path else ""})
            continue
        actual, error = safe_file_text_hash(path, strip=kind == "gaoxia_architecture")
        if error:
            missing_source_files.append({**ref, "resolved_path": str(path), "error": error})
            continue
        if expected and actual != expected:
            changed_source_files.append({**ref, "resolved_path": str(path), "expected": expected, "actual": actual})

    memory_hashes = current_project_memory_payload_hashes(project)
    compare_payload_hash_rows(
        [row for row in imported_sources if row.get("kind") == "gaoxia_project_memory"],
        current_hashes=memory_hashes,
        state_file="sources.jsonl",
        group="project_memory",
        unknown_hashes=unknown_hashes,
        changed_payloads=changed_payloads,
        missing_payloads=missing_payloads,
    )
    narrative_hashes = current_narrative_payload_hashes(project)
    compare_payload_hash_rows(
        imported_debts,
        current_hashes=narrative_hashes.get("narrative_debt", {}),
        state_file="debts.json",
        group="narrative_debt",
        unknown_hashes=unknown_hashes,
        changed_payloads=changed_payloads,
        missing_payloads=missing_payloads,
    )
    compare_payload_hash_rows(
        imported_characters,
        current_hashes=narrative_hashes.get("character_arc", {}),
        state_file="characters.json",
        group="character_arc",
        unknown_hashes=unknown_hashes,
        changed_payloads=changed_payloads,
        missing_payloads=missing_payloads,
    )
    compare_payload_hash_rows(
        imported_contracts,
        current_hashes=narrative_hashes.get("chapter_contract", {}),
        state_file="contracts.jsonl",
        group="chapter_contract",
        unknown_hashes=unknown_hashes,
        changed_payloads=changed_payloads,
        missing_payloads=missing_payloads,
    )
    compare_payload_hash_rows(
        [row for row in imported_sources if row.get("kind") == "gaoxia_chapter_card"],
        current_hashes=narrative_hashes.get("chapter_card", {}),
        state_file="sources.jsonl",
        group="chapter_card",
        unknown_hashes=unknown_hashes,
        changed_payloads=changed_payloads,
        missing_payloads=missing_payloads,
    )

    return {
        "changed_chapters": changed_chapters,
        "missing_chapter_files": missing_chapter_files,
        "changed_source_files": changed_source_files,
        "missing_source_files": missing_source_files,
        "changed_payloads": changed_payloads,
        "missing_payloads": missing_payloads,
        "unknown_hashes": unknown_hashes,
    }


def build_gaoxia_import_audit(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    max_vault_notes: int = 120,
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    generated_at = now_iso()
    meta_path = project / "project.json"
    try:
        meta = read_json(meta_path, None)
    except KitError as exc:
        return {
            "ok": False,
            "type": "gaoxia_import_audit",
            "generated_at": generated_at,
            "status": "not_gaoxia_project",
            "project_dir": str(project),
            "state_dir": str(state),
            "checks": [
                {
                    "id": "gaoxia_project_json_valid",
                    "ok": False,
                    "severity": "must_fix",
                    "message": "Gaoxia project.json is missing or invalid.",
                    "detail": str(exc),
                }
            ],
            "action_plan": build_continuity_action_plan(
                [
                    continuity_audit_action(
                        "select_gaoxia_project",
                        "must_fix",
                        "Select a valid Gaoxia project directory",
                        "The audit needs a project.json file before it can compare Gaoxia source files with .novel-agent state.",
                        source_check="gaoxia_project_json_valid",
                    )
                ]
            ),
            "recommended_commands": [],
        }
    if not isinstance(meta, dict):
        return {
            "ok": False,
            "type": "gaoxia_import_audit",
            "generated_at": generated_at,
            "status": "not_gaoxia_project",
            "project_dir": str(project),
            "state_dir": str(state),
            "checks": [
                {
                    "id": "gaoxia_project_json_valid",
                    "ok": False,
                    "severity": "must_fix",
                    "message": "Gaoxia project.json is missing or invalid.",
                    "detail": str(meta_path),
                }
            ],
            "action_plan": build_continuity_action_plan(
                [
                    continuity_audit_action(
                        "select_gaoxia_project",
                        "must_fix",
                        "Select a valid Gaoxia project directory",
                        "The audit needs a project.json file before it can compare Gaoxia source files with .novel-agent state.",
                        source_check="gaoxia_project_json_valid",
                    )
                ]
            ),
            "recommended_commands": [],
        }

    source_scan = scan_gaoxia_project(
        project,
        include_chapters=True,
        include_vault=True,
        include_narrative_state=True,
        max_vault_notes=max_vault_notes,
    )
    expected = source_scan.get("counts") if isinstance(source_scan.get("counts"), dict) else {}
    state_exists = state.exists()
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    add_check("gaoxia_project_json_valid", True, "must_fix", "Gaoxia project.json is valid.", str(meta_path))
    add_check("state_initialized", state_exists, "must_fix", ".novel-agent state exists.", str(state))
    if not state_exists:
        action_plan = build_continuity_action_plan(
            [
                continuity_audit_action(
                    "import_gaoxia_state",
                    "must_fix",
                    "Import Gaoxia continuity state",
                    "No .novel-agent state exists yet, so desktop agents cannot build durable chapter context.",
                    command=f"python cli.py import-gaoxia {project}",
                    source_check="state_initialized",
                )
            ]
        )
        return {
            "ok": False,
            "type": "gaoxia_import_audit",
            "generated_at": generated_at,
            "status": "not_imported",
            "project_dir": str(project),
            "state_dir": str(state),
            "source_inventory": source_scan,
            "imported_state": {},
            "checks": checks,
            "action_plan": action_plan,
            "recommended_commands": [
                f"python cli.py import-gaoxia {project} --dry-run",
                f"python cli.py import-gaoxia {project}",
            ],
        }

    data = load_state(project)
    sources = data["sources"] if isinstance(data.get("sources"), list) else []
    facts = data["facts"] if isinstance(data.get("facts"), list) else []
    chapters = data["chapters"] if isinstance(data.get("chapters"), list) else []
    contracts = data["contracts"] if isinstance(data.get("contracts"), list) else []
    characters_payload = data["characters"] if isinstance(data.get("characters"), dict) else {}
    debts_payload = data["debts"] if isinstance(data.get("debts"), dict) else {}
    characters = characters_payload.get("characters", []) if isinstance(characters_payload, dict) else []
    debts = debts_payload.get("debts", []) if isinstance(debts_payload, dict) else []
    imported_sources = [row for row in sources if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    imported_facts = [row for row in facts if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    active_imported_facts = [row for row in imported_facts if fact_active(row)]
    imported_chapters = [row for row in chapters if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    imported_contracts = [row for row in contracts if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    imported_characters = [row for row in characters if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    imported_debts = [row for row in debts if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    actual = {
        "architecture_sources": len([row for row in imported_sources if row.get("kind") == "gaoxia_architecture"]),
        "chapters": len(imported_chapters),
        "vault_notes": len([row for row in imported_sources if str(row.get("kind") or "").startswith("gaoxia_vault:")]),
        "narrative_debts": len(imported_debts),
        "character_arcs": len(imported_characters),
        "chapter_contracts": len([row for row in imported_contracts if row.get("kind") == "gaoxia_chapter_contract"]),
        "chapter_cards": len([row for row in imported_sources if row.get("kind") == "gaoxia_chapter_card"]),
        "project_memory_entries": len([row for row in imported_sources if row.get("kind") == "gaoxia_project_memory"]),
        "facts": len(imported_facts),
    }
    deltas = {key: int(expected.get(key) or 0) - int(actual.get(key) or 0) for key in actual if key != "facts"}
    chapter_paths = [
        path
        for path in sorted((project / "chapters").glob("*.md"))
        if path.stem.isdigit() and path.read_text(encoding="utf-8").strip()
    ] if (project / "chapters").exists() else []
    expected_chapter_numbers = sorted(int(path.stem) for path in chapter_paths)
    imported_chapter_numbers = sorted(int(row.get("chapter")) for row in imported_chapters if str(row.get("chapter") or "").isdigit())
    missing_chapter_numbers = [number for number in expected_chapter_numbers if number not in set(imported_chapter_numbers)]
    duplicate_imported_chapters = sorted(number for number in set(imported_chapter_numbers) if imported_chapter_numbers.count(number) > 1)
    fact_evidence_missing = [
        row
        for row in active_imported_facts
        if not first_nonempty(row.get("evidence"), row.get("source_path")) and not split_list(row.get("source_ids"))
    ]
    manifest = data["manifest"] if isinstance(data.get("manifest"), dict) else {}
    imported_path = str(manifest.get("gaoxia_project_path") or "")
    latest_chapter = imported_chapter_numbers[-1] if imported_chapter_numbers else 0
    target = chapter or max(1, latest_chapter + 1)
    context: dict[str, Any] = {}
    context_error = ""
    try:
        context = build_chapter_context(project, chapter=target)
    except Exception as exc:  # noqa: BLE001 - report audit evidence
        context_error = str(exc)
    visible_sources = context.get("sources", []) if isinstance(context, dict) else []
    visible_facts = context.get("facts", []) if isinstance(context, dict) else []
    visible_imported_sources = [row for row in visible_sources if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    visible_imported_facts = [row for row in visible_facts if isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE]
    freshness = build_gaoxia_import_freshness(
        project,
        imported_sources=imported_sources,
        imported_chapters=imported_chapters,
        imported_debts=imported_debts,
        imported_characters=imported_characters,
        imported_contracts=imported_contracts,
    )
    stale_chapter_rows = list(freshness.get("changed_chapters") or []) + list(freshness.get("missing_chapter_files") or [])
    stale_source_rows = list(freshness.get("changed_source_files") or []) + list(freshness.get("missing_source_files") or [])
    stale_payload_rows = list(freshness.get("changed_payloads") or []) + list(freshness.get("missing_payloads") or [])
    unknown_hash_rows = list(freshness.get("unknown_hashes") or [])

    imported_path_ok = imported_path in {"", str(project)}
    if imported_path and not imported_path_ok:
        try:
            imported_path_ok = Path(imported_path).expanduser() == project
        except RuntimeError:
            imported_path_ok = False
    add_check("manifest_points_to_project", imported_path_ok, "warning", "Manifest Gaoxia project path matches this project.", imported_path)
    add_check("imported_architecture_complete", deltas["architecture_sources"] <= 0, "review", "Architecture source files are imported.", {"expected": expected.get("architecture_sources", 0), "actual": actual["architecture_sources"], "missing": max(0, deltas["architecture_sources"])})
    add_check("imported_chapters_complete", not missing_chapter_numbers and not duplicate_imported_chapters, "must_fix", "Accepted chapter files are imported once.", {"expected": len(expected_chapter_numbers), "actual": len(imported_chapter_numbers), "missing_chapters": missing_chapter_numbers[:50], "duplicate_chapters": duplicate_imported_chapters})
    add_check("imported_vault_complete", deltas["vault_notes"] <= 0, "review", "Vault notes selected for import are present.", {"expected": expected.get("vault_notes", 0), "actual": actual["vault_notes"], "missing": max(0, deltas["vault_notes"]), "max_vault_notes": max_vault_notes})
    add_check("imported_project_memory_complete", deltas["project_memory_entries"] <= 0, "review", "Project memory entries are imported.", {"expected": expected.get("project_memory_entries", 0), "actual": actual["project_memory_entries"], "missing": max(0, deltas["project_memory_entries"])})
    add_check("imported_narrative_debts_complete", deltas["narrative_debts"] <= 0, "review", "Narrative debts are imported.", {"expected": expected.get("narrative_debts", 0), "actual": actual["narrative_debts"], "missing": max(0, deltas["narrative_debts"])})
    add_check("imported_character_arcs_complete", deltas["character_arcs"] <= 0, "review", "Character arcs are imported.", {"expected": expected.get("character_arcs", 0), "actual": actual["character_arcs"], "missing": max(0, deltas["character_arcs"])})
    add_check("imported_chapter_contracts_complete", deltas["chapter_contracts"] <= 0, "review", "Chapter contracts are imported.", {"expected": expected.get("chapter_contracts", 0), "actual": actual["chapter_contracts"], "missing": max(0, deltas["chapter_contracts"])})
    add_check("imported_chapter_cards_complete", deltas["chapter_cards"] <= 0, "review", "Chapter cards are imported.", {"expected": expected.get("chapter_cards", 0), "actual": actual["chapter_cards"], "missing": max(0, deltas["chapter_cards"])})
    add_check("imported_facts_present", actual["facts"] > 0 or int(expected.get("estimated_facts") or 0) == 0, "must_fix", "Imported facts exist when source material exists.", {"expected_min": expected.get("estimated_facts", 0), "actual": actual["facts"]})
    add_check(
        "imported_chapter_hashes_current",
        not stale_chapter_rows,
        "must_fix",
        "Imported chapter records match current Gaoxia chapter files.",
        {
            "changed": len(freshness.get("changed_chapters") or []),
            "missing": len(freshness.get("missing_chapter_files") or []),
            "examples": stale_chapter_rows[:20],
        },
    )
    add_check(
        "imported_source_files_current",
        not stale_source_rows,
        "review",
        "Imported architecture and Vault source records match current Gaoxia files.",
        {
            "changed": len(freshness.get("changed_source_files") or []),
            "missing": len(freshness.get("missing_source_files") or []),
            "examples": stale_source_rows[:20],
        },
    )
    add_check(
        "imported_payload_hashes_current",
        not stale_payload_rows,
        "review",
        "Imported project memory and narrative-state payloads match current Gaoxia JSON.",
        {
            "changed": len(freshness.get("changed_payloads") or []),
            "missing": len(freshness.get("missing_payloads") or []),
            "examples": stale_payload_rows[:20],
        },
    )
    add_check(
        "imported_source_hashes_recorded",
        not unknown_hash_rows,
        "warning",
        "Imported records include source hashes for later stale-state audits.",
        {"missing_hashes": len(unknown_hash_rows), "examples": unknown_hash_rows[:20]},
    )
    add_check("imported_fact_evidence_present", not fact_evidence_missing, "warning", "Imported active facts keep source evidence.", {"missing": len(fact_evidence_missing)})
    add_check("target_context_builds", not context_error and bool(context.get("project")), "must_fix", f"Chapter {target} context builds after import.", context_error or {"target_chapter": target})
    add_check("target_context_has_imported_material", bool(visible_imported_sources or visible_imported_facts) or int(expected.get("estimated_facts") or 0) == 0, "review", f"Chapter {target} context exposes imported material that is visible for that chapter.", {"visible_imported_sources": len(visible_imported_sources), "visible_imported_facts": len(visible_imported_facts)})

    blockers = [item for item in checks if not item["ok"] and item["severity"] == "must_fix"]
    reviews = [item for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "needs_reimport"
    elif reviews:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"

    actions: list[dict[str, Any]] = []
    for item in blockers:
        actions.append(
            continuity_audit_action(
                f"fix_{item['id']}",
                "must_fix",
                item["message"],
                "This import issue can make chapter-safe context incomplete.",
                command=f"python cli.py import-gaoxia {project}",
                source_check=item["id"],
                details=item.get("detail"),
            )
        )
    for item in reviews:
        actions.append(
            continuity_audit_action(
                f"review_{item['id']}",
                "review",
                item["message"],
                "Review this source family before another desktop agent treats the imported state as complete.",
                command=f"python cli.py import-gaoxia {project} --dry-run",
                source_check=item["id"],
                details=item.get("detail"),
            )
        )
    if warnings:
        actions.append(
            continuity_audit_action(
                "inspect_import_warnings",
                "improve",
                "Inspect non-blocking import warnings",
                f"{len(warnings)} warning(s) remain after import.",
                command=f"python cli.py import-audit {project} --chapter {target} --format markdown",
                source_check="import_warnings",
                details=[item["id"] for item in warnings],
            )
        )
    recommended_commands = [
        f"python cli.py import-gaoxia {project} --dry-run",
        f"python cli.py import-audit {project} --chapter {target} --format markdown",
        f"python cli.py prepare-session {project} --chapter {target} --format markdown",
        f"python cli.py continuity-audit {project} --chapter {target} --format markdown",
    ]
    if status in {"needs_reimport", "needs_review"}:
        recommended_commands.insert(1, f"python cli.py import-gaoxia {project}")

    report: dict[str, Any] = {
        "ok": status in {"ready", "ready_with_warnings"},
        "type": "gaoxia_import_audit",
        "generated_at": generated_at,
        "status": status,
        "project_dir": str(project),
        "state_dir": str(state),
        "target_chapter": target,
        "source_inventory": source_scan,
        "imported_state": {
            "counts": actual,
            "deltas": deltas,
            "chapter_numbers": imported_chapter_numbers,
            "fact_coverage": fact_coverage_summary(active_imported_facts),
        },
        "checks": checks,
        "summary": {
            "must_fix": len(blockers),
            "review": len(reviews),
            "warnings": len(warnings),
            "expected_chapters": len(expected_chapter_numbers),
            "imported_chapters": len(imported_chapter_numbers),
            "visible_imported_sources": len(visible_imported_sources),
            "visible_imported_facts": len(visible_imported_facts),
            "stale_chapters": len(stale_chapter_rows),
            "stale_source_files": len(stale_source_rows),
            "stale_payloads": len(stale_payload_rows),
            "unknown_source_hashes": len(unknown_hash_rows),
        },
        "action_plan": build_continuity_action_plan(actions),
        "recommended_commands": unique_strings(recommended_commands),
    }
    if include_context:
        report["chapter_context"] = context
    else:
        report["chapter_context_summary"] = {
            "target_chapter": target,
            "visible_imported_sources": len(visible_imported_sources),
            "visible_imported_facts": len(visible_imported_facts),
            "previous_tail": (context.get("previous_chapter") or {}).get("tail") if isinstance(context, dict) else "",
        }
    return report


def write_import_report(path_value: str, report: dict[str, Any]) -> None:
    if not path_value:
        return
    text = json.dumps(report, ensure_ascii=False, indent=2) + "\n"
    if path_value == "-":
        sys.stderr.write(text)
        return
    path = Path(path_value).expanduser()
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")


def imported_row(row: dict[str, Any], imported_at: str) -> dict[str, Any]:
    row["import_source"] = IMPORT_SOURCE
    row["imported_at"] = imported_at
    return row


def with_source_hash(row: dict[str, Any], *, source_hash: str = "", source_payload_hash: str = "") -> dict[str, Any]:
    if source_hash:
        row["source_hash"] = source_hash
    if source_payload_hash:
        row["source_payload_hash"] = source_payload_hash
    return row


def make_fact_row(
    *,
    kind: str,
    subject: str,
    predicate: str,
    object_value: str,
    chapter_range: str | list[Any] | None = None,
    source_ids: Any = None,
    source_path: str = "",
    confidence: str = "agent-confirmed",
    status: str = "active",
    reveal_after_chapter: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
    fact_id: str = "",
) -> dict[str, Any]:
    now = now_iso()
    return {
        "id": fact_id or make_id("fact"),
        "kind": kind or "fact",
        "subject": subject.strip(),
        "predicate": predicate.strip() or "is",
        "object": object_value.strip(),
        "chapter_ranges": parse_ranges(chapter_range),
        "source_ids": split_list(source_ids),
        "source_path": source_path,
        "confidence": confidence,
        "status": status or "active",
        "reveal_after_chapter": reveal_after_chapter,
        "required_phrases": split_list(required_phrases),
        "forbidden_phrases": split_list(forbidden_phrases),
        "future_markers": split_list(future_markers),
        "created_at": now,
        "updated_at": now,
    }


def remove_imported_state(state: Path) -> None:
    for name in ("sources.jsonl", "research.jsonl", "contracts.jsonl", "chapters.jsonl", "conflicts.jsonl", "facts.jsonl", "proposals.jsonl"):
        path = state / name
        rows = [row for row in read_jsonl(path) if row.get("import_source") != IMPORT_SOURCE]
        write_jsonl(path, rows)
    for name, key in (("characters.json", "characters"), ("debts.json", "debts")):
        path = state / name
        payload = read_json(path, {key: []})
        rows = payload.get(key, []) if isinstance(payload, dict) else []
        if isinstance(rows, list):
            payload[key] = [row for row in rows if not (isinstance(row, dict) and row.get("import_source") == IMPORT_SOURCE)]
            write_json(path, payload)


def limit_text(text: str, limit: int) -> str:
    cleaned = text.strip()
    if len(cleaned) <= limit:
        return cleaned
    return cleaned[:limit] + "\n\n[truncated by long-novel-agent import]"


def import_project_memory(project: Path, imported_at: str) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    entries: list[dict[str, Any]] = []
    facts: list[dict[str, Any]] = []
    payload = read_json(project / "project_memory.json", {})
    raw_entries = payload.get("entries", []) if isinstance(payload, dict) else []
    if not isinstance(raw_entries, list):
        return entries, facts
    for index, item in enumerate(raw_entries, 1):
        if not isinstance(item, dict):
            continue
        content = str(item.get("content") or item.get("text") or item.get("summary") or "").strip()
        if not content:
            continue
        title = str(item.get("title") or item.get("kind") or f"项目记忆 {index}").strip()
        source_payload_hash = payload_hash(item)
        entries.append(
            imported_row(
                {
                    "id": f"gaoxia-memory-{index}",
                    "kind": "gaoxia_project_memory",
                    "title": title,
                    "source_path": "project_memory.json",
                    "source_payload_hash": source_payload_hash,
                    "summary": limit_text(content, 4000),
                    "chapter_ranges": [],
                    "required_phrases": [],
                    "forbidden_phrases": split_list(item.get("forbidden_phrases")),
                    "credibility": "gaoxia-project-memory",
                },
                imported_at,
            )
        )
        facts.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind=str(item.get("kind") or "rule"),
                        subject=title,
                        predicate="project_memory",
                        object_value=limit_text(content, 1200),
                        source_ids=[f"gaoxia-memory-{index}"],
                        source_path="project_memory.json",
                        confidence="gaoxia-project-memory",
                        forbidden_phrases=item.get("forbidden_phrases"),
                    ),
                    source_payload_hash=source_payload_hash,
                ),
                imported_at,
            )
        )
    return entries, facts


def import_gaoxia_vault(project: Path, imported_at: str, *, max_notes: int) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    vault = project / "Vault"
    if not vault.exists():
        return [], []
    entries: list[dict[str, Any]] = []
    facts: list[dict[str, Any]] = []
    for path in sorted(vault.rglob("*.md")):
        rel = path.relative_to(project).as_posix()
        if is_ignored_vault_path(rel):
            continue
        text = path.read_text(encoding="utf-8")
        source_hash = text_hash(text)
        frontmatter, body = parse_simple_frontmatter(text)
        title = str(frontmatter_value(frontmatter, "title") or path.stem)
        summary = first_nonempty(
            frontmatter_value(frontmatter, "summary"),
            frontmatter_value(frontmatter, "description"),
            frontmatter_value(frontmatter, "abstract"),
            body_excerpt(body),
        )
        if not summary:
            continue
        chapter_range = first_nonempty(
            frontmatter_value(frontmatter, "chapter_range"),
            frontmatter_value(frontmatter, "chapter"),
            frontmatter_value(frontmatter, "chapters"),
        )
        reveal_after = coerce_optional_int(first_nonempty(frontmatter_value(frontmatter, "reveal_after_chapter"), frontmatter_value(frontmatter, "spoiler_after")))
        source_id = f"gaoxia-vault-{slug_id(rel)}"
        kind = str(frontmatter_value(frontmatter, "type") or infer_vault_kind(rel))
        entries.append(
            imported_row(
                {
                    "id": source_id,
                    "kind": f"gaoxia_vault:{kind}",
                    "title": title,
                    "source_path": rel,
                    "source_hash": source_hash,
                    "summary": limit_text(str(summary), 6000),
                    "chapter_ranges": parse_ranges(chapter_range),
                    "required_phrases": split_list(frontmatter_value(frontmatter, "required_phrases")),
                    "forbidden_phrases": split_list(frontmatter_value(frontmatter, "forbidden_phrases")),
                    "future_markers": split_list(frontmatter_value(frontmatter, "aliases")) + [title],
                    "credibility": "gaoxia-vault",
                    "reveal_after_chapter": reveal_after,
                },
                imported_at,
            )
        )
        facts.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind=kind,
                        subject=title,
                        predicate="vault_summary",
                        object_value=limit_text(str(summary), 1200),
                        chapter_range=chapter_range,
                        source_ids=[source_id],
                        source_path=rel,
                        confidence="gaoxia-vault",
                        reveal_after_chapter=reveal_after,
                        required_phrases=frontmatter_value(frontmatter, "required_phrases"),
                        forbidden_phrases=frontmatter_value(frontmatter, "forbidden_phrases"),
                        future_markers=split_list(frontmatter_value(frontmatter, "aliases")) + [title],
                        fact_id=f"fact-{source_id}",
                    ),
                    source_hash=source_hash,
                ),
                imported_at,
            )
        )
        if len(entries) >= max_notes:
            break
    return entries, facts


def is_ignored_vault_path(relative_path: str) -> bool:
    lowered = "/" + relative_path.lower()
    return "/.obsidian/" in lowered or "/.trash/" in lowered or "/templates/" in lowered


def parse_simple_frontmatter(text: str) -> tuple[dict[str, Any], str]:
    if not text.startswith("---\n"):
        return {}, text
    end = text.find("\n---", 4)
    if end < 0:
        return {}, text
    raw = text[4:end]
    body = text[text.find("\n", end + 1) + 1 :]
    data: dict[str, Any] = {}
    current_key = ""
    current_items: list[str] = []
    for line in raw.splitlines():
        if re.match(r"^\s+-\s+", line) and current_key:
            current_items.append(line.split("-", 1)[1].strip().strip("\"'"))
            data[current_key] = current_items
            continue
        match = re.match(r"^\s*([^:#]+?)\s*:\s*(.*)$", line)
        if not match:
            continue
        current_key = normalize_key(match.group(1))
        value = strip_yaml_comment(match.group(2).strip())
        if value in {"", "|", ">", "|-", ">-", "|+", ">+"}:
            data[current_key] = ""
            current_items = []
            continue
        current_items = []
        data[current_key] = value.strip().strip("\"'")
    return data, body


def normalize_key(value: str) -> str:
    return re.sub(r"[\s_-]+", "", value.strip().lower())


def strip_yaml_comment(value: str) -> str:
    in_single = False
    in_double = False
    for index, char in enumerate(value):
        if char == "'" and not in_double:
            in_single = not in_single
        elif char == '"' and not in_single:
            in_double = not in_double
        elif char == "#" and not in_single and not in_double:
            return value[:index].strip()
    return value


def frontmatter_value(frontmatter: dict[str, Any], *keys: str) -> Any:
    for key in keys:
        normalized = normalize_key(key)
        if normalized in frontmatter:
            return frontmatter[normalized]
    return None


def first_nonempty(*values: Any) -> str:
    for value in values:
        if isinstance(value, list):
            joined = "；".join(str(item).strip() for item in value if str(item).strip())
            if joined:
                return joined
            continue
        text = str(value or "").strip()
        if text:
            return text
    return ""


def body_excerpt(body: str) -> str:
    lines = [line.strip() for line in body.splitlines() if line.strip() and not line.strip().startswith("#")]
    return "\n".join(lines[:12])


def infer_vault_kind(relative_path: str) -> str:
    first = relative_path.split("/", 2)[1].lower() if "/" in relative_path else ""
    mapping = {
        "characters": "character",
        "events": "event",
        "locations": "location",
        "props": "prop",
        "organizations": "organization",
        "plans": "chapter_plan",
        "chapternotes": "chapter_note",
        "debts": "narrative_debt",
        "characterarcs": "character_arc",
        "style": "style_rule",
        "xp": "xp_rule",
    }
    return mapping.get(first, "note")


def slug_id(value: str) -> str:
    digest = hashlib.sha1(value.encode("utf-8")).hexdigest()[:12]
    stem = re.sub(r"[^A-Za-z0-9]+", "-", Path(value).stem).strip("-").lower()[:30]
    return f"{stem or 'note'}-{digest}"


def derive_forbidden_from_debt(title: str, item: dict[str, Any]) -> list[str]:
    phrases = split_list(item.get("forbidden_phrases") or item.get("forbidden_moves"))
    detail = first_nonempty(item.get("detail"), item.get("summary"), item.get("next_required_action"), item.get("debt_content"))
    for text in (title, detail):
        match = re.search(r"(.{1,16}?)(?:还)?不能(.{1,18})", text)
        if match:
            phrases.append((match.group(1) + match.group(2)).strip(" ，,。；;"))
    return unique_strings(phrases)


def import_gaoxia_chapters(project: Path, state: Path, imported_at: str) -> tuple[int, list[dict[str, Any]]]:
    chapters_dir = project / "chapters"
    if not chapters_dir.exists():
        return 0, []
    rows = read_jsonl(state / "chapters.jsonl")
    manual_chapters = {int(row.get("chapter", -1)) for row in rows if row.get("import_source") != IMPORT_SOURCE}
    facts: list[dict[str, Any]] = []
    count = 0
    for path in sorted(chapters_dir.glob("*.md")):
        if not path.stem.isdigit():
            continue
        chapter = int(path.stem)
        if chapter in manual_chapters:
            continue
        text = path.read_text(encoding="utf-8")
        if not text.strip():
            continue
        title = chapter_title(text, chapter)
        source_hash = text_hash(text)
        rows.append(
            imported_row(
                {
                    "id": f"chapter-{chapter:04d}",
                    "chapter": chapter,
                    "title": title,
                    "file": str(path),
                    "source_path": path.relative_to(project).as_posix(),
                    "hash": source_hash,
                    "text_units": count_text_units(text),
                    "tail": tail_text(text),
                    "summary": "",
                    "handoff": "",
                    "recorded_at": imported_at,
                },
                imported_at,
            )
        )
        facts.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind="event",
                        subject=f"第 {chapter} 章",
                        predicate="accepted_chapter",
                        object_value=limit_text(body_excerpt(text) or tail_text(text), 1200),
                        chapter_range=f"{chapter}+",
                        source_ids=[f"chapter-{chapter:04d}"],
                        source_path=path.relative_to(project).as_posix(),
                        confidence="accepted-chapter",
                        fact_id=f"fact-chapter-{chapter:04d}",
                    ),
                    source_hash=source_hash,
                ),
                imported_at,
            )
        )
        count += 1
    rows.sort(key=lambda row: int(row.get("chapter", 0)))
    write_jsonl(state / "chapters.jsonl", rows)
    return count, facts


def chapter_title(text: str, chapter: int) -> str:
    for line in text.splitlines():
        cleaned = line.strip().strip("#").strip()
        if cleaned:
            return cleaned[:80]
    return f"第 {chapter} 章"


def import_gaoxia_narrative_state(project: Path, state: Path, imported_at: str) -> tuple[dict[str, int], list[dict[str, Any]]]:
    path = project / ".gaoxia" / "learning" / "narrative_state.json"
    payload = read_json(path, {})
    if not isinstance(payload, dict):
        return {"narrative_debts": 0, "character_arcs": 0, "chapter_contracts": 0, "chapter_cards": 0}, []
    debt_count, debt_facts = import_narrative_debts(state, payload.get("debts"), imported_at)
    arc_count, arc_facts = import_character_arcs(state, payload.get("character_arcs"), imported_at)
    contract_count, contract_facts = import_chapter_contracts(state, payload.get("chapter_contracts"), imported_at)
    card_count, card_facts = import_chapter_cards(state, payload.get("chapter_cards"), imported_at)
    return {
        "narrative_debts": debt_count,
        "character_arcs": arc_count,
        "chapter_contracts": contract_count,
        "chapter_cards": card_count,
    }, debt_facts + arc_facts + contract_facts + card_facts


def import_narrative_debts(state: Path, raw: Any, imported_at: str) -> tuple[int, list[dict[str, Any]]]:
    rows = raw if isinstance(raw, list) else []
    payload = read_json(state / "debts.json", {"debts": []})
    debts = payload.get("debts", []) if isinstance(payload, dict) else []
    facts: list[dict[str, Any]] = []
    count = 0
    for index, item in enumerate(rows, 1):
        if not isinstance(item, dict):
            continue
        title = first_nonempty(item.get("title"), item.get("debt_content"), item.get("summary"), item.get("content"))
        if not title:
            continue
        source_payload_hash = payload_hash(item)
        debts.append(
            imported_row(
                {
                    "id": str(item.get("id") or f"gaoxia-debt-{index}"),
                    "title": title,
                    "source_path": ".gaoxia/learning/narrative_state.json",
                    "source_payload_hash": source_payload_hash,
                    "detail": first_nonempty(item.get("detail"), item.get("summary"), item.get("next_required_action")),
                    "status": item.get("status") or item.get("debt_status") or "open",
                    "risk_level": item.get("risk_level"),
                    "expected_payoff_range": item.get("expected_payoff_range"),
                    "chapter_ranges": parse_ranges(item.get("chapter_range") or item.get("visible_chapters") or item.get("applies_to")),
                    "source_chapters": item.get("source_chapters", []),
                },
                imported_at,
            )
        )
        facts.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind="narrative_debt",
                        subject=title,
                        predicate="debt_state",
                        object_value=first_nonempty(item.get("detail"), item.get("summary"), item.get("next_required_action"), item.get("expected_payoff_range")),
                        chapter_range=item.get("chapter_range") or item.get("visible_chapters") or item.get("applies_to"),
                        source_ids=[str(item.get("id") or f"gaoxia-debt-{index}")],
                        source_path=".gaoxia/learning/narrative_state.json",
                        confidence="gaoxia-narrative-state",
                        status=str(item.get("status") or item.get("debt_status") or "active"),
                        forbidden_phrases=derive_forbidden_from_debt(title, item),
                        fact_id=f"fact-gaoxia-debt-{slug_id(str(item.get('id') or title or index))}",
                    ),
                    source_payload_hash=source_payload_hash,
                ),
                imported_at,
            )
        )
        count += 1
    payload["debts"] = debts
    write_json(state / "debts.json", payload)
    return count, facts


def import_character_arcs(state: Path, raw: Any, imported_at: str) -> tuple[int, list[dict[str, Any]]]:
    rows = raw if isinstance(raw, list) else []
    payload = read_json(state / "characters.json", {"characters": []})
    characters = payload.get("characters", []) if isinstance(payload, dict) else []
    facts: list[dict[str, Any]] = []
    count = 0
    for index, item in enumerate(rows, 1):
        if not isinstance(item, dict):
            continue
        name = first_nonempty(item.get("character"), item.get("name"), item.get("title"))
        state_text = first_nonempty(item.get("current_state"), item.get("state"), item.get("phase"), item.get("summary"))
        if not name and not state_text:
            continue
        source_payload_hash = payload_hash(item)
        characters.append(
            imported_row(
                {
                    "id": str(item.get("id") or f"gaoxia-character-{index}"),
                    "name": name or f"角色 {index}",
                    "source_path": ".gaoxia/learning/narrative_state.json",
                    "source_payload_hash": source_payload_hash,
                    "state": state_text,
                    "phase": item.get("phase"),
                    "unresolved_pressure": item.get("unresolved_pressure"),
                    "required_next_check": item.get("required_next_check"),
                    "chapter_ranges": parse_ranges(item.get("chapter_range") or item.get("visible_chapters") or item.get("applies_to")),
                    "source_chapters": item.get("source_chapters", []),
                },
                imported_at,
            )
        )
        facts.append(
            imported_row(
                with_source_hash(
                    make_fact_row(
                        kind="character",
                        subject=name or f"角色 {index}",
                        predicate="state",
                        object_value=state_text,
                        chapter_range=item.get("chapter_range") or item.get("visible_chapters") or item.get("applies_to"),
                        source_ids=[str(item.get("id") or f"gaoxia-character-{index}")],
                        source_path=".gaoxia/learning/narrative_state.json",
                        confidence="gaoxia-narrative-state",
                        forbidden_phrases=item.get("forbidden_phrases") or item.get("forbidden_states") or item.get("required_next_check"),
                        fact_id=f"fact-gaoxia-character-{slug_id(str(item.get('id') or name or index))}",
                    ),
                    source_payload_hash=source_payload_hash,
                ),
                imported_at,
            )
        )
        count += 1
    payload["characters"] = characters
    write_json(state / "characters.json", payload)
    return count, facts


