def update_handoff_from_latest_chapter(state: Path) -> None:
    rows = read_jsonl(state / "chapters.jsonl")
    if not rows:
        return
    latest = max(rows, key=lambda row: int(row.get("chapter", 0)))
    text = "\n".join(
        [
            "# Handoff",
            "",
            f"Updated: {now_iso()}",
            f"Imported from Gaoxia chapter: {latest.get('chapter')}",
            "",
            "## Previous Tail",
            str(latest.get("tail") or ""),
            "",
            "## Next Step",
            "Build the next chapter context before writing.",
            "",
        ]
    )
    (state / "handoff.md").write_text(text, encoding="utf-8")


