def add_fact(
    project_dir: str | Path,
    *,
    kind: str,
    subject: str,
    predicate: str,
    object_value: str,
    chapter_range: str = "",
    source_ids: Any = None,
    source_path: str = "",
    confidence: str = "agent-confirmed",
    status: str = "active",
    reveal_after_chapter: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    if not subject.strip() or not predicate.strip() or not object_value.strip():
        raise KitError("Fact requires subject, predicate, and object")
    entry = make_fact_row(
        kind=kind,
        subject=subject,
        predicate=predicate,
        object_value=object_value,
        chapter_range=chapter_range,
        source_ids=source_ids,
        source_path=source_path,
        confidence=confidence,
        status=status,
        reveal_after_chapter=reveal_after_chapter,
        required_phrases=required_phrases,
        forbidden_phrases=forbidden_phrases,
        future_markers=future_markers,
    )
    append_jsonl(state / "facts.jsonl", entry)
    return {"ok": True, "entry": entry}


def update_fact(
    project_dir: str | Path,
    *,
    fact_id: str,
    kind: str | None = None,
    subject: str | None = None,
    predicate: str | None = None,
    object_value: str | None = None,
    chapter_range: str | None = None,
    source_ids: Any = None,
    source_path: str | None = None,
    confidence: str | None = None,
    status: str | None = None,
    reveal_after_chapter: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "facts.jsonl")
    for row in rows:
        if row.get("id") != fact_id:
            continue
        if kind is not None:
            row["kind"] = kind
        if subject is not None:
            row["subject"] = subject
        if predicate is not None:
            row["predicate"] = predicate
        if object_value is not None:
            row["object"] = object_value
        if chapter_range is not None:
            row["chapter_ranges"] = parse_ranges(chapter_range)
        if source_ids is not None:
            row["source_ids"] = split_list(source_ids)
        if source_path is not None:
            row["source_path"] = source_path
        if confidence is not None:
            row["confidence"] = confidence
        if status is not None:
            row["status"] = status
        if reveal_after_chapter is not None:
            row["reveal_after_chapter"] = reveal_after_chapter
        if required_phrases is not None:
            row["required_phrases"] = split_list(required_phrases)
        if forbidden_phrases is not None:
            row["forbidden_phrases"] = split_list(forbidden_phrases)
        if future_markers is not None:
            row["future_markers"] = split_list(future_markers)
        row["updated_at"] = now_iso()
        write_jsonl(state / "facts.jsonl", rows)
        return {"ok": True, "entry": row}
    raise KitError(f"Fact not found: {fact_id}")


def supersede_fact(project_dir: str | Path, *, fact_id: str, replacement_fact_id: str = "", reason: str = "") -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "facts.jsonl")
    for row in rows:
        if row.get("id") != fact_id:
            continue
        row["status"] = "superseded"
        row["superseded_by"] = replacement_fact_id
        row["superseded_reason"] = reason
        row["updated_at"] = now_iso()
        write_jsonl(state / "facts.jsonl", rows)
        return {"ok": True, "entry": row}
    raise KitError(f"Fact not found: {fact_id}")


def list_facts(project_dir: str | Path, *, chapter: int | None = None, kind: str = "", include_inactive: bool = False) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "facts.jsonl")
    result: list[dict[str, Any]] = []
    for row in rows:
        if kind and str(row.get("kind") or "") != kind:
            continue
        if not include_inactive and not fact_active(row):
            continue
        if chapter is not None and not entry_visible(row, chapter):
            continue
        result.append(row)
    return {"ok": True, "chapter": chapter, "facts": result}


def fact_active(row: dict[str, Any]) -> bool:
    status = str(row.get("status") or "active").strip().lower()
    return status in ACTIVE_FACT_STATUSES


def context_section_budget(name: str, value: Any) -> dict[str, Any]:
    text = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
    if isinstance(value, list):
        item_count = len(value)
    elif isinstance(value, dict):
        item_count = len(value)
    elif isinstance(value, str):
        item_count = 1 if value.strip() else 0
    elif value is None:
        item_count = 0
    else:
        item_count = 1
    return {
        "name": name,
        "items": item_count,
        "chars": len(text),
        "bytes": len(text.encode("utf-8")),
        "text_units": count_text_units(text),
    }


def build_context_budget(context: dict[str, Any], *, chapter: int) -> dict[str, Any]:
    section_names = [
        "project",
        "previous_chapter",
        "rules",
        "characters",
        "open_debts",
        "contracts",
        "facts",
        "agent_capabilities",
        "style_profile",
        "sources",
        "research",
        "resolved_conflicts",
        "chapter_contract",
        "handoff",
        "style",
    ]
    sections = [context_section_budget(name, context.get(name)) for name in section_names]
    total_chars = sum(int(row["chars"]) for row in sections)
    total_bytes = sum(int(row["bytes"]) for row in sections)
    total_units = sum(int(row["text_units"]) for row in sections)
    counts = {
        "facts": len(context.get("facts", [])) if isinstance(context.get("facts"), list) else 0,
        "open_debts": len(context.get("open_debts", [])) if isinstance(context.get("open_debts"), list) else 0,
        "sources": len(context.get("sources", [])) if isinstance(context.get("sources"), list) else 0,
        "research": len(context.get("research", [])) if isinstance(context.get("research"), list) else 0,
        "contracts": len(context.get("contracts", [])) if isinstance(context.get("contracts"), list) else 0,
        "characters": len(context.get("characters", [])) if isinstance(context.get("characters"), list) else 0,
    }
    warnings: list[str] = []
    if total_chars >= CONTEXT_BUDGET_CRITICAL_CHARS:
        warnings.append(f"chapter context is very large: {total_chars} chars")
    elif total_chars >= CONTEXT_BUDGET_WARNING_CHARS:
        warnings.append(f"chapter context is large: {total_chars} chars")
    if counts["facts"] >= CONTEXT_BUDGET_FACT_WARNING_COUNT:
        warnings.append(f"visible fact count is high: {counts['facts']}")
    if counts["open_debts"] >= CONTEXT_BUDGET_DEBT_WARNING_COUNT:
        warnings.append(f"open debt count is high: {counts['open_debts']}")
    if counts["sources"] + counts["research"] >= CONTEXT_BUDGET_SOURCE_WARNING_COUNT:
        warnings.append(f"visible source and research count is high: {counts['sources'] + counts['research']}")
    status = "ok"
    if total_chars >= CONTEXT_BUDGET_CRITICAL_CHARS:
        status = "critical"
    elif warnings:
        status = "warning"
    recommendations: list[str] = []
    if warnings:
        recommendations.extend(
            [
                "Use the highest-risk facts, current chapter contract, previous chapter tail, and open debts as the active drafting priority.",
                "After drafting, call chapter-readiness or check-chapter before presenting the chapter as ready.",
                "If the host agent has limited context, read the largest context_budget.sections first and ask the author to confirm which old material can be summarized.",
            ]
        )
    else:
        recommendations.append("Context size is within the default local-agent budget.")
    return {
        "type": "chapter_context_budget",
        "target_chapter": chapter,
        "status": status,
        "needs_compression": status in {"warning", "critical"},
        "total": {
            "chars": total_chars,
            "bytes": total_bytes,
            "text_units": total_units,
        },
        "counts": counts,
        "thresholds": {
            "warning_chars": CONTEXT_BUDGET_WARNING_CHARS,
            "critical_chars": CONTEXT_BUDGET_CRITICAL_CHARS,
            "fact_warning_count": CONTEXT_BUDGET_FACT_WARNING_COUNT,
            "debt_warning_count": CONTEXT_BUDGET_DEBT_WARNING_COUNT,
            "source_warning_count": CONTEXT_BUDGET_SOURCE_WARNING_COUNT,
        },
        "sections": sorted(sections, key=lambda row: int(row["chars"]), reverse=True),
        "warnings": warnings,
        "recommendations": recommendations,
    }


def compact_context_row(row: dict[str, Any], *, fields: tuple[str, ...], max_text_chars: int = 320) -> dict[str, Any]:
    compact: dict[str, Any] = {}
    for key in fields:
        if key not in row:
            continue
        value = row.get(key)
        if isinstance(value, str):
            cleaned = value.strip()
            if not cleaned:
                continue
            compact[key] = cleaned[:max_text_chars] + ("..." if len(cleaned) > max_text_chars else "")
        elif isinstance(value, (int, float, bool)) or value is None:
            if value is not None:
                compact[key] = value
        elif isinstance(value, list):
            compact[key] = value[:6]
        elif isinstance(value, dict):
            compact[key] = {str(k): v for k, v in list(value.items())[:8]}
    return compact


def chapter_range_distance(row: dict[str, Any], chapter: int) -> int:
    ranges = parse_ranges(row.get("chapter_ranges") or row.get("chapter_range"))
    if not ranges:
        return 100000
    distances: list[int] = []
    for item in ranges:
        if not isinstance(item, dict):
            continue
        try:
            start = int(item.get("start")) if item.get("start") is not None else None
            end = int(item.get("end")) if item.get("end") is not None else None
        except (TypeError, ValueError):
            continue
        if start is None:
            continue
        if end is None:
            distances.append(0 if chapter >= start else abs(chapter - start))
            continue
        low, high = min(start, end), max(start, end)
        if low <= chapter <= high:
            distances.append(0)
        else:
            distances.append(min(abs(chapter - low), abs(chapter - high)))
    return min(distances) if distances else 100000


def compact_brief_row(row: dict[str, Any], *, fields: tuple[str, ...], chapter: int) -> dict[str, Any]:
    compact = compact_context_row(row, fields=fields)
    distance = chapter_range_distance(row, chapter)
    if distance < 100000:
        compact["chapter_distance"] = distance
    return compact


def priority_facts_for_brief(facts: list[dict[str, Any]], chapter: int, *, limit: int) -> list[dict[str, Any]]:
    kind_priority = {
        "life_state": 0,
        "prop": 1,
        "relationship": 2,
        "event": 3,
        "location": 4,
        "character": 5,
        "rule": 6,
    }
    sorted_facts = sorted(
        facts,
        key=lambda row: (
            kind_priority.get(str(row.get("kind") or ""), 20),
            chapter_range_distance(row, chapter),
            str(row.get("subject") or ""),
            str(row.get("predicate") or ""),
        ),
    )
    return [
        compact_brief_row(
            row,
            fields=(
                "id",
                "kind",
                "subject",
                "predicate",
                "object",
                "chapter_range",
                "chapter_ranges",
                "status",
                "evidence",
                "source_path",
                "forbidden_phrases",
                "required_phrases",
                "future_markers",
            ),
            chapter=chapter,
        )
        for row in sorted_facts[:limit]
    ]


def recent_items_for_brief(items: list[dict[str, Any]], chapter: int, *, limit: int, fields: tuple[str, ...]) -> list[dict[str, Any]]:
    sorted_items = sorted(
        enumerate(items),
        key=lambda row: (
            chapter_range_distance(row[1], chapter),
            -row[0],
        ),
    )
    return [compact_brief_row(row, fields=fields, chapter=chapter) for _, row in sorted_items[:limit]]


def build_context_brief(context: dict[str, Any], *, chapter: int) -> dict[str, Any]:
    rules = context.get("rules") if isinstance(context.get("rules"), dict) else {}
    previous = context.get("previous_chapter") if isinstance(context.get("previous_chapter"), dict) else {}
    facts = context.get("facts") if isinstance(context.get("facts"), list) else []
    open_debts = context.get("open_debts") if isinstance(context.get("open_debts"), list) else []
    sources = context.get("sources") if isinstance(context.get("sources"), list) else []
    research = context.get("research") if isinstance(context.get("research"), list) else []
    contracts = context.get("contracts") if isinstance(context.get("contracts"), list) else []
    chapter_contract = context.get("chapter_contract") if isinstance(context.get("chapter_contract"), dict) else {}
    budget = context.get("context_budget") if isinstance(context.get("context_budget"), dict) else {}
    focus = split_list(chapter_contract.get("continuity_focus"))
    if not focus:
        focus = [
            "Use the previous chapter tail, visible rules, high-priority facts, open debts, and current chapter contract before drafting.",
            "After drafting, call chapter-readiness or check-chapter before presenting the chapter as ready.",
        ]
    brief = {
        "type": "chapter_context_brief",
        "target_chapter": chapter,
        "read_this_first": True,
        "budget_status": budget.get("status") or "unknown",
        "previous_chapter": {
            "chapter": previous.get("chapter"),
            "title": previous.get("title") or "",
            "tail": previous.get("tail") or "",
        },
        "handoff": str(context.get("handoff") or "").strip()[:1200],
        "required": split_list(rules.get("required_phrases"))[:20],
        "forbidden": split_list(rules.get("forbidden_phrases"))[:20],
        "future_markers": split_list(rules.get("future_markers"))[:20],
        "chapter_contract": {
            "goal": chapter_contract.get("goal") or "",
            "must_use": split_list(chapter_contract.get("must_use"))[:20],
            "must_avoid": split_list(chapter_contract.get("must_avoid"))[:20],
            "continuity_focus": focus[:20],
        },
        "high_priority_facts": priority_facts_for_brief(facts, chapter, limit=CONTEXT_BRIEF_FACT_LIMIT),
        "open_debts": recent_items_for_brief(
            open_debts,
            chapter,
            limit=CONTEXT_BRIEF_DEBT_LIMIT,
            fields=("id", "title", "detail", "status", "expected_chapter", "payoff_window", "evidence"),
        ),
        "visible_sources": recent_items_for_brief(
            sources,
            chapter,
            limit=CONTEXT_BRIEF_SOURCE_LIMIT,
            fields=("id", "title", "source_path", "summary", "chapter_range", "chapter_ranges", "credibility", "required_phrases", "forbidden_phrases"),
        ),
        "visible_research": recent_items_for_brief(
            research,
            chapter,
            limit=CONTEXT_BRIEF_SOURCE_LIMIT,
            fields=("id", "title", "url", "summary", "chapter_range", "chapter_ranges", "reliability", "required_phrases", "forbidden_phrases"),
        ),
        "contracts": recent_items_for_brief(
            contracts,
            chapter,
            limit=CONTEXT_BRIEF_CONTRACT_LIMIT,
            fields=("id", "chapter", "title", "goal", "required_beats", "acceptance_checks", "forbidden_moves", "chapter_range", "chapter_ranges"),
        ),
        "counts": {
            "facts_in_brief": min(len(facts), CONTEXT_BRIEF_FACT_LIMIT),
            "facts_total": len(facts),
            "open_debts_in_brief": min(len(open_debts), CONTEXT_BRIEF_DEBT_LIMIT),
            "open_debts_total": len(open_debts),
            "sources_in_brief": min(len(sources), CONTEXT_BRIEF_SOURCE_LIMIT),
            "sources_total": len(sources),
            "research_in_brief": min(len(research), CONTEXT_BRIEF_SOURCE_LIMIT),
            "research_total": len(research),
            "contracts_in_brief": min(len(contracts), CONTEXT_BRIEF_CONTRACT_LIMIT),
            "contracts_total": len(contracts),
        },
        "next_checks": ["chapter-readiness", "check-chapter", "diff-contract"],
    }
    brief_text = json.dumps(brief, ensure_ascii=False, sort_keys=True, default=str)
    brief["size"] = {
        "chars": len(brief_text),
        "bytes": len(brief_text.encode("utf-8")),
        "text_units": count_text_units(brief_text),
    }
    return brief


def build_chapter_context(project_dir: str | Path, *, chapter: int) -> dict[str, Any]:
    data = load_state(project_dir)
    manifest = data["manifest"]
    rules = data["rules"]
    chapters = sorted(data["chapters"], key=lambda row: int(row.get("chapter", 0)))
    previous = None
    for row in chapters:
        if int(row.get("chapter", 0)) < chapter:
            previous = row
    visible_sources = [row for row in data["sources"] if entry_visible(row, chapter)]
    visible_research = [row for row in data["research"] if entry_visible(row, chapter)]
    visible_contracts = [row for row in data["contracts"] if entry_visible(row, chapter)]
    visible_conflicts = [row for row in data["conflicts"] if entry_visible(row, chapter)]
    visible_facts = [row for row in data["facts"] if fact_active(row) and entry_visible(row, chapter)]
    characters = visible_characters(data["characters"], chapter)
    debts = visible_debts(data["debts"], chapter)
    required = collect_phrases(rules, "required_phrases")
    forbidden = collect_phrases(rules, "forbidden_phrases")
    for row in visible_sources + visible_research + visible_contracts + visible_facts:
        required.extend(split_list(row.get("required_phrases")))
        forbidden.extend(split_list(row.get("forbidden_phrases")))
        required.extend(split_list(row.get("required_beats")))
        forbidden.extend(split_list(row.get("forbidden_moves")))
    future_markers = collect_future_markers(rules, chapter)
    for row in data["sources"] + data["research"] + data["contracts"] + data["facts"]:
        future_markers.extend(entry_future_markers(row, chapter))
    context = {
        "project": manifest,
        "target_chapter": chapter,
        "previous_chapter": previous,
        "handoff": data["handoff"].strip(),
        "style": data["style"].strip(),
        "rules": {
            "required_phrases": unique_strings(required),
            "forbidden_phrases": unique_strings(forbidden),
            "future_markers": unique_strings(future_markers),
        },
        "characters": characters,
        "open_debts": debts,
        "contracts": visible_contracts,
        "facts": visible_facts,
        "agent_capabilities": data["agents"],
        "style_profile": data["style_profile"].get("profile", {}) if isinstance(data["style_profile"], dict) else {},
        "sources": visible_sources,
        "research": visible_research,
        "resolved_conflicts": visible_conflicts,
        "chapter_contract": {
            "goal": f"Write or revise chapter {chapter} using only visible state.",
            "must_use": unique_strings(required),
            "must_avoid": unique_strings(forbidden + future_markers),
            "continuity_focus": build_continuity_focus(previous, characters, debts, visible_facts),
        },
    }
    context["context_budget"] = build_context_budget(context, chapter=chapter)
    context["context_brief"] = build_context_brief(context, chapter=chapter)
    context["context_fingerprint"] = {
        "type": "chapter_context_fingerprint",
        "target_chapter": chapter,
        "sha256": payload_hash(context_fingerprint_payload(context)),
    }
    return context


def build_chapter_context_brief(project_dir: str | Path, *, chapter: int) -> dict[str, Any]:
    context = build_chapter_context(project_dir, chapter=chapter)
    brief = context.get("context_brief") if isinstance(context.get("context_brief"), dict) else {}
    budget = context.get("context_budget") if isinstance(context.get("context_budget"), dict) else {}
    total = budget.get("total") if isinstance(budget.get("total"), dict) else {}
    counts = budget.get("counts") if isinstance(budget.get("counts"), dict) else {}
    payload = dict(brief)
    payload["project"] = context.get("project", {})
    payload["context_budget_summary"] = {
        "status": budget.get("status") or "unknown",
        "needs_compression": budget.get("needs_compression"),
        "chars": total.get("chars", 0),
        "text_units": total.get("text_units", 0),
        "facts": counts.get("facts", 0),
        "open_debts": counts.get("open_debts", 0),
        "sources": counts.get("sources", 0),
        "research": counts.get("research", 0),
        "warnings": budget.get("warnings") if isinstance(budget.get("warnings"), list) else [],
    }
    payload["source"] = "build_chapter_context"
    return payload


def collect_phrases(rules: dict[str, Any], key: str) -> list[str]:
    return split_list(rules.get(key))


def collect_future_markers(rules: dict[str, Any], chapter: int) -> list[str]:
    markers = []
    for item in rules.get("future_markers", []):
        if isinstance(item, dict):
            reveal_after = item.get("reveal_after_chapter")
            text = str(item.get("text") or item.get("marker") or "").strip()
            if not text:
                continue
            if reveal_after is None or chapter <= int(reveal_after):
                markers.append(text)
        else:
            markers.append(str(item))
    return unique_strings(markers)


def visible_characters(payload: dict[str, Any], chapter: int) -> list[dict[str, Any]]:
    rows = payload.get("characters", [])
    if isinstance(rows, dict):
        rows = [{"name": name, **value} if isinstance(value, dict) else {"name": name, "state": value} for name, value in rows.items()]
    return [row for row in rows if isinstance(row, dict) and entry_visible(row, chapter)]


def visible_debts(payload: dict[str, Any], chapter: int) -> list[dict[str, Any]]:
    rows = payload.get("debts", [])
    if isinstance(rows, dict):
        rows = [{"title": name, **value} if isinstance(value, dict) else {"title": name, "detail": value} for name, value in rows.items()]
    result = []
    for row in rows:
        if not isinstance(row, dict) or not entry_visible(row, chapter):
            continue
        status = str(row.get("status") or row.get("debt_status") or "open").lower()
        if status in {"done", "closed", "resolved", "ignored"}:
            continue
        result.append(row)
    return result


def build_continuity_focus(
    previous: dict[str, Any] | None,
    characters: list[dict[str, Any]],
    debts: list[dict[str, Any]],
    facts: list[dict[str, Any]] | None = None,
) -> list[str]:
    focus = []
    if previous and previous.get("tail"):
        focus.append(f"Carry forward previous chapter tail: {previous['tail'][:180]}")
    for character in characters[:8]:
        name = str(character.get("name") or character.get("title") or "").strip()
        state = str(character.get("state") or character.get("current_state") or "").strip()
        if name or state:
            focus.append(f"Character state: {name} {state}".strip())
    for debt in debts[:8]:
        title = str(debt.get("title") or debt.get("debt_content") or debt.get("detail") or "").strip()
        if title:
            focus.append(f"Open debt: {title}")
    for fact in (facts or [])[:10]:
        subject = str(fact.get("subject") or "").strip()
        predicate = str(fact.get("predicate") or "").strip()
        object_value = str(fact.get("object") or "").strip()
        if subject and object_value:
            focus.append(f"Fact: {subject} {predicate} {object_value}".strip())
    return focus


def record_chapter(
    project_dir: str | Path,
    *,
    chapter: int,
    file: str,
    title: str = "",
    summary: str = "",
    handoff: str = "",
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    entry = {
        "id": f"chapter-{chapter:04d}",
        "chapter": chapter,
        "title": title or path.stem,
        "file": str(path),
        "hash": text_hash(text),
        "text_units": count_text_units(text),
        "tail": tail_text(text),
        "summary": summary.strip(),
        "handoff": handoff.strip(),
        "recorded_at": now_iso(),
    }
    rows = [row for row in read_jsonl(state / "chapters.jsonl") if int(row.get("chapter", -1)) != chapter]
    rows.append(entry)
    rows.sort(key=lambda row: int(row.get("chapter", 0)))
    write_jsonl(state / "chapters.jsonl", rows)
    manifest = read_json(state / "manifest.json", {})
    manifest["current_chapter"] = max(int(manifest.get("current_chapter") or 0), chapter)
    manifest["updated_at"] = now_iso()
    write_json(state / "manifest.json", manifest)
    return {"ok": True, "entry": entry}


def record_style_sample(project_dir: str | Path, *, chapter: int, file: str, note: str = "") -> dict[str, Any]:
    state = ensure_state(project_dir)
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    payload = read_json(state / "style_profile.json", {"samples": [], "profile": {}})
    samples = payload.get("samples", []) if isinstance(payload, dict) else []
    if not isinstance(samples, list):
        samples = []
    sample = {
        "id": f"style-{chapter:04d}",
        "chapter": chapter,
        "file": str(path),
        "hash": text_hash(text),
        "metrics": style_metrics(text),
        "note": note.strip(),
        "recorded_at": now_iso(),
    }
    samples = [row for row in samples if not (isinstance(row, dict) and int(row.get("chapter") or -1) == chapter)]
    samples.append(sample)
    samples.sort(key=lambda row: int(row.get("chapter", 0)) if isinstance(row, dict) else 0)
    payload = {"samples": samples, "profile": merge_style_profile(samples)}
    write_json(state / "style_profile.json", payload)
    return {"ok": True, "sample": sample, "profile": payload["profile"]}


def check_chapter(project_dir: str | Path, *, chapter: int, file: str) -> dict[str, Any]:
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    context = build_chapter_context(project_dir, chapter=chapter)
    issues: list[dict[str, Any]] = []
    for phrase in context["rules"]["required_phrases"]:
        if phrase and phrase not in text:
            issues.append(make_issue("error", "missing_required", f"Missing required phrase: {phrase}", expected=phrase, actual="not found", suggested_fix=f"Add or clearly satisfy: {phrase}"))
    for phrase in context["rules"]["forbidden_phrases"]:
        if phrase and phrase in text:
            issues.append(make_issue("error", "forbidden_phrase", f"Forbidden phrase appears: {phrase}", phrase=phrase, evidence=find_evidence(text, phrase), expected=f"Do not use or imply: {phrase}", actual=phrase, suggested_fix=f"Remove this action or rewrite it so it does not happen: {phrase}"))
    for marker in context["rules"]["future_markers"]:
        if marker and len(marker) >= 2 and marker in text:
            issues.append(make_issue("error", "future_marker", f"Future-only marker appears: {marker}", phrase=marker, evidence=find_evidence(text, marker), expected="Keep future-only setting hidden in this chapter", actual=marker, suggested_fix="Replace it with non-spoiler wording or remove the reveal."))
    issues.extend(check_character_conflicts(text, context["characters"]))
    issues.extend(check_fact_conflicts(text, context["facts"]))
    issues.extend(check_contracts(text, context["contracts"]))
    issues.extend(check_resolved_debts(text, load_state(project_dir)["debts"]))
    issues.extend(check_resolved_conflicts(text, context["resolved_conflicts"]))
    issues.extend(check_style_profile(text, load_state(project_dir)["style_profile"]))
    for marker in AI_MARKERS:
        if marker in text:
            issues.append(make_issue("warning", "model_like_phrase", f"Possible model-like prose marker: {marker}", phrase=marker, evidence=find_evidence(text, marker), expected="Use concrete action, image, or consequence", actual=marker, suggested_fix="Rewrite the sentence with scene-level detail instead of explanation."))
    previous_same_chapter = None
    for row in load_state(project_dir)["chapters"]:
        if int(row.get("chapter", -1)) == chapter:
            previous_same_chapter = row
            break
    current_units = count_text_units(text)
    if previous_same_chapter:
        old_units = int(previous_same_chapter.get("text_units") or 0)
        if old_units and current_units < old_units * 0.65:
            issues.append(
                make_issue(
                    "warning",
                    "shrinkage",
                    f"Current text is much shorter than accepted chapter record: {current_units}/{old_units}",
                    expected=f"Length close to prior accepted record: {old_units}",
                    actual=str(current_units),
                    suggested_fix="Check whether accepted material was accidentally deleted.",
                    current_units=current_units,
                    previous_units=old_units,
                )
            )
    score = continuity_score(issues)
    return {
        "ok": True,
        "status": "pass" if not any(issue["severity"] == "error" for issue in issues) else "needs_revision",
        "chapter": chapter,
        "text_units": current_units,
        "score": score,
        "issues": issues,
        "revision_plan": build_revision_plan(issues),
    }


def check_style_profile(text: str, payload: dict[str, Any]) -> list[dict[str, Any]]:
    profile = payload.get("profile", {}) if isinstance(payload, dict) else {}
    if not isinstance(profile, dict) or int(profile.get("sample_count") or 0) < 2:
        return []
    metrics = style_metrics(text)
    issues: list[dict[str, Any]] = []
    baseline_sentence = float(profile.get("avg_sentence_units") or 0)
    current_sentence = float(metrics.get("avg_sentence_units") or 0)
    if baseline_sentence and (current_sentence > baseline_sentence * 1.8 or current_sentence < baseline_sentence * 0.45):
        issues.append(
            make_issue(
                "warning",
                "style_sentence_drift",
                "Average sentence length differs from recorded style profile.",
                expected=str(round(baseline_sentence, 2)),
                actual=str(round(current_sentence, 2)),
                suggested_fix="Check sentence rhythm against accepted samples before presenting the chapter.",
            )
        )
    baseline_dialogue = float(profile.get("dialogue_line_ratio") or 0)
    current_dialogue = float(metrics.get("dialogue_line_ratio") or 0)
    if baseline_dialogue and abs(current_dialogue - baseline_dialogue) > 0.45:
        issues.append(
            make_issue(
                "warning",
                "style_dialogue_ratio_drift",
                "Dialogue density differs from recorded style profile.",
                expected=str(round(baseline_dialogue, 3)),
                actual=str(round(current_dialogue, 3)),
                suggested_fix="Check whether this chapter intentionally changes scene rhythm or voice.",
            )
        )
    return issues


def diff_chapter_contract(project_dir: str | Path, *, chapter: int, file: str) -> dict[str, Any]:
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    context = build_chapter_context(project_dir, chapter=chapter)
    required_checks: list[dict[str, Any]] = []
    forbidden_checks: list[dict[str, Any]] = []

    for phrase in context["rules"]["required_phrases"]:
        add_contract_presence_check(required_checks, text, phrase, source="project_rule")
    for phrase in context["rules"]["forbidden_phrases"]:
        add_contract_absence_check(forbidden_checks, text, phrase, source="project_rule")
    for phrase in context["rules"]["future_markers"]:
        add_contract_absence_check(forbidden_checks, text, phrase, source="future_marker")

    for contract in context["contracts"]:
        contract_id = str(contract.get("id") or contract.get("title") or contract.get("name") or "contract")
        for beat in split_list(contract.get("required_beats")):
            add_contract_presence_check(required_checks, text, beat, source=contract_id)
        for move in split_list(contract.get("forbidden_moves")):
            add_contract_absence_check(forbidden_checks, text, move, source=contract_id)
        for check in split_list(contract.get("acceptance_checks")):
            add_contract_presence_check(required_checks, text, check, source=contract_id, check_type="acceptance_check")

    missing = [row for row in required_checks if row["status"] == "missing"]
    violations = [row for row in forbidden_checks if row["status"] == "violated"]
    score = max(0, 100 - len(missing) * 10 - len(violations) * 20)
    return {
        "ok": True,
        "chapter": chapter,
        "file": str(path),
        "status": "pass" if not missing and not violations else "needs_revision",
        "score": score,
        "summary": {
            "required_total": len(required_checks),
            "required_satisfied": len(required_checks) - len(missing),
            "required_missing": len(missing),
            "forbidden_total": len(forbidden_checks),
            "forbidden_violations": len(violations),
        },
        "required": required_checks,
        "forbidden": forbidden_checks,
    }


CHAPTER_READINESS_IMPROVE_TYPES = {
    "model_like_phrase",
    "style_sentence_drift",
    "style_dialogue_ratio_drift",
}

REVISION_PLAN_GROUPS: tuple[dict[str, Any], ...] = (
    {
        "group": "canon_fact_conflicts",
        "message": "Repair recorded fact, character, and conflict-state breaks before prose edits.",
        "types": {
            "fact_required_missing",
            "fact_conflict",
            "prop_ownership_conflict",
            "timeline_order_conflict",
            "location_state_conflict",
            "relationship_state_conflict",
            "life_state_conflict",
            "character_state_conflict",
            "resolved_conflict_violation",
        },
        "actions": [
            "Revise the draft to match the recorded fact_context expected_text values.",
            "If the author intentionally changed canon, create a reviewed post-write fact or conflict update before accepting the chapter.",
        ],
    },
    {
        "group": "chapter_boundaries",
        "message": "Remove future reveals, forbidden actions, or reopened resolved debts next.",
        "types": {"future_marker", "forbidden_phrase", "resolved_debt_repeated"},
        "actions": [
            "Delete or rewrite the flagged future-only or forbidden text.",
            "Keep unresolved consequences in the allowed chapter range unless the author approves a state update.",
        ],
    },
    {
        "group": "required_content",
        "message": "Add missing required project rules and chapter-contract beats.",
        "types": {"missing_required", "contract_missing_beat", "contract_required_missing"},
        "actions": [
            "Add a visible scene beat, line, or consequence for each missing required item.",
            "Run chapter-readiness again after adding the required content.",
        ],
    },
    {
        "group": "contract_violations",
        "message": "Remove moves forbidden by the visible chapter contract.",
        "types": {"contract_forbidden_move", "contract_forbidden_violation"},
        "actions": [
            "Replace forbidden moves with allowed consequences or postpone them to an allowed later chapter.",
            "Use diff-contract if the contract item needs separate inspection.",
        ],
    },
    {
        "group": "draft_integrity",
        "message": "Check whether accepted material was removed or shortened unexpectedly.",
        "types": {"shrinkage"},
        "actions": [
            "Compare the current draft with the last accepted chapter record before author presentation.",
        ],
    },
    {
        "group": "style_and_voice",
        "message": "Polish style after continuity and contract issues are resolved.",
        "types": CHAPTER_READINESS_IMPROVE_TYPES,
        "actions": [
            "Revise flagged prose markers against accepted style samples.",
            "Keep the author's voice decision separate from blocking continuity fixes.",
        ],
    },
)


def build_revision_plan(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues = [item for item in items if isinstance(item, dict)]
    if not issues:
        return []
    used: set[int] = set()
    plan: list[dict[str, Any]] = []
    for group in REVISION_PLAN_GROUPS:
        issue_types = set(group.get("types") or set())
        matched = [item for item in issues if id(item) not in used and str(item.get("type") or "") in issue_types]
        if not matched:
            continue
        for item in matched:
            used.add(id(item))
        plan.append(
            build_revision_plan_step(
                matched,
                group=str(group.get("group") or "other"),
                message=str(group.get("message") or ""),
                actions=[str(action) for action in group.get("actions", []) if str(action).strip()],
                priority=len(plan) + 1,
            )
        )
    remaining = [item for item in issues if id(item) not in used]
    if remaining:
        plan.append(
            build_revision_plan_step(
                remaining,
                group="other",
                message="Review remaining chapter issues after named groups are handled.",
                actions=["Inspect the issue message, evidence, expected value, and suggested_fix."],
                priority=len(plan) + 1,
            )
        )
    return plan


def build_revision_plan_step(
    items: list[dict[str, Any]],
    *,
    group: str,
    message: str,
    actions: list[str],
    priority: int,
) -> dict[str, Any]:
    issue_types = unique_strings([str(item.get("type") or "") for item in items])
    severity_counts: dict[str, int] = {}
    for item in items:
        severity = str(item.get("severity") or "warning")
        severity_counts[severity] = severity_counts.get(severity, 0) + 1
    fact_contexts = unique_fact_contexts(items, limit=4)
    status = "must_fix" if severity_counts.get("error") else ("improve" if group == "style_and_voice" else "review")
    return {
        "priority": priority,
        "group": group,
        "status": status,
        "count": len(items),
        "issue_types": issue_types,
        "severity_counts": severity_counts,
        "message": message,
        "evidence": unique_strings([str(item.get("evidence") or "") for item in items])[:4],
        "fact_contexts": fact_contexts,
        "suggested_actions": unique_strings(actions + [str(item.get("suggested_fix") or "") for item in items])[:6],
    }


def unique_fact_contexts(items: list[dict[str, Any]], *, limit: int = 4) -> list[dict[str, Any]]:
    contexts: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in items:
        context = item.get("fact_context")
        if not isinstance(context, dict):
            continue
        key = str(context.get("id") or context.get("expected_text") or json.dumps(context, ensure_ascii=False, sort_keys=True))
        if key in seen:
            continue
        seen.add(key)
        contexts.append(context)
        if len(contexts) >= limit:
            break
    return contexts


def build_chapter_readiness(project_dir: str | Path, *, chapter: int, file: str) -> dict[str, Any]:
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    check = check_chapter(project_dir, chapter=chapter, file=str(path))
    contract = diff_chapter_contract(project_dir, chapter=chapter, file=str(path))
    must_fix: list[dict[str, Any]] = []
    review: list[dict[str, Any]] = []
    improve: list[dict[str, Any]] = []

    for issue in check.get("issues", []) if isinstance(check.get("issues"), list) else []:
        if not isinstance(issue, dict):
            continue
        item = readiness_item_from_issue(issue)
        if issue.get("severity") == "error":
            must_fix.append(item)
        elif str(issue.get("type") or "") in CHAPTER_READINESS_IMPROVE_TYPES:
            improve.append(item)
        else:
            review.append(item)

    for row in contract.get("required", []) if isinstance(contract.get("required"), list) else []:
        if isinstance(row, dict) and row.get("status") == "missing":
            must_fix.append(readiness_item_from_contract(row, issue_type="contract_required_missing"))
    for row in contract.get("forbidden", []) if isinstance(contract.get("forbidden"), list) else []:
        if isinstance(row, dict) and row.get("status") == "violated":
            must_fix.append(readiness_item_from_contract(row, issue_type="contract_forbidden_violation"))

    status = "ready"
    if must_fix:
        status = "needs_revision"
    elif review:
        status = "review"
    elif improve:
        status = "ready_with_notes"
    score = min(int(check.get("score") or 0), int(contract.get("score") or 0))
    must_fix_items = unique_readiness_items(must_fix)
    review_items = unique_readiness_items(review)
    improve_items = unique_readiness_items(improve)
    return {
        "ok": True,
        "type": "chapter_readiness",
        "generated_at": now_iso(),
        "project_dir": str(project_root(project_dir)),
        "chapter": chapter,
        "file": str(path),
        "status": status,
        "ready_to_present": status in {"ready", "ready_with_notes"},
        "score": score,
        "text_units": check.get("text_units"),
        "summary": {
            "must_fix": len(must_fix),
            "review": len(review),
            "improve": len(improve),
            "check_status": check.get("status"),
            "contract_status": contract.get("status"),
            "check_score": check.get("score"),
            "contract_score": contract.get("score"),
        },
        "must_fix": must_fix_items,
        "review": review_items,
        "improve": improve_items,
        "revision_plan": build_revision_plan(must_fix_items + review_items + improve_items),
        "check": check,
        "contract": contract,
        "recommended_commands": chapter_readiness_commands(project_root(project_dir), chapter, path, status),
    }


def build_chapter_revision_prompt(
    project_dir: str | Path,
    *,
    chapter: int,
    file: str,
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    readiness = build_chapter_readiness(project, chapter=chapter, file=str(path))
    return build_chapter_revision_prompt_from_readiness(
        project,
        chapter=chapter,
        path=path,
        readiness=readiness,
        include_context=include_context,
    )


def build_chapter_revision_prompt_from_readiness(
    project: Path,
    *,
    chapter: int,
    path: Path,
    readiness: dict[str, Any],
    include_context: bool = False,
) -> dict[str, Any]:
    context = build_chapter_context(project, chapter=chapter)
    items = revision_prompt_items(readiness)
    plan = readiness.get("revision_plan") if isinstance(readiness.get("revision_plan"), list) else []
    steps = [revision_prompt_step(step, items) for step in plan if isinstance(step, dict)]
    report: dict[str, Any] = {
        "ok": True,
        "type": "chapter_revision_prompt",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "chapter": chapter,
        "file": str(path),
        "status": readiness.get("status"),
        "ready_to_present": bool(readiness.get("ready_to_present")),
        "read_only": True,
        "writes_project_state": False,
        "readiness_summary": readiness.get("summary") if isinstance(readiness.get("summary"), dict) else {},
        "revision_plan": plan,
        "steps": steps,
        "chapter_context_summary": chapter_revision_context_summary(context),
        "write_operations_not_performed": [
            "record_chapter",
            "propose_after_write_updates",
            "apply_after_write_updates",
            "record_agent_activity",
        ],
        "acceptance_checklist": [
            "Revise the draft according to the revision steps in order.",
            "Run chapter-readiness again after the revision.",
            "Do not record the chapter until the author accepts it.",
            "Create and review a post-write proposal before changing durable facts, characters, debts, or handoff.",
        ],
        "recommended_commands": chapter_revision_prompt_commands(project, chapter, path),
    }
    if include_context:
        report["chapter_context"] = context
    report["prompt_markdown"] = render_revision_prompt_for_agent(report)
    return report


def revision_prompt_items(readiness: dict[str, Any]) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for key in ("must_fix", "review", "improve"):
        rows = readiness.get(key) if isinstance(readiness.get(key), list) else []
        for row in rows:
            if isinstance(row, dict):
                item = compact_readiness_item(row)
                item["bucket"] = key
                items.append(item)
    return items


def revision_prompt_step(step: dict[str, Any], items: list[dict[str, Any]]) -> dict[str, Any]:
    issue_types = set(str(item) for item in step.get("issue_types", []) if str(item).strip())
    matched = [item for item in items if str(item.get("type") or "") in issue_types]
    return {
        "priority": step.get("priority"),
        "group": step.get("group"),
        "status": step.get("status"),
        "count": step.get("count"),
        "issue_types": step.get("issue_types") if isinstance(step.get("issue_types"), list) else [],
        "message": step.get("message"),
        "fact_contexts": step.get("fact_contexts") if isinstance(step.get("fact_contexts"), list) else [],
        "suggested_actions": step.get("suggested_actions") if isinstance(step.get("suggested_actions"), list) else [],
        "items": matched[:8],
    }


def chapter_revision_context_summary(context: dict[str, Any]) -> dict[str, Any]:
    previous = context.get("previous_chapter") if isinstance(context.get("previous_chapter"), dict) else {}
    rules = context.get("rules") if isinstance(context.get("rules"), dict) else {}
    contract = context.get("chapter_contract") if isinstance(context.get("chapter_contract"), dict) else {}
    return {
        "target_chapter": context.get("target_chapter"),
        "previous_chapter": {
            "chapter": previous.get("chapter"),
            "title": previous.get("title"),
            "tail": str(previous.get("tail") or "")[:500],
        },
        "handoff": str(context.get("handoff") or "")[:800],
        "required_phrases": split_list(rules.get("required_phrases"))[:20],
        "forbidden_phrases": split_list(rules.get("forbidden_phrases"))[:20],
        "future_markers": split_list(rules.get("future_markers"))[:20],
        "must_use": split_list(contract.get("must_use"))[:20],
        "must_avoid": split_list(contract.get("must_avoid"))[:20],
        "visible_counts": {
            "facts": len(context.get("facts", [])) if isinstance(context.get("facts"), list) else 0,
            "sources": len(context.get("sources", [])) if isinstance(context.get("sources"), list) else 0,
            "research": len(context.get("research", [])) if isinstance(context.get("research"), list) else 0,
            "contracts": len(context.get("contracts", [])) if isinstance(context.get("contracts"), list) else 0,
            "open_debts": len(context.get("open_debts", [])) if isinstance(context.get("open_debts"), list) else 0,
        },
    }


def render_revision_prompt_for_agent(report: dict[str, Any]) -> str:
    context = report.get("chapter_context_summary") if isinstance(report.get("chapter_context_summary"), dict) else {}
    previous = context.get("previous_chapter") if isinstance(context.get("previous_chapter"), dict) else {}
    lines = [
        "# Long Novel Agent Chapter Revision Prompt",
        "",
        f"Project: {report.get('project_dir')}",
        f"Chapter: {report.get('chapter')}",
        f"Draft file: {report.get('file')}",
        f"Readiness status: {report.get('status')}",
        "",
        "## Task",
        "- Revise the draft using the revision steps below, in order.",
        "- Preserve accepted chapter facts, visible chapter context, character state, prop ownership, relationship state, location state, life state, required beats, and forbidden boundaries.",
        "- Do not record the chapter, apply proposals, write agent activity, or change `.novel-agent/` during this revision.",
        "- If the author intentionally changes canon, state the required post-write proposal instead of silently changing durable state.",
        "",
        "## Chapter Context Summary",
        f"- Previous chapter: {previous.get('chapter') or 'None'}",
        f"- Previous tail: {previous.get('tail') or 'None'}",
        f"- Handoff: {context.get('handoff') or 'None'}",
        f"- Required phrases: {', '.join(context.get('required_phrases') or []) or 'None'}",
        f"- Forbidden phrases: {', '.join(context.get('forbidden_phrases') or []) or 'None'}",
        f"- Future markers: {', '.join(context.get('future_markers') or []) or 'None'}",
        "",
        "## Revision Steps",
    ]
    steps = report.get("steps") if isinstance(report.get("steps"), list) else []
    if not steps:
        lines.append("- No revision step is required by current checks.")
    for step in steps:
        if not isinstance(step, dict):
            continue
        lines.append(f"### {step.get('priority')}. {step.get('group')} ({step.get('status')})")
        if step.get("message"):
            lines.append(f"- Goal: {step.get('message')}")
        issue_types = ", ".join(str(item) for item in step.get("issue_types", []) if str(item).strip())
        if issue_types:
            lines.append(f"- Issue types: {issue_types}")
        fact_contexts = step.get("fact_contexts") if isinstance(step.get("fact_contexts"), list) else []
        if fact_contexts:
            lines.append("- Facts to preserve:")
            for fact in fact_contexts[:4]:
                if isinstance(fact, dict):
                    lines.append(f"  - {fact.get('expected_text') or fact.get('id')}")
        actions = step.get("suggested_actions") if isinstance(step.get("suggested_actions"), list) else []
        if actions:
            lines.append("- Actions:")
            for action in actions[:6]:
                action_text = str(action or "").strip()
                if action_text:
                    lines.append(f"  - {action_text}")
        items = step.get("items") if isinstance(step.get("items"), list) else []
        if items:
            lines.append("- Evidence:")
            for item in items[:5]:
                if not isinstance(item, dict):
                    continue
                detail = str(item.get("evidence") or item.get("actual") or item.get("message") or "").strip()
                lines.append(f"  - {item.get('type')}: {detail}")
    lines.extend(["", "## Acceptance Checklist"])
    checklist = report.get("acceptance_checklist") if isinstance(report.get("acceptance_checklist"), list) else []
    lines.extend(f"- {item}" for item in checklist or ["Run chapter-readiness again after revision."])
    return "\n".join(lines).rstrip() + "\n"


