def resolve_existing_project_file(project: Path, file: str, *, label: str) -> Path:
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project / path
    if not path.exists():
        raise KitError(f"{label} file not found: {path}")
    if not path.is_file():
        raise KitError(f"{label} path is not a file: {path}")
    return path


def revision_comparison_items(readiness: dict[str, Any]) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for bucket in ("must_fix", "review", "improve"):
        rows = readiness.get(bucket) if isinstance(readiness.get(bucket), list) else []
        for row in rows:
            if not isinstance(row, dict):
                continue
            item = compact_readiness_item(row)
            item["bucket"] = bucket
            item["key"] = revision_comparison_key(item)
            items.append(item)
    return items


def revision_comparison_key(item: dict[str, Any]) -> str:
    fact_context = item.get("fact_context") if isinstance(item.get("fact_context"), dict) else {}
    key = {
        "source": item.get("source"),
        "type": item.get("type"),
        "bucket": item.get("bucket"),
        "fact_id": item.get("fact_id") or fact_context.get("id"),
        "contract_source": item.get("contract_source"),
        "expected": item.get("expected"),
        "message": item.get("message"),
    }
    return json.dumps(key, ensure_ascii=False, sort_keys=True, separators=(",", ":"))


def revision_comparison_summary(readiness: dict[str, Any], items: list[dict[str, Any]]) -> dict[str, Any]:
    summary = readiness.get("summary") if isinstance(readiness.get("summary"), dict) else {}
    return {
        "status": readiness.get("status"),
        "ready_to_present": bool(readiness.get("ready_to_present")),
        "score": readiness.get("score"),
        "must_fix": int(summary.get("must_fix") or 0),
        "review": int(summary.get("review") or 0),
        "improve": int(summary.get("improve") or 0),
        "issue_count": len(items),
        "revision_step_count": len(readiness.get("revision_plan", [])) if isinstance(readiness.get("revision_plan"), list) else 0,
    }


def revision_comparison_status(
    before: dict[str, Any],
    after: dict[str, Any],
    *,
    before_keys: set[str],
    after_keys: set[str],
) -> str:
    if bool(after.get("ready_to_present")) and not bool(before.get("ready_to_present")):
        return "improved_ready_to_present"
    if bool(after.get("ready_to_present")) and bool(before.get("ready_to_present")):
        return "still_ready"
    before_blockers = int(before.get("must_fix") or 0)
    after_blockers = int(after.get("must_fix") or 0)
    before_total = int(before.get("issue_count") or 0)
    after_total = int(after.get("issue_count") or 0)
    if after_blockers > before_blockers or after_total > before_total:
        return "regressed"
    if after_blockers < before_blockers or after_total < before_total:
        return "improved_with_new_issues" if after_keys - before_keys else "improved_needs_more_revision"
    if before_keys == after_keys:
        return "unchanged"
    return "mixed"


def revision_comparison_next_steps(status: str, after_summary: dict[str, Any], *, has_new_issues: bool) -> list[str]:
    if status in {"improved_ready_to_present", "still_ready"}:
        return [
            "Show the revised draft and readiness result to the author for review.",
            "Do not record the chapter until the author accepts it.",
            "After author acceptance, create and review a post-write proposal before changing durable state.",
        ]
    steps = []
    if int(after_summary.get("must_fix") or 0) > 0:
        steps.append("Fix remaining must_fix items before presenting the draft.")
    if has_new_issues:
        steps.append("Review new issues introduced by the revision before further prose work.")
    if status == "regressed":
        steps.append("Compare the revised draft with the earlier draft and restore any lost required content or continuity.")
    steps.append("Run chapter-revision-prompt on the revised draft, then run chapter-revision-compare again after the next edit.")
    return steps


def keyed_revision_items(items: list[dict[str, Any]]) -> dict[str, dict[str, Any]]:
    by_key: dict[str, dict[str, Any]] = {}
    for item in items:
        key = str(item.get("key") or "")
        if key and key not in by_key:
            by_key[key] = item
    return by_key


def select_revision_comparison_items(keys: set[str], by_key: dict[str, dict[str, Any]], *, limit: int = 12) -> list[dict[str, Any]]:
    selected: list[dict[str, Any]] = []
    for key in sorted(keys):
        item = by_key.get(key)
        if not isinstance(item, dict):
            continue
        selected.append({k: v for k, v in item.items() if k != "key"})
        if len(selected) >= limit:
            break
    return selected


