def build_chapter_revision_comparison(
    project_dir: str | Path,
    *,
    chapter: int,
    before_file: str,
    after_file: str,
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    before_path = resolve_existing_project_file(project, before_file, label="Before revision")
    after_path = resolve_existing_project_file(project, after_file, label="After revision")
    before_readiness = build_chapter_readiness(project, chapter=chapter, file=str(before_path))
    after_readiness = build_chapter_readiness(project, chapter=chapter, file=str(after_path))
    before_items = revision_comparison_items(before_readiness)
    after_items = revision_comparison_items(after_readiness)
    before_by_key = keyed_revision_items(before_items)
    after_by_key = keyed_revision_items(after_items)
    before_keys = set(before_by_key)
    after_keys = set(after_by_key)
    resolved_keys = before_keys - after_keys
    new_keys = after_keys - before_keys
    remaining_keys = before_keys & after_keys
    before_summary = revision_comparison_summary(before_readiness, before_items)
    after_summary = revision_comparison_summary(after_readiness, after_items)
    status = revision_comparison_status(before_summary, after_summary, before_keys=before_keys, after_keys=after_keys)
    revision_prompt_after = build_chapter_revision_prompt_from_readiness(
        project,
        chapter=chapter,
        path=after_path,
        readiness=after_readiness,
        include_context=include_context,
    )
    return {
        "ok": True,
        "type": "chapter_revision_comparison",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "chapter": chapter,
        "before_file": str(before_path),
        "after_file": str(after_path),
        "status": status,
        "ready_to_present_after": bool(after_readiness.get("ready_to_present")),
        "read_only": True,
        "writes_project_state": False,
        "summary": {
            "before": before_summary,
            "after": after_summary,
            "resolved": len(resolved_keys),
            "new": len(new_keys),
            "remaining": len(remaining_keys),
            "score_delta": (int(after_summary.get("score") or 0) - int(before_summary.get("score") or 0)),
            "must_fix_delta": int(after_summary.get("must_fix") or 0) - int(before_summary.get("must_fix") or 0),
            "issue_count_delta": int(after_summary.get("issue_count") or 0) - int(before_summary.get("issue_count") or 0),
        },
        "resolved_issues": select_revision_comparison_items(resolved_keys, before_by_key),
        "new_issues": select_revision_comparison_items(new_keys, after_by_key),
        "remaining_issues": select_revision_comparison_items(remaining_keys, after_by_key),
        "before_readiness": before_readiness,
        "after_readiness": after_readiness,
        "revision_prompt_after": revision_prompt_after,
        "write_operations_not_performed": [
            "record_chapter",
            "propose_after_write_updates",
            "apply_after_write_updates",
            "record_agent_activity",
        ],
        "next_steps": revision_comparison_next_steps(status, after_summary, has_new_issues=bool(new_keys)),
        "recommended_commands": chapter_revision_comparison_commands(project, chapter, before_path, after_path),
    }


