def build_chapter_range_delivery_packet(
    project_dir: str | Path,
    *,
    start_chapter: int,
    end_chapter: int,
    handoff_chapter: int | None = None,
    draft_dir: str = "chapters",
    file_template: str = "{chapter:03d}.md",
    agent_id: str = "",
    required_actions: Any = None,
    expected_context_hash: str = "",
    limit: int = 20,
    include_context: bool = False,
) -> dict[str, Any]:
    if start_chapter < 1 or end_chapter < 1:
        raise KitError("Chapter numbers must be positive.")
    if end_chapter < start_chapter:
        raise KitError("End chapter must be greater than or equal to start chapter.")
    target = int(handoff_chapter or (end_chapter + 1))
    project = project_root(project_dir)
    range_report = build_chapter_range_readiness(
        project,
        start_chapter=start_chapter,
        end_chapter=end_chapter,
        draft_dir=draft_dir,
        file_template=file_template,
    )
    chapters = range_report.get("chapters") if isinstance(range_report.get("chapters"), list) else []
    deliveries: list[dict[str, Any]] = []
    delivery_errors: list[dict[str, Any]] = []
    for row in chapters:
        if not isinstance(row, dict) or row.get("exists") is False:
            continue
        chapter = int(row.get("chapter") or 0)
        file_path = str(row.get("file") or "")
        if not chapter or not file_path:
            continue
        try:
            deliveries.append(
                build_chapter_delivery_packet(project, chapter=chapter, file=file_path, include_context=include_context)
            )
        except KitError as exc:
            delivery_errors.append({"chapter": chapter, "file": file_path, "error": str(exc)})
    handoff_range = build_handoff_range_report(
        project,
        start_chapter=start_chapter,
        end_chapter=end_chapter,
        handoff_chapter=target,
        draft_dir=draft_dir,
        file_template=file_template,
        agent_id=agent_id,
        required_actions=required_actions,
        expected_context_hash=expected_context_hash,
        limit=limit,
        include_context=include_context,
    )
    pending_count = int(handoff_range.get("pending_range_proposals_count") or 0)
    high_risk_count = int(handoff_range.get("high_risk_range_proposals_count") or 0)
    blockers: list[str] = []
    review_items: list[str] = []
    warnings: list[str] = []
    range_status = str(range_report.get("status") or "")
    if range_status == "needs_files":
        blockers.append("One or more draft files in this chapter range are missing.")
    elif not range_report.get("ready_to_present"):
        blockers.append("One or more draft chapters are not ready for author presentation.")
    if delivery_errors:
        blockers.append("One or more chapter delivery packets could not be built.")
    not_ready_deliveries = [
        item for item in deliveries if isinstance(item, dict) and not bool(item.get("ready_to_present"))
    ]
    if not_ready_deliveries:
        blockers.append("One or more chapter delivery packets require revision.")
    if high_risk_count:
        review_items.append("High-risk pending proposal exists inside this chapter range.")
    elif pending_count:
        review_items.append("Pending post-write proposals exist inside this chapter range.")
    handoff_status = str(handoff_range.get("status") or "")
    if handoff_status == "blocked":
        blockers.append("The multi-chapter handoff report is blocked.")
    elif handoff_status == "needs_review":
        review_items.append("The multi-chapter handoff report needs review.")
    elif handoff_status == "ready_with_warnings":
        warnings.append("The multi-chapter handoff report has warnings.")
    if range_status == "ready_with_notes":
        warnings.append("One or more chapters have improvement notes.")
    if blockers:
        status = "blocked" if range_status == "needs_files" or delivery_errors or handoff_status == "blocked" else "needs_revision"
    elif review_items:
        status = "needs_author_review"
    elif warnings:
        status = "ready_with_notes"
    else:
        status = "ready_for_author_review"
    ready_to_present = status in {"ready_for_author_review", "ready_with_notes", "needs_author_review"}
    gates = [
        {
            "id": "chapter_range_readiness",
            "status": range_status,
            "required": True,
            "passed": bool(range_report.get("ready_to_present")),
        },
        {
            "id": "per_chapter_delivery",
            "status": "ready" if not not_ready_deliveries and not delivery_errors else "needs_revision",
            "required": True,
            "passed": not not_ready_deliveries and not delivery_errors,
        },
        {
            "id": "handoff_range_report",
            "status": handoff_status,
            "required": True,
            "passed": handoff_status in {"ready", "ready_with_warnings"},
        },
        {
            "id": "author_acceptance",
            "status": "required_before_record_chapters",
            "required": True,
            "passed": False,
        },
        {
            "id": "post_write_proposals",
            "status": "review_required" if pending_count else "required_when_state_changes",
            "required": True,
            "passed": False,
        },
    ]
    next_steps: list[str] = []
    if blockers:
        next_steps.append("Fix blocking range delivery issues before giving this batch to the author.")
    if review_items:
        next_steps.append("Ask the author to review pending or high-risk updates before durable writes.")
    if ready_to_present and not blockers:
        next_steps.append("Present the chapter range with readiness notes, proposal status, and skipped write operations clearly listed.")
    next_steps.append("After author acceptance, record each accepted chapter with author confirmation and create post-write proposals.")
    return {
        "ok": status in {"ready_for_author_review", "ready_with_notes"},
        "type": "chapter_range_delivery_packet",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "range": {"start": start_chapter, "end": end_chapter},
        "handoff_chapter": target,
        "status": status,
        "ready_to_present": ready_to_present,
        "read_only": True,
        "writes_project_state": False,
        "chapter_range_readiness": range_report,
        "chapter_deliveries": deliveries,
        "chapter_delivery_errors": delivery_errors,
        "handoff_range_report": handoff_range,
        "pending_range_proposals_count": pending_count,
        "high_risk_range_proposals_count": high_risk_count,
        "delivery_gates": gates,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "write_operations_not_performed": [
            "record_chapter",
            "propose_after_write_updates",
            "apply_after_write_updates",
            "record_agent_activity",
        ],
        "next_steps": next_steps,
        "recommended_commands": chapter_range_delivery_commands(
            project,
            start_chapter=start_chapter,
            end_chapter=end_chapter,
            handoff_chapter=target,
            draft_dir=draft_dir,
            file_template=file_template,
            chapters=chapters,
        ),
    }


def build_chapter_range_acceptance_plan(
    project_dir: str | Path,
    *,
    start_chapter: int,
    end_chapter: int,
    handoff_chapter: int | None = None,
    draft_dir: str = "chapters",
    file_template: str = "{chapter:03d}.md",
    author_confirmation: str = "",
    agent_id: str = "",
    required_actions: Any = None,
    expected_context_hash: str = "",
    limit: int = 20,
    include_context: bool = False,
) -> dict[str, Any]:
    if start_chapter < 1 or end_chapter < 1:
        raise KitError("Chapter numbers must be positive.")
    if end_chapter < start_chapter:
        raise KitError("End chapter must be greater than or equal to start chapter.")
    target = int(handoff_chapter or (end_chapter + 1))
    project = project_root(project_dir)
    confirmation = normalize_author_confirmation(author_confirmation)
    delivery = build_chapter_range_delivery_packet(
        project,
        start_chapter=start_chapter,
        end_chapter=end_chapter,
        handoff_chapter=target,
        draft_dir=draft_dir,
        file_template=file_template,
        agent_id=agent_id,
        required_actions=required_actions,
        expected_context_hash=expected_context_hash,
        limit=limit,
        include_context=include_context,
    )
    range_report = delivery.get("chapter_range_readiness") if isinstance(delivery.get("chapter_range_readiness"), dict) else {}
    chapters = range_report.get("chapters") if isinstance(range_report.get("chapters"), list) else []
    delivery_by_chapter = {
        int(item.get("chapter") or 0): item
        for item in delivery.get("chapter_deliveries", [])
        if isinstance(item, dict) and int(item.get("chapter") or 0)
    }
    blockers = list(delivery.get("blockers") if isinstance(delivery.get("blockers"), list) else [])
    review_items = list(delivery.get("review_items") if isinstance(delivery.get("review_items"), list) else [])
    warnings = list(delivery.get("warnings") if isinstance(delivery.get("warnings"), list) else [])
    if not bool(delivery.get("ready_to_present")) and not blockers:
        blockers.append("Chapter range delivery is not ready for author acceptance.")
    if not confirmation:
        review_items.append("Author confirmation is missing; durable writer commands must not be executed yet.")

    ready_chapters = [
        row
        for row in chapters
        if isinstance(row, dict)
        and row.get("exists") is not False
        and bool(row.get("ready_to_present"))
        and int(row.get("chapter") or 0) in delivery_by_chapter
    ]
    if blockers:
        status = "blocked" if str(delivery.get("status") or "") == "blocked" else "needs_revision"
    elif not confirmation:
        status = "needs_author_confirmation"
    elif review_items:
        status = "needs_author_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready_to_record"
    ready_to_record_chapters = status in {"ready_to_record", "ready_with_warnings"} and bool(confirmation)
    chapter_plans: list[dict[str, Any]] = []
    for row in chapters:
        if not isinstance(row, dict):
            continue
        chapter = int(row.get("chapter") or 0)
        file_path = str(row.get("file") or "")
        delivery_packet = delivery_by_chapter.get(chapter, {})
        draft = delivery_packet.get("draft") if isinstance(delivery_packet.get("draft"), dict) else {}
        can_record = ready_to_record_chapters and row.get("exists") is not False and bool(row.get("ready_to_present"))
        chapter_plans.append(
            {
                "chapter": chapter,
                "file": file_path,
                "exists": row.get("exists") is not False,
                "readiness_status": row.get("status"),
                "delivery_status": delivery_packet.get("status") if isinstance(delivery_packet, dict) else "",
                "ready_to_record_chapter": can_record,
                "draft_sha256": draft.get("sha256"),
                "text_units": draft.get("text_units") or row.get("text_units"),
                "steps": [
                    {
                        "order": 1,
                        "id": "prepare_session_for_write_guard",
                        "writes_project_state": False,
                        "requires_author_confirmation": False,
                        "allowed_now": row.get("exists") is not False,
                        "command_key": f"prepare_session_for_write_guard_{chapter}",
                    },
                    {
                        "order": 2,
                        "id": "write_session_check",
                        "writes_project_state": False,
                        "requires_author_confirmation": False,
                        "allowed_now": row.get("exists") is not False,
                        "command_key": f"write_session_check_{chapter}",
                    },
                    {
                        "order": 3,
                        "id": "record_chapter",
                        "writes_project_state": True,
                        "requires_author_confirmation": True,
                        "requires_write_session_check": True,
                        "allowed_now": can_record,
                        "command_key": f"record_chapter_{chapter}_after_author_acceptance",
                    },
                    {
                        "order": 4,
                        "id": "proposal_template",
                        "writes_project_state": False,
                        "requires_author_confirmation": False,
                        "allowed_now": row.get("exists") is not False,
                        "command_key": f"proposal_template_{chapter}",
                    },
                    {
                        "order": 5,
                        "id": "propose_after_write",
                        "writes_project_state": True,
                        "requires_author_confirmation": True,
                        "requires_write_session_check": True,
                        "allowed_now": can_record,
                        "command_key": f"propose_after_write_{chapter}",
                    },
                    {
                        "order": 6,
                        "id": "proposal_readiness",
                        "writes_project_state": False,
                        "requires_author_confirmation": False,
                        "allowed_now": True,
                        "command_key": f"proposal_readiness_{chapter}",
                    },
                    {
                        "order": 7,
                        "id": "apply_after_write",
                        "writes_project_state": True,
                        "requires_author_confirmation": True,
                        "requires_write_session_check": True,
                        "requires_proposal_readiness": True,
                        "allowed_now": False,
                        "command_key": f"apply_after_write_{chapter}_after_readiness",
                    },
                ],
            }
        )

    commands = chapter_range_acceptance_plan_commands(
        project,
        start_chapter=start_chapter,
        end_chapter=end_chapter,
        handoff_chapter=target,
        draft_dir=draft_dir,
        file_template=file_template,
        chapters=chapters,
        author_confirmation=confirmation,
    )
    gates = [
        {
            "id": "chapter_range_delivery",
            "status": delivery.get("status"),
            "required": True,
            "passed": bool(delivery.get("ready_to_present")),
        },
        {
            "id": "author_confirmation",
            "status": "present" if confirmation else "missing",
            "required": True,
            "passed": bool(confirmation),
        },
        {
            "id": "record_chapter_author_confirmation",
            "status": "required_on_each_record_chapter",
            "required": True,
            "passed": bool(confirmation),
        },
        {
            "id": "proposal_readiness_before_apply",
            "status": "required_before_each_apply_after_write",
            "required": True,
            "passed": False,
        },
        {
            "id": "record_agent_activity_after_acceptance",
            "status": "recommended_after_state_writes",
            "required": False,
            "passed": False,
        },
    ]
    next_steps: list[str] = []
    if blockers:
        next_steps.append("Resolve delivery blockers before recording accepted chapters.")
    if not confirmation:
        next_steps.append("Add --author-confirmation with a concise author acceptance note, then rerun this plan.")
    if review_items:
        next_steps.append("Resolve author-review items before executing durable writer commands.")
    if ready_to_record_chapters:
        next_steps.append("Record accepted chapters in chapter order, using the author confirmation shown in this plan.")
        next_steps.append("Save post-write proposals for durable facts, character state, debts, and handoff changes.")
        next_steps.append("Run proposal-readiness for every saved proposal before apply-after-write.")
        next_steps.append("Record agent activity after the accepted range has been processed.")
    existing_chapters = [
        int(plan.get("chapter") or 0)
        for plan in chapter_plans
        if isinstance(plan, dict) and plan.get("exists") is not False and int(plan.get("chapter") or 0)
    ]
    per_chapter_write_guards = [
        {
            "chapter": chapter,
            "prepare_session_command_key": f"prepare_session_for_write_guard_{chapter}",
            "write_session_check_command_key": f"write_session_check_{chapter}",
            "writer_command_keys": [
                f"record_chapter_{chapter}_after_author_acceptance",
                f"propose_after_write_{chapter}",
                f"apply_after_write_{chapter}_after_readiness",
            ],
        }
        for chapter in existing_chapters
    ]
    pre_write_review = {
        "status": status,
        "purpose": "Review the exact writer boundary for an accepted chapter range before any durable state command runs.",
        "read_only": True,
        "writes_project_state": False,
        "requires_author_confirmation": True,
        "requires_per_chapter_write_session_check": True,
        "must_review_before_writing": [
            "range_delivery.ready_to_present",
            "author_confirmation_present",
            "per-chapter prepare_session_for_write_guard output for current project_id, state sha256, and chapter context hash",
            "per-chapter write_session_check before record_chapter and propose_after_write",
            "proposal_readiness before every apply_after_write_updates",
            "recommended command keys and their write scopes",
        ],
        "guard_value_sources": {
            "project_id": "recommended_commands.prepare_session_for_write_guard_<chapter> -> project_identity.project_id",
            "project_state_sha256": "recommended_commands.prepare_session_for_write_guard_<chapter> -> project_state_fingerprint.sha256",
            "chapter_context_hash": "recommended_commands.prepare_session_for_write_guard_<chapter> -> chapter_context_fingerprint.sha256",
        },
        "per_chapter_write_guards": per_chapter_write_guards,
        "state_files_that_may_change": [
            ".novel-agent/chapters.jsonl",
            ".novel-agent/manifest.json",
            ".novel-agent/proposals.jsonl",
            ".novel-agent/facts.jsonl",
            ".novel-agent/characters.json",
            ".novel-agent/debts.json",
            ".novel-agent/handoff.md",
            ".novel-agent/snapshots/",
            ".novel-agent/agent_activity.jsonl",
            ".novel-agent/audit.jsonl",
        ],
        "durable_write_operations": [
            {
                "operation": "record_chapters",
                "per_chapter_command_keys": [f"record_chapter_{chapter}_after_author_acceptance" for chapter in existing_chapters],
                "allowed_now": ready_to_record_chapters,
                "requires_author_confirmation": True,
                "requires_per_chapter_write_session_check": True,
                "expected_write_scope": [".novel-agent/chapters.jsonl", ".novel-agent/manifest.json", ".novel-agent/audit.jsonl"],
            },
            {
                "operation": "propose_after_write_updates",
                "per_chapter_command_keys": [f"propose_after_write_{chapter}" for chapter in existing_chapters],
                "allowed_now": ready_to_record_chapters,
                "requires_author_confirmation": True,
                "requires_per_chapter_write_session_check": True,
                "expected_write_scope": [".novel-agent/proposals.jsonl", ".novel-agent/audit.jsonl"],
            },
            {
                "operation": "apply_after_write_updates",
                "per_chapter_command_keys": [f"apply_after_write_{chapter}_after_readiness" for chapter in existing_chapters],
                "allowed_now": False,
                "requires_author_confirmation": True,
                "requires_project_state_guard": True,
                "requires_proposal_readiness": True,
                "expected_write_scope": [
                    ".novel-agent/proposals.jsonl",
                    ".novel-agent/facts.jsonl",
                    ".novel-agent/characters.json",
                    ".novel-agent/debts.json",
                    ".novel-agent/handoff.md",
                    ".novel-agent/snapshots/",
                    ".novel-agent/audit.jsonl",
                ],
            },
            {
                "operation": "record_agent_activity",
                "command_key": "record_agent_activity_after_acceptance",
                "allowed_now": ready_to_record_chapters,
                "requires_author_confirmation": False,
                "requires_human_review": True,
                "expected_write_scope": [".novel-agent/agent_activity.jsonl"],
            },
        ],
        "do_not_execute_when": [
            "range_delivery.ready_to_present is false",
            "author_confirmation_present is false",
            "the relevant chapter write_session_check does not return ready",
            "proposal_readiness returns needs_revision, needs_author_review, rejected, or already_applied for the proposal being applied",
            "the command would write outside .novel-agent/",
        ],
    }
    return {
        "ok": status in {"ready_to_record", "ready_with_warnings"},
        "type": "chapter_range_acceptance_plan",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "range": {"start": start_chapter, "end": end_chapter},
        "handoff_chapter": target,
        "status": status,
        "ready_to_record_chapters": ready_to_record_chapters,
        "read_only": True,
        "writes_project_state": False,
        "author_confirmation_present": bool(confirmation),
        "author_confirmation_hash": text_hash(confirmation) if confirmation else "",
        "summary": {
            "chapters": len(chapters),
            "ready_chapters": len(ready_chapters),
            "blocked_chapters": len(chapters) - len(ready_chapters),
            "blockers": len(blockers),
            "review_items": len(review_items),
            "warnings": len(warnings),
        },
        "acceptance_gates": gates,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "chapter_plans": chapter_plans,
        "pre_write_review": pre_write_review,
        "range_delivery": delivery,
        "write_operations_not_performed": [
            "record_chapter",
            "propose_after_write_updates",
            "apply_after_write_updates",
            "record_agent_activity",
        ],
        "required_write_order": [
            "prepare_chapter_session for each accepted chapter to collect fresh writer guard values",
            "write_session_check returns ready for each accepted chapter before its record/propose writer commands",
            "record_chapter for each author-accepted chapter",
            "proposal_template for each chapter with durable state changes",
            "propose_after_write_updates for each update set",
            "proposal_readiness for each saved proposal",
            "apply_after_write_updates only when readiness allows it and author confirmation is present",
            "record_agent_activity after the accepted range is processed",
            "prepare_chapter_session for the handoff chapter before the next draft",
        ],
        "next_steps": next_steps,
        "recommended_commands": commands,
    }


def author_review_queue_command(
    project: Path,
    *,
    target: int,
    platform: str,
    mode: str,
    install_config: str = "",
    start_chapter: int | None = None,
    end_chapter: int | None = None,
    handoff_chapter: int | None = None,
    draft_dir: str = "chapters",
    file_template: str = "{chapter:03d}.md",
    include_writer_mode: bool = False,
) -> str:
    parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "author-review-queue",
        project,
        "--chapter",
        target,
        "--platform",
        platform,
        "--mode",
        mode,
        "--format",
        "markdown",
    ]
    if install_config:
        parts.extend(["--install-config", install_config])
    if start_chapter is not None and end_chapter is not None:
        parts.extend(["--start", start_chapter, "--end", end_chapter])
        if handoff_chapter:
            parts.extend(["--handoff-chapter", handoff_chapter])
        parts.extend(["--draft-dir", draft_dir, "--file-template", file_template])
    if include_writer_mode:
        parts.append("--include-writer-mode")
    return shell_command(parts)


def build_author_review_queue(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    platform: str = "codex",
    mode: str = "read-only",
    install_config: str = "",
    start_chapter: int | None = None,
    end_chapter: int | None = None,
    handoff_chapter: int | None = None,
    draft_dir: str = "chapters",
    file_template: str = "{chapter:03d}.md",
    author_confirmation: str = "",
    include_writer_mode: bool = False,
    limit: int = 20,
) -> dict[str, Any]:
    selected_platform = (platform or "codex").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported platform: {platform}")
    selected_mode = (mode or "read-only").strip().lower()
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported mode: {mode}")
    if (start_chapter is None) != (end_chapter is None):
        raise KitError("--start and --end must be used together.")
    if start_chapter is not None and end_chapter is not None and end_chapter < start_chapter:
        raise KitError("--end must be greater than or equal to --start.")

    project = project_root(project_dir)
    state = state_root(project)
    target = int(chapter or 1)
    limit_value = max(1, int(limit or 20))
    items: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()

    def add_item(
        *,
        item_id: str,
        priority: str,
        category: str,
        title: str,
        message: str,
        source_report: str,
        command: str = "",
        commands: Any = None,
        chapter_value: int | None = None,
        proposal_id: str = "",
        details: Any = None,
        requires_author_decision: bool = True,
    ) -> None:
        normalized_priority = priority if priority in {"blocker", "review", "warning"} else "review"
        key = (category, item_id, title, message)
        if key in seen:
            return
        seen.add(key)
        row: dict[str, Any] = {
            "id": item_id,
            "priority": normalized_priority,
            "category": category,
            "title": title,
            "message": message,
            "source_report": source_report,
            "requires_author_decision": bool(requires_author_decision),
            "writes_project_state": False,
        }
        if command:
            row["command"] = command
        if commands:
            row["commands"] = commands
        if chapter_value:
            row["chapter"] = chapter_value
        if proposal_id:
            row["proposal_id"] = proposal_id
        if details is not None:
            row["details"] = details
        items.append(row)

    if not state.exists():
        target = int(chapter or 1)
        add_item(
            item_id="project_not_initialized",
            priority="blocker",
            category="project",
            title="Project state is missing",
            message="The project has no .novel-agent state, so author review cannot inspect durable continuity yet.",
            source_report="author_review_queue",
            command=shell_command(["python", kit_root() / "cli.py", "quickstart", project, "--source", "auto", "--dry-run", "--format", "markdown"]),
            requires_author_decision=False,
        )
        summary = author_review_queue_summary(items)
        return {
            "ok": False,
            "type": "author_review_queue",
            "generated_at": now_iso(),
            "status": "blocked",
            "read_only": True,
            "writes_project_state": False,
            "project_dir": str(project),
            "target_chapter": target,
            "platform": selected_platform,
            "mode": selected_mode,
            "summary": summary,
            "items": items,
            "source_reports": {"project_status": {"status": "not_initialized"}},
            "next_actions": ["Initialize or import the project before reviewing author decisions."],
            "recommended_commands": {
                "quickstart_dry_run": shell_command(["python", kit_root() / "cli.py", "quickstart", project, "--source", "auto", "--dry-run", "--format", "markdown"]),
            },
        }

    project_state = project_status(project, chapter=chapter, platform=selected_platform, install_config=install_config, include_author_review_queue=False)
    target = int(project_state.get("target_chapter") or target)
    data = load_state(project)
    source_reports: dict[str, Any] = {
        "project_status": {
            "readiness": project_state.get("readiness"),
            "target_chapter": target,
            "counts": project_state.get("counts"),
        }
    }

    proposals = data.get("proposals") if isinstance(data.get("proposals"), list) else []
    pending = [
        row
        for row in proposals
        if isinstance(row, dict) and str(row.get("status") or "proposed").lower() in {"proposed", "pending", "needs_revision"}
    ]
    for index, row in enumerate(pending[:limit_value], start=1):
        proposal_id = str(row.get("id") or f"pending-{index}").strip()
        chapter_value = int(row.get("chapter") or 0) or None
        try:
            readiness = build_proposal_readiness(project, proposal_id=proposal_id if row.get("id") else "")
        except KitError as exc:
            add_item(
                item_id=f"proposal_{proposal_id}_unreadable",
                priority="blocker",
                category="proposal",
                title="Proposal cannot be reviewed",
                message=str(exc),
                source_report="proposal_readiness",
                command=shell_command(["python", kit_root() / "cli.py", "list-open-threads", project, "--chapter", target]),
                chapter_value=chapter_value,
                proposal_id=proposal_id,
                requires_author_decision=False,
            )
            continue
        status = str(readiness.get("status") or "unknown")
        if status in {"already_applied", "rejected"}:
            continue
        summary = readiness.get("summary") if isinstance(readiness.get("summary"), dict) else {}
        risk_level = str(summary.get("risk_level") or "none")
        high_risk = int(summary.get("high_risk") or 0)
        errors = int(summary.get("errors") or 0)
        warnings = int(summary.get("warnings") or 0)
        if high_risk:
            priority = "blocker"
            title = "High-risk proposal needs author decision"
        elif status == "needs_revision" or errors:
            priority = "blocker"
            title = "Proposal needs revision before author decision"
        elif status == "ready":
            priority = "review"
            title = "Ready proposal needs apply or reject decision"
        else:
            priority = "review"
            title = "Proposal needs author review"
        add_item(
            item_id=f"proposal_{proposal_id}",
            priority=priority,
            category="proposal",
            title=title,
            message=f"Proposal {proposal_id} for chapter {chapter_value or 'unknown'} is {status}; risk={risk_level}, errors={errors}, warnings={warnings}.",
            source_report="proposal_readiness",
            commands=readiness.get("recommended_commands"),
            chapter_value=chapter_value,
            proposal_id=proposal_id,
            details={
                "status": status,
                "risk_level": risk_level,
                "high_risk": high_risk,
                "errors": errors,
                "warnings": warnings,
                "score": readiness.get("score"),
            },
        )
    if len(pending) > limit_value:
        add_item(
            item_id="pending_proposals_over_limit",
            priority="review",
            category="proposal",
            title="More pending proposals exist",
            message=f"{len(pending) - limit_value} pending proposal(s) are not shown because --limit is {limit_value}.",
            source_report="proposals_jsonl",
            command=shell_command(["python", kit_root() / "cli.py", "list-open-threads", project, "--chapter", target]),
        )

    conflicts = data.get("conflicts") if isinstance(data.get("conflicts"), list) else []
    conflict_issues = 0
    for row in conflicts:
        if not isinstance(row, dict):
            continue
        conflict_id = str(row.get("id") or f"conflict-{conflict_issues + 1}").strip()
        conflict_text = str(row.get("conflict") or "").strip()
        chosen = str(row.get("chosen") or "").strip()
        reason = str(row.get("reason") or "").strip()
        scope = str(row.get("scope") or "canon").strip().lower()
        if not conflict_text or not chosen:
            conflict_issues += 1
            add_item(
                item_id=f"conflict_{conflict_id}_incomplete",
                priority="blocker",
                category="conflict",
                title="Resolved conflict record is incomplete",
                message="A conflict record is missing conflict text or chosen version.",
                source_report="conflicts_jsonl",
                command=shell_command(["python", kit_root() / "cli.py", "resolve-conflict", project, "--conflict", "<conflict>", "--chosen", "<author chosen version>", "--reason", "<reason>"]),
                details={"conflict_id": conflict_id},
                requires_author_decision=False,
            )
        elif not reason:
            conflict_issues += 1
            add_item(
                item_id=f"conflict_{conflict_id}_missing_reason",
                priority="review",
                category="conflict",
                title="Conflict decision lacks reason",
                message=f"Conflict {conflict_id} has a chosen version but no reason explaining why it wins.",
                source_report="conflicts_jsonl",
                command=shell_command(["python", kit_root() / "cli.py", "resolve-conflict", project, "--conflict", conflict_text, "--chosen", chosen, "--reason", "<author reason>"]),
                details={"conflict_id": conflict_id, "chosen": chosen},
            )
        elif scope == "range" and not row.get("chapter_ranges") and not row.get("chapter_range") and not row.get("effective_until_chapter"):
            conflict_issues += 1
            add_item(
                item_id=f"conflict_{conflict_id}_missing_range",
                priority="review",
                category="conflict",
                title="Range conflict lacks chapter boundary",
                message=f"Conflict {conflict_id} is range-scoped but has no chapter boundary.",
                source_report="conflicts_jsonl",
                command=shell_command(["python", kit_root() / "cli.py", "resolve-conflict", project, "--conflict", conflict_text, "--chosen", chosen, "--reason", reason, "--chapter-range", "<chapter range>"]),
                details={"conflict_id": conflict_id, "scope": scope},
            )
        if conflict_issues >= limit_value:
            break

    audit = build_continuity_audit(project, chapter=target, platform=selected_platform)
    source_reports["continuity_audit"] = {
        "status": audit.get("status"),
        "summary": audit.get("summary"),
        "blockers": len(audit.get("blockers") if isinstance(audit.get("blockers"), list) else []),
        "review_items": len(audit.get("review_items") if isinstance(audit.get("review_items"), list) else []),
    }
    action_plan = audit.get("action_plan") if isinstance(audit.get("action_plan"), dict) else {}
    excluded_audit_checks = {"pending_proposals_clear", "high_risk_proposals_clear"}
    for group, priority in (("must_fix", "blocker"), ("review", "review")):
        rows = action_plan.get(group) if isinstance(action_plan.get(group), list) else []
        for row in rows[:limit_value]:
            if not isinstance(row, dict):
                continue
            source_check = str(row.get("source_check") or "")
            if source_check in excluded_audit_checks:
                continue
            action_id = str(row.get("id") or f"continuity_{group}_{len(items) + 1}")
            add_item(
                item_id=f"continuity_{action_id}",
                priority=priority,
                category="continuity",
                title=str(row.get("title") or "Continuity item needs review"),
                message=str(row.get("reason") or row.get("description") or ""),
                source_report="continuity_audit",
                command=str(row.get("command") or ""),
                details={"source_check": source_check, "action": row},
                requires_author_decision=priority != "blocker",
            )

    include_writer = bool(include_writer_mode) or selected_mode == "writer"
    writer_report: dict[str, Any] = {}
    if include_writer:
        writer_report = build_writer_mode_readiness(
            project,
            platform=selected_platform,
            install_config=install_config,
            chapter=target,
            author_confirmation=author_confirmation,
        )
        source_reports["writer_mode_readiness"] = {
            "status": writer_report.get("status"),
            "ok": writer_report.get("ok"),
            "author_confirmation_present": writer_report.get("author_confirmation_present"),
        }
        for check in writer_report.get("checks", []) if isinstance(writer_report.get("checks"), list) else []:
            if not isinstance(check, dict) or check.get("ok"):
                continue
            check_id = str(check.get("id") or "")
            if check_id in {"pending_proposals_reviewed", "high_risk_proposals_clear"}:
                continue
            severity = str(check.get("severity") or "review")
            priority = "blocker" if severity == "blocker" else "warning" if severity == "warning" else "review"
            add_item(
                item_id=f"writer_mode_{check_id}",
                priority=priority,
                category="writer_mode",
                title="Writer mode needs review",
                message=str(check.get("message") or check_id),
                source_report="writer_mode_readiness",
                commands=writer_report.get("recommended_commands"),
                details=check,
                requires_author_decision=check_id == "author_confirmed_writer_scope" or priority == "review",
            )

    acceptance_report: dict[str, Any] = {}
    if start_chapter is not None and end_chapter is not None:
        acceptance_report = build_chapter_range_acceptance_plan(
            project,
            start_chapter=start_chapter,
            end_chapter=end_chapter,
            handoff_chapter=handoff_chapter,
            draft_dir=draft_dir,
            file_template=file_template,
            author_confirmation=author_confirmation,
            required_actions=["prepare-session"],
        )
        source_reports["chapter_range_acceptance_plan"] = {
            "status": acceptance_report.get("status"),
            "summary": acceptance_report.get("summary"),
            "ready_to_record_chapters": acceptance_report.get("ready_to_record_chapters"),
        }
        for key, priority, title in (
            ("blockers", "blocker", "Chapter range acceptance is blocked"),
            ("review_items", "review", "Chapter range acceptance needs author review"),
            ("warnings", "warning", "Chapter range acceptance has warning"),
        ):
            rows = acceptance_report.get(key) if isinstance(acceptance_report.get(key), list) else []
            for index, message in enumerate(rows[:limit_value], start=1):
                add_item(
                    item_id=f"range_acceptance_{key}_{index}",
                    priority=priority,
                    category="range_acceptance",
                    title=title,
                    message=str(message),
                    source_report="chapter_range_acceptance_plan",
                    commands=acceptance_report.get("recommended_commands"),
                    details={"range": acceptance_report.get("range"), "status": acceptance_report.get("status")},
                    requires_author_decision=priority == "review",
                )

    summary = author_review_queue_summary(items)
    if summary["blockers"]:
        status = "blocked"
    elif summary["review"]:
        status = "needs_author_review"
    elif summary["warnings"]:
        status = "ready_with_warnings"
    else:
        status = "clear"

    commands: dict[str, str] = {
        "rerun_author_review_queue": author_review_queue_command(
            project,
            target=target,
            platform=selected_platform,
            mode=selected_mode,
            install_config=install_config,
            start_chapter=start_chapter,
            end_chapter=end_chapter,
            handoff_chapter=handoff_chapter,
            draft_dir=draft_dir,
            file_template=file_template,
            include_writer_mode=include_writer_mode,
        ),
        "continuity_audit": shell_command(["python", kit_root() / "cli.py", "continuity-audit", project, "--chapter", target, "--platform", selected_platform, "--format", "markdown"]),
    }
    first_proposal = next((item for item in items if item.get("category") == "proposal" and item.get("proposal_id")), {})
    if first_proposal:
        proposal_id = str(first_proposal.get("proposal_id") or "")
        commands["first_proposal_readiness"] = shell_command(["python", kit_root() / "cli.py", "proposal-readiness", project, "--proposal-id", proposal_id, "--format", "markdown"])
        commands["first_proposal_review"] = shell_command(["python", kit_root() / "cli.py", "proposal-review", project, "--proposal-id", proposal_id, "--format", "markdown"])
    if include_writer:
        writer_parts: list[object] = [
            "python",
            kit_root() / "cli.py",
            "writer-mode-readiness",
            project,
            "--platform",
            selected_platform,
            "--chapter",
            target,
            "--author-confirmation",
            normalize_author_confirmation(author_confirmation) or "<author-approved writer mode scope>",
            "--format",
            "markdown",
        ]
        if install_config:
            writer_parts.extend(["--install-config", install_config])
        commands["writer_mode_readiness"] = shell_command(writer_parts)
    if start_chapter is not None and end_chapter is not None:
        commands["chapter_range_acceptance_plan"] = shell_command(
            [
                "python",
                kit_root() / "cli.py",
                "chapter-range-acceptance-plan",
                project,
                "--start",
                start_chapter,
                "--end",
                end_chapter,
                "--handoff-chapter",
                handoff_chapter or end_chapter + 1,
                "--draft-dir",
                draft_dir,
                "--file-template",
                file_template,
                "--author-confirmation",
                normalize_author_confirmation(author_confirmation) or "<author acceptance summary>",
                "--format",
                "markdown",
            ]
        )

    next_actions: list[str] = []
    if summary["blockers"]:
        next_actions.append("Resolve blocker items before durable writer commands or handoff acceptance.")
    if summary["review"]:
        next_actions.append("Ask the author to decide the review items, then rerun this queue.")
    if status == "clear":
        next_actions.append("No author-review item is currently queued for the selected target.")
    if status == "ready_with_warnings":
        next_actions.append("Warnings remain, but no blocker or author-review item is queued.")

    review_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-evidence-review",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--format",
        "markdown",
    ]
    if install_config:
        review_parts.extend(["--install-config", install_config])

    return {
        "ok": status in {"clear", "ready_with_warnings"},
        "type": "author_review_queue",
        "generated_at": now_iso(),
        "status": status,
        "read_only": True,
        "writes_project_state": False,
        "project_dir": str(project),
        "target_chapter": target,
        "platform": selected_platform,
        "mode": selected_mode,
        "range": {"start": start_chapter, "end": end_chapter, "handoff_chapter": handoff_chapter or (end_chapter + 1 if end_chapter else None)},
        "summary": summary,
        "items": items,
        "source_reports": source_reports,
        "next_actions": next_actions,
        "recommended_commands": commands,
    }


def author_review_queue_summary(items: list[dict[str, Any]]) -> dict[str, Any]:
    by_category: dict[str, int] = {}
    for item in items:
        category = str(item.get("category") or "other")
        by_category[category] = by_category.get(category, 0) + 1
    return {
        "total": len(items),
        "blockers": sum(1 for item in items if item.get("priority") == "blocker"),
        "review": sum(1 for item in items if item.get("priority") == "review"),
        "warnings": sum(1 for item in items if item.get("priority") == "warning"),
        "requires_author_decision": sum(1 for item in items if item.get("requires_author_decision")),
        "by_category": by_category,
    }


def readiness_item_from_issue(issue: dict[str, Any]) -> dict[str, Any]:
    item = {
        "source": "check_chapter",
        "severity": issue.get("severity") or "warning",
        "type": issue.get("type") or "issue",
        "message": issue.get("message") or "",
        "expected": issue.get("expected") or "",
        "actual": issue.get("actual") or "",
        "evidence": issue.get("evidence") or "",
        "suggested_fix": issue.get("suggested_fix") or "",
    }
    if issue.get("fact_id"):
        item["fact_id"] = issue.get("fact_id")
    if isinstance(issue.get("fact_context"), dict):
        item["fact_context"] = issue.get("fact_context")
    return item


def readiness_item_from_contract(row: dict[str, Any], *, issue_type: str) -> dict[str, Any]:
    text = str(row.get("text") or "").strip()
    source = str(row.get("source") or "").strip()
    if issue_type == "contract_required_missing":
        message = f"Missing contract item: {text}"
        expected = f"Chapter should satisfy: {text}"
        actual = "not found"
        suggested_fix = "Add a clear beat, line, or scene consequence that satisfies this contract item."
    else:
        message = f"Forbidden contract item appears: {text}"
        expected = f"Chapter should avoid: {text}"
        actual = text
        suggested_fix = "Remove this action or rewrite it so the forbidden move does not happen."
    return {
        "source": "diff_chapter_contract",
        "severity": "error",
        "type": issue_type,
        "message": message,
        "expected": expected,
        "actual": actual,
        "evidence": row.get("evidence") or "",
        "suggested_fix": suggested_fix,
        "contract_source": source,
        "text": text,
    }


def unique_readiness_items(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str]] = set()
    result: list[dict[str, Any]] = []
    for item in items:
        key = (str(item.get("source") or ""), str(item.get("type") or ""), str(item.get("message") or ""))
        if key in seen:
            continue
        seen.add(key)
        result.append(item)
    return result


def chapter_readiness_commands(project: Path, chapter: int, path: Path, status: str) -> dict[str, str]:
    commands = {
        "check_chapter": shell_command(["python", kit_root() / "cli.py", "check-chapter", project, "--chapter", chapter, "--file", path]),
        "diff_contract": shell_command(["python", kit_root() / "cli.py", "diff-contract", project, "--chapter", chapter, "--file", path]),
    }
    if status in {"ready", "ready_with_notes"}:
        commands["record_chapter_after_author_acceptance"] = shell_command(
            [
                "python",
                kit_root() / "cli.py",
                "record-chapter",
                project,
                "--chapter",
                chapter,
                "--file",
                path,
                "--author-confirmation",
                CHAPTER_ACCEPTANCE_AUTHOR_CONFIRMATION,
            ]
        )
        commands["proposal_template_after_acceptance"] = shell_command(["python", kit_root() / "cli.py", "proposal-template", project, "--chapter", chapter, "--file", path])
    return commands


def add_contract_presence_check(
    rows: list[dict[str, Any]],
    text: str,
    phrase: str,
    *,
    source: str,
    check_type: str = "required",
) -> None:
    phrase = str(phrase or "").strip()
    if not phrase:
        return
    satisfied = phrase in text
    rows.append(
        {
            "text": phrase,
            "source": source,
            "type": check_type,
            "status": "satisfied" if satisfied else "missing",
            "evidence": find_evidence(text, phrase) if satisfied else "",
        }
    )


def add_contract_absence_check(rows: list[dict[str, Any]], text: str, phrase: str, *, source: str) -> None:
    phrase = str(phrase or "").strip()
    if not phrase:
        return
    violated = phrase in text
    rows.append(
        {
            "text": phrase,
            "source": source,
            "type": "forbidden",
            "status": "violated" if violated else "clear",
            "evidence": find_evidence(text, phrase) if violated else "",
        }
    )


def make_issue(
    severity: str,
    issue_type: str,
    message: str,
    *,
    phrase: str = "",
    evidence: str = "",
    expected: str = "",
    actual: str = "",
    suggested_fix: str = "",
    **extra: Any,
) -> dict[str, Any]:
    issue = {
        "severity": severity,
        "type": issue_type,
        "message": message,
        "evidence": evidence,
        "expected": expected,
        "actual": actual,
        "suggested_fix": suggested_fix,
    }
    if phrase:
        issue["phrase"] = phrase
    issue.update(extra)
    return issue


def find_evidence(text: str, phrase: str, window: int = 36) -> str:
    if not phrase:
        return ""
    index = text.find(phrase)
    if index < 0:
        return ""
    start = max(0, index - window)
    end = min(len(text), index + len(phrase) + window)
    return text[start:end].replace("\n", " ")


def check_character_conflicts(text: str, characters: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for character in characters:
        name = str(character.get("name") or character.get("title") or "").strip()
        aliases = split_list(character.get("aliases"))
        names = [name] + aliases
        if names and not any(item and item in text for item in names):
            continue
        for phrase in split_list(character.get("forbidden_phrases") or character.get("forbidden_states")):
            if phrase and phrase in text:
                issues.append(
                    make_issue(
                        "error",
                        "character_state_conflict",
                        f"Character state conflict for {name or 'unknown'}: {phrase}",
                        phrase=phrase,
                        evidence=find_evidence(text, phrase),
                        expected=str(character.get("state") or character.get("current_state") or "Preserve recorded character state"),
                        actual=phrase,
                        suggested_fix=f"Rewrite {name or 'the character'} so this state/action does not occur.",
                        character=name,
                    )
                )
    return issues


def check_fact_conflicts(text: str, facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for fact in facts:
        subject = str(fact.get("subject") or "").strip()
        predicate = str(fact.get("predicate") or "").strip()
        object_value = str(fact.get("object") or "").strip()
        expected = f"{subject} {predicate} {object_value}".strip()
        for phrase in split_list(fact.get("required_phrases")):
            if phrase and phrase not in text:
                issues.append(
                    make_issue(
                        "error",
                        "fact_required_missing",
                        f"Required fact marker is missing: {phrase}",
                        phrase=phrase,
                        expected=expected,
                        actual="not found",
                        suggested_fix=f"Add a scene action or line that satisfies: {phrase}",
                        fact_id=str(fact.get("id") or ""),
                        fact_context=fact_issue_context(fact),
                    )
                )
        for phrase in split_list(fact.get("forbidden_phrases")):
            if phrase and phrase in text:
                issues.append(
                    make_issue(
                        "error",
                        "fact_conflict",
                        f"Fact conflict: {phrase}",
                        phrase=phrase,
                        evidence=find_evidence(text, phrase),
                        expected=expected,
                        actual=phrase,
                        suggested_fix="Rewrite this beat so it follows the recorded fact.",
                        fact_id=str(fact.get("id") or ""),
                        fact_context=fact_issue_context(fact),
                    )
                )
        if predicate.lower() in OWNERSHIP_PREDICATES or predicate in OWNERSHIP_PREDICATES:
            issues.extend(check_ownership_fact(text, fact, subject, object_value, expected))
    issues.extend(check_timeline_fact_conflicts(text, facts))
    issues.extend(check_location_fact_conflicts(text, facts))
    issues.extend(check_relationship_fact_conflicts(text, facts))
    issues.extend(check_life_status_fact_conflicts(text, facts))
    return issues


def check_ownership_fact(text: str, fact: dict[str, Any], subject: str, expected_holder: str, expected: str) -> list[dict[str, Any]]:
    if not subject or not expected_holder or subject not in text:
        return []
    transfer_verbs = ["交给", "递给", "交到", "给了", "交还给", "归还给", "落到", "被", "拿走"]
    issues: list[dict[str, Any]] = []
    for verb in transfer_verbs:
        pattern = re.compile(re.escape(subject) + r"[^。；，,\n]{0,18}" + re.escape(verb) + r"[^。；，,\n]{0,18}")
        for match in pattern.finditer(text):
            evidence = match.group(0)
            if expected_holder not in evidence:
                issues.append(
                    make_issue(
                        "error",
                        "prop_ownership_conflict",
                        f"Possible ownership conflict for {subject}",
                        evidence=evidence,
                        expected=expected,
                        actual=evidence,
                        suggested_fix=f"Keep {subject} with {expected_holder}, or record a confirmed fact update before using this transfer.",
                        fact_id=str(fact.get("id") or ""),
                        fact_context=fact_issue_context(fact),
                    )
                )
    return issues


def fact_kind(fact: dict[str, Any]) -> str:
    return str(fact.get("kind") or "").strip().lower()


def fact_predicate(fact: dict[str, Any]) -> str:
    return str(fact.get("predicate") or "").strip().lower()


def fact_expected_text(fact: dict[str, Any]) -> str:
    return f"{fact.get('subject') or ''} {fact.get('predicate') or ''} {fact.get('object') or ''}".strip()


def fact_issue_context(fact: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": str(fact.get("id") or ""),
        "kind": str(fact.get("kind") or ""),
        "subject": str(fact.get("subject") or ""),
        "predicate": str(fact.get("predicate") or ""),
        "object": str(fact.get("object") or ""),
        "expected_text": fact_expected_text(fact),
        "chapter_ranges": fact.get("chapter_ranges") if isinstance(fact.get("chapter_ranges"), list) else [],
        "source_path": str(fact.get("source_path") or ""),
        "source_ids": split_list(fact.get("source_ids")),
        "evidence": str(fact.get("evidence") or ""),
        "confidence": str(fact.get("confidence") or ""),
    }


def fact_matches(fact: dict[str, Any], *, kinds: set[str], predicates: set[str]) -> bool:
    kind = fact_kind(fact)
    predicate = fact_predicate(fact)
    return kind in kinds or predicate in predicates


def text_segments(text: str) -> list[str]:
    return [part.strip() for part in re.split(r"[。！？!?；;\n]+", text) if part.strip()]


def segments_with(text: str, *phrases: str) -> list[str]:
    wanted = [phrase for phrase in phrases if phrase]
    if not wanted:
        return []
    return [segment for segment in text_segments(text) if all(phrase in segment for phrase in wanted)]


def contains_any(text: str, phrases: set[str] | list[str] | tuple[str, ...]) -> bool:
    lowered = text.lower()
    return any(phrase and (phrase in text or phrase.lower() in lowered) for phrase in phrases)


def matched_terms(text: str, phrases: set[str] | list[str] | tuple[str, ...]) -> list[str]:
    lowered = text.lower()
    return [phrase for phrase in phrases if phrase and (phrase in text or phrase.lower() in lowered)]


def negated_phrase(segment: str, phrase: str) -> bool:
    index = segment.find(phrase)
    if index < 0:
        return False
    prefix = segment[max(0, index - 5) : index]
    return any(marker in prefix for marker in NEGATION_PREFIXES)


def check_timeline_fact_conflicts(text: str, facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for fact in facts:
        predicate = fact_predicate(fact)
        subject = str(fact.get("subject") or "").strip()
        object_value = str(fact.get("object") or "").strip()
        if not subject or not object_value or len(subject) < 2 or len(object_value) < 2:
            continue
        subject_index = text.find(subject)
        object_index = text.find(object_value)
        if subject_index < 0 or object_index < 0:
            continue
        expected = fact_expected_text(fact)
        if predicate in TIMELINE_AFTER_PREDICATES and subject_index < object_index:
            issues.append(
                make_issue(
                    "error",
                    "timeline_order_conflict",
                    f"Timeline order conflicts with fact: {expected}",
                    evidence=find_order_evidence(text, subject, object_value),
                    expected=f"{object_value} before {subject}",
                    actual=f"{subject} before {object_value}",
                    suggested_fix="Revise the sequence, or record a superseding timeline fact if the author changed the order.",
                    fact_id=str(fact.get("id") or ""),
                    fact_context=fact_issue_context(fact),
                )
            )
        if predicate in TIMELINE_BEFORE_PREDICATES and subject_index > object_index:
            issues.append(
                make_issue(
                    "error",
                    "timeline_order_conflict",
                    f"Timeline order conflicts with fact: {expected}",
                    evidence=find_order_evidence(text, subject, object_value),
                    expected=f"{subject} before {object_value}",
                    actual=f"{object_value} before {subject}",
                    suggested_fix="Revise the sequence, or record a superseding timeline fact if the author changed the order.",
                    fact_id=str(fact.get("id") or ""),
                    fact_context=fact_issue_context(fact),
                )
            )
    return issues


def find_order_evidence(text: str, first: str, second: str, window: int = 42) -> str:
    first_index = text.find(first)
    second_index = text.find(second)
    if first_index < 0 or second_index < 0:
        return ""
    start = max(0, min(first_index, second_index) - window)
    end = min(len(text), max(first_index + len(first), second_index + len(second)) + window)
    return text[start:end].replace("\n", " ")


def location_facts(facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return [
        fact
        for fact in facts
        if fact_matches(fact, kinds=LOCATION_FACT_KINDS, predicates=LOCATION_PREDICATES)
        and str(fact.get("subject") or "").strip()
        and str(fact.get("object") or "").strip()
    ]


def check_location_fact_conflicts(text: str, facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows = location_facts(facts)
    known_locations = unique_strings([str(row.get("object") or "").strip() for row in rows])
    if len(known_locations) < 2:
        return []
    issues: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for fact in rows:
        subject = str(fact.get("subject") or "").strip()
        expected_location = str(fact.get("object") or "").strip()
        for segment in segments_with(text, subject):
            if expected_location and expected_location in segment:
                continue
            for location in known_locations:
                if location == expected_location or location not in segment or negated_phrase(segment, location):
                    continue
                key = (str(fact.get("id") or ""), location, segment)
                if key in seen:
                    continue
                seen.add(key)
                issues.append(
                    make_issue(
                        "warning",
                        "location_state_conflict",
                        f"Location state may conflict for {subject}",
                        phrase=location,
                        evidence=segment,
                        expected=f"{subject} at {expected_location}",
                        actual=segment,
                        suggested_fix="Confirm whether this is intentional movement; if accepted, record the new location as a post-write fact.",
                        fact_id=str(fact.get("id") or ""),
                        fact_context=fact_issue_context(fact),
                    )
                )
    return issues


RELATIONSHIP_CONTRADICTIONS: tuple[tuple[set[str], set[str]], ...] = (
    ({"敌对", "敌人", "仇敌", "对立", "追杀", "反目", "决裂"}, {"结盟", "盟友", "同盟", "合作", "并肩", "和解"}),
    ({"结盟", "盟友", "同盟", "合作", "并肩", "朋友", "同伴"}, {"敌对", "追杀", "反目", "决裂", "背叛", "倒戈"}),
    ({"师徒", "师父", "徒弟"}, {"断绝师徒", "逐出师门"}),
)


def relationship_participants(subject: str) -> list[str]:
    parts = [part.strip() for part in re.split(r"[/／&、,，]|和|与", subject) if part.strip()]
    return parts or ([subject] if subject else [])


def check_relationship_fact_conflicts(text: str, facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for fact in facts:
        if not fact_matches(fact, kinds=RELATIONSHIP_FACT_KINDS, predicates=RELATIONSHIP_PREDICATES):
            continue
        subject = str(fact.get("subject") or "").strip()
        expected_state = str(fact.get("object") or "").strip()
        if not subject or not expected_state:
            continue
        participants = relationship_participants(subject)
        candidate_segments = [segment for segment in text_segments(text) if subject in segment or all(name in segment for name in participants)]
        if not candidate_segments:
            continue
        for expected_terms, conflict_terms in RELATIONSHIP_CONTRADICTIONS:
            if not contains_any(expected_state, expected_terms):
                continue
            for segment in candidate_segments:
                hits = matched_terms(segment, conflict_terms)
                if not hits:
                    continue
                issues.append(
                    make_issue(
                        "error",
                        "relationship_state_conflict",
                        f"Relationship state conflicts with fact: {fact_expected_text(fact)}",
                        phrase=hits[0],
                        evidence=segment,
                        expected=fact_expected_text(fact),
                        actual=segment,
                        suggested_fix="Keep the recorded relationship state, or record a confirmed relationship update after author acceptance.",
                        fact_id=str(fact.get("id") or ""),
                        fact_context=fact_issue_context(fact),
                    )
                )
                break
    return issues


def life_status_category(text: str) -> str:
    if contains_any(text, DEATH_TERMS):
        return "dead"
    if contains_any(text, ALIVE_TERMS):
        return "alive"
    return ""


def check_life_status_fact_conflicts(text: str, facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for fact in facts:
        if not fact_matches(fact, kinds=LIFE_STATUS_KINDS, predicates=LIFE_STATUS_PREDICATES):
            continue
        subject = str(fact.get("subject") or "").strip()
        object_value = str(fact.get("object") or "").strip()
        expected = life_status_category(object_value)
        if not subject or not expected:
            continue
        for segment in segments_with(text, subject):
            actual = life_status_category(segment)
            if not actual or actual == expected:
                continue
            hits = matched_terms(segment, DEATH_TERMS if actual == "dead" else ALIVE_TERMS)
            issues.append(
                make_issue(
                    "error",
                    "life_state_conflict",
                    f"Life state conflicts with fact: {fact_expected_text(fact)}",
                    phrase=hits[0] if hits else "",
                    evidence=segment,
                    expected=fact_expected_text(fact),
                    actual=segment,
                    suggested_fix="Keep the recorded life state, or record a confirmed high-risk state update after author review.",
                    fact_id=str(fact.get("id") or ""),
                    fact_context=fact_issue_context(fact),
                )
            )
            break
    return issues


def check_contracts(text: str, contracts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for contract in contracts:
        for beat in split_list(contract.get("required_beats")):
            if beat and beat not in text:
                issues.append(
                    make_issue(
                        "error",
                        "contract_missing_beat",
                        f"Chapter contract beat is missing: {beat}",
                        phrase=beat,
                        expected=beat,
                        actual="not found",
                        suggested_fix=f"Add a concrete scene beat for: {beat}",
                        contract_id=str(contract.get("id") or ""),
                    )
                )
        for move in split_list(contract.get("forbidden_moves")):
            if move and move in text:
                issues.append(
                    make_issue(
                        "error",
                        "contract_forbidden_move",
                        f"Chapter contract forbids this move: {move}",
                        phrase=move,
                        evidence=find_evidence(text, move),
                        expected=f"Do not include: {move}",
                        actual=move,
                        suggested_fix="Replace this move with an allowed consequence or delay it to a later chapter.",
                        contract_id=str(contract.get("id") or ""),
                    )
                )
    return issues


def check_resolved_debts(text: str, debts_payload: dict[str, Any]) -> list[dict[str, Any]]:
    rows = debts_payload.get("debts", []) if isinstance(debts_payload, dict) else []
    issues: list[dict[str, Any]] = []
    for debt in rows if isinstance(rows, list) else []:
        if not isinstance(debt, dict):
            continue
        status = str(debt.get("status") or debt.get("debt_status") or "").lower()
        if status not in RESOLVED_STATUSES:
            continue
        markers = split_list(debt.get("repeat_markers")) or split_list(debt.get("title") or debt.get("debt_content"))
        for marker in markers:
            if marker and marker in text:
                issues.append(
                    make_issue(
                        "warning",
                        "resolved_debt_repeated",
                        f"Resolved debt appears again: {marker}",
                        phrase=marker,
                        evidence=find_evidence(text, marker),
                        expected="Do not reopen a resolved debt without a new confirmed update.",
                        actual=marker,
                        suggested_fix="Treat it as past consequence, or create a new debt before using it as unresolved.",
                        debt_id=str(debt.get("id") or ""),
                    )
                )
    return issues


def check_resolved_conflicts(text: str, conflicts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for conflict in conflicts:
        scope = str(conflict.get("scope") or "canon").strip().lower()
        if scope in {"viewpoint", "perceived", "character_view"}:
            continue
        chosen = str(conflict.get("chosen") or "").strip()
        for option in split_list(conflict.get("options")):
            if not option or option == chosen:
                continue
            if option in text:
                issues.append(
                    make_issue(
                        "error",
                        "resolved_conflict_violation",
                        f"Resolved conflict was reverted: {option}",
                        phrase=option,
                        evidence=find_evidence(text, option),
                        expected=chosen,
                        actual=option,
                        suggested_fix="Use the chosen version, or call resolve_conflict again with the author's new decision.",
                        conflict_id=str(conflict.get("id") or ""),
                    )
                )
    return issues


def continuity_score(issues: list[dict[str, Any]]) -> int:
    score = 100
    for issue in issues:
        score -= 20 if issue.get("severity") == "error" else 6
    return max(0, score)


def update_after_write(project_dir: str | Path, *, chapter: int, file: str) -> dict[str, Any]:
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    context = build_chapter_context(project_dir, chapter=chapter)
    check = check_chapter(project_dir, chapter=chapter, file=str(path))
    names = []
    for character in context["characters"]:
        name = str(character.get("name") or character.get("title") or "").strip()
        if name and name in text:
            names.append(name)
    suggestions = {
        "chapter": chapter,
        "archive_updates": {
            "chapter_note": "Summarize accepted events, state changes, and next handoff.",
            "characters_to_review": unique_strings(names),
            "debts_to_review": context["open_debts"],
            "rules_to_review": check["issues"],
        },
        "next_handoff": {
            "previous_tail": tail_text(text),
            "continuity_focus": context["chapter_contract"]["continuity_focus"],
            "open_questions": ["Mark any unresolved promise, clue, or character pressure before writing the next chapter."],
        },
    }
    state = ensure_state(project_dir)
    handoff_text = render_handoff_markdown(suggestions)
    (state / "handoff.md").write_text(handoff_text, encoding="utf-8")
    return {"ok": True, "suggestions": suggestions, "handoff_path": str(state / "handoff.md")}


def parse_json_value(value: str | None, project_dir: str | Path | None = None) -> Any:
    if not value:
        return {}
    text = read_text_value(value, project_dir).strip()
    if not text:
        return {}
    try:
        return json.loads(text)
    except json.JSONDecodeError as exc:
        raise KitError(f"Invalid JSON updates: {exc}") from exc


def normalize_update_payload(payload: Any) -> dict[str, Any]:
    if payload is None:
        return {}
    if isinstance(payload, dict):
        return payload
    raise KitError("Updates must be a JSON object")


def propose_after_write_updates(project_dir: str | Path, *, chapter: int, file: str, updates: Any = None) -> dict[str, Any]:
    state = ensure_state(project_dir)
    path = Path(file).expanduser()
    if not path.is_absolute():
        path = project_root(project_dir) / path
    if not path.exists():
        raise KitError(f"Chapter file not found: {path}")
    text = path.read_text(encoding="utf-8")
    payload = normalize_update_payload(updates)
    proposal_id = make_id("proposal")
    proposal = {
        "id": proposal_id,
        "chapter": chapter,
        "file": str(path),
        "status": "proposed",
        "chapter_tail": tail_text(text),
        "facts": payload.get("facts", []),
        "characters": payload.get("characters", []),
        "debts": payload.get("debts", []),
        "handoff": payload.get("handoff") or tail_text(text),
        "notes": payload.get("notes", ""),
        "created_at": now_iso(),
    }
    validation = validate_proposal_payload(state, proposal, require_evidence=True)
    proposal["validation_status"] = "valid" if validation["ok"] else "needs_revision"
    proposal["risk"] = validation["risk"]
    append_jsonl(state / "proposals.jsonl", proposal)
    return {"ok": True, "proposal": proposal, "validation": validation}


def apply_after_write_updates(project_dir: str | Path, *, proposal_id: str = "", updates: Any = None) -> dict[str, Any]:
    state = ensure_state(project_dir)
    proposal = normalize_update_payload(updates)
    proposals = read_jsonl(state / "proposals.jsonl")
    if proposal_id:
        for row in proposals:
            if row.get("id") == proposal_id:
                proposal = row
                break
        else:
            raise KitError(f"Proposal not found: {proposal_id}")
    if not proposal:
        raise KitError("apply-after-write requires a proposal_id or updates JSON")
    if str(proposal.get("status") or "") == "rejected":
        raise KitError(f"Proposal has been rejected: {proposal.get('rejected_reason') or proposal.get('id')}")
    validation = validate_proposal_payload(state, proposal, require_evidence=True)
    if not validation["ok"]:
        raise KitError("Proposal validation failed: " + json.dumps(validation["issues"], ensure_ascii=False))
    snapshot = create_state_snapshot(state, reason="before_apply_after_write", metadata={"proposal_id": proposal.get("id")})
    applied = {
        "facts": apply_fact_updates(state, proposal.get("facts", [])),
        "characters": apply_character_updates(state, proposal.get("characters", [])),
        "debts": apply_debt_updates(state, proposal.get("debts", [])),
        "handoff": False,
    }
    handoff = str(proposal.get("handoff") or "").strip()
    if handoff:
        (state / "handoff.md").write_text(render_applied_handoff(proposal), encoding="utf-8")
        applied["handoff"] = True
    for row in proposals:
        if row.get("id") == proposal.get("id"):
            row["status"] = "applied"
            row["applied_at"] = now_iso()
    if proposals:
        write_jsonl(state / "proposals.jsonl", proposals)
    return {"ok": True, "proposal_id": proposal.get("id"), "snapshot": snapshot, "applied": applied, "validation": validation}


def resolve_proposal(state: Path, *, proposal_id: str = "", updates: Any = None) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    proposals = read_jsonl(state / "proposals.jsonl")
    proposal = normalize_update_payload(updates)
    if proposal_id:
        for row in proposals:
            if row.get("id") == proposal_id:
                return row, proposals
        raise KitError(f"Proposal not found: {proposal_id}")
    if not proposal:
        raise KitError("A proposal_id or updates JSON is required")
    return proposal, proposals


def proposal_evidence_items(item: dict[str, Any]) -> list[str]:
    values: list[Any] = []
    for key in ("evidence", "evidence_text", "source_excerpt", "quote"):
        value = item.get(key)
        if value:
            values.append(value)
    results: list[str] = []
    for value in values:
        if isinstance(value, list):
            results.extend(str(part).strip() for part in value if str(part).strip())
        else:
            text = str(value).strip()
            if text:
                results.append(text)
    return unique_strings(results)


def proposal_evidence(item: dict[str, Any]) -> str:
    evidence = proposal_evidence_items(item)
    return evidence[0] if evidence else ""


def assess_proposal_risk(proposal: dict[str, Any]) -> dict[str, Any]:
    items: list[dict[str, Any]] = []
    for section in ("facts", "characters", "debts"):
        values = proposal.get(section, [])
        for index, item in enumerate(values if isinstance(values, list) else []):
            if isinstance(item, dict):
                items.extend(match_risk_rules(section, index, proposal_item_text(item)))
    handoff = str(proposal.get("handoff") or "").strip()
    if handoff:
        items.extend(match_risk_rules("handoff", 0, handoff))
    unique: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, int]] = set()
    for item in items:
        key = (item["category"], item["level"], item["section"], int(item["index"]))
        if key in seen:
            continue
        seen.add(key)
        unique.append(item)
    level = "low"
    if unique:
        level = max((item["level"] for item in unique), key=lambda value: RISK_LEVEL_RANK.get(value, 0))
    return {"level": level, "items": unique, "requires_author_review": any(item["level"] == "high" for item in unique)}


def proposal_item_text(item: dict[str, Any]) -> str:
    values: list[str] = []
    for key in (
        "kind",
        "subject",
        "predicate",
        "object",
        "object_value",
        "name",
        "character",
        "title",
        "state",
        "current_state",
        "summary",
        "detail",
        "debt_content",
        "status",
        "notes",
    ):
        value = item.get(key)
        if value:
            values.append(str(value))
    values.extend(proposal_evidence_items(item))
    return " ".join(values)


def match_risk_rules(section: str, index: int, text: str) -> list[dict[str, Any]]:
    lowered = text.lower()
    matched: list[dict[str, Any]] = []
    for rule in RISK_RULES:
        for phrase in rule["phrases"]:
            phrase_text = str(phrase)
            if phrase_text and (phrase_text in text or phrase_text.lower() in lowered):
                matched.append(
                    {
                        "section": section,
                        "index": index,
                        "category": rule["category"],
                        "level": rule["level"],
                        "matched": phrase_text,
                        "message": rule["message"],
                    }
                )
                break
    return matched


def proposal_chapter_text(proposal: dict[str, Any], base_dir: str | Path | None = None) -> str:
    file_value = str(proposal.get("file") or "").strip()
    if not file_value:
        return ""
    path = Path(file_value).expanduser()
    if base_dir and not path.is_absolute():
        path = Path(base_dir).expanduser() / path
    if path.exists() and path.is_file():
        return path.read_text(encoding="utf-8")
    return ""


def validate_item_evidence(
    issues: list[dict[str, Any]],
    *,
    section: str,
    index: int,
    item: dict[str, Any],
    chapter_text: str,
    require_evidence: bool,
) -> None:
    evidence = proposal_evidence_items(item)
    if require_evidence and not evidence:
        issues.append(proposal_issue("error", f"{section}_missing_evidence", f"{section}s[{index}] requires evidence", item=item))
        return
    if chapter_text and evidence and not any(text in chapter_text for text in evidence):
        issues.append(
            proposal_issue(
                "error",
                "evidence_not_in_chapter",
                f"{section}s[{index}] evidence must appear in the chapter text",
                item=item,
                evidence=evidence,
            )
        )


def validate_proposal_payload(state: Path, proposal: dict[str, Any], *, require_evidence: bool = True) -> dict[str, Any]:
    issues: list[dict[str, Any]] = proposal_schema_issues(proposal, require_evidence=require_evidence)
    risk = assess_proposal_risk(proposal)
    for item in risk["items"]:
        if item["level"] in {"high", "medium"}:
            issues.append(
                proposal_issue(
                    "warning",
                    "high_risk_update" if item["level"] == "high" else "medium_risk_update",
                    item["message"],
                    risk=item,
                )
            )
    fact_rows = read_jsonl(state / "facts.jsonl")
    active_facts = [row for row in fact_rows if fact_active(row)]
    chapter_text = proposal_chapter_text(proposal, state.parent)
    for index, item in enumerate(proposal.get("facts", []) if isinstance(proposal.get("facts"), list) else []):
        if not isinstance(item, dict):
            issues.append(proposal_issue("error", "fact_invalid", f"facts[{index}] must be an object"))
            continue
        subject = str(item.get("subject") or "").strip()
        predicate = str(item.get("predicate") or "").strip()
        object_value = str(item.get("object") or item.get("object_value") or "").strip()
        if not subject or not predicate or not object_value:
            issues.append(proposal_issue("error", "fact_missing_fields", f"facts[{index}] requires subject, predicate, and object", item=item))
        validate_item_evidence(issues, section="fact", index=index, item=item, chapter_text=chapter_text, require_evidence=require_evidence)
        fact_id = str(item.get("id") or "").strip()
        for existing in active_facts:
            if fact_id and existing.get("id") == fact_id:
                continue
            if str(existing.get("subject") or "") == subject and str(existing.get("predicate") or "") == predicate:
                existing_object = str(existing.get("object") or "").strip()
                if object_value and existing_object and object_value != existing_object:
                    issues.append(
                        proposal_issue(
                            "error",
                            "fact_conflicts_existing",
                            f"facts[{index}] conflicts with existing fact {existing.get('id')}",
                            item=item,
                            existing=existing,
                        )
                    )
    for index, item in enumerate(proposal.get("characters", []) if isinstance(proposal.get("characters"), list) else []):
        if not isinstance(item, dict):
            issues.append(proposal_issue("error", "character_invalid", f"characters[{index}] must be an object"))
            continue
        if not first_nonempty(item.get("name"), item.get("character"), item.get("title")):
            issues.append(proposal_issue("error", "character_missing_name", f"characters[{index}] requires name", item=item))
        if not first_nonempty(item.get("state"), item.get("current_state"), item.get("summary")):
            issues.append(proposal_issue("warning", "character_missing_state", f"characters[{index}] has no state text", item=item))
        validate_item_evidence(issues, section="character", index=index, item=item, chapter_text=chapter_text, require_evidence=require_evidence)
    for index, item in enumerate(proposal.get("debts", []) if isinstance(proposal.get("debts"), list) else []):
        if not isinstance(item, dict):
            issues.append(proposal_issue("error", "debt_invalid", f"debts[{index}] must be an object"))
            continue
        if not first_nonempty(item.get("id"), item.get("title"), item.get("debt_content")):
            issues.append(proposal_issue("error", "debt_missing_identity", f"debts[{index}] requires id or title", item=item))
        validate_item_evidence(issues, section="debt", index=index, item=item, chapter_text=chapter_text, require_evidence=require_evidence)
    if not str(proposal.get("handoff") or "").strip():
        issues.append(proposal_issue("warning", "handoff_missing", "proposal has no handoff text"))
    return {
        "ok": not any(issue["severity"] == "error" for issue in issues),
        "status": "pass" if not any(issue["severity"] == "error" for issue in issues) else "needs_revision",
        "risk": risk,
        "issues": issues,
    }


def proposal_schema_issues(proposal: dict[str, Any], *, require_evidence: bool = True) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    if not isinstance(proposal, dict):
        return [proposal_issue("error", "schema_type", "proposal must be an object")]
    if "chapter" in proposal and not isinstance(proposal.get("chapter"), int):
        issues.append(proposal_issue("error", "schema_type", "chapter must be an integer"))
    if "file" in proposal and not isinstance(proposal.get("file"), str):
        issues.append(proposal_issue("error", "schema_type", "file must be a string"))
    for key in ("facts", "characters", "debts"):
        value = proposal.get(key, [])
        if value is None:
            continue
        if not isinstance(value, list):
            issues.append(proposal_issue("error", "schema_type", f"{key} must be an array"))
            continue
        for index, item in enumerate(value):
            if not isinstance(item, dict):
                issues.append(proposal_issue("error", "schema_type", f"{key}[{index}] must be an object"))
                continue
            if key == "facts":
                for field in ("subject", "predicate"):
                    if not str(item.get(field) or "").strip():
                        issues.append(proposal_issue("error", "schema_required", f"facts[{index}].{field} is required", item=item))
                if not first_nonempty(item.get("object"), item.get("object_value")):
                    issues.append(proposal_issue("error", "schema_required", f"facts[{index}].object is required", item=item))
            elif key == "characters":
                if not first_nonempty(item.get("name"), item.get("character"), item.get("title")):
                    issues.append(proposal_issue("error", "schema_required", f"characters[{index}].name is required", item=item))
            elif key == "debts":
                if not first_nonempty(item.get("id"), item.get("title"), item.get("debt_content")):
                    issues.append(proposal_issue("error", "schema_required", f"debts[{index}].title or id is required", item=item))
            if require_evidence and not proposal_evidence_items(item):
                issues.append(proposal_issue("error", "schema_required", f"{key}[{index}].evidence is required", item=item))
    if "handoff" in proposal and not isinstance(proposal.get("handoff"), str):
        issues.append(proposal_issue("error", "schema_type", "handoff must be a string"))
    return issues


def proposal_issue(severity: str, issue_type: str, message: str, **extra: Any) -> dict[str, Any]:
    issue = {"severity": severity, "type": issue_type, "message": message}
    issue.update(extra)
    return issue


def validate_proposal(project_dir: str | Path, *, proposal_id: str = "", updates: Any = None) -> dict[str, Any]:
    state = ensure_state(project_dir)
    proposal, _ = resolve_proposal(state, proposal_id=proposal_id, updates=updates)
    validation = validate_proposal_payload(state, proposal, require_evidence=True)
    return {"ok": True, "proposal_id": proposal.get("id"), "validation": validation}


def build_proposal_template(project_dir: str | Path, *, chapter: int, file: str = "") -> dict[str, Any]:
    ensure_state(project_dir)
    chapter_text = ""
    resolved_file = ""
    if file:
        path = Path(file).expanduser()
        if not path.is_absolute():
            path = project_root(project_dir) / path
        if not path.exists():
            raise KitError(f"Chapter file not found: {path}")
        resolved_file = str(path)
        chapter_text = path.read_text(encoding="utf-8")
    context = build_chapter_context(project_dir, chapter=chapter)
    template = {
        "chapter": chapter,
        "file": resolved_file,
        "facts": [
            {
                "kind": "",
                "subject": "",
                "predicate": "",
                "object": "",
                "chapter_range": f"{chapter}+",
                "source_ids": [],
                "evidence": "",
            }
        ],
        "characters": [
            {
                "name": "",
                "state": "",
                "evidence": "",
            }
        ],
        "debts": [
            {
                "title": "",
                "detail": "",
                "status": "open",
                "evidence": "",
            }
        ],
        "handoff": "",
        "notes": "",
    }
    return {
        "ok": True,
        "schema": {"name": PROPOSAL_SCHEMA_FILE, "path": str(proposal_schema_path())},
        "template": template,
        "context_summary": proposal_context_summary(context),
        "chapter_tail": tail_text(chapter_text) if chapter_text else "",
        "instructions": [
            "Keep only real updates; delete placeholder rows before proposing.",
            "Every fact, character update, and debt update must include evidence copied from the chapter text.",
            "Run propose-after-write, validate-proposal, and diff-proposal before apply-after-write.",
        ],
    }


def proposal_context_summary(context: dict[str, Any]) -> dict[str, Any]:
    return {
        "target_chapter": context.get("target_chapter"),
        "required_phrases": context.get("rules", {}).get("required_phrases", [])[:20],
        "forbidden_phrases": context.get("rules", {}).get("forbidden_phrases", [])[:20],
        "future_markers": context.get("rules", {}).get("future_markers", [])[:20],
        "previous_chapter_tail": ((context.get("previous_chapter") or {}).get("tail") or "")[:500],
        "facts": [
            {
                "id": row.get("id"),
                "kind": row.get("kind"),
                "subject": row.get("subject"),
                "predicate": row.get("predicate"),
                "object": row.get("object"),
            }
            for row in context.get("facts", [])[:12]
            if isinstance(row, dict)
        ],
        "characters": [
            {
                "name": row.get("name") or row.get("character") or row.get("title"),
                "state": row.get("state") or row.get("current_state") or row.get("summary"),
            }
            for row in context.get("characters", [])[:8]
            if isinstance(row, dict)
        ],
        "open_debts": [
            {
                "id": row.get("id"),
                "title": row.get("title") or row.get("debt_content"),
                "status": row.get("status") or row.get("debt_status"),
            }
            for row in context.get("open_debts", [])[:8]
            if isinstance(row, dict)
        ],
        "contracts": [
            {
                "id": row.get("id"),
                "title": row.get("title") or row.get("name"),
                "goal": row.get("goal") or row.get("objective"),
                "required_beats": split_list(row.get("required_beats"))[:10],
                "forbidden_moves": split_list(row.get("forbidden_moves"))[:10],
            }
            for row in context.get("contracts", [])[:5]
            if isinstance(row, dict)
        ],
    }


def diff_proposal(project_dir: str | Path, *, proposal_id: str = "", updates: Any = None) -> dict[str, Any]:
    state = ensure_state(project_dir)
    proposal, _ = resolve_proposal(state, proposal_id=proposal_id, updates=updates)
    return {"ok": True, "proposal_id": proposal.get("id"), "risk": assess_proposal_risk(proposal), "diff": diff_proposal_payload(state, proposal)}


def build_proposal_review(project_dir: str | Path, *, proposal_id: str = "", updates: Any = None) -> dict[str, Any]:
    project = project_root(project_dir)
    state = ensure_state(project)
    proposal, _ = resolve_proposal(state, proposal_id=proposal_id, updates=updates)
    validation = validate_proposal_payload(state, proposal, require_evidence=True)
    risk = assess_proposal_risk(proposal)
    diff = diff_proposal_payload(state, proposal)
    proposal_identifier = str(proposal.get("id") or proposal_id or "").strip()
    commands = build_proposal_review_commands(project, proposal_identifier)
    error_count = sum(1 for issue in validation.get("issues", []) if issue.get("severity") == "error")
    warning_count = sum(1 for issue in validation.get("issues", []) if issue.get("severity") == "warning")
    diff_counts = summarize_proposal_diff_counts(diff)
    review_required = bool((risk.get("requires_author_review")) or risk.get("level") == "high" or warning_count)
    return {
        "type": "proposal_review",
        "ok": True,
        "generated_at": now_iso(),
        "project_dir": str(project),
        "state_dir": str(state),
        "source": "saved" if proposal_identifier else "inline",
        "proposal_id": proposal_identifier,
        "proposal_status": proposal.get("status") or "inline",
        "chapter": proposal.get("chapter"),
        "file": proposal.get("file"),
        "ready_to_apply": bool(validation.get("ok")),
        "author_review_required": review_required,
        "summary": {
            "validation_status": validation.get("status"),
            "risk_level": risk.get("level"),
            "errors": error_count,
            "warnings": warning_count,
            **diff_counts,
        },
        "risk": risk,
        "validation": validation,
        "diff": diff,
        "proposal": proposal,
        "commands": commands,
        "next_steps": proposal_review_next_steps(proposal_identifier, validation, risk),
    }


def build_proposal_readiness(project_dir: str | Path, *, proposal_id: str = "", updates: Any = None) -> dict[str, Any]:
    project = project_root(project_dir)
    state = ensure_state(project)
    review = build_proposal_review(project, proposal_id=proposal_id, updates=updates)
    validation = review.get("validation") if isinstance(review.get("validation"), dict) else {}
    risk = review.get("risk") if isinstance(review.get("risk"), dict) else {}
    diff = review.get("diff") if isinstance(review.get("diff"), dict) else {}
    proposal = review.get("proposal") if isinstance(review.get("proposal"), dict) else {}
    proposal_identifier = str(review.get("proposal_id") or "").strip()
    proposal_status = str(review.get("proposal_status") or "inline").strip()
    issues = validation.get("issues") if isinstance(validation.get("issues"), list) else []
    errors = [item for item in issues if isinstance(item, dict) and item.get("severity") == "error"]
    warnings = [item for item in issues if isinstance(item, dict) and item.get("severity") == "warning"]
    risk_items = risk.get("items") if isinstance(risk.get("items"), list) else []
    high_risk = [item for item in risk_items if isinstance(item, dict) and item.get("level") == "high"]
    medium_risk = [item for item in risk_items if isinstance(item, dict) and item.get("level") == "medium"]
    diff_counts = summarize_proposal_diff_counts(diff)
    saved = bool(proposal_identifier)

    must_fix: list[dict[str, Any]] = []
    review_items: list[dict[str, Any]] = []
    improve: list[dict[str, Any]] = []
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    add_check("proposal_saved", saved, "must_fix", "Proposal is saved before durable apply.", proposal_identifier or "inline")
    add_check("proposal_not_rejected", proposal_status != "rejected", "must_fix", "Proposal is not rejected.", proposal_status)
    add_check("proposal_not_applied", proposal_status != "applied", "must_fix", "Proposal has not already been applied.", proposal_status)
    add_check("validation_errors_clear", not errors, "must_fix", "Proposal validation has no errors.", {"errors": len(errors)})
    add_check(
        "author_review_clear",
        not warnings and not high_risk,
        "review",
        "No warning or high-risk item needs author review.",
        {"warnings": len(warnings), "high_risk": len(high_risk), "medium_risk": len(medium_risk)},
    )
    add_check("durable_diff_nonempty", any(value > 0 for value in diff_counts.values()), "review", "Proposal changes at least one durable field.", diff_counts)

    for issue in errors:
        must_fix.append(proposal_readiness_item_from_issue(issue))
    for issue in warnings:
        review_items.append(proposal_readiness_item_from_issue(issue))
    if not saved:
        must_fix.append(
            {
                "source": "proposal_readiness",
                "type": "proposal_not_saved",
                "message": "Inline updates should be saved with propose-after-write before durable apply.",
                "suggested_fix": "Save the updates as a proposal, then run proposal-readiness with --proposal-id.",
            }
        )
    if proposal_status == "rejected":
        must_fix.append(
            {
                "source": "proposal_readiness",
                "type": "proposal_rejected",
                "message": "Rejected proposals cannot be applied.",
                "suggested_fix": "Create a new proposal if the author wants a different durable update.",
            }
        )
    if proposal_status == "applied":
        improve.append(
            {
                "source": "proposal_readiness",
                "type": "proposal_already_applied",
                "message": "This proposal has already been applied.",
                "suggested_fix": "Do not apply it again; build the next chapter context instead.",
            }
        )
    if not any(value > 0 for value in diff_counts.values()):
        review_items.append(
            {
                "source": "diff_proposal",
                "type": "empty_durable_diff",
                "message": "The proposal does not change facts, character state, debts, or handoff.",
                "suggested_fix": "Reject no-op proposals or add the missing durable update with chapter evidence.",
            }
        )

    if proposal_status == "rejected":
        status = "rejected"
    elif proposal_status == "applied":
        status = "already_applied"
    elif must_fix:
        status = "needs_revision"
    elif review_items or warnings or high_risk:
        status = "needs_author_review"
    else:
        status = "ready"

    score = proposal_readiness_score(errors, warnings, high_risk, medium_risk, saved=saved, has_diff=any(value > 0 for value in diff_counts.values()))
    actions = proposal_readiness_actions(project, proposal_identifier, proposal, status, checks)
    return {
        "type": "proposal_readiness",
        "ok": True,
        "generated_at": now_iso(),
        "project_dir": str(project),
        "state_dir": str(state),
        "proposal_id": proposal_identifier,
        "proposal_status": proposal_status,
        "chapter": proposal.get("chapter"),
        "file": proposal.get("file"),
        "status": status,
        "ready_to_apply": status == "ready",
        "apply_allowed_after_author_review": status in {"ready", "needs_author_review"},
        "author_review_required": status == "needs_author_review",
        "score": score,
        "summary": {
            "must_fix": len(unique_readiness_items(must_fix)),
            "review": len(unique_readiness_items(review_items)),
            "improve": len(unique_readiness_items(improve)),
            "errors": len(errors),
            "warnings": len(warnings),
            "risk_level": risk.get("level"),
            "high_risk": len(high_risk),
            "medium_risk": len(medium_risk),
            **diff_counts,
        },
        "must_fix": unique_readiness_items(must_fix),
        "review": unique_readiness_items(review_items),
        "improve": unique_readiness_items(improve),
        "checks": checks,
        "validation": validation,
        "risk": risk,
        "diff": diff,
        "action_plan": build_continuity_action_plan(actions),
        "recommended_commands": proposal_readiness_commands(project, proposal_identifier, proposal, status),
    }


def proposal_readiness_item_from_issue(issue: dict[str, Any]) -> dict[str, Any]:
    item = {
        "source": "validate_proposal",
        "severity": issue.get("severity") or "warning",
        "type": issue.get("type") or "issue",
        "message": issue.get("message") or "",
        "suggested_fix": "",
    }
    if issue.get("evidence"):
        item["evidence"] = issue.get("evidence")
    if issue.get("risk"):
        item["risk"] = issue.get("risk")
    if issue.get("existing"):
        item["existing"] = issue.get("existing")
    return item


def proposal_readiness_score(
    errors: list[dict[str, Any]],
    warnings: list[dict[str, Any]],
    high_risk: list[dict[str, Any]],
    medium_risk: list[dict[str, Any]],
    *,
    saved: bool,
    has_diff: bool,
) -> int:
    score = 100
    score -= len(errors) * 35
    score -= len(warnings) * 8
    score -= len(high_risk) * 15
    score -= len(medium_risk) * 6
    if not saved:
        score -= 20
    if not has_diff:
        score -= 10
    return max(0, min(100, score))


def proposal_readiness_actions(
    project: Path,
    proposal_id: str,
    proposal: dict[str, Any],
    status: str,
    checks: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    actions: list[dict[str, Any]] = []
    for check in checks:
        if not isinstance(check, dict) or check.get("ok"):
            continue
        severity = str(check.get("severity") or "review")
        priority = "must_fix" if severity == "must_fix" else "review"
        actions.append(
            continuity_audit_action(
                f"fix_{check.get('id')}",
                priority,
                str(check.get("message") or check.get("id")),
                "Proposal readiness failed this check.",
                command=proposal_readiness_command_for_check(project, proposal_id, proposal, str(check.get("id") or ""), status),
                source_check=str(check.get("id") or ""),
                details=check.get("detail"),
            )
        )
    if status == "ready" and proposal_id:
        actions.append(
            continuity_audit_action(
                "apply_after_author_confirmation",
                "review",
                "Apply only after author confirmation",
                "The proposal is structurally ready; durable state still needs explicit author approval.",
                command=shell_command(
                    [
                        "python",
                        kit_root() / "cli.py",
                        "apply-after-write",
                        project,
                        "--proposal-id",
                        proposal_id,
                        "--author-confirmation",
                        "Author approved applying this proposal after proposal-readiness.",
                    ]
                ),
            )
        )
    return actions


def proposal_readiness_command_for_check(project: Path, proposal_id: str, proposal: dict[str, Any], check_id: str, status: str) -> str:
    if check_id == "proposal_saved":
        chapter = proposal.get("chapter") or "<chapter>"
        file_value = proposal.get("file") or "<chapter-file>"
        return shell_command(["python", kit_root() / "cli.py", "propose-after-write", project, "--chapter", chapter, "--file", file_value, "--updates", "<updates.json>"])
    if proposal_id:
        if check_id in {"validation_errors_clear", "author_review_clear", "durable_diff_nonempty"}:
            return shell_command(["python", kit_root() / "cli.py", "proposal-review", project, "--proposal-id", proposal_id, "--format", "markdown"])
        if check_id == "proposal_not_rejected":
            return shell_command(["python", kit_root() / "cli.py", "propose-after-write", project, "--chapter", proposal.get("chapter") or "<chapter>", "--file", proposal.get("file") or "<chapter-file>", "--updates", "<updates.json>"])
        if check_id == "proposal_not_applied":
            return shell_command(["python", kit_root() / "cli.py", "build-context", project, "--chapter", int(proposal.get("chapter") or 1) + 1, "--format", "markdown"])
        return shell_command(["python", kit_root() / "cli.py", "proposal-readiness", project, "--proposal-id", proposal_id, "--format", "markdown"])
    return ""


def proposal_readiness_commands(project: Path, proposal_id: str, proposal: dict[str, Any], status: str) -> dict[str, str]:
    commands: dict[str, str] = {}
    if proposal_id:
        commands["validate"] = shell_command(["python", kit_root() / "cli.py", "validate-proposal", project, "--proposal-id", proposal_id])
        commands["diff"] = shell_command(["python", kit_root() / "cli.py", "diff-proposal", project, "--proposal-id", proposal_id])
        commands["review"] = shell_command(["python", kit_root() / "cli.py", "proposal-review", project, "--proposal-id", proposal_id, "--format", "markdown"])
        commands["readiness"] = shell_command(["python", kit_root() / "cli.py", "proposal-readiness", project, "--proposal-id", proposal_id, "--format", "markdown"])
        if status in {"ready", "needs_author_review"}:
            commands["apply_after_author_confirmation"] = shell_command(
                [
                    "python",
                    kit_root() / "cli.py",
                    "apply-after-write",
                    project,
                    "--proposal-id",
                    proposal_id,
                    "--author-confirmation",
                    "Author approved applying this proposal after proposal-readiness.",
                ]
            )
        if status not in {"already_applied", "rejected"}:
            commands["reject"] = shell_command(["python", kit_root() / "cli.py", "reject-proposal", project, "--proposal-id", proposal_id, "--reason", "Author rejected this proposal."])
        return commands
    chapter = proposal.get("chapter") or "<chapter>"
    file_value = proposal.get("file") or "<chapter-file>"
    commands["save_first"] = shell_command(["python", kit_root() / "cli.py", "propose-after-write", project, "--chapter", chapter, "--file", file_value, "--updates", "<updates.json>"])
    return commands


def summarize_proposal_diff_counts(diff: dict[str, Any]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for section in ("facts", "characters", "debts"):
        value = diff.get(section) if isinstance(diff.get(section), dict) else {}
        counts[f"{section}_create"] = len(value.get("create") or [])
        counts[f"{section}_update"] = len(value.get("update") or [])
        counts[f"{section}_skipped"] = int(value.get("skipped") or 0)
    handoff = diff.get("handoff") if isinstance(diff.get("handoff"), dict) else {}
    counts["handoff_update"] = 1 if handoff.get("will_update") else 0
    return counts


def build_proposal_review_commands(project: Path, proposal_id: str) -> dict[str, str]:
    if not proposal_id:
        return {
            "save_first": "Save the inline updates with propose-after-write before applying durable state changes.",
            "review_panel": f"Open {kit_root() / 'assets' / 'review-panel.html'} for manual JSON inspection.",
        }
    return {
        "validate": shell_command(["python", kit_root() / "cli.py", "validate-proposal", project, "--proposal-id", proposal_id]),
        "diff": shell_command(["python", kit_root() / "cli.py", "diff-proposal", project, "--proposal-id", proposal_id]),
        "apply_after_author_approval": shell_command(
            [
                "python",
                kit_root() / "cli.py",
                "apply-after-write",
                project,
                "--proposal-id",
                proposal_id,
                "--author-confirmation",
                "Author approved applying this proposal after reviewing proposal-review.",
            ]
        ),
        "reject": shell_command(["python", kit_root() / "cli.py", "reject-proposal", project, "--proposal-id", proposal_id, "--reason", "Author rejected this proposal."]),
        "review_panel": f"Open {kit_root() / 'assets' / 'review-panel.html'} for manual JSON inspection.",
    }


def proposal_review_next_steps(proposal_id: str, validation: dict[str, Any], risk: dict[str, Any]) -> list[str]:
    if not proposal_id:
        return ["Save this inline proposal with propose-after-write before any durable apply."]
    if not validation.get("ok"):
        return ["Revise the proposal until validate-proposal has no error issues.", "Reject the proposal if the proposed canon change is wrong."]
    steps = ["Review validation warnings, diff, and chapter evidence before applying."]
    if risk.get("requires_author_review") or risk.get("level") == "high":
        steps.append("Ask the author to explicitly approve high-risk continuity changes before apply-after-write.")
    steps.append("Run apply-after-write with author confirmation only after the author accepts the proposal.")
    return steps


def proposal_review_output_path(project_dir: str | Path, output_dir: str | None, proposal_id: str) -> Path:
    project = project_root(project_dir)
    raw = "" if output_dir is None else str(output_dir).strip()
    if raw:
        path = Path(raw).expanduser()
        if not path.is_absolute():
            path = project / path
        return path.resolve()
    suffix = snapshot_slug(proposal_id or f"proposal-{int(time.time())}")
    return (project / f"long-novel-agent-proposal-review-{suffix}").resolve()


def write_proposal_review_bundle(review: dict[str, Any], output_dir: str | None = None, *, force: bool = False) -> dict[str, Any]:
    out_dir = proposal_review_output_path(review.get("project_dir") or ".", output_dir, str(review.get("proposal_id") or "inline"))
    payloads: dict[str, tuple[str, Any]] = {
        "README.md": ("text", render_proposal_review_markdown(review)),
        "proposal-review.html": ("text", render_proposal_review_html(review)),
        "proposal-review.json": ("json", review),
        "proposal.json": ("json", review.get("proposal") or {}),
        "validation.json": ("json", review.get("validation") or {}),
        "diff.json": ("json", review.get("diff") or {}),
        "commands.txt": ("text", render_proposal_review_commands_text(review)),
    }
    for relative_name in payloads:
        path = out_dir / relative_name
        if path.exists() and not force:
            raise KitError(f"Proposal review file already exists: {path}")
    written_files: list[dict[str, Any]] = []
    for relative_name, (kind, content) in payloads.items():
        path = out_dir / relative_name
        written = write_json_pack_file(path, content, force=force) if kind == "json" else write_text_pack_file(path, str(content), force=force)
        written_files.append({"name": relative_name, **written})
    updated = dict(review)
    updated["output_dir"] = str(out_dir)
    updated["written_files"] = written_files
    return updated


def diff_proposal_payload(state: Path, proposal: dict[str, Any]) -> dict[str, Any]:
    facts = read_jsonl(state / "facts.jsonl")
    characters = read_json(state / "characters.json", {"characters": []}).get("characters", [])
    debts = read_json(state / "debts.json", {"debts": []}).get("debts", [])
    return {
        # Fact application only updates by explicit id; keep diff semantics identical.
        "facts": diff_rows(proposal.get("facts", []), facts, "id", []),
        "characters": diff_rows(proposal.get("characters", []), characters if isinstance(characters, list) else [], "id", ["name", "character"]),
        "debts": diff_rows(proposal.get("debts", []), debts if isinstance(debts, list) else [], "id", ["title", "debt_content"]),
        "handoff": {"will_update": bool(str(proposal.get("handoff") or "").strip()), "preview": str(proposal.get("handoff") or "")[:240]},
    }


def diff_rows(updates: Any, existing_rows: list[Any], id_key: str, identity_keys: list[str]) -> dict[str, Any]:
    created: list[dict[str, Any]] = []
    updated: list[dict[str, Any]] = []
    skipped = 0
    for item in updates if isinstance(updates, list) else []:
        if not isinstance(item, dict):
            skipped += 1
            continue
        match = find_existing_row(item, existing_rows, id_key, identity_keys)
        target = updated if match else created
        target.append({"incoming": item, "existing": match})
    return {"create": created, "update": updated, "skipped": skipped}


def find_existing_row(item: dict[str, Any], existing_rows: list[Any], id_key: str, identity_keys: list[str]) -> dict[str, Any] | None:
    item_id = str(item.get(id_key) or "").strip()
    for row in existing_rows:
        if not isinstance(row, dict):
            continue
        if item_id and row.get(id_key) == item_id:
            return row
        for key in identity_keys:
            value = str(item.get(key) or "").strip()
            if value and str(row.get(key) or "").strip() == value:
                return row
    return None


def reject_proposal(project_dir: str | Path, *, proposal_id: str, reason: str = "") -> dict[str, Any]:
    state = ensure_state(project_dir)
    proposal, proposals = resolve_proposal(state, proposal_id=proposal_id, updates=None)
    for row in proposals:
        if row.get("id") == proposal.get("id"):
            row["status"] = "rejected"
            row["rejected_reason"] = reason
            row["rejected_at"] = now_iso()
            write_jsonl(state / "proposals.jsonl", proposals)
            return {"ok": True, "proposal": row}
    raise KitError(f"Proposal not found: {proposal_id}")


def apply_fact_updates(state: Path, updates: Any) -> int:
    rows = read_jsonl(state / "facts.jsonl")
    count = 0
    for item in updates if isinstance(updates, list) else []:
        if not isinstance(item, dict):
            continue
        fact_id = str(item.get("id") or "").strip()
        existing = next((row for row in rows if fact_id and row.get("id") == fact_id), None)
        if existing:
            existing.update(
                {
                    "kind": item.get("kind", existing.get("kind")),
                    "subject": item.get("subject", existing.get("subject")),
                    "predicate": item.get("predicate", existing.get("predicate")),
                    "object": item.get("object", existing.get("object")),
                    "chapter_ranges": parse_ranges(item.get("chapter_range") or item.get("chapter_ranges") or existing.get("chapter_ranges")),
                    "source_ids": split_list(item.get("source_ids") or existing.get("source_ids")),
                    "confidence": item.get("confidence", existing.get("confidence")),
                    "status": item.get("status", existing.get("status", "active")),
                    "required_phrases": split_list(item.get("required_phrases") or existing.get("required_phrases")),
                    "forbidden_phrases": split_list(item.get("forbidden_phrases") or existing.get("forbidden_phrases")),
                    "future_markers": split_list(item.get("future_markers") or existing.get("future_markers")),
                    "evidence": item.get("evidence", existing.get("evidence", "")),
                    "updated_at": now_iso(),
                }
            )
        else:
            rows.append(
                make_fact_row(
                    kind=str(item.get("kind") or "fact"),
                    subject=str(item.get("subject") or ""),
                    predicate=str(item.get("predicate") or "is"),
                    object_value=str(item.get("object") or item.get("object_value") or ""),
                    chapter_range=item.get("chapter_range") or item.get("chapter_ranges"),
                    source_ids=item.get("source_ids"),
                    source_path=str(item.get("source_path") or ""),
                    confidence=str(item.get("confidence") or "agent-confirmed"),
                    status=str(item.get("status") or "active"),
                    reveal_after_chapter=coerce_optional_int(item.get("reveal_after_chapter")),
                    required_phrases=item.get("required_phrases"),
                    forbidden_phrases=item.get("forbidden_phrases"),
                    future_markers=item.get("future_markers"),
                    fact_id=fact_id,
                )
            )
            rows[-1]["evidence"] = proposal_evidence(item)
        count += 1
    write_jsonl(state / "facts.jsonl", rows)
    return count


def apply_character_updates(state: Path, updates: Any) -> int:
    payload = read_json(state / "characters.json", {"characters": []})
    rows = payload.get("characters", []) if isinstance(payload, dict) else []
    if not isinstance(rows, list):
        rows = []
    count = 0
    for item in updates if isinstance(updates, list) else []:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or item.get("character") or item.get("title") or "").strip()
        if not name:
            continue
        existing = next((row for row in rows if isinstance(row, dict) and str(row.get("name") or row.get("character") or "") == name), None)
        if existing:
            existing.update(item)
            existing["name"] = name
            existing["updated_at"] = now_iso()
        else:
            row = dict(item)
            row["id"] = str(row.get("id") or make_id("character"))
            row["name"] = name
            row["updated_at"] = now_iso()
            rows.append(row)
        count += 1
    payload["characters"] = rows
    write_json(state / "characters.json", payload)
    return count


def apply_debt_updates(state: Path, updates: Any) -> int:
    payload = read_json(state / "debts.json", {"debts": []})
    rows = payload.get("debts", []) if isinstance(payload, dict) else []
    if not isinstance(rows, list):
        rows = []
    count = 0
    for item in updates if isinstance(updates, list) else []:
        if not isinstance(item, dict):
            continue
        title = str(item.get("title") or item.get("debt_content") or "").strip()
        debt_id = str(item.get("id") or "").strip()
        if not title and not debt_id:
            continue
        existing = next(
            (
                row
                for row in rows
                if isinstance(row, dict)
                and ((debt_id and row.get("id") == debt_id) or (title and str(row.get("title") or row.get("debt_content") or "") == title))
            ),
            None,
        )
        if existing:
            existing.update(item)
            existing["updated_at"] = now_iso()
        else:
            row = dict(item)
            row["id"] = debt_id or make_id("debt")
            row["title"] = title or row["id"]
            row["updated_at"] = now_iso()
            rows.append(row)
        count += 1
    payload["debts"] = rows
    write_json(state / "debts.json", payload)
    return count


def render_applied_handoff(proposal: dict[str, Any]) -> str:
    lines = [
        "# Handoff",
        "",
        f"Updated: {now_iso()}",
        f"Source chapter: {proposal.get('chapter')}",
        "",
        "## Next Step",
        str(proposal.get("handoff") or ""),
        "",
        "## Previous Tail",
        str(proposal.get("chapter_tail") or ""),
        "",
    ]
    return "\n".join(lines)


def list_open_threads(project_dir: str | Path, *, chapter: int | None = None) -> dict[str, Any]:
    data = load_state(project_dir)
    target = chapter or int(data["manifest"].get("current_chapter") or 1)
    debts = visible_debts(data["debts"], target)
    contracts = [row for row in data["contracts"] if entry_visible(row, target) and str(row.get("status") or "open").lower() not in {"done", "closed"}]
    return {
        "ok": True,
        "target_chapter": target,
        "open_debts": debts,
        "open_contracts": contracts,
        "resolved_conflicts": [row for row in data["conflicts"] if entry_visible(row, target)],
        "handoff": data["handoff"].strip(),
    }


def next_target_chapter(data: dict[str, Any], chapter: int | None = None) -> int:
    if chapter:
        return chapter
    latest = latest_chapter_record(data.get("chapters", []))
    latest_chapter = int((latest or {}).get("chapter") or data.get("manifest", {}).get("current_chapter") or 0)
    return max(1, latest_chapter + 1)


def build_agent_template(*, platform: str = "generic", mode: str = "writer") -> dict[str, Any]:
    selected_platform = (platform or "generic").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported agent template platform: {platform}")
    selected_mode = (mode or "writer").strip().lower()
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported agent template mode: {mode}")
    write_enabled = selected_mode == "writer"
    workflow = [
        "Use the host desktop agent's native file parsing, long-context reading, web research, PDF/OCR, and search abilities.",
        "Treat .novel-agent/ as the durable continuity state. Do not rely on chat history for long novel memory.",
        "For first-time local setup, use build_desktop_setup_guide, verify_desktop_setup, and build_desktop_client_checklist before quickstart.",
        "When opening a project, call get_project_status or project-status to inspect readiness and next actions.",
        "Before durable state changes, call build_author_review_queue or author-review-queue to see pending author decisions across proposals, conflicts, writer mode, and accepted chapter ranges.",
        "When opening a project or switching target chapters, call prepare_chapter_session for a startup packet.",
        "Before drafting or revising a chapter, call build_chapter_context for the target chapter. If the host context window is small, call build_chapter_context_brief first and keep it visible while reading the fuller packet.",
        "Before presenting a draft to the author, call build_chapter_delivery_packet. If that tool is unavailable, call build_chapter_readiness. After revising a draft, call build_chapter_revision_comparison when the previous draft is available. Before a multi-chapter handoff or review, call build_chapter_range_delivery_packet or build_chapter_range_readiness. Use check_chapter and diff_chapter_contract when the host client cannot call the combined reports.",
        "After author acceptance for one chapter, call build_chapter_acceptance_plan before durable writes. For several accepted chapters, call build_chapter_range_acceptance_plan. Then call record_chapter, build_proposal_template, propose_after_write_updates, build_proposal_readiness, and apply_after_write_updates only when readiness allows it. Use validate_proposal and diff_proposal as lower-level checks when needed.",
        "For durable narrative writes, pass --author-confirmation in CLI or author_confirmation in MCP with a concise author approval note.",
        "Before handing the project to another agent, call verify_handoff_readiness or handoff-readiness.",
    ]
    if not write_enabled:
        workflow = [
            "Use read-only MCP mode for inspection, planning, review, and continuity checks.",
            "Do not call write tools. Ask the author to rerun with writer mode before changing .novel-agent/.",
            "Use build_desktop_setup_guide, verify_desktop_setup, build_desktop_client_checklist, get_project_status, build_author_review_queue, verify_handoff_readiness, prepare_chapter_session, build_chapter_context, build_chapter_context_brief, build_chapter_delivery_packet, build_chapter_readiness, build_chapter_revision_comparison, build_chapter_acceptance_plan, build_chapter_range_delivery_packet, build_chapter_range_acceptance_plan, build_chapter_range_readiness, build_proposal_readiness, check_chapter, diff_chapter_contract, list_open_threads, build_handoff_report, get_agent_template, and doctor.",
        ]
    template = {
        "ok": True,
        "type": "agent_template",
        "platform": selected_platform,
        "mode": selected_mode,
        "capabilities_to_declare": ["mcp", "cli", "file-read", "file-write"] if write_enabled else ["mcp", "cli", "file-read"],
        "mcp_start_mode": "normal" if write_enabled else "read-only",
        "workflow": workflow,
        "must_call_before_write": ["prepare_chapter_session", "build_chapter_context"],
        "small_context_first_read": ["build_chapter_context_brief"],
        "must_call_before_ready": ["build_chapter_delivery_packet", "build_chapter_readiness"],
        "must_call_after_revision": ["build_chapter_revision_comparison"],
        "use_before_multi_chapter_handoff": ["build_chapter_range_delivery_packet", "build_chapter_range_readiness"],
        "must_call_after_acceptance": ["build_author_review_queue", "build_chapter_acceptance_plan", "build_chapter_range_acceptance_plan", "record_chapter", "build_proposal_template", "propose_after_write_updates", "build_proposal_readiness", "apply_after_write_updates"] if write_enabled else [],
        "author_confirmation": "Required for writer tools that change durable narrative state. Use --author-confirmation in CLI or author_confirmation in MCP after author approval." if write_enabled else "Not applicable in read-only mode.",
        "handoff_tools": ["verify_handoff_readiness", "build_handoff_report", "export_state_package"],
        "installation_hint": {
            "codex": "Use install.py --mcp-platform codex --print-mcp-config.",
            "claude-desktop": "Use install.py --mcp-platform claude-desktop --print-mcp-config.",
            "cursor": "Use install.py --mcp-platform cursor --print-mcp-config.",
            "generic": "Use install.py --mcp-platform generic-json --print-mcp-config.",
        }[selected_platform],
    }
    template["markdown"] = render_agent_template_markdown(template)
    return template


def render_agent_template_markdown(template: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Host Instructions",
        "",
        f"Platform: {template.get('platform')}",
        f"Mode: {template.get('mode')}",
        f"MCP start mode: {template.get('mcp_start_mode')}",
        "",
        "## Installation Hint",
        str((template.get("installation_hint") or "")),
        "",
        "## Capabilities To Declare",
    ]
    lines.extend(f"- {item}" for item in split_list(template.get("capabilities_to_declare")))
    lines.append("")
    lines.append("## Workflow")
    workflow = template.get("workflow") if isinstance(template.get("workflow"), list) else split_list(template.get("workflow"))
    lines.extend(f"- {item}" for item in workflow)
    lines.append("")
    lines.append("## Required Tool Gates")
    lines.append("- Before write: " + ", ".join(split_list(template.get("must_call_before_write")) or ["None"]))
    lines.append("- Before ready: " + ", ".join(split_list(template.get("must_call_before_ready")) or ["None"]))
    lines.append("- After revision: " + ", ".join(split_list(template.get("must_call_after_revision")) or ["None"]))
    lines.append("- After acceptance: " + ", ".join(split_list(template.get("must_call_after_acceptance")) or ["None"]))
    lines.append("- Handoff: " + ", ".join(split_list(template.get("handoff_tools")) or ["None"]))
    lines.append("- Author confirmation: " + str(template.get("author_confirmation") or "None"))
    return "\n".join(lines) + "\n"


def prepare_chapter_session(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    platform: str = "generic",
    mode: str = "writer",
    include_context: bool = True,
) -> dict[str, Any]:
    data = load_state(project_dir)
    target = next_target_chapter(data, chapter)
    context = build_chapter_context(project_dir, chapter=target)
    project_state_fingerprint = build_project_state_fingerprint(project_dir)
    project_identity = project_state_fingerprint.get("project_identity") if isinstance(project_state_fingerprint.get("project_identity"), dict) else {}
    context_fingerprint = context.get("context_fingerprint") if isinstance(context.get("context_fingerprint"), dict) else {}
    handoff = build_handoff_report(project_dir, chapter=target, include_context=False)
    threads = list_open_threads(project_dir, chapter=target)
    health = doctor(project_dir)
    template = build_agent_template(platform=platform, mode=mode)
    selected_mode = str(template["mode"])
    author_queue = build_author_review_queue(
        project_dir,
        chapter=target,
        platform=str(template["platform"]),
        mode=selected_mode,
        include_writer_mode=selected_mode == "writer",
        limit=10,
    )
    failed_checks = [item for item in health.get("checks", []) if isinstance(item, dict) and not item.get("ok")]
    coverage = {}
    for item in health.get("checks", []):
        if isinstance(item, dict) and item.get("name") == "continuity_coverage":
            detail = item.get("detail")
            if isinstance(detail, dict):
                coverage = detail
            break
    warnings: list[str] = []
    for check in failed_checks:
        warnings.append(f"health check failed: {check.get('name')}")
    if handoff.get("pending_proposals"):
        warnings.append(f"{len(handoff['pending_proposals'])} pending proposal(s) require review")
    if handoff.get("high_risk_proposals"):
        warnings.append(f"{len(handoff['high_risk_proposals'])} high-risk proposal(s) require author review")
    author_queue_summary = author_queue.get("summary") if isinstance(author_queue.get("summary"), dict) else {}
    if author_queue.get("status") == "blocked":
        warnings.append(f"author review queue has {author_queue_summary.get('blockers', 0)} blocker(s)")
    elif author_queue.get("status") == "needs_author_review":
        warnings.append(f"author review queue has {author_queue_summary.get('review', 0)} author-review item(s)")
    elif author_queue.get("status") == "ready_with_warnings":
        warnings.append(f"author review queue has {author_queue_summary.get('warnings', 0)} warning(s)")
    if not context.get("previous_chapter") and target > 1:
        warnings.append("target chapter is greater than 1 but no previous accepted chapter is recorded")
    if not context.get("agent_capabilities"):
        warnings.append("no host agent capability declaration is recorded")
    context_budget = context.get("context_budget") if isinstance(context.get("context_budget"), dict) else {}
    budget_status = str(context_budget.get("status") or "ok")
    if budget_status in {"warning", "critical"}:
        total = context_budget.get("total") if isinstance(context_budget.get("total"), dict) else {}
        warnings.append(f"chapter context budget is {budget_status}: {total.get('chars', 0)} chars")
    before_draft = [
        "Use the included chapter_context as the active context for this chapter.",
        "Review handoff_report.recent_agent_activity before drafting or revising.",
        "If project files or .novel-agent state changed after this packet, call build_chapter_context again.",
    ]
    before_ready = ["build_chapter_delivery_packet", "build_chapter_readiness", "build_chapter_range_delivery_packet", "build_chapter_range_readiness", "check_chapter", "diff_chapter_contract"]
    after_revision = ["build_chapter_revision_comparison"]
    after_acceptance = template.get("must_call_after_acceptance") if selected_mode == "writer" else []
    packet: dict[str, Any] = {
        "ok": not failed_checks,
        "type": "chapter_session_packet",
        "generated_at": now_iso(),
        "project_dir": str(project_root(project_dir)),
        "state_dir": str(state_root(project_dir)),
        "project_identity": project_identity,
        "project_state_fingerprint": project_state_fingerprint,
        "chapter_context_fingerprint": context_fingerprint,
        "target_chapter": target,
        "platform": template["platform"],
        "mode": template["mode"],
        "status": "needs_attention" if warnings else "ready",
        "warnings": unique_strings(warnings),
        "tool_gates": {
            "before_draft": before_draft,
            "before_ready": before_ready,
            "after_revision": after_revision,
            "after_author_acceptance": after_acceptance,
            "handoff": template.get("handoff_tools", []),
        },
        "health": {
            "ok": health.get("ok"),
            "failed_checks": failed_checks,
            "continuity_coverage": coverage,
        },
        "author_review_queue": author_queue,
        "handoff_report": handoff,
        "recent_agent_activity": handoff.get("recent_agent_activity", []),
        "open_threads": threads,
        "agent_template": {
            "workflow": template.get("workflow", []),
            "capabilities_to_declare": template.get("capabilities_to_declare", []),
            "mcp_start_mode": template.get("mcp_start_mode"),
        },
        "recommended_commands": [
            f"python cli.py prepare-session {project_root(project_dir)} --chapter {target} --platform {template['platform']} --mode {template['mode']} --format markdown",
            author_review_queue_command(
                project_root(project_dir),
                target=target,
                platform=str(template["platform"]),
                mode=selected_mode,
                include_writer_mode=selected_mode == "writer",
            ),
            f"python cli.py build-context {project_root(project_dir)} --chapter {target} --format markdown",
            f"python cli.py check-chapter {project_root(project_dir)} --chapter {target} --file chapters/{target:03d}.md",
            f"python cli.py diff-contract {project_root(project_dir)} --chapter {target} --file chapters/{target:03d}.md",
        ],
    }
    if selected_mode == "writer":
        write_guard_args: list[object] = []
        if project_identity.get("project_id"):
            write_guard_args.extend(["--expected-project-id", project_identity.get("project_id")])
        if project_state_fingerprint.get("sha256"):
            write_guard_args.extend(["--expected-state-sha256", project_state_fingerprint.get("sha256")])
        context_guard_args = list(write_guard_args)
        if context_fingerprint.get("sha256"):
            context_guard_args.extend(["--expected-context-hash", context_fingerprint.get("sha256")])
        packet["recommended_commands"].extend(
            [
                shell_command(["python", "cli.py", "record-chapter", project_root(project_dir), "--chapter", target, "--file", f"chapters/{target:03d}.md", "--author-confirmation", CHAPTER_ACCEPTANCE_AUTHOR_CONFIRMATION, *context_guard_args]),
                f"python cli.py proposal-template {project_root(project_dir)} --chapter {target} --file chapters/{target:03d}.md",
                shell_command(["python", "cli.py", "propose-after-write", project_root(project_dir), "--chapter", target, "--file", f"chapters/{target:03d}.md", "--updates", "updates.json", "--author-confirmation", CHAPTER_ACCEPTANCE_AUTHOR_CONFIRMATION, *context_guard_args]),
            ]
        )
    if include_context:
        packet["chapter_context"] = context
    else:
        packet["chapter_context_summary"] = {
            "previous_tail": (context.get("previous_chapter") or {}).get("tail") or "",
            "required_phrases": context["rules"]["required_phrases"],
            "forbidden_phrases": context["rules"]["forbidden_phrases"],
            "future_markers": context["rules"]["future_markers"],
            "characters": len(context["characters"]),
            "facts": len(context["facts"]),
            "sources": len(context["sources"]),
            "research": len(context["research"]),
            "open_debts": len(context["open_debts"]),
            "contracts": len(context["contracts"]),
            "context_budget": context.get("context_budget", {}),
            "context_brief": context.get("context_brief", {}),
        }
    return packet


def default_agent_capabilities(mode: str) -> list[str]:
    selected_mode = (mode or "writer").strip().lower()
    if selected_mode == "read-only":
        return ["mcp", "cli", "file-read"]
    return ["mcp", "cli", "file-read", "file-write"]


def shell_single_quote(value: object) -> str:
    return "'" + str(value).replace("'", "'\"'\"'") + "'"


def shell_command(parts: list[object]) -> str:
    kit = kit_root()

    def quote_part(part: object) -> str:
        if isinstance(part, Path):
            try:
                if part.resolve().is_relative_to(kit):
                    return shell_single_quote(part)
            except OSError:
                pass
        return shlex.quote(str(part))

    return " ".join(quote_part(part) for part in parts)


def kit_root() -> Path:
    return Path(__file__).resolve().parent


def install_platform_for_agent(platform: str) -> str:
    selected = (platform or "generic").strip().lower()
    if selected == "generic":
        return "generic-json"
    return selected


def agent_platform_display_name(platform: str) -> str:
    selected = (platform or "generic").strip().lower()
    if selected == "generic":
        return "Generic JSON MCP Client"
    return DESKTOP_PLATFORM_GUIDE_NAMES.get(install_platform_for_agent(selected), selected)


def desktop_agent_start_filename(platform: str) -> str:
    selected = (platform or "generic").strip().lower()
    if selected not in AGENT_TEMPLATE_PLATFORMS:
        selected = "generic"
    return f"agent-start-{selected}.md"


def desktop_agent_start_platform_notes(platform: str) -> list[str]:
    selected = (platform or "generic").strip().lower()
    if selected == "codex":
        return [
            "Use MCP tools when the Codex desktop session exposes them; use the CLI commands in `commands.txt` only when MCP is unavailable.",
            "Keep the project directory exactly as shown in this file when calling tools or commands.",
        ]
    if selected == "cursor":
        return [
            "Use the Cursor MCP tool panel or Cursor terminal with the generated commands; keep the same workspace directory for file reads and CLI calls.",
            "Do not edit `.novel-agent/` JSON by hand; use the kit tools so audit rows and locks remain valid.",
        ]
    if selected == "claude-desktop":
        return [
            "Claude Desktop needs its real local MCP config path supplied by the user before merge or doctor checks.",
            "When MCP tools are not visible in Claude Desktop, use the CLI commands in `commands.txt` and record that limitation in the desktop evidence.",
        ]
    return [
        "Map the listed MCP tool names to the client UI; if the client cannot expose stdio MCP, use the CLI commands in `commands.txt`.",
        "This local pack is not for remote connector-only platforms unless a separate local wrapper is provided.",
    ]


def default_desktop_config_path(platform: str) -> Path | None:
    selected = (platform or "generic").strip().lower()
    if selected == "codex":
        return Path.home() / ".codex" / "config.toml"
    if selected == "cursor":
        return Path.home() / ".cursor" / "mcp.json"
    return None


def desktop_skill_target_root(install_target: str = "") -> Path:
    raw = str(install_target or "").strip()
    if raw:
        return Path(raw).expanduser().resolve()
    return Path.home() / ".codex" / "skills"


def desktop_installed_skill_path(install_target: str = "") -> Path:
    return desktop_skill_target_root(install_target) / "long-novel-agent"


def normalize_mcp_tool_profile(tool_profile: str = DEFAULT_MCP_TOOL_PROFILE) -> str:
    selected = (tool_profile or DEFAULT_MCP_TOOL_PROFILE).strip().lower()
    if selected not in MCP_TOOL_PROFILES:
        raise KitError(f"Unsupported MCP tool profile: {tool_profile}")
    return selected


def normalize_agent_mode(mode: str = "read-only") -> str:
    selected = (mode or "read-only").strip().lower()
    if selected not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported agent mode: {mode}")
    return selected


def describe_mcp_tool_profile(tool_profile: str = DEFAULT_MCP_TOOL_PROFILE) -> str:
    selected = normalize_mcp_tool_profile(tool_profile)
    return MCP_TOOL_PROFILE_DESCRIPTIONS.get(selected, MCP_TOOL_PROFILE_DESCRIPTIONS[DEFAULT_MCP_TOOL_PROFILE])


def load_mcp_tool_names_from_server_source() -> set[str]:
    server_path = kit_root() / "server.py"
    try:
        text = server_path.read_text(encoding="utf-8")
    except OSError:
        return set()
    return {
        name
        for name in re.findall(r'"name"\s*:\s*"([A-Za-z_][A-Za-z0-9_]*)"', text)
        if name != "long_novel_agent"
    }


def mcp_profile_tool_names(tool_profile: str, *, all_tool_names: set[str] | None = None) -> set[str]:
    selected = normalize_mcp_tool_profile(tool_profile)
    if selected == "core":
        return set(MCP_CORE_PROFILE_TOOLS)
    if selected == "writing":
        return set(MCP_WRITING_PROFILE_TOOLS)
    return set(all_tool_names or load_mcp_tool_names_from_server_source() or MCP_WRITING_PROFILE_TOOLS)


def mcp_visible_tool_names_for(
    *,
    mode: str = "read-only",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
    all_tool_names: set[str] | None = None,
) -> set[str]:
    selected_mode = normalize_agent_mode(mode)
    names = mcp_profile_tool_names(tool_profile, all_tool_names=all_tool_names)
    if selected_mode == "read-only":
        names = {name for name in names if name not in MCP_MUTATING_TOOLS}
    return names


def mcp_tool_required_profile(tool_name: str, *, all_tool_names: set[str] | None = None) -> str | None:
    if tool_name in MCP_CORE_PROFILE_TOOLS:
        return "core"
    if tool_name in MCP_WRITING_PROFILE_TOOLS:
        return "writing"
    names = all_tool_names or load_mcp_tool_names_from_server_source()
    if tool_name in names:
        return "full"
    return None


def suggest_mcp_tool_names(tool_name: str, *, all_tool_names: set[str]) -> list[str]:
    needle = tool_name.lower().replace("-", "_")
    scored: list[tuple[int, str]] = []
    for candidate in sorted(all_tool_names):
        lowered = candidate.lower()
        score = 0
        if lowered == needle:
            score = 100
        elif lowered.replace("_", "") == needle.replace("_", ""):
            score = 90
        elif needle and needle in lowered:
            score = 80
        elif needle and any(part and part in lowered for part in needle.split("_")):
            score = 50
        if score:
            scored.append((score, candidate))
    return [name for _, name in sorted(scored, key=lambda item: (-item[0], item[1]))[:8]]


def explain_tool_visibility(
    tool_name: str,
    *,
    mode: str = "read-only",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
    all_tool_names: set[str] | None = None,
) -> dict[str, Any]:
    selected_mode = normalize_agent_mode(mode)
    selected_profile = normalize_mcp_tool_profile(tool_profile)
    all_names = set(all_tool_names or load_mcp_tool_names_from_server_source() or MCP_WRITING_PROFILE_TOOLS)
    name = (tool_name or "").strip()
    if not name:
        raise KitError("tool_name is required")
    known = name in all_names
    profile_names = mcp_profile_tool_names(selected_profile, all_tool_names=all_names)
    profile_allows = known and name in profile_names
    mode_allows = name not in MCP_MUTATING_TOOLS or selected_mode == "writer"
    visible = bool(known and profile_allows and mode_allows)
    required_profile = mcp_tool_required_profile(name, all_tool_names=all_names)
    suggested_profile = required_profile if required_profile and required_profile != selected_profile else selected_profile
    suggested_mode = "writer" if name in MCP_MUTATING_TOOLS else selected_mode
    blocked_by: list[str] = []
    if not known:
        blocked_by.append("unknown_tool")
    if known and not profile_allows:
        blocked_by.append("tool_profile")
    if known and profile_allows and not mode_allows:
        blocked_by.append("read_only_mode")

    profiles: list[dict[str, Any]] = []
    for profile in ("core", "writing", "full"):
        profile_tool_names = mcp_profile_tool_names(profile, all_tool_names=all_names)
        included = name in profile_tool_names if known else False
        profiles.append(
            {
                "profile": profile,
                "description": describe_mcp_tool_profile(profile),
                "included": included,
                "visible_in_read_only": bool(included and name not in MCP_MUTATING_TOOLS),
                "visible_in_writer": bool(included),
            }
        )

    actions: list[dict[str, Any]] = []
    if not known:
        actions.append(
            {
                "id": "check_tool_name",
                "title": "Check the MCP tool name",
                "detail": "The tool is not in this kit's local MCP tool registry.",
                "command": "python /path/to/long-novel-agent/cli.py tool-visibility <tool-name> --format markdown",
            }
        )
    elif not profile_allows and required_profile:
        actions.append(
            {
                "id": "change_tool_profile",
                "title": f"Use --tool-profile {required_profile}",
                "detail": f"`{name}` is outside profile `{selected_profile}` and first appears in `{required_profile}`.",
                "command": f"python /path/to/long-novel-agent/cli.py desktop-setup /path/to/novel --mode {selected_mode} --tool-profile {required_profile} --format markdown",
            }
        )
    if known and not mode_allows:
        actions.append(
            {
                "id": "use_writer_mode",
                "title": "Use writer mode only after author approval",
                "detail": f"`{name}` writes .novel-agent/ state and is hidden or rejected in read-only mode.",
                "command": f"python /path/to/long-novel-agent/cli.py writer-mode-readiness /path/to/novel --author-confirmation \"<author-approved writer mode scope>\" --format markdown",
            }
        )
    if known:
        actions.append(
            {
                "id": "verify_visible_tools",
                "title": "Restart the desktop app and verify the visible MCP tools",
                "detail": "Local config changes are not visible inside the desktop client until the client reloads its MCP config.",
                "command": f"python /path/to/long-novel-agent/cli.py desktop-verify /path/to/novel --mode {selected_mode} --tool-profile {suggested_profile} --start-mcp-test --format markdown",
            }
        )

    return {
        "type": "tool_visibility_explanation",
        "local_only": True,
        "read_only": True,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "tool_name": name,
        "known_tool": known,
        "requested_mode": selected_mode,
        "requested_tool_profile": selected_profile,
        "requested_profile_description": describe_mcp_tool_profile(selected_profile),
        "visible": visible,
        "profile_allows": profile_allows,
        "mode_allows": mode_allows,
        "mutating_tool": name in MCP_MUTATING_TOOLS,
        "blocked_by": blocked_by,
        "required_profile": required_profile,
        "suggested_profile": suggested_profile,
        "suggested_mode": suggested_mode,
        "suggested_matches": [] if known else suggest_mcp_tool_names(name, all_tool_names=all_names),
        "profiles": profiles,
        "visible_tool_count": len(mcp_visible_tool_names_for(mode=selected_mode, tool_profile=selected_profile, all_tool_names=all_names)),
        "all_tool_count": len(all_names),
        "recommended_actions": actions,
        "notes": [
            "This explanation is local and read-only.",
            "A tool must pass both the selected tool profile and read-only/writer mode checks before it appears in tools/list.",
            "Local desktop apps usually need a restart or MCP reload after config changes.",
        ],
    }


def render_tool_visibility_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# MCP Tool Visibility",
        "",
        f"- Tool: `{report.get('tool_name')}`",
        f"- Known tool: `{report.get('known_tool')}`",
        f"- Requested mode: `{report.get('requested_mode')}`",
        f"- Requested tool profile: `{report.get('requested_tool_profile')}`",
        f"- Visible now: `{report.get('visible')}`",
        f"- Blocked by: {', '.join(f'`{item}`' for item in report.get('blocked_by') or []) or 'none'}",
        f"- Required profile: `{report.get('required_profile') or 'unknown'}`",
        f"- Suggested mode: `{report.get('suggested_mode')}`",
        f"- Visible tool count in this selection: `{report.get('visible_tool_count')}`",
        "",
        "## Profile Matrix",
        "",
        "| Profile | Included | Visible In Read-Only | Visible In Writer | Description |",
        "| --- | --- | --- | --- | --- |",
    ]
    for item in report.get("profiles") if isinstance(report.get("profiles"), list) else []:
        if not isinstance(item, dict):
            continue
        lines.append(
            f"| `{item.get('profile')}` | `{item.get('included')}` | `{item.get('visible_in_read_only')}` | `{item.get('visible_in_writer')}` | {item.get('description')} |"
        )
    matches = report.get("suggested_matches") if isinstance(report.get("suggested_matches"), list) else []
    if matches:
        lines.extend(["", "## Similar Tool Names"])
        lines.extend(f"- `{item}`" for item in matches)
    actions = report.get("recommended_actions") if isinstance(report.get("recommended_actions"), list) else []
    if actions:
        lines.extend(["", "## Recommended Actions"])
        for item in actions:
            if not isinstance(item, dict):
                continue
            lines.extend(
                [
                    f"### {item.get('title')}",
                    f"- {item.get('detail')}",
                    "",
                    "```bash",
                    str(item.get("command") or ""),
                    "```",
                    "",
                ]
            )
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    if notes:
        lines.extend(["## Notes"])
        lines.extend(f"- {item}" for item in notes)
    return "\n".join(lines).rstrip() + "\n"


def desktop_mcp_server_args(skill_path: Path, *, read_only: bool, tool_profile: str = DEFAULT_MCP_TOOL_PROFILE) -> list[str]:
    args = [str(skill_path / "server.py")]
    if read_only:
        args.append("--read-only")
    selected_profile = normalize_mcp_tool_profile(tool_profile)
    if selected_profile != DEFAULT_MCP_TOOL_PROFILE:
        args.extend(["--tool-profile", selected_profile])
    return args


def desktop_mcp_config_snippet(
    platform: str,
    *,
    install_target: str = "",
    mode: str = "read-only",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
) -> str:
    selected_platform = (platform or "generic-json").strip().lower()
    read_only = (mode or "read-only").strip().lower() != "writer"
    selected_profile = normalize_mcp_tool_profile(tool_profile)
    skill_path = desktop_installed_skill_path(install_target)
    args = desktop_mcp_server_args(skill_path, read_only=read_only, tool_profile=selected_profile)
    if selected_platform == "codex":
        quoted_args = ", ".join(json.dumps(item, ensure_ascii=False) for item in args)
        return "\n".join(
            [
                "[mcp_servers.long-novel-agent]",
                f"command = {json.dumps(sys.executable, ensure_ascii=False)}",
                f"args = [{quoted_args}]",
                "",
            ]
        )
    if selected_platform in {"cursor", "claude-desktop", "generic-json"}:
        payload = {
            "mcpServers": {
                "long-novel-agent": {
                    "command": sys.executable,
                    "args": args,
                }
            }
        }
        return json.dumps(payload, ensure_ascii=False, indent=2) + "\n"
    raise KitError(f"Unsupported MCP config platform: {platform}")


def desktop_mcp_config_filename(platform: str, mode: str) -> str:
    extension = "toml" if platform == "codex" else "json"
    return f"mcp-configs/{platform}-{mode}.{extension}"


def render_desktop_mcp_configs_readme(pack: dict[str, Any], config_files: list[dict[str, Any]]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    lines = [
        "# Local MCP Config Snippets",
        "",
        "These files are copyable local MCP snippets for desktop agents that can start a stdio MCP server.",
        "",
        f"- Project: `{pack.get('project_dir')}`",
        f"- Selected platform: `{pack.get('platform')}`",
        f"- Selected mode: `{pack.get('mode')}`",
        f"- MCP tool profile: `{pack.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}`",
        f"- Skill install target: `{pack.get('install_target') or str(desktop_skill_target_root())}`",
        f"- Installed skill path used in snippets: `{desktop_installed_skill_path(str(pack.get('install_target') or ''))}`",
        f"- Selected config path: `{pack.get('config_path') or 'not set'}`",
        "",
        "## Files",
    ]
    for item in config_files:
        lines.append(
            f"- `{item.get('name')}`: {item.get('platform')} / {item.get('mode')}; "
            f"profile `{item.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}`; "
            f"{'selected pack target' if item.get('selected') else 'alternate local snippet'}."
        )
    lines.extend(
        [
            "",
            "## Commands",
        ]
    )
    for key in ("merge_mcp_config", "upgrade_install", "uninstall", "doctor"):
        command = str(commands.get(key) or "").strip()
        if command:
            lines.append(f"- {key}: `{command}`")
    lines.extend(
        [
            "",
            "Writer snippets expose write tools. Keep read-only mode for first installation unless the author explicitly trusts this desktop agent to update `.novel-agent/`.",
            "Claude Desktop and generic JSON clients need their real local config path supplied by the user before merge or doctor checks.",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def desktop_platform_guide_name(platform: str) -> str:
    return f"platforms/{platform}.md"


def desktop_platform_config_path_note(platform: str, pack: dict[str, Any]) -> str:
    selected_platform = install_platform_for_agent(str(pack.get("platform") or "codex"))
    configured = str(pack.get("config_path") or "").strip()
    if configured and platform == selected_platform:
        return f"This pack was generated with `{configured}` as the selected config path."
    default_path = default_desktop_config_path(platform)
    if default_path:
        return f"Default local config path used by this kit: `{default_path}`."
    if platform == "claude-desktop":
        return "Claude Desktop config location differs by installation. Check the app's local MCP settings and pass that path explicitly."
    return "Use the local MCP config file chosen by the desktop client."


def render_desktop_platform_guides_readme(pack: dict[str, Any]) -> str:
    selected_platform = install_platform_for_agent(str(pack.get("platform") or "codex"))
    lines = [
        "# Platform Guides",
        "",
        "Open the file that matches the local desktop agent. These guides are local-only and assume the client can start a stdio MCP server or run CLI commands.",
        "",
    ]
    for platform in DESKTOP_MCP_CONFIG_PLATFORMS:
        label = DESKTOP_PLATFORM_GUIDE_NAMES.get(platform, platform)
        selected = " selected by this pack" if platform == selected_platform else ""
        lines.append(f"- [{label}]({platform}.md){selected}")
    lines.extend(
        [
            "",
            "Remote connector-only platforms are outside this local desktop flow.",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_platform_guide(pack: dict[str, Any], platform: str) -> str:
    label = DESKTOP_PLATFORM_GUIDE_NAMES.get(platform, platform)
    selected_platform = install_platform_for_agent(str(pack.get("platform") or "codex"))
    selected = platform == selected_platform
    mode = str(pack.get("mode") or "read-only")
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    result_file = str(pack.get("result_file") or "desktop-results.json")
    config_read_only = desktop_mcp_config_filename(platform, "read-only")
    config_writer = desktop_mcp_config_filename(platform, "writer")
    install_platform = platform
    read_only_print_command = shell_command(
        ["python", kit_root() / "install.py", "--mcp-platform", install_platform, "--print-mcp-config"]
    )
    writer_print_command = shell_command(
        ["python", kit_root() / "install.py", "--mcp-platform", install_platform, "--writer-mcp", "--print-mcp-config"]
    )
    auto_config_command = ""
    if platform in {"codex", "cursor"}:
        auto_config_command = shell_command(
            ["python", kit_root() / "install.py", "--mcp-platform", install_platform, "--mcp-config", "auto"]
        )
    selected_merge = str(commands.get("merge_mcp_config") or "").strip() if selected else ""
    selected_doctor = str(commands.get("doctor") or "").strip() if selected else ""
    selected_checklist = str(commands.get("desktop_checklist") or "").strip() if selected else ""
    selected_record = str(commands.get("record_desktop_check") or "").strip() if selected else ""
    selected_prepare = str(commands.get("prepare_session") or "").strip() if selected else ""
    lines = [
        f"# {label} Local Setup",
        "",
        f"- Project directory: `{pack.get('project_dir')}`",
        f"- Selected in this pack: {'yes' if selected else 'no'}",
        f"- Recommended first mode: `read-only`",
        f"- Pack mode: `{mode}`",
        f"- Target chapter: {pack.get('target_chapter')}",
        f"- Config note: {desktop_platform_config_path_note(platform, pack)}",
        "",
        "## What To Copy",
        f"- Read-only snippet: `{config_read_only}`",
        f"- Writer snippet: `{config_writer}`",
        "- Use writer mode only after the author allows this desktop agent to change `.novel-agent/`.",
        "",
        "## Install Or Merge",
        "Print a read-only snippet:",
        "",
        "```bash",
        read_only_print_command,
        "```",
        "",
        "Print a writer snippet:",
        "",
        "```bash",
        writer_print_command,
        "```",
    ]
    if auto_config_command:
        lines.extend(
            [
                "",
                "Merge into the default local config path:",
                "",
                "```bash",
                auto_config_command,
                "```",
            ]
        )
    else:
        lines.extend(
            [
                "",
                "This platform needs an explicit config path before merge or doctor checks:",
                "",
                "```bash",
                shell_command(
                    [
                        "python",
                        kit_root() / "install.py",
                        "--mcp-platform",
                        install_platform,
                        "--mcp-config",
                        "/path/to/mcp-config.json",
                    ]
                ),
                "```",
            ]
        )
    if selected_merge:
        lines.extend(
            [
                "",
                "Command generated for this pack:",
                "",
                "```bash",
                selected_merge,
                "```",
            ]
        )
    lines.extend(
        [
            "",
            "## Verify",
            "- Restart the desktop client after changing its MCP config.",
            "- Run `desktop-verify` or `doctor --start-mcp-test` for the local command path.",
            "- Then use `checklist.md` inside the actual desktop client; local command verification is not enough.",
        ]
    )
    if selected_doctor:
        lines.extend(["", "```bash", selected_doctor, "```"])
    if selected_checklist:
        lines.extend(["", "```bash", selected_checklist, "```"])
    lines.extend(
        [
            "",
            "## Evidence",
            f"- Fill `{result_file}` only after the real desktop client shows the server, tools, and required calls.",
            "- Evidence should be short tool names, tool-call summaries, status text, or sanitized screenshots transcribed into text.",
            "- Do not include API keys, access tokens, full manuscripts, or unrelated private data.",
        ]
    )
    if selected_record:
        lines.extend(["", "Record the finished check:", "", "```bash", selected_record, "```"])
    if selected_prepare:
        lines.extend(["", "Open the target chapter session:", "", "```bash", selected_prepare, "```"])
    lines.extend(
        [
            "",
            "## Not Supported Here",
            "Remote connector-only platforms need a separate wrapper and are not part of this local desktop setup.",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def build_desktop_platform_guide_files(pack: dict[str, Any]) -> tuple[list[dict[str, Any]], dict[str, tuple[str, Any]]]:
    selected_platform = install_platform_for_agent(str(pack.get("platform") or "codex"))
    files: list[dict[str, Any]] = [
        {
            "name": "platforms/README.md",
            "description": "Index of local desktop platform setup guides.",
            "platform": "all",
            "selected": False,
        }
    ]
    payloads: dict[str, tuple[str, Any]] = {
        "platforms/README.md": ("text", render_desktop_platform_guides_readme(pack))
    }
    for platform in DESKTOP_MCP_CONFIG_PLATFORMS:
        label = DESKTOP_PLATFORM_GUIDE_NAMES.get(platform, platform)
        name = desktop_platform_guide_name(platform)
        files.append(
            {
                "name": name,
                "description": f"{label} local MCP setup guide.",
                "platform": platform,
                "selected": platform == selected_platform,
            }
        )
        payloads[name] = ("text", render_desktop_platform_guide(pack, platform))
    return files, payloads


def build_desktop_mcp_config_files(pack: dict[str, Any]) -> tuple[list[dict[str, Any]], dict[str, tuple[str, Any]]]:
    selected_platform = str(pack.get("platform") or "codex")
    selected_mode = str(pack.get("mode") or "read-only")
    install_target = str(pack.get("install_target") or "")
    tool_profile = normalize_mcp_tool_profile(str(pack.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE))
    files: list[dict[str, Any]] = [
        {
            "name": "mcp-configs/README.md",
            "description": "Copyable MCP config snippet index for local desktop agents.",
            "platform": "all",
            "mode": "all",
            "selected": False,
        }
    ]
    payloads: dict[str, tuple[str, Any]] = {}
    config_rows: list[dict[str, Any]] = []
    for platform_name in DESKTOP_MCP_CONFIG_PLATFORMS:
        for mode_name in ("read-only", "writer"):
            name = desktop_mcp_config_filename(platform_name, mode_name)
            row = {
                "name": name,
                "description": f"{platform_name} {mode_name} local MCP config snippet.",
                "platform": platform_name,
                "mode": mode_name,
                "tool_profile": tool_profile,
                "selected": platform_name == install_platform_for_agent(selected_platform) and mode_name == selected_mode,
            }
            files.append(row)
            config_rows.append(row)
            payloads[name] = (
                "text",
                desktop_mcp_config_snippet(platform_name, install_target=install_target, mode=mode_name, tool_profile=tool_profile),
            )
    payloads["mcp-configs/README.md"] = ("text", render_desktop_mcp_configs_readme(pack, config_rows))
    return files, payloads


