def append_desktop_pack_troubleshooting_read_errors(payload: dict[str, Any], read_errors: list[dict[str, str]]) -> dict[str, Any]:
    if not read_errors:
        return payload
    payload["ok"] = False
    payload["read_errors"] = read_errors
    first_checks = payload.get("first_checks") if isinstance(payload.get("first_checks"), list) else []
    first_checks.insert(
        0,
        {
            "id": "repair_invalid_pack_json",
            "read": ["metadata.json", "commands.json", PACK_INDEX_FILE],
            "why": "one or more desktop-pack JSON inputs could not be parsed; repair or regenerate the pack before following failure guidance",
        },
    )
    payload["first_checks"] = first_checks
    return payload


def render_desktop_pack_troubleshooting_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Local Desktop Troubleshooting",
        "",
        "This is the read-only troubleshooting packet for a generated local desktop pack.",
        "",
        "## Target",
        f"- Project directory: `{payload.get('project_dir')}`",
        f"- Output directory: `{payload.get('output_dir')}`",
        f"- Platform: `{payload.get('platform')}`",
        f"- Mode: `{payload.get('mode')}`",
        f"- Target chapter: {payload.get('target_chapter')}",
        f"- Result JSON: `{payload.get('result_file')}`",
        f"- Machine-readable packet: `{DESKTOP_PACK_TROUBLESHOOTING_JSON_FILE}`",
        f"- JSON schema: `{DESKTOP_PACK_TROUBLESHOOTING_SCHEMA_OUTPUT_FILE}`",
        "",
        "## First Checks",
    ]
    for item in payload.get("first_checks") if isinstance(payload.get("first_checks"), list) else []:
        if not isinstance(item, dict):
            continue
        lines.append(f"- `{item.get('id')}`: {item.get('why')}")
        read_files = item.get("read") if isinstance(item.get("read"), list) else []
        if read_files:
            lines.append(f"  - Read: {', '.join(f'`{name}`' for name in read_files)}")
        command = item.get("command") if isinstance(item.get("command"), dict) else {}
        if command.get("command"):
            lines.append(f"  - Command `{command.get('key')}`: `{command.get('command')}`")
    lines.extend(["", "## Symptoms", "", "| Severity | Symptom | Summary | Commands | Regenerate pack |", "| --- | --- | --- | --- | --- |"])
    for item in payload.get("symptoms") if isinstance(payload.get("symptoms"), list) else []:
        if not isinstance(item, dict):
            continue
        commands = []
        for command in item.get("commands") if isinstance(item.get("commands"), list) else []:
            if isinstance(command, dict):
                marker = "" if command.get("present") else " (missing)"
                commands.append(f"`{command.get('key')}`{marker}")
        lines.append(
            f"| `{item.get('severity')}` | `{item.get('id')}` {item.get('title')} | {item.get('summary')} | {', '.join(commands) or '-'} | `{bool(item.get('regenerate_pack_after_fix'))}` |"
        )
        read_first = item.get("read_first") if isinstance(item.get("read_first"), list) else []
        if read_first:
            lines.append(f"|  | Read first |  | {', '.join(f'`{name}`' for name in read_first)} |  |")
        do_not = item.get("do_not") if isinstance(item.get("do_not"), list) else []
        if do_not:
            lines.append(f"|  | Do not |  | {', '.join(f'`{name}`' for name in do_not)} |  |")
    regenerate = payload.get("when_to_regenerate") if isinstance(payload.get("when_to_regenerate"), list) else []
    lines.extend(["", "## Regenerate The Pack"])
    for item in regenerate:
        lines.append(f"- {item}")
    boundaries = payload.get("write_boundaries") if isinstance(payload.get("write_boundaries"), dict) else {}
    lines.extend(
        [
            "",
            "## Write Boundaries",
            f"- Troubleshooting is read-only: `{boundaries.get('troubleshooting_is_read_only')}`",
            f"- Does not write project state: `{payload.get('would_write_project_state') is False}`",
            f"- Does not write install config: `{payload.get('would_write_install_config') is False}`",
            f"- Does not write pack files: `{payload.get('would_write_pack_files') is False}`",
            f"- Does not record real desktop-client evidence: `{payload.get('records_real_client_evidence') is False}`",
        ]
    )
    blocked = boundaries.get("read_only_agents_must_not_execute") if isinstance(boundaries.get("read_only_agents_must_not_execute"), list) else []
    if blocked:
        lines.append(f"- Read-only agents must not execute: {', '.join(f'`{name}`' for name in blocked)}")
    if payload.get("read_errors"):
        lines.extend(["", "## Read Errors"])
        for item in payload.get("read_errors") if isinstance(payload.get("read_errors"), list) else []:
            if isinstance(item, dict):
                lines.append(f"- `{item.get('file')}`: {item.get('message')}")
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_troubleshooting_html(pack: dict[str, Any], payload: dict[str, Any]) -> str:
    def text(value: Any) -> str:
        return html.escape("" if value is None else str(value), quote=True)

    def code_items(values: Any) -> str:
        if not isinstance(values, list) or not values:
            return "<span class=\"muted\">None</span>"
        return " ".join(f"<code>{text(item)}</code>" for item in values)

    def list_items(values: Any) -> str:
        if not isinstance(values, list) or not values:
            return "<li class=\"muted\">None</li>"
        return "\n".join(f"<li>{text(item)}</li>" for item in values)

    def command_blocks(values: Any) -> str:
        if not isinstance(values, list) or not values:
            return "<p class=\"muted\">No command references.</p>"
        blocks: list[str] = []
        for item in values:
            if not isinstance(item, dict):
                continue
            key = text(item.get("key"))
            command = text(item.get("command") or "missing from commands.json")
            present_class = "ok" if item.get("present") else "warn"
            present_label = "present" if item.get("present") else "missing"
            blocks.append(
                "\n".join(
                    [
                        "<div class=\"command-block\">",
                        f"<div><code>{key}</code> <span class=\"pill {present_class}\">{present_label}</span></div>",
                        f"<pre>{command}</pre>",
                        "</div>",
                    ]
                )
            )
        return "\n".join(blocks) if blocks else "<p class=\"muted\">No command references.</p>"

    first_checks: list[str] = []
    for item in payload.get("first_checks") if isinstance(payload.get("first_checks"), list) else []:
        if not isinstance(item, dict):
            continue
        command = item.get("command") if isinstance(item.get("command"), dict) else {}
        first_checks.append(
            "\n".join(
                [
                    "<article class=\"check\">",
                    f"<h3>{text(item.get('id'))}</h3>",
                    f"<p>{text(item.get('why'))}</p>",
                    f"<p class=\"small\">Read: {code_items(item.get('read'))}</p>",
                    f"<p class=\"small\">Command: <code>{text(command.get('key') or 'none')}</code></p>" if command else "",
                    "</article>",
                ]
            )
        )

    symptom_cards: list[str] = []
    for item in payload.get("symptoms") if isinstance(payload.get("symptoms"), list) else []:
        if not isinstance(item, dict):
            continue
        severity = text(item.get("severity") or "info")
        symptom_cards.append(
            "\n".join(
                [
                    f"<article class=\"symptom severity-{severity}\">",
                    "<div class=\"symptom-head\">",
                    f"<h3>{text(item.get('title'))}</h3>",
                    f"<span class=\"pill severity\">{severity}</span>",
                    "</div>",
                    f"<p>{text(item.get('summary'))}</p>",
                    f"<p class=\"small\">Read first: {code_items(item.get('read_first'))}</p>",
                    "<h4>Actions</h4>",
                    f"<ul>{list_items(item.get('actions'))}</ul>",
                    "<h4>Commands</h4>",
                    command_blocks(item.get("commands")),
                    "<h4>Do not</h4>",
                    f"<p>{code_items(item.get('do_not'))}</p>",
                    f"<p class=\"small\">Regenerate pack after fix: <strong>{text(bool(item.get('regenerate_pack_after_fix')))}</strong></p>",
                    "</article>",
                ]
            )
        )

    boundaries = payload.get("write_boundaries") if isinstance(payload.get("write_boundaries"), dict) else {}
    blocked = boundaries.get("read_only_agents_must_not_execute") if isinstance(boundaries.get("read_only_agents_must_not_execute"), list) else []
    regenerate = payload.get("when_to_regenerate") if isinstance(payload.get("when_to_regenerate"), list) else []
    source_files = payload.get("source_files") if isinstance(payload.get("source_files"), list) else []
    return "\n".join(
        [
            "<!doctype html>",
            "<html lang=\"en\">",
            "<head>",
            "  <meta charset=\"utf-8\">",
            "  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">",
            "  <title>Long Novel Agent Troubleshooting</title>",
            "  <style>",
            "    :root { color-scheme: light; --bg: #f7f7f4; --panel: #ffffff; --text: #1f2933; --muted: #64707d; --line: #d7d9d2; --accent: #0f766e; --warn: #b45309; --danger: #b91c1c; }",
            "    * { box-sizing: border-box; }",
            "    body { margin: 0; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: var(--bg); color: var(--text); line-height: 1.55; }",
            "    header { padding: 32px clamp(18px, 4vw, 56px) 22px; background: #263238; color: #fff; }",
            "    header h1 { margin: 0 0 8px; font-size: clamp(28px, 4vw, 44px); letter-spacing: 0; }",
            "    header p { max-width: 920px; margin: 0; color: #e5ece8; }",
            "    main { padding: 24px clamp(18px, 4vw, 56px) 48px; }",
            "    section { max-width: 1180px; margin: 0 auto 22px; }",
            "    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(230px, 1fr)); gap: 12px; }",
            "    .panel, .check, .symptom { background: var(--panel); border: 1px solid var(--line); border-radius: 8px; padding: 16px; }",
            "    .target dl { display: grid; grid-template-columns: max-content 1fr; gap: 6px 12px; margin: 0; }",
            "    dt { color: var(--muted); }",
            "    dd { margin: 0; overflow-wrap: anywhere; }",
            "    h2 { margin: 0 0 12px; font-size: 22px; letter-spacing: 0; }",
            "    h3 { margin: 0 0 8px; font-size: 18px; letter-spacing: 0; }",
            "    h4 { margin: 14px 0 6px; font-size: 13px; text-transform: uppercase; color: var(--muted); letter-spacing: 0.06em; }",
            "    code { background: #eef1ed; border: 1px solid #dfe4dd; border-radius: 5px; padding: 2px 5px; font-size: 0.92em; }",
            "    pre { white-space: pre-wrap; overflow-wrap: anywhere; margin: 8px 0 0; padding: 10px; background: #172026; color: #eef5f2; border-radius: 6px; }",
            "    .small, .muted { color: var(--muted); font-size: 0.94rem; }",
            "    .pill { display: inline-flex; align-items: center; min-height: 24px; padding: 2px 8px; border-radius: 999px; font-size: 12px; font-weight: 700; background: #e5ece8; color: #263238; }",
            "    .pill.ok { background: #d7f2e6; color: #166534; }",
            "    .pill.warn { background: #fff3d6; color: var(--warn); }",
            "    .symptom-head { display: flex; align-items: flex-start; justify-content: space-between; gap: 12px; }",
            "    .severity-blocker { border-left: 5px solid var(--danger); }",
            "    .severity-warning { border-left: 5px solid var(--warn); }",
            "    .severity-info { border-left: 5px solid var(--accent); }",
            "    .severity { background: #f3e8e8; color: var(--danger); }",
            "    .command-block + .command-block { margin-top: 10px; }",
            "    ul { padding-left: 18px; margin: 6px 0; }",
            "    a { color: #0f766e; }",
            "  </style>",
            "</head>",
            "<body>",
            "  <header>",
            "    <h1>Troubleshooting Dashboard</h1>",
            "    <p>Read-only local guide for install, MCP tool visibility, chapter session, source intake, evidence, and pack file issues. It does not run commands or write files.</p>",
            "  </header>",
            "  <main>",
            "    <section class=\"panel target\">",
            "      <h2>Target</h2>",
            "      <dl>",
            f"        <dt>Project</dt><dd>{text(payload.get('project_dir'))}</dd>",
            f"        <dt>Pack</dt><dd>{text(payload.get('output_dir'))}</dd>",
            f"        <dt>Platform</dt><dd>{text(payload.get('platform'))}</dd>",
            f"        <dt>Mode</dt><dd>{text(payload.get('mode'))}</dd>",
            f"        <dt>Tool profile</dt><dd>{text(pack.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE)}</dd>",
            f"        <dt>Chapter</dt><dd>{text(payload.get('target_chapter'))}</dd>",
            f"        <dt>Result JSON</dt><dd>{text(payload.get('result_file'))}</dd>",
            "      </dl>",
            f"      <p class=\"small\">Source files: {code_items(source_files)}</p>",
            f"      <p class=\"small\">Markdown: <a href=\"{text(DESKTOP_PACK_TROUBLESHOOTING_MD_FILE)}\">{text(DESKTOP_PACK_TROUBLESHOOTING_MD_FILE)}</a> · JSON: <a href=\"{text(DESKTOP_PACK_TROUBLESHOOTING_JSON_FILE)}\">{text(DESKTOP_PACK_TROUBLESHOOTING_JSON_FILE)}</a> · Home: <a href=\"index.html\">index.html</a></p>",
            "    </section>",
            "    <section>",
            "      <h2>First Checks</h2>",
            f"      <div class=\"grid\">{''.join(first_checks)}</div>",
            "    </section>",
            "    <section>",
            "      <h2>Symptom Guide</h2>",
            f"      <div class=\"grid\">{''.join(symptom_cards)}</div>",
            "    </section>",
            "    <section class=\"panel\">",
            "      <h2>When To Regenerate This Pack</h2>",
            f"      <ul>{list_items(regenerate)}</ul>",
            "    </section>",
            "    <section class=\"panel\">",
            "      <h2>Write Boundaries</h2>",
            f"      <p>Troubleshooting is read-only: <strong>{text(boundaries.get('troubleshooting_is_read_only'))}</strong></p>",
            f"      <p>Writes project state: <strong>{text(payload.get('would_write_project_state'))}</strong></p>",
            f"      <p>Writes install config: <strong>{text(payload.get('would_write_install_config'))}</strong></p>",
            f"      <p>Writes pack files: <strong>{text(payload.get('would_write_pack_files'))}</strong></p>",
            f"      <p>Records real desktop evidence: <strong>{text(payload.get('records_real_client_evidence'))}</strong></p>",
            f"      <p>Read-only agents must not execute: {code_items(blocked)}</p>",
            f"      <p class=\"small\">Remote connector-only platforms: {text(boundaries.get('remote_connector_only_platforms'))}</p>",
            "    </section>",
            "  </main>",
            "</body>",
            "</html>",
            "",
        ]
    )


def render_desktop_pack_troubleshooting(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    result_file = str(pack.get("result_file") or "desktop-results.json")

    def command_block(key: str, fallback: str) -> list[str]:
        command = str(commands.get(key) or fallback).strip()
        return ["```bash", command, "```"]

    lines = [
        "# Local Desktop Troubleshooting",
        "",
        "Use this file when a local desktop agent cannot see the kit, cannot call MCP tools, cannot open the target chapter session, or cannot record verification evidence.",
        "",
        "## Target",
        f"- Project directory: `{pack.get('project_dir')}`",
        f"- Platform: {pack.get('platform')}",
        f"- Mode: {pack.get('mode')}",
        f"- Target chapter: {pack.get('target_chapter')}",
        f"- MCP config: `{pack.get('config_path') or 'not configured in this pack'}`",
        f"- Result JSON: `{result_file}`",
        f"- Machine-readable guide: `{DESKTOP_PACK_TROUBLESHOOTING_JSON_FILE}`",
        f"- JSON schema: `{DESKTOP_PACK_TROUBLESHOOTING_SCHEMA_OUTPUT_FILE}`",
        "",
        "## First Checks",
        "1. Open `START_HERE.md` and confirm the project directory, platform, mode, and target chapter.",
        "2. Run the local verification command before opening the desktop client:",
        "",
        *command_block("desktop_verify", "See setup.md for desktop-verify or doctor commands."),
        "",
        "3. Restart or reload the desktop client after any MCP config change.",
        "4. In the client, use `client-prompts.md` prompt 2 to confirm `long-novel-agent` server and tools are visible.",
        "5. If the local terminal check passes but the desktop client still fails, treat it as a client config or reload problem, not a novel continuity problem.",
        "",
        "## Symptom Guide",
        "",
        "### The desktop client does not show `long-novel-agent`",
        "- Confirm the MCP config path in this pack matches the desktop app you are using.",
        "- Open the matching file in `platforms/` and compare the config location and server command.",
        "- Use the matching snippet under `mcp-configs/` if editing config manually.",
        "- Restart the desktop app after saving config.",
        "- Re-run local verification after changing config.",
        "",
        *command_block("desktop_verify", "See setup.md for desktop-verify or doctor commands."),
        "",
        "### Local verification works, but the GUI client cannot call tools",
        "- Check whether the app has been restarted after config changes.",
        "- Check that the same user account and same config file are used by the GUI client.",
        "- Ask the client to list tools again with `client-prompts.md`.",
        "- Do not fill required GUI evidence as `passed` until the real client visibly calls a tool.",
        "",
        "### Read-only and writer mode are mixed up",
        "- First install should usually stay read-only.",
        "- If writer mode is expected, the server command must omit `--read-only`.",
        "- If read-only mode is expected, write tools must be hidden or rejected.",
        "- Rebuild or replace the MCP snippet, then restart the desktop client.",
        "- Do not run `record-desktop-check` until the mode boundary is proven in the real client.",
        "",
        "### `prepare_chapter_session` says the project is not initialized",
        "- Open `project-wizard.json` and fill the project answers.",
        "- Run the dry-run command before applying changes.",
        "",
        *command_block("quickstart_from_wizard_dry_run", "See project-wizard.md"),
        "",
        "- Apply only after the dry-run report matches the intended project.",
        "",
        *command_block("quickstart_from_wizard_apply", "See project-wizard.md"),
        "",
        "- Regenerate this pack after initialization if `chapter-session.md` still shows pending state.",
        "",
        *command_block("desktop_pack", "See commands.txt"),
        "",
        "### Chapter context is empty, stale, or missing expected source material",
        "- If source files were parsed after this pack was generated, save confirmed summaries through `source-intake.json` first.",
        "- Review `source-intake.json` in `source-intake-review.html`, then use dry-run.",
        "",
        *command_block("source_intake_dry_run", "See source-intake.md"),
        "",
        "- Apply source intake only after author approval and a clean dry-run report.",
        "",
        *command_block("source_intake_apply", "See source-intake.md"),
        "",
        "- Call `prepare-session` again after applying source material.",
        "",
        *command_block("prepare_session", "See commands.txt"),
        "",
        "### `check_chapter` reports continuity issues",
        "- Treat blocking issues as draft problems, not as state problems.",
        "- Revise the chapter text against `chapter-session.md`, `continuity-audit.md`, and `build_chapter_context` output.",
        "- Do not edit `.novel-agent/` files manually to make the warning disappear.",
        "- If canon really changed after author acceptance, create a post-write proposal and apply it only after review.",
        "",
        "### Result JSON cannot be recorded",
        "- Open `result-json-guide.md` and confirm every required check ID still exists.",
        "- Open `index.html` and load the filled result JSON.",
        "- Required checks need `status: passed` and short real-client evidence.",
        "- `range_readiness_gate` evidence must show `build_chapter_range_readiness` or `chapter-range-readiness`.",
        "- Writer mode evidence for `write_session_preflight_gate` must show `check_write_session` or `write-session-check` before durable writer commands.",
        "- Writer mode evidence for `proposal_readiness_gate` must show `build_proposal_readiness` or `proposal-readiness` before apply.",
        "- Writer mode evidence for `acceptance_write_gate` must show a durable write command and `author_confirmation` or `--author-confirmation`.",
        "- Remove API keys, access tokens, full manuscripts, screenshots with private content, and long logs from evidence.",
        "",
        *command_block("desktop_results_doctor", "See commands.txt"),
        "",
        *command_block("record_desktop_check", "See commands.txt"),
        "",
        "### `desktop-pack` refuses to write files",
        "- Existing pack files are protected by default.",
        "- Use a new `--output-dir` or re-run the generated command with `--force` after confirming the directory is disposable.",
        "",
        *command_block("desktop_pack", "See commands.txt"),
        "",
        "### A write command reports a lock",
        "- Another writer may be changing `.novel-agent/`.",
        "- Stop parallel writer agents and retry after the active write completes.",
        "- Use `project-status` or `doctor` to inspect project health before retrying.",
        "- Do not delete lock files by hand unless you have confirmed no writer process is alive.",
        "",
        "### Evidence safety warnings appear",
        "- Warnings usually mean the evidence is too large or may include secrets.",
        "- Keep only server name, tool name, status, and one short proof detail.",
        "- Use `desktop-evidence.txt` as scratch space, then reduce it before filling the result JSON.",
        "",
        "## When To Regenerate This Pack",
        "- After installing or changing MCP config.",
        "- After initializing `.novel-agent/` from the wizard.",
        "- After applying source intake.",
        "- After changing platform, mode, or target chapter.",
        "- After recording a real desktop client check and wanting fresh `project-status.md`, `project-status.json`, `desktop-matrix.md`, or `desktop-matrix.json`.",
        "",
        "## Boundaries",
        "- This guide is only for local desktop agents that can run stdio MCP or CLI.",
        "- Remote connector-only platforms need a separate wrapper and are not part of this local flow.",
        "- This guide helps find setup and evidence problems; it does not judge literary quality.",
    ]
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_local_checks_markdown(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    ordered = [
        ("desktop_verify", "Verify local MCP config and stdio read path."),
        ("project_status", "Read project readiness, blockers, warnings, and verification status."),
        ("continuity_audit", "Read continuity risks for the target chapter."),
        ("prepare_session", "Open the target chapter startup packet."),
        ("desktop_checklist", "Print the real desktop client evidence checklist."),
    ]
    lines = [
        "# Local Checks",
        "",
        "Use this file before opening or rechecking the desktop client. It verifies only local CLI and stdio MCP readiness.",
        "",
        "## Target",
        f"- Project directory: `{pack.get('project_dir')}`",
        f"- Platform: {pack.get('platform')}",
        f"- Mode: {pack.get('mode')}",
        f"- Target chapter: {pack.get('target_chapter')}",
        f"- MCP config: `{pack.get('config_path') or 'not configured in this pack'}`",
        "",
        "## Run",
        "",
        "```bash",
        "bash local-checks.sh",
        "```",
        "",
        "On macOS, double-click `local-checks.command` to open the same check script in Terminal.",
        "",
        "The script returns non-zero when a local check fails. Open `troubleshooting.md` for the matching symptom before editing `.novel-agent/` or MCP config by hand.",
        "",
        "## What It Checks",
    ]
    for key, description in ordered:
        command = str(commands.get(key) or "").strip()
        lines.extend([f"### {key}", f"- Purpose: {description}"])
        if command:
            lines.extend(["- Command:", "", "```bash", command, "```", ""])
        else:
            lines.extend(["- Command: not available in this generated pack.", ""])
    lines.extend(
        [
            "## What It Does Not Prove",
            "- It does not prove the real GUI desktop client has loaded MCP tools.",
            "- It does not record `desktop_verifications.jsonl`.",
            "- It does not make source intake writes or post-write proposal writes.",
            "- It does not judge prose quality or replace `check_chapter` on an actual draft.",
            "",
            "After local checks pass, use `real-client-walkthrough.md` and `client-prompts.md` inside the actual desktop client, then fill the result JSON, run `desktop-results-doctor`, and record with `record-desktop-check` after it passes.",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_local_checks_script(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    ordered = [
        ("desktop_verify", "local MCP setup"),
        ("project_status", "project status"),
        ("continuity_audit", "continuity audit"),
        ("prepare_session", "chapter session"),
        ("desktop_checklist", "desktop checklist"),
    ]
    lines = [
        "#!/usr/bin/env bash",
        "set -u",
        "",
        "PASS_COUNT=0",
        "FAIL_COUNT=0",
        "SKIP_COUNT=0",
        "",
        "run_check() {",
        '  label="$1"',
        '  command="$2"',
        '  if [ -z "$command" ]; then',
        '    echo "[SKIP] $label: command not available in this pack"',
        "    SKIP_COUNT=$((SKIP_COUNT + 1))",
        "    return 0",
        "  fi",
        '  echo ""',
        '  echo "==> $label"',
        '  echo "$command"',
        '  if sh -c "$command"; then',
        '    echo "[PASS] $label"',
        "    PASS_COUNT=$((PASS_COUNT + 1))",
        "  else",
        "    status=$?",
        '    echo "[FAIL] $label exited with $status"',
        "    FAIL_COUNT=$((FAIL_COUNT + 1))",
        "  fi",
        "}",
        "",
        'echo "Long Novel Agent local desktop checks"',
        f"echo {shlex.quote('Project: ' + str(pack.get('project_dir') or ''))}",
        f"echo {shlex.quote('Platform: ' + str(pack.get('platform') or ''))}",
        f"echo {shlex.quote('Mode: ' + str(pack.get('mode') or ''))}",
        f"echo {shlex.quote('Target chapter: ' + str(pack.get('target_chapter') or ''))}",
        "",
    ]
    for key, label in ordered:
        command = str(commands.get(key) or "").strip()
        lines.append(f"run_check {shlex.quote(label)} {shlex.quote(command)}")
    lines.extend(
        [
            "",
            'echo ""',
            'echo "Summary: $PASS_COUNT passed, $FAIL_COUNT failed, $SKIP_COUNT skipped"',
            'echo "This script does not prove GUI desktop-client MCP access. Use real-client-walkthrough.md and client-prompts.md for GUI evidence."',
            'echo "If a local check failed, open troubleshooting.md for the matching symptom."',
            'if [ "$FAIL_COUNT" -gt 0 ]; then',
            "  exit 1",
            "fi",
            "exit 0",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


