def render_desktop_pack_doctor_file(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    doctor_command = str(commands.get("pack_doctor") or "").strip()
    doctor_json_command = str(commands.get("pack_doctor_json") or "").strip()
    verify_command = str(commands.get("verify_pack_cli") or "").strip()
    lines = [
        "# Pack Doctor",
        "",
        "Use this before installing, sharing, or handing this desktop pack to another local agent.",
        "",
        "## What It Checks",
        "- `pack-manifest.json` still matches generated files.",
        f"- `metadata.json`, `{DESKTOP_PACK_COMMANDS_INDEX_JSON_FILE}`, `commands.json`, `commands.schema.json`, schema files, startup files, and the result template are present.",
        "- `commands.json` contains the core install, verify, evidence, source intake, and chapter-session commands.",
        "- `commands.json` references Kit files that still exist on the current machine and whose `cli.py` version matches this doctor.",
        "- `pack_rebind_dry_run` and `pack_rebind_apply` are available when generated commands need this machine's Kit path.",
        "- Local script permissions are usable on POSIX systems.",
        "- Python, bash, and optional PowerShell availability are visible from the current machine.",
        "- `chapter-session.json` is readable and clearly marked if the project still needs initialization.",
        "- `pack-doctor.json` stores the latest machine-readable report for this pack. It can be refreshed locally and is not included in `pack-manifest.json`.",
        "",
        "## Run Markdown Report",
        "",
        "```bash",
        doctor_command or "python /path/to/long-novel-agent/cli.py pack-doctor /path/to/pack --format markdown",
        "```",
        "",
        "## Refresh JSON Report",
        "",
        "```bash",
        doctor_json_command or "python /path/to/long-novel-agent/cli.py pack-doctor /path/to/pack --format json --output /path/to/pack/pack-doctor.json",
        "```",
        "",
        "## Rebind Kit Paths",
        "",
        "If the report says command Kit paths are missing or stale, use the rebind commands from `commands.json`.",
        "Run `pack_rebind_dry_run` first. Use `pack_rebind_apply` only after reviewing the planned file changes.",
        "Apply updates generated pack files plus `pack-manifest.json` and `pack-doctor.json`; it does not write `.novel-agent/` or local MCP config.",
        "",
        "If the doctor reports file mismatches, run the integrity check directly:",
        "",
        "```bash",
        "python verify-pack.py --json",
        verify_command or "python /path/to/long-novel-agent/cli.py verify-pack /path/to/pack --format markdown",
        "```",
        "",
        "## Boundaries",
        "- This is read-only.",
        "- It does not write `.novel-agent/`.",
        "- It does not change local MCP config.",
        "- It does not run install, upgrade, uninstall, source-intake apply, or record-desktop-check.",
        "- It does not prove the real GUI desktop client can call MCP tools.",
    ]
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_archive_local_script(pack: dict[str, Any]) -> str:
    cli_path = str(kit_root() / "cli.py")
    lines = [
        "#!/usr/bin/env bash",
        "set -u",
        "",
        'SCRIPT_DIR="$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)"',
        'PYTHON_BIN="${PYTHON_BIN:-python3}"',
        f"CLI_PATH={shell_single_quote(cli_path)}",
        "",
        "print_plan() {",
        '  echo "Long Novel Agent desktop pack archiver"',
        '  echo ""',
        '  echo "Default mode is preview only. No zip is written unless you pass --yes."',
        '  echo ""',
        '  echo "Pack directory:"',
        '  echo "$SCRIPT_DIR"',
        '  echo ""',
        '  echo "Archive command:"',
        '  echo "$PYTHON_BIN $CLI_PATH archive-pack $SCRIPT_DIR --force --format markdown"',
        '  echo ""',
        '  echo "To create the zip after review: bash archive-local.sh --yes"',
        '  echo "This writes only a local .zip next to the pack directory."',
        '  echo "It does not write .novel-agent/, change MCP config, or record GUI desktop-client evidence."',
        "}",
        "",
        'MODE="${1:-}"',
        'if [ -z "$MODE" ]; then',
        '  MODE="--plan"',
        "fi",
        "",
        'case "$MODE" in',
        "  --plan|--dry-run)",
        "    print_plan",
        "    exit 0",
        "    ;;",
        "  --yes)",
        '    if [ ! -f "$CLI_PATH" ]; then',
        '      echo "Cannot find long-novel-agent CLI: $CLI_PATH" >&2',
        "      exit 1",
        "    fi",
        '    echo "Long Novel Agent desktop pack archiver"',
        '    echo "Creating zip for pack directory:"',
        '    echo "$SCRIPT_DIR"',
        '    if "$PYTHON_BIN" "$CLI_PATH" archive-pack "$SCRIPT_DIR" --force --format markdown; then',
        '      echo "Archive created."',
        "    else",
        "      status=$?",
        '      echo "archive-pack failed with $status. Run $PYTHON_BIN verify-pack.py --json and open troubleshooting.md if needed." >&2',
        "      exit $status",
        "    fi",
        '    echo "This script did not write .novel-agent/, change MCP config, or record GUI desktop-client evidence."',
        "    exit 0",
        "    ;;",
        "  --help|-h)",
        '    echo "Usage: bash archive-local.sh [--plan|--dry-run|--yes]"',
        "    exit 0",
        "    ;;",
        "  *)",
        '    echo "Usage: bash archive-local.sh [--plan|--dry-run|--yes]" >&2',
        "    exit 2",
        "    ;;",
        "esac",
    ]
    return "\n".join(lines).rstrip() + "\n"


