        f'USER_STEPS_FILE="${{SCRIPT_DIR}}/{DESKTOP_USER_STEPS_HTML_FILE}"',
        'INDEX_FILE="${SCRIPT_DIR}/index.html"',
        'PACK_INDEX_FILE="${SCRIPT_DIR}/pack-index.json"',
        'START_FILE="${SCRIPT_DIR}/START_HERE.md"',
        f'STARTER_FILE="${{SCRIPT_DIR}}/{STARTER_BRIEF_MD_FILE}"',
        'NEXT_FILE="${SCRIPT_DIR}/next-step.md"',
        'QUICK_FILE="${SCRIPT_DIR}/quick-install.md"',
