        f'echo "Mode: {str(pack.get("mode") or "")}"',
        f'echo "Target chapter: {str(pack.get("target_chapter") or "")}"',
        'echo ""',
        'echo "This launcher opens local pack files only."',
        'echo "It does not install, change MCP config, write .novel-agent/, run checks, or record desktop-client evidence."',
        'echo ""',
        'if [ ! -f "$FIRST_THREE_FILE" ]; then',
        f'  echo "Missing {DESKTOP_FIRST_THREE_HTML_FILE} next to open-local.sh: $FIRST_THREE_FILE" >&2',
        "  exit 1",
        "fi",
        'if [ ! -f "$INDEX_FILE" ]; then',
        '  echo "Missing index.html next to open-local.sh: $INDEX_FILE" >&2',
        "  exit 1",
        "fi",
        "",
        'echo "Primary file:"',
        'echo "$FIRST_THREE_FILE"',
        'echo ""',
        'echo "Detailed dashboard:"',
        'echo "$INDEX_FILE"',
        'echo ""',
        'echo "First-step files:"',
        'for file in "$FIRST_THREE_FILE" "$USER_STEPS_FILE" "$PACK_INDEX_FILE" "$START_FILE" "$STARTER_FILE" "$NEXT_FILE" "$QUICK_FILE"; do',
        '  if [ -f "$file" ]; then',
        '    echo "- $file"',
