def render_desktop_pack_local_checks_cmd(pack: dict[str, Any]) -> str:
    commands = [
        (
            "local MCP setup",
            desktop_pack_windows_cli_command(
                "desktop-verify",
                [
                    '"%PROJECT_DIR%"',
                    "--platform",
                    '"%PLATFORM_NAME%"',
                    "--mode",
                    '"%MODE_NAME%"',
                    "--start-mcp-test",
                    "--format",
                    "markdown",
                    *(["--install-config", '"%CONFIG_PATH%"'] if str(pack.get("config_path") or "").strip() else []),
                    *(["--install-target", '"%INSTALL_TARGET%"'] if str(pack.get("install_target") or "").strip() else []),
                ],
            ),
        ),
        (
            "project status",
            desktop_pack_windows_cli_command(
                "project-status",
                ['"%PROJECT_DIR%"', "--platform", '"%PLATFORM_NAME%"', "--format", "markdown"],
            ),
        ),
        (
            "continuity audit",
            desktop_pack_windows_cli_command(
                "continuity-audit",
                ['"%PROJECT_DIR%"', "--chapter", '"%TARGET_CHAPTER%"', "--platform", '"%PLATFORM_NAME%"', "--format", "markdown"],
            ),
        ),
        (
            "chapter session",
            desktop_pack_windows_cli_command(
                "prepare-session",
                ['"%PROJECT_DIR%"', "--chapter", '"%TARGET_CHAPTER%"', "--platform", '"%PLATFORM_NAME%"', "--mode", '"%MODE_NAME%"', "--format", "markdown"],
            ),
        ),
        (
            "desktop checklist",
            desktop_pack_windows_cli_command(
                "desktop-checklist",
                [
                    '"%PROJECT_DIR%"',
                    "--platform",
                    '"%PLATFORM_NAME%"',
                    "--mode",
                    '"%MODE_NAME%"',
                    "--chapter",
                    '"%TARGET_CHAPTER%"',
                    "--format",
                    "markdown",
                    *(["--install-config", '"%CONFIG_PATH%"'] if str(pack.get("config_path") or "").strip() else []),
                    *(["--install-target", '"%INSTALL_TARGET%"'] if str(pack.get("install_target") or "").strip() else []),
                ],
            ),
        ),
    ]
    lines = [
        *desktop_pack_windows_vars(pack),
        "set PASS_COUNT=0",
        "set FAIL_COUNT=0",
        "",
        'echo Long Novel Agent Windows local desktop checks',
        'echo Project: "%PROJECT_DIR%"',
        'echo Platform: "%PLATFORM_NAME%"',
        'echo Mode: "%MODE_NAME%"',
        'echo Target chapter: "%TARGET_CHAPTER%"',
        "",
        *desktop_pack_windows_python_required_lines(),
        "",
    ]
    for label, command in commands:
        lines.extend(
            [
                "echo.",
                f"echo ==> {label}",
                f"echo {command}",
                command,
                "if errorlevel 1 (",
                f"  echo [FAIL] {label}",
                "  set /a FAIL_COUNT+=1",
                ") else (",
                f"  echo [PASS] {label}",
                "  set /a PASS_COUNT+=1",
                ")",
            ]
        )
    lines.extend(
        [
            "echo.",
            'echo Summary: %PASS_COUNT% passed, %FAIL_COUNT% failed',
            'echo This script does not prove GUI desktop-client MCP access. Use real-client-walkthrough.md and client-prompts.md for GUI evidence.',
            'echo If a local check failed, open troubleshooting.md for the matching symptom.',
            'if not "%FAIL_COUNT%"=="0" exit /b 1',
            "exit /b 0",
        ]
    )
    return "\r\n".join(lines).rstrip() + "\r\n"


def ps_value(value: object) -> str:
    return "'" + str(value or "").replace("'", "''") + "'"


def ps_array(name: str, values: list[str]) -> list[str]:
    lines = [f"${name} = @("]
    for index, value in enumerate(values):
        suffix = "," if index < len(values) - 1 else ""
        lines.append(f"  {value}{suffix}")
    lines.append(")")
    return lines


def desktop_pack_powershell_vars(pack: dict[str, Any]) -> list[str]:
    return [
        "$ErrorActionPreference = 'Stop'",
        "$ScriptDir = Split-Path -Parent $PSCommandPath",
        f"$CliPath = {ps_value(kit_root() / 'cli.py')}",
        f"$InstallPath = {ps_value(kit_root() / 'install.py')}",
        f"$ProjectDir = {ps_value(pack.get('project_dir'))}",
        f"$PlatformName = {ps_value(pack.get('platform') or 'codex')}",
        f"$ModeName = {ps_value(pack.get('mode') or 'read-only')}",
        f"$TargetChapter = {ps_value(pack.get('target_chapter') or 1)}",
        f"$ConfigPath = {ps_value(pack.get('config_path') or '')}",
        f"$InstallTarget = {ps_value(pack.get('install_target') or '')}",
        f"$SourceName = {ps_value(pack.get('source') or 'auto')}",
        f"$InstallPlatform = {ps_value(install_platform_for_agent(str(pack.get('platform') or 'codex')))}",
        "",
        "function Resolve-PythonCommand {",
        "  if ($env:PYTHON_BIN) { return @($env:PYTHON_BIN) }",
        "  if (Get-Command python -ErrorAction SilentlyContinue) { return @('python') }",
        "  if (Get-Command py -ErrorAction SilentlyContinue) { return @('py', '-3') }",
        "  return @()",
        "}",
        "",
        "$script:PythonCommand = @(Resolve-PythonCommand)",
        "",
        "function Format-PythonCommand {",
        "  if (-not $script:PythonCommand -or $script:PythonCommand.Count -eq 0) { return 'not found' }",
        "  return ($script:PythonCommand -join ' ')",
        "}",
        "",
        "function Assert-PythonCommand {",
        "  if (-not $script:PythonCommand -or $script:PythonCommand.Count -eq 0) {",
        "    Write-Host 'Cannot find Python 3. Install Python 3 or set PYTHON_BIN=python before running this command.'",
        "    exit 1",
        "  }",
        "}",
        "",
        "function Invoke-LongNovelPython {",
        "  param([string[]]$Arguments)",
        "  Assert-PythonCommand",
        "  $exe = $script:PythonCommand[0]",
        "  $prefix = @()",
        "  if ($script:PythonCommand.Count -gt 1) {",
        "    $prefix = $script:PythonCommand[1..($script:PythonCommand.Count - 1)]",
        "  }",
        "  & $exe @prefix @Arguments",
        "  return $LASTEXITCODE",
        "}",
    ]


def desktop_pack_powershell_cli_args(subcommand: str, args: list[str]) -> list[str]:
    return ["$CliPath", ps_value(subcommand), *args]


def desktop_pack_powershell_install_args(extra_flags: list[str]) -> list[str]:
    return ["$InstallPath", *extra_flags]


def desktop_pack_powershell_plan_lines(command_var: str, *, apply_label: str) -> list[str]:
    return [
        f"Write-Host ('PowerShell command: ' + (Format-PythonCommand) + ' ' + (${command_var} -join ' '))",
        "Write-Host ('Python command: ' + (Format-PythonCommand))",
        "Write-Host ''",
        f"Write-Host '{apply_label}'",
    ]


def desktop_pack_powershell_usage(script_name: str) -> str:
    return f"Usage: powershell -ExecutionPolicy Bypass -File .\\{script_name} [--plan|--dry-run|--yes]"


def render_desktop_pack_install_local_ps1(pack: dict[str, Any]) -> str:
    args = [
        "$ProjectDir",
        ps_value("--platform"),
        "$PlatformName",
        ps_value("--mode"),
        "$ModeName",
        ps_value("--chapter"),
        "$TargetChapter",
        ps_value("--apply"),
        ps_value("--format"),
        ps_value("markdown"),
    ]
    if str(pack.get("config_path") or "").strip():
        args.extend([ps_value("--install-config"), "$ConfigPath"])
    if str(pack.get("install_target") or "").strip():
        args.extend([ps_value("--install-target"), "$InstallTarget"])
    if str(pack.get("source") or "auto").strip().lower() != "auto":
        args.extend([ps_value("--source"), "$SourceName"])
    lines = [
        *desktop_pack_powershell_vars(pack),
        "$CheckScript = Join-Path $ScriptDir 'local-checks.ps1'",
        *ps_array("ApplyArgs", desktop_pack_powershell_cli_args("desktop-bootstrap", args)),
        "$ModeArg = if ($args.Count -eq 0) { '--plan' } else { [string]$args[0] }",
        "switch ($ModeArg.ToLowerInvariant()) {",
        "  '--plan' {",
        "    Write-Host 'Long Novel Agent PowerShell local installer'",
        "    Write-Host ''",
        "    Write-Host 'Default mode is preview only. No files are written unless you pass --yes.'",
        "    Write-Host ''",
        "    Write-Host 'This may write when applied:'",
        "    Write-Host '- Installed skill directory'",
        "    Write-Host '- Desktop MCP config'",
        "    Write-Host '- .novel-agent/ project state'",
        "    Write-Host ''",
        *desktop_pack_powershell_plan_lines("ApplyArgs", apply_label="To apply after review: powershell -ExecutionPolicy Bypass -File .\\install-local.ps1 --yes"),
        "    Write-Host 'After applying, the script runs local-checks.ps1 when available.'",
        "    Write-Host 'This script does not prove GUI desktop-client MCP access.'",
        "    exit 0",
        "  }",
        "  '--dry-run' {",
        "    & $PSCommandPath --plan",
        "    exit $LASTEXITCODE",
        "  }",
        "  '--yes' {",
        "    Assert-PythonCommand",
        "    if (-not (Test-Path $CliPath)) {",
        "      Write-Host \"Cannot find long-novel-agent CLI: $CliPath\"",
        "      exit 1",
        "    }",
        "    Write-Host 'Long Novel Agent PowerShell local installer'",
        "    Write-Host 'Executing reviewed desktop-bootstrap --apply command.'",
        "    Write-Host ('PowerShell command: ' + (Format-PythonCommand) + ' ' + ($ApplyArgs -join ' '))",
        "    $status = Invoke-LongNovelPython -Arguments $ApplyArgs",
        "    if ($status -ne 0) {",
        "      Write-Host 'desktop-bootstrap failed. Open troubleshooting.md before manual config edits.'",
        "      exit $status",
        "    }",
        "    Write-Host 'desktop-bootstrap completed.'",
        "    if (Test-Path $CheckScript) {",
        "      Write-Host 'Running local-checks.ps1'",
        "      & powershell -ExecutionPolicy Bypass -File $CheckScript",
        "      if ($LASTEXITCODE -ne 0) {",
        "        Write-Host 'local-checks.ps1 failed. Open troubleshooting.md for the matching symptom.'",
        "        exit $LASTEXITCODE",
        "      }",
        "    } else {",
        "      Write-Host 'local-checks.ps1 was not found next to install-local.ps1; skip local checks.'",
        "    }",
        "    Write-Host 'This script does not prove GUI desktop-client MCP access. Use real-client-walkthrough.md and client-prompts.md for GUI evidence.'",
        "    exit 0",
        "  }",
        "  '--help' {",
        f"    Write-Host {ps_value(desktop_pack_powershell_usage('install-local.ps1'))}",
        "    exit 0",
        "  }",
        "  '-h' {",
        f"    Write-Host {ps_value(desktop_pack_powershell_usage('install-local.ps1'))}",
        "    exit 0",
        "  }",
        "  default {",
        f"    Write-Host {ps_value(desktop_pack_powershell_usage('install-local.ps1'))}",
        "    exit 2",
        "  }",
        "}",
    ]
    return "\r\n".join(lines).rstrip() + "\r\n"


