def render_desktop_pack_local_checks_ps1(pack: dict[str, Any]) -> str:
    commands = [
        (
            "local MCP setup",
            desktop_pack_powershell_cli_args(
                "desktop-verify",
                [
                    "$ProjectDir",
                    ps_value("--platform"),
                    "$PlatformName",
                    ps_value("--mode"),
                    "$ModeName",
                    ps_value("--start-mcp-test"),
                    ps_value("--format"),
                    ps_value("markdown"),
                    *([ps_value("--install-config"), "$ConfigPath"] if str(pack.get("config_path") or "").strip() else []),
                    *([ps_value("--install-target"), "$InstallTarget"] if str(pack.get("install_target") or "").strip() else []),
                ],
            ),
        ),
        (
            "project status",
            desktop_pack_powershell_cli_args("project-status", ["$ProjectDir", ps_value("--platform"), "$PlatformName", ps_value("--format"), ps_value("markdown")]),
        ),
        (
            "continuity audit",
            desktop_pack_powershell_cli_args("continuity-audit", ["$ProjectDir", ps_value("--chapter"), "$TargetChapter", ps_value("--platform"), "$PlatformName", ps_value("--format"), ps_value("markdown")]),
        ),
        (
            "chapter session",
            desktop_pack_powershell_cli_args(
                "prepare-session",
                ["$ProjectDir", ps_value("--chapter"), "$TargetChapter", ps_value("--platform"), "$PlatformName", ps_value("--mode"), "$ModeName", ps_value("--format"), ps_value("markdown")],
            ),
        ),
        (
            "desktop checklist",
            desktop_pack_powershell_cli_args(
                "desktop-checklist",
                [
                    "$ProjectDir",
                    ps_value("--platform"),
                    "$PlatformName",
                    ps_value("--mode"),
                    "$ModeName",
                    ps_value("--chapter"),
                    "$TargetChapter",
                    ps_value("--format"),
                    ps_value("markdown"),
                    *([ps_value("--install-config"), "$ConfigPath"] if str(pack.get("config_path") or "").strip() else []),
                    *([ps_value("--install-target"), "$InstallTarget"] if str(pack.get("install_target") or "").strip() else []),
                ],
            ),
        ),
    ]
    lines = [
        *desktop_pack_powershell_vars(pack),
        "$PassCount = 0",
        "$FailCount = 0",
        "$Checks = @(",
    ]
    for index, (label, args) in enumerate(commands):
        suffix = "," if index < len(commands) - 1 else ""
        lines.extend(
            [
                "  @{",
                f"    Label = {ps_value(label)}",
                "    Arguments = @(",
                *[f"      {value}{',' if arg_index < len(args) - 1 else ''}" for arg_index, value in enumerate(args)],
                "    )",
                f"  }}{suffix}",
            ]
        )
    lines.extend(
        [
            ")",
            "",
            "Assert-PythonCommand",
            "Write-Host 'Long Novel Agent PowerShell local desktop checks'",
            "Write-Host \"Project: $ProjectDir\"",
            "Write-Host \"Platform: $PlatformName\"",
            "Write-Host \"Mode: $ModeName\"",
            "Write-Host \"Target chapter: $TargetChapter\"",
            "foreach ($Check in $Checks) {",
            "  Write-Host ''",
            "  Write-Host \"==> $($Check.Label)\"",
            "  Write-Host ('PowerShell command: ' + (Format-PythonCommand) + ' ' + ($Check.Arguments -join ' '))",
            "  $status = Invoke-LongNovelPython -Arguments $Check.Arguments",
            "  if ($status -ne 0) {",
            "    Write-Host \"[FAIL] $($Check.Label)\"",
            "    $FailCount += 1",
            "  } else {",
            "    Write-Host \"[PASS] $($Check.Label)\"",
            "    $PassCount += 1",
            "  }",
            "}",
            "Write-Host ''",
            "Write-Host \"Summary: $PassCount passed, $FailCount failed\"",
            "Write-Host 'This script does not prove GUI desktop-client MCP access. Use real-client-walkthrough.md and client-prompts.md for GUI evidence.'",
            "Write-Host 'If a local check failed, open troubleshooting.md for the matching symptom.'",
            "if ($FailCount -ne 0) { exit 1 }",
            "exit 0",
        ]
    )
    return "\r\n".join(lines).rstrip() + "\r\n"


def render_desktop_pack_install_local_markdown(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    bootstrap = str(commands.get("desktop_bootstrap_apply") or "").strip()
    lines = [
        "# Install Local",
        "",
        "Use this when the user wants a guarded terminal script for local desktop-agent setup.",
        "",
        "## Target",
        f"- Project directory: `{pack.get('project_dir')}`",
        f"- Platform: {pack.get('platform')}",
        f"- Mode: {pack.get('mode')}",
        f"- Target chapter: {pack.get('target_chapter')}",
        f"- MCP config: `{pack.get('config_path') or 'not configured in this pack'}`",
        f"- Install target: `{pack.get('install_target') or 'default skill install target'}`",
        "",
        "## Preview First",
        "",
        "```bash",
        "bash install-local.sh",
        "```",
        "",
        "On macOS, double-click `install-local.command` to open this preview in Terminal.",
        "",
        "Default mode prints the command and exits without writing files.",
        "",
        "## Apply",
        "",
        "```bash",
        "bash install-local.sh --yes",
        "```",
        "",
        "The macOS launcher asks you to type `YES` before it runs this apply step.",
        "",
        "The script calls this command:",
        "",
        "```bash",
        bootstrap or "See bootstrap-plan.md",
        "```",
        "",
        "With `--yes`, the command may write:",
        "- Installed skill directory.",
        "- Desktop MCP config for the selected local client.",
        "- `.novel-agent/` project state through quickstart or import.",
        "- Optional generated local guide files if the bootstrap plan includes them.",
        "",
        "After the bootstrap command succeeds, the script runs the `local-checks.sh` file next to `install-local.sh` when that file exists. This works even if the script is launched by absolute path from another directory.",
        "",
        "## Boundaries",
        "- This script is for local desktop agents that can use stdio MCP or CLI.",
        "- It does not prove the real GUI desktop client has loaded MCP tools.",
        "- It does not record `desktop_verifications.jsonl`.",
        "- Remote connector-only platforms need a separate wrapper.",
        "- Review `troubleshooting.md` before editing config files by hand when the script fails.",
    ]
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_install_local_script(pack: dict[str, Any]) -> str:
    commands = pack.get("commands") if isinstance(pack.get("commands"), dict) else {}
    bootstrap = str(commands.get("desktop_bootstrap_apply") or "").strip()
    lines = [
        "#!/usr/bin/env bash",
        "set -u",
        "",
        'SCRIPT_DIR="$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)"',
        f"APPLY_COMMAND={shlex.quote(bootstrap)}",
        'CHECK_SCRIPT="${SCRIPT_DIR}/local-checks.sh"',
        "",
        "print_plan() {",
        '  echo "Long Novel Agent local installer"',
        '  echo ""',
        '  echo "Default mode is preview only. No files are written unless you pass --yes."',
        '  echo ""',
        '  echo "This may write when applied:"',
        '  echo "- Installed skill directory"',
        '  echo "- Desktop MCP config"',
        '  echo "- .novel-agent/ project state"',
        '  echo ""',
        '  echo "Apply command:"',
        '  if [ -n "$APPLY_COMMAND" ]; then',
        '    echo "$APPLY_COMMAND"',
        "  else",
        '    echo "No desktop-bootstrap command was generated in this pack."',
        "  fi",
        '  echo ""',
        '  echo "To apply after review: bash install-local.sh --yes"',
        '  echo "After applying, the script runs the local-checks.sh file next to install-local.sh when available."',
        '  echo "This script does not prove GUI desktop-client MCP access."',
        "}",
        "",
        'MODE="${1:-}"',
        'if [ -z "$MODE" ]; then',
        '  MODE="--plan"',
        "fi",
        "",
        'case "$MODE" in',
        "  --plan|--dry-run)",
        "    print_plan",
        "    exit 0",
        "    ;;",
        "  --yes)",
        '    if [ -z "$APPLY_COMMAND" ]; then',
        '      echo "No desktop-bootstrap command was generated in this pack." >&2',
        "      exit 1",
        "    fi",
        '    echo "Long Novel Agent local installer"',
        '    echo "Executing reviewed desktop-bootstrap --apply command."',
        '    echo "$APPLY_COMMAND"',
        '    if sh -c "$APPLY_COMMAND"; then',
        '      echo "desktop-bootstrap completed."',
        "    else",
        "      status=$?",
        '      echo "desktop-bootstrap failed with $status. Open troubleshooting.md before manual config edits." >&2',
        "      exit $status",
        "    fi",
        '    if [ -f "$CHECK_SCRIPT" ]; then',
        '      echo ""',
        '      echo "Running $CHECK_SCRIPT"',
        '      if bash "$CHECK_SCRIPT"; then',
        '        echo "local-checks.sh completed."',
        "      else",
        "        status=$?",
        '        echo "local-checks.sh failed with $status. Open troubleshooting.md for the matching symptom." >&2',
        "        exit $status",
        "      fi",
        "    else",
        '      echo "local-checks.sh was not found next to install-local.sh; skip local checks."',
        "    fi",
        '    echo "This script does not prove GUI desktop-client MCP access. Use real-client-walkthrough.md and client-prompts.md for GUI evidence."',
        "    exit 0",
        "    ;;",
        "  --help|-h)",
        '    echo "Usage: bash install-local.sh [--plan|--dry-run|--yes]"',
        "    exit 0",
        "    ;;",
        "  *)",
        '    echo "Usage: bash install-local.sh [--plan|--dry-run|--yes]" >&2',
        "    exit 2",
        "    ;;",
        "esac",
    ]
    return "\n".join(lines).rstrip() + "\n"


