def write_text_pack_file(path: Path, content: str, *, force: bool) -> dict[str, Any]:
    existed = path.exists()
    if existed and not force:
        raise KitError(f"Desktop pack file already exists: {path}")
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
    return {"path": str(path), "bytes": path.stat().st_size, "existed": existed}


def write_json_pack_file(path: Path, payload: Any, *, force: bool) -> dict[str, Any]:
    existed = path.exists()
    if existed and not force:
        raise KitError(f"Desktop pack file already exists: {path}")
    write_json(path, payload)
    return {"path": str(path), "bytes": path.stat().st_size, "existed": existed}


def normalize_handoff_target_os(value: str = "auto") -> str:
    selected = (value or "auto").strip().lower()
    if selected == "auto":
        if os.name == "nt":
            return "windows"
        if sys.platform == "darwin":
            return "macos"
        return "linux"
    if selected not in {"macos", "linux", "windows"}:
        raise KitError(f"Unsupported handoff target OS: {value}")
    return selected


def standalone_binary_name(name: str, target_os: str) -> str:
    suffix = ".exe" if target_os == "windows" else ""
    return f"{name}{suffix}"


def standalone_runtime_output_path(output_dir: str = "") -> Path:
    raw = str(output_dir or "").strip()
    if raw:
        path = Path(raw).expanduser()
        if not path.is_absolute():
            path = Path.cwd() / path
        return path.resolve()
    return (kit_root() / "standalone-runtime").resolve()


def pyinstaller_available() -> bool:
    return importlib.util.find_spec("PyInstaller") is not None


def standalone_runtime_data_specs() -> list[tuple[Path, str]]:
    root = kit_root()
    specs = [
        (root / "schemas", "schemas"),
        (root / "assets", "assets"),
        (root / "agents", "agents"),
        (root / "SKILL.md", "SKILL.md"),
        (root / "cli.py", "cli.py"),
        (root / "server.py", "server.py"),
        (root / "install.py", "install.py"),
    ]
    return [(source, dest) for source, dest in specs if source.exists()]


def pyinstaller_add_data_value(source: Path, dest: str) -> str:
    return f"{source}{os.pathsep}{dest}"


def build_standalone_runtime(
    *,
    output_dir: str = "",
    target_os: str = "auto",
    apply: bool = False,
    force: bool = False,
) -> dict[str, Any]:
    selected_os = normalize_handoff_target_os(target_os)
    out_dir = standalone_runtime_output_path(output_dir)
    build_dir = out_dir / "_pyinstaller-build"
    spec_dir = out_dir / "_pyinstaller-spec"
    cli_name = standalone_binary_name(STANDALONE_CLI_NAME, selected_os)
    mcp_name = standalone_binary_name(STANDALONE_MCP_NAME, selected_os)
    entries = [
        {
            "id": "cli",
            "name": STANDALONE_CLI_NAME,
            "script": kit_root() / "cli.py",
            "output": out_dir / cli_name,
        },
        {
            "id": "mcp",
            "name": STANDALONE_MCP_NAME,
            "script": kit_root() / "server.py",
            "output": out_dir / mcp_name,
        },
    ]
    commands: list[dict[str, Any]] = []
    data_specs = standalone_runtime_data_specs()
    for entry in entries:
        command = [
            sys.executable,
            "-m",
            "PyInstaller",
            "--onefile",
            "--clean",
            "--name",
            entry["name"],
            "--distpath",
            out_dir,
            "--workpath",
            build_dir / entry["id"],
            "--specpath",
            spec_dir,
        ]
        for source, dest in data_specs:
            command.extend(["--add-data", pyinstaller_add_data_value(source, dest)])
        if force:
            command.append("--noconfirm")
        command.append(entry["script"])
        commands.append(
            {
                "id": entry["id"],
                "name": entry["name"],
                "script": str(entry["script"]),
                "output": str(entry["output"]),
                "command": shell_command(command),
                "command_args": [str(part) for part in command],
                "data": [{"source": str(source), "dest": dest} for source, dest in data_specs],
            }
        )
    available = pyinstaller_available()
    report: dict[str, Any] = {
        "ok": True,
        "type": "standalone_runtime_build",
        "generated_at": now_iso(),
        "kit_version": KIT_VERSION,
        "applied": bool(apply),
        "target_os": selected_os,
        "output_dir": str(out_dir),
        "pyinstaller_available": available,
        "commands": commands,
        "runtime_files": {
            "cli": str(out_dir / cli_name),
            "mcp": str(out_dir / mcp_name),
        },
        "notes": [
            "Builds two local executables: long-novel-agent for CLI commands and long-novel-agent-mcp for stdio MCP.",
            "The generated runtime is local-only and needs no server.",
            "Cross-building is not guaranteed; build on each target OS when possible.",
        ],
    }
    if not apply:
        report["status"] = "plan_only"
        report["next_actions"] = [
            "Install PyInstaller in a build environment if it is not available.",
            "Run this command again with --apply to create the runtime files.",
            "Then pass --runtime-dir to desktop-handoff-bundle.",
        ]
        return report
    if not available:
        report["ok"] = False
        report["status"] = "missing_pyinstaller"
        report["next_actions"] = [
            "Install PyInstaller in the build environment, or provide existing runtime files with desktop-handoff-bundle --runtime-cli-bin and --runtime-mcp-bin.",
        ]
        return report
    out_dir.mkdir(parents=True, exist_ok=True)
    if force:
        for entry in entries:
            output = Path(entry["output"])
            if output.exists():
                output.unlink()
        if build_dir.exists():
            shutil.rmtree(build_dir)
        if spec_dir.exists():
            shutil.rmtree(spec_dir)
    else:
        existing = [str(entry["output"]) for entry in entries if Path(entry["output"]).exists()]
        if existing:
            raise KitError("Standalone runtime output already exists; use --force to replace: " + ", ".join(existing))
    runs: list[dict[str, Any]] = []
    for item in commands:
        proc = subprocess.run(item["command_args"], text=True, capture_output=True, check=False)
        runs.append(
            {
                "id": item["id"],
                "returncode": proc.returncode,
                "stdout_tail": proc.stdout[-2000:],
                "stderr_tail": proc.stderr[-2000:],
                "output_exists": Path(item["output"]).exists(),
            }
        )
        if proc.returncode != 0:
            break
    for entry in entries:
        output = Path(entry["output"])
        if output.exists() and selected_os != "windows":
            output.chmod(output.stat().st_mode | 0o755)
    report["runs"] = runs
    report["ok"] = bool(runs) and all(item.get("returncode") == 0 and item.get("output_exists") for item in runs)
    report["status"] = "built" if report["ok"] else "failed"
    report["next_actions"] = (
        ["Use desktop-handoff-bundle --runtime-dir with this output directory."]
        if report["ok"]
        else ["Inspect stdout_tail and stderr_tail for the failed PyInstaller command."]
    )
    return report


def desktop_handoff_bundle_output_path(project_dir: str | Path, output_dir: str = "") -> Path:
    project = project_root(project_dir)
    raw = str(output_dir or "").strip()
    if raw:
        path = Path(raw).expanduser()
        if not path.is_absolute():
            path = project.parent / path
        return path.resolve()
    return (project.parent / HANDOFF_BUNDLE_DIR_NAME).resolve()


def resolve_runtime_source(
    runtime_dir: str = "",
    runtime_bin: str = "",
    *,
    base_name: str,
    target_os: str,
) -> Path | None:
    raw_bin = str(runtime_bin or "").strip()
    if raw_bin:
        path = Path(raw_bin).expanduser()
        if not path.is_absolute():
            path = Path.cwd() / path
        return path.resolve()
    raw_dir = str(runtime_dir or "").strip()
    if not raw_dir:
        return None
    directory = Path(raw_dir).expanduser()
    if not directory.is_absolute():
        directory = Path.cwd() / directory
    directory = directory.resolve()
    names = [
        standalone_binary_name(base_name, target_os),
        base_name,
        f"{base_name}.exe",
    ]
    for name in names:
        candidate = directory / name
        if candidate.exists() and candidate.is_file():
            return candidate
    return None


def copy_runtime_binary(source: Path | None, target: Path, *, force: bool) -> dict[str, Any]:
    if source is None:
        return {
            "present": False,
            "source": "",
            "target": str(target),
            "status": "missing",
        }
    if not source.exists() or not source.is_file():
        raise KitError(f"Runtime binary does not exist: {source}")
    if target.exists() and not force:
        raise KitError(f"Runtime target already exists: {target}")
    target.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(source, target)
    if os.name != "nt":
        target.chmod(target.stat().st_mode | 0o755)
    return {
        "present": True,
        "source": str(source),
        "target": str(target),
        "bytes": target.stat().st_size,
        "sha256": local_file_sha256(target),
        "status": "copied",
    }


def path_is_relative_to(path: Path, parent: Path) -> bool:
    try:
        path.resolve().relative_to(parent.resolve())
        return True
    except ValueError:
        return False


def copy_project_snapshot_for_handoff(source: Path, target: Path, *, bundle_dir: Path) -> dict[str, Any]:
    excluded_names = {
        ".git",
        ".hg",
        ".svn",
        ".venv",
        "venv",
        "node_modules",
        "__pycache__",
        ".pytest_cache",
        ".mypy_cache",
        ".ruff_cache",
        "dist",
        "build",
        "release",
        HANDOFF_BUNDLE_DIR_NAME,
        "long-novel-agent-desktop-pack",
    }
    copied_files: list[dict[str, Any]] = []
    skipped: list[dict[str, str]] = []
    target.mkdir(parents=True, exist_ok=True)
    for item in sorted(source.rglob("*")):
        resolved = item.resolve()
        if path_is_relative_to(resolved, bundle_dir):
            skipped.append({"path": str(item), "reason": "inside_bundle"})
            continue
        relative = item.relative_to(source)
        if any(part in excluded_names for part in relative.parts):
            if item.is_dir():
                continue
            skipped.append({"path": relative.as_posix(), "reason": "excluded_name"})
            continue
        if item.is_symlink():
            skipped.append({"path": relative.as_posix(), "reason": "symlink"})
            continue
        if item.is_dir():
            (target / relative).mkdir(parents=True, exist_ok=True)
            continue
        if not item.is_file():
            skipped.append({"path": relative.as_posix(), "reason": "not_regular_file"})
            continue
        destination = target / relative
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(item, destination)
        copied_files.append({"name": relative.as_posix(), "bytes": destination.stat().st_size})
    return {
        "source": str(source),
        "target": str(target),
        "file_count": len(copied_files),
        "bytes": sum(int(item.get("bytes") or 0) for item in copied_files),
        "skipped_count": len(skipped),
        "skipped": skipped[:200],
        "files": copied_files[:500],
    }


def handoff_bundle_file_entries(bundle_dir: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for path in sorted(bundle_dir.rglob("*")):
        if not path.is_file():
            continue
        relative = path.relative_to(bundle_dir).as_posix()
        rows.append(
            {
                "name": relative,
                "bytes": path.stat().st_size,
                "sha256": local_file_sha256(path),
            }
        )
    return rows


