def render_handoff_bundle_start_script(bundle: dict[str, Any]) -> str:
    cli_name = str(bundle.get("runtime_cli_name") or STANDALONE_CLI_NAME)
    mcp_name = str(bundle.get("runtime_mcp_name") or STANDALONE_MCP_NAME)
    platform = shlex.quote(str(bundle.get("platform") or "codex"))
    mode = shlex.quote(str(bundle.get("mode") or "read-only"))
    tool_profile = shlex.quote(str(bundle.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE))
    chapter = str(int(bundle.get("target_chapter") or 1))
    return f"""#!/usr/bin/env bash
set -u

BUNDLE_DIR="$(cd "$(dirname "$0")" && pwd)"
PROJECT_DIR="$BUNDLE_DIR/{HANDOFF_BUNDLE_PROJECT_DIR}"
PACK_DIR="$BUNDLE_DIR/{HANDOFF_BUNDLE_PACK_DIR}"
CLI_BIN="$BUNDLE_DIR/{HANDOFF_BUNDLE_RUNTIME_DIR}/{cli_name}"
MCP_BIN="$BUNDLE_DIR/{HANDOFF_BUNDLE_RUNTIME_DIR}/{mcp_name}"

echo "Long Novel Agent handoff bundle"
echo "Bundle: $BUNDLE_DIR"
echo "Project: $PROJECT_DIR"
echo "Pack: $PACK_DIR"

if [ ! -x "$CLI_BIN" ]; then
  echo "Missing executable CLI: $CLI_BIN"
  echo "This bundle needs runtime/{cli_name} before it can run without Python."
  exit 2
fi

mkdir -p "$BUNDLE_DIR/mcp-configs/current"
cat > "$BUNDLE_DIR/mcp-configs/current/codex-read-only.toml" <<EOF
[mcp_servers.long-novel-agent]
command = "$MCP_BIN"
args = ["--read-only", "--tool-profile", {json.dumps(str(bundle.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE))}]
EOF

cat > "$BUNDLE_DIR/mcp-configs/current/generic-read-only.json" <<EOF
{{
  "mcpServers": {{
    "long-novel-agent": {{
      "command": "$MCP_BIN",
      "args": ["--read-only", "--tool-profile", {json.dumps(str(bundle.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE))}]
    }}
  }}
}}
EOF

echo
echo "MCP executable:"
echo "$MCP_BIN"
echo "Current snippets:"
echo "$BUNDLE_DIR/mcp-configs/current"
echo
echo "Refreshing pack paths with bundled CLI..."
"$CLI_BIN" desktop-pack "$PROJECT_DIR" --platform {platform} --mode {mode} --tool-profile {tool_profile} --chapter {chapter} --output-dir "$PACK_DIR" --force --format markdown || true
echo
echo "Checking local bundle..."
"$CLI_BIN" doctor "$PROJECT_DIR" || true
"$CLI_BIN" desktop-pack-readiness "$PACK_DIR" --format markdown || true
echo
echo "Preparing chapter session..."
"$CLI_BIN" prepare-session "$PROJECT_DIR" --chapter {chapter} --platform {platform} --mode {mode} --format markdown || true
echo
echo "Next file for the desktop agent: $BUNDLE_DIR/agent-read-me-first.md"
"""


def render_handoff_bundle_macos_command() -> str:
    return """#!/usr/bin/env bash
DIR="$(cd "$(dirname "$0")" && pwd)"
exec /bin/bash "$DIR/START_HERE.sh"
"""


def render_handoff_bundle_ps1(bundle: dict[str, Any]) -> str:
    cli_name = str(bundle.get("runtime_cli_name") or f"{STANDALONE_CLI_NAME}.exe")
    mcp_name = str(bundle.get("runtime_mcp_name") or f"{STANDALONE_MCP_NAME}.exe")
    platform = str(bundle.get("platform") or "codex")
    mode = str(bundle.get("mode") or "read-only")
    tool_profile = str(bundle.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE)
    chapter = str(int(bundle.get("target_chapter") or 1))
    read_only_args = json.dumps(["--read-only", "--tool-profile", tool_profile], ensure_ascii=False)
    return f"""$ErrorActionPreference = "Continue"
$BundleDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$ProjectDir = Join-Path $BundleDir "{HANDOFF_BUNDLE_PROJECT_DIR}"
$PackDir = Join-Path $BundleDir "{HANDOFF_BUNDLE_PACK_DIR}"
$CliBin = Join-Path $BundleDir "{HANDOFF_BUNDLE_RUNTIME_DIR}\\{cli_name}"
$McpBin = Join-Path $BundleDir "{HANDOFF_BUNDLE_RUNTIME_DIR}\\{mcp_name}"
if (!(Test-Path $CliBin)) {{
  $CliBin = Join-Path $BundleDir "{HANDOFF_BUNDLE_RUNTIME_DIR}\\{STANDALONE_CLI_NAME}"
}}
if (!(Test-Path $McpBin)) {{
  $McpBin = Join-Path $BundleDir "{HANDOFF_BUNDLE_RUNTIME_DIR}\\{STANDALONE_MCP_NAME}"
}}

Write-Host "Long Novel Agent handoff bundle"
Write-Host "Bundle: $BundleDir"
Write-Host "Project: $ProjectDir"
Write-Host "Pack: $PackDir"

if (!(Test-Path $CliBin)) {{
  Write-Error "Missing executable CLI: $CliBin"
  exit 2
}}

$CurrentConfigDir = Join-Path $BundleDir "mcp-configs\\current"
New-Item -ItemType Directory -Force -Path $CurrentConfigDir | Out-Null
$Generic = @{{
  mcpServers = @{{
    "long-novel-agent" = @{{
      command = $McpBin
      args = {read_only_args}
    }}
  }}
}} | ConvertTo-Json -Depth 6
$Generic | Set-Content -Encoding UTF8 (Join-Path $CurrentConfigDir "generic-read-only.json")

Write-Host ""
Write-Host "MCP executable:"
Write-Host $McpBin
Write-Host "Current snippets:"
Write-Host $CurrentConfigDir
Write-Host ""
Write-Host "Refreshing pack paths with bundled CLI..."
& $CliBin desktop-pack $ProjectDir --platform "{platform}" --mode "{mode}" --tool-profile "{tool_profile}" --chapter "{chapter}" --output-dir $PackDir --force --format markdown
Write-Host ""
Write-Host "Checking local bundle..."
& $CliBin doctor $ProjectDir
& $CliBin desktop-pack-readiness $PackDir --format markdown
Write-Host ""
Write-Host "Preparing chapter session..."
& $CliBin prepare-session $ProjectDir --chapter "{chapter}" --platform "{platform}" --mode "{mode}" --format markdown
Write-Host ""
Write-Host "Next file for the desktop agent: $(Join-Path $BundleDir 'agent-read-me-first.md')"
"""


def render_handoff_bundle_cmd() -> str:
    return """@echo off
powershell -ExecutionPolicy Bypass -File "%~dp0START_HERE.ps1"
"""


def mcp_json_config(command: str, args: list[str]) -> str:
    return json.dumps({"mcpServers": {"long-novel-agent": {"command": command, "args": args}}}, ensure_ascii=False, indent=2) + "\n"


def mcp_codex_config(command: str, args: list[str]) -> str:
    return "\n".join(
        [
            "[mcp_servers.long-novel-agent]",
            f"command = {json.dumps(command, ensure_ascii=False)}",
            "args = " + json.dumps(args, ensure_ascii=False),
            "",
        ]
    )


def write_handoff_mcp_configs(bundle_dir: Path, mcp_command: str, *, tool_profile: str, force: bool) -> list[dict[str, Any]]:
    read_args = ["--read-only"]
    if tool_profile:
        read_args.extend(["--tool-profile", tool_profile])
    writer_args: list[str] = []
    if tool_profile:
        writer_args.extend(["--tool-profile", tool_profile])
    payloads = {
        "mcp-configs/README.md": (
            "# MCP Config Snippets\n\n"
            "These snippets point at the bundled standalone MCP executable. If this bundle is moved, run the top-level START_HERE launcher to refresh the current snippets.\n\n"
            "Use read-only mode first. Use writer mode only after author approval and writer-mode readiness checks.\n"
        ),
        "mcp-configs/codex-read-only.toml": mcp_codex_config(mcp_command, read_args),
        "mcp-configs/codex-writer.toml": mcp_codex_config(mcp_command, writer_args),
        "mcp-configs/cursor-read-only.json": mcp_json_config(mcp_command, read_args),
        "mcp-configs/cursor-writer.json": mcp_json_config(mcp_command, writer_args),
        "mcp-configs/claude-desktop-read-only.json": mcp_json_config(mcp_command, read_args),
        "mcp-configs/claude-desktop-writer.json": mcp_json_config(mcp_command, writer_args),
        "mcp-configs/generic-read-only.json": mcp_json_config(mcp_command, read_args),
        "mcp-configs/generic-writer.json": mcp_json_config(mcp_command, writer_args),
    }
    written: list[dict[str, Any]] = []
    for name, content in payloads.items():
        path = bundle_dir / name
        result = write_text_pack_file(path, content, force=force)
        written.append({"name": name, **result})
    return written


def build_handoff_runtime_commands(bundle: dict[str, Any]) -> dict[str, Any]:
    cli = f"./{HANDOFF_BUNDLE_RUNTIME_DIR}/{bundle.get('runtime_cli_name') or STANDALONE_CLI_NAME}"
    mcp = f"./{HANDOFF_BUNDLE_RUNTIME_DIR}/{bundle.get('runtime_mcp_name') or STANDALONE_MCP_NAME}"
    project = f"./{HANDOFF_BUNDLE_PROJECT_DIR}"
    pack = f"./{HANDOFF_BUNDLE_PACK_DIR}"
    chapter = int(bundle.get("target_chapter") or 1)
    platform = str(bundle.get("platform") or "codex")
    mode = str(bundle.get("mode") or "read-only")
    tool_profile = str(bundle.get("tool_profile") or DEFAULT_MCP_TOOL_PROFILE)
    refresh_pack = [
        cli,
        "desktop-pack",
        project,
        "--platform",
        platform,
        "--mode",
        mode,
        "--tool-profile",
        tool_profile,
        "--chapter",
        chapter,
        "--output-dir",
        pack,
        "--force",
        "--format",
        "markdown",
    ]
    prepare = [cli, "prepare-session", project, "--chapter", chapter, "--platform", platform, "--mode", mode, "--format", "markdown"]
    return {
        "refresh_pack": shell_command(refresh_pack),
        "doctor": shell_command([cli, "doctor", project]),
        "pack_readiness": shell_command([cli, "desktop-pack-readiness", pack, "--format", "markdown"]),
        "prepare_session": shell_command(prepare),
        "mcp_server_read_only": shell_command([mcp, "--read-only", "--tool-profile", tool_profile]),
        "mcp_server_writer": shell_command([mcp, "--tool-profile", tool_profile]),
    }


def create_desktop_handoff_bundle_archive(output_dir: Path, archive_path: str = "", *, force: bool = False) -> dict[str, Any]:
    return create_desktop_pack_archive(output_dir, archive_path, force=force)


def build_desktop_handoff_bundle(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
    source: str = "auto",
    chapter: int | None = None,
    output_dir: str = "",
    runtime_dir: str = "",
    runtime_cli_bin: str = "",
    runtime_mcp_bin: str = "",
    target_os: str = "auto",
    skip_project_copy: bool = False,
    archive: str | None = None,
    force: bool = False,
) -> dict[str, Any]:
    selected_platform = (platform or "codex").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported desktop handoff platform: {platform}")
    selected_mode = (mode or "read-only").strip().lower()
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported desktop handoff mode: {mode}")
    selected_tool_profile = normalize_mcp_tool_profile(tool_profile)
    selected_source = (source or "auto").strip().lower()
    if selected_source not in QUICKSTART_SOURCES:
        raise KitError(f"Unsupported desktop handoff source: {source}")
    selected_os = normalize_handoff_target_os(target_os)
    source_project = project_root(project_dir)
    bundle_dir = desktop_handoff_bundle_output_path(source_project, output_dir)
    if bundle_dir.exists():
        if not force:
            raise KitError(f"Desktop handoff bundle already exists: {bundle_dir}")
        if bundle_dir == source_project or path_is_relative_to(source_project, bundle_dir):
            raise KitError(f"Refusing to replace a directory that contains the source project: {bundle_dir}")
        shutil.rmtree(bundle_dir)
    bundle_dir.mkdir(parents=True, exist_ok=True)
    project_snapshot = bundle_dir / HANDOFF_BUNDLE_PROJECT_DIR
    if skip_project_copy:
        project_snapshot.mkdir(parents=True, exist_ok=True)
        snapshot_report = {
            "source": str(source_project),
            "target": str(project_snapshot),
            "file_count": 0,
            "bytes": 0,
            "skipped_count": 0,
            "skipped": [],
            "files": [],
            "status": "skipped",
        }
    else:
        snapshot_report = copy_project_snapshot_for_handoff(source_project, project_snapshot, bundle_dir=bundle_dir)
        snapshot_report["status"] = "copied"
    runtime_dir_path = bundle_dir / HANDOFF_BUNDLE_RUNTIME_DIR
    cli_name = standalone_binary_name(STANDALONE_CLI_NAME, selected_os)
    mcp_name = standalone_binary_name(STANDALONE_MCP_NAME, selected_os)
    cli_source = resolve_runtime_source(runtime_dir, runtime_cli_bin, base_name=STANDALONE_CLI_NAME, target_os=selected_os)
    mcp_source = resolve_runtime_source(runtime_dir, runtime_mcp_bin, base_name=STANDALONE_MCP_NAME, target_os=selected_os)
    cli_runtime = copy_runtime_binary(cli_source, runtime_dir_path / cli_name, force=True)
    mcp_runtime = copy_runtime_binary(mcp_source, runtime_dir_path / mcp_name, force=True)
    if not cli_runtime.get("present") or not mcp_runtime.get("present"):
        missing_text = [
            "# Missing Runtime",
            "",
            "This bundle was created without both standalone runtime files.",
            "",
            f"- Expected CLI: `{HANDOFF_BUNDLE_RUNTIME_DIR}/{cli_name}`",
            f"- Expected MCP: `{HANDOFF_BUNDLE_RUNTIME_DIR}/{mcp_name}`",
            "",
            "Build them with `standalone-build --apply`, then recreate this bundle with `--runtime-dir`.",
        ]
        write_text_pack_file(runtime_dir_path / "MISSING_RUNTIME.md", "\n".join(missing_text) + "\n", force=True)
    status = project_status(project_snapshot, chapter=chapter, platform=selected_platform, install_config="")
    target = int(chapter or status.get("target_chapter") or 1)
    pack_dir = bundle_dir / HANDOFF_BUNDLE_PACK_DIR
    pack = build_desktop_pack(
        project_snapshot,
        platform=selected_platform,
        mode=selected_mode,
        install_config="",
        install_target="",
        tool_profile=selected_tool_profile,
        source=selected_source,
        chapter=target,
        output_dir=str(pack_dir),
        archive=None,
        force=True,
    )
    bundle: dict[str, Any] = {
        "ok": bool(cli_runtime.get("present") and mcp_runtime.get("present")),
        "type": "desktop_handoff_bundle",
        "generated_at": now_iso(),
        "kit_version": KIT_VERSION,
        "status": "ready" if cli_runtime.get("present") and mcp_runtime.get("present") else "needs_runtime",
        "bundle_dir": str(bundle_dir),
        "source_project_dir": str(source_project),
        "project_dir": str(project_snapshot),
        "pack_dir": str(pack_dir),
        "platform": selected_platform,
        "mode": selected_mode,
        "tool_profile": selected_tool_profile,
        "target_chapter": target,
        "target_os": selected_os,
        "runtime_cli_name": cli_name,
        "runtime_mcp_name": mcp_name,
        "project_snapshot": snapshot_report,
        "runtime": {
            "cli": cli_runtime,
            "mcp": mcp_runtime,
        },
        "desktop_pack": {
            "type": pack.get("type"),
            "output_dir": pack.get("output_dir"),
            "file_count": len(pack.get("written_files") or []),
            "result_file": pack.get("result_file"),
            "target_chapter": pack.get("target_chapter"),
        },
        "notes": [
            "The bundle is local-only and does not require a server.",
            "The top-level launchers use the bundled CLI executable when runtime files are present.",
            "The generated pack still contains Python fallback commands for developer machines; use runtime-commands.json for no-Python commands.",
        ],
    }
    commands = build_handoff_runtime_commands(bundle)
    bundle["commands"] = commands
    written_files: list[dict[str, Any]] = []
    payloads: dict[str, tuple[str, Any]] = {
        "README.md": ("text", render_handoff_bundle_readme(bundle)),
        "START_HERE.md": ("text", render_handoff_bundle_start_here(bundle)),
        "agent-read-me-first.md": ("text", render_handoff_agent_readme(bundle)),
        "START_HERE.sh": ("text", render_handoff_bundle_start_script(bundle)),
        "START_HERE.command": ("text", render_handoff_bundle_macos_command()),
        "START_HERE.ps1": ("text", render_handoff_bundle_ps1(bundle)),
        "START_HERE.cmd": ("text", render_handoff_bundle_cmd()),
        "runtime-commands.json": ("json", {"type": "desktop_handoff_runtime_commands", "commands": commands}),
        "runtime-commands.md": (
            "text",
            "# Runtime Commands\n\nRun these commands from the bundle directory.\n\n"
            + "\n".join(f"- `{key}`: `{value}`" for key, value in commands.items())
            + "\n",
        ),
    }
    for name, (kind, content) in payloads.items():
        path = bundle_dir / name
        written = write_json_pack_file(path, content, force=True) if kind == "json" else write_text_pack_file(path, str(content), force=True)
        if name in {"START_HERE.sh", "START_HERE.command"}:
            path.chmod(path.stat().st_mode | 0o755)
            written["mode"] = oct(path.stat().st_mode & 0o777)
        written_files.append({"name": name, **written})
    written_files.extend(write_handoff_mcp_configs(bundle_dir, str(runtime_dir_path / mcp_name), tool_profile=selected_tool_profile, force=True))
    files = handoff_bundle_file_entries(bundle_dir)
    bundle["file_count"] = len(files)
    bundle["files"] = files
    written = write_json_pack_file(bundle_dir / HANDOFF_BUNDLE_MANIFEST_FILE, bundle, force=True)
    written_files.append({"name": HANDOFF_BUNDLE_MANIFEST_FILE, **written})
    bundle["written_files"] = written_files
    if archive is not None:
        bundle["archive"] = create_desktop_handoff_bundle_archive(bundle_dir, archive, force=force)
    return bundle


def local_file_sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def build_project_state_fingerprint(project_dir: str | Path) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    missing: list[str] = []
    files: list[dict[str, Any]] = []
    if not state.exists():
        return {
            "type": "project_state_fingerprint",
            "status": "not_initialized",
            "project_dir": str(project),
            "state_dir": str(state),
            "state_exists": False,
            "tracked_file_count": len(STATE_SNAPSHOT_FILES),
            "file_count": 0,
            "missing_tracked_files": list(STATE_SNAPSHOT_FILES),
            "files": [],
            "sha256": "",
            "project_identity": project_identity_payload(project, {}),
            "project_id": "",
        }
    manifest = read_json(state / "manifest.json", {})
    identity = project_identity_payload(project, manifest if isinstance(manifest, dict) else {})
    for name in STATE_SNAPSHOT_FILES:
        path = state / name
        if not path.exists() or not path.is_file():
            missing.append(name)
            continue
        files.append(
            {
                "name": name,
                "bytes": path.stat().st_size,
                "sha256": local_file_sha256(path),
            }
        )
    digest_input = json.dumps(files, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return {
        "type": "project_state_fingerprint",
        "status": "tracked" if files else "empty",
        "project_dir": str(project),
        "state_dir": str(state),
        "state_exists": True,
        "tracked_file_count": len(STATE_SNAPSHOT_FILES),
        "file_count": len(files),
        "missing_tracked_files": missing,
        "files": files,
        "sha256": hashlib.sha256(digest_input).hexdigest(),
        "project_identity": identity,
        "project_id": identity.get("project_id") or "",
    }


def compare_project_state_fingerprints(
    baseline: dict[str, Any],
    current: dict[str, Any],
) -> dict[str, Any]:
    baseline_files = {
        str(item.get("name") or ""): item
        for item in baseline.get("files", []) if isinstance(item, dict) and str(item.get("name") or "")
    }
    current_files = {
        str(item.get("name") or ""): item
        for item in current.get("files", []) if isinstance(item, dict) and str(item.get("name") or "")
    }
    baseline_names = set(baseline_files)
    current_names = set(current_files)
    added = sorted(current_names - baseline_names)
    removed = sorted(baseline_names - current_names)
    changed: list[dict[str, Any]] = []
    unchanged: list[str] = []
    for name in sorted(baseline_names & current_names):
        before = baseline_files[name]
        after = current_files[name]
        if before.get("sha256") != after.get("sha256") or before.get("bytes") != after.get("bytes"):
            changed.append(
                {
                    "name": name,
                    "baseline_sha256": before.get("sha256"),
                    "current_sha256": after.get("sha256"),
                    "baseline_bytes": before.get("bytes"),
                    "current_bytes": after.get("bytes"),
                }
            )
        else:
            unchanged.append(name)
    same_sha256 = bool(baseline.get("sha256") or current.get("sha256")) and baseline.get("sha256") == current.get("sha256")
    return {
        "ok": same_sha256 and not added and not removed and not changed,
        "same_sha256": same_sha256,
        "baseline_sha256": baseline.get("sha256") or "",
        "current_sha256": current.get("sha256") or "",
        "added": added,
        "removed": removed,
        "changed": changed,
        "unchanged_count": len(unchanged),
        "baseline_file_count": len(baseline_files),
        "current_file_count": len(current_files),
    }


def validate_write_session_guard(
    project_dir: str | Path,
    *,
    operation: str,
    expected_project_id: str = "",
    expected_state_sha256: str = "",
    expected_context_hash: str = "",
    chapter: int | None = None,
) -> dict[str, Any]:
    expected_project = str(expected_project_id or "").strip()
    expected_state = str(expected_state_sha256 or "").strip()
    expected_context = str(expected_context_hash or "").strip()
    if not any((expected_project, expected_state, expected_context)):
        return {}
    fingerprint = build_project_state_fingerprint(project_dir)
    actual_identity = fingerprint.get("project_identity") if isinstance(fingerprint.get("project_identity"), dict) else {}
    actual_project = str(actual_identity.get("project_id") or fingerprint.get("project_id") or "").strip()
    actual_state = str(fingerprint.get("sha256") or "").strip()
    checks: list[dict[str, Any]] = []
    if expected_project:
        ok = bool(actual_project) and actual_project == expected_project
        checks.append({"id": "expected_project_id", "ok": ok, "expected": expected_project, "actual": actual_project})
        if not ok:
            raise KitError(
                f"{operation} refused: project identity mismatch. "
                f"expected_project_id={expected_project} actual_project_id={actual_project or '<missing>'}"
            )
    if expected_state:
        ok = bool(actual_state) and actual_state == expected_state
        checks.append({"id": "expected_state_sha256", "ok": ok, "expected": expected_state, "actual": actual_state})
        if not ok:
            raise KitError(
                f"{operation} refused: .novel-agent state changed after the chapter session was prepared. "
                f"expected_state_sha256={expected_state} current_state_sha256={actual_state or '<missing>'}. "
                "Run prepare-session again before writing durable state."
            )
    actual_context = ""
    if expected_context:
        if not chapter:
            raise KitError(f"{operation} refused: expected_context_hash requires a target chapter.")
        context = build_chapter_context(project_dir, chapter=int(chapter))
        actual_context = payload_hash(context_fingerprint_payload(context))
        ok = actual_context == expected_context
        checks.append({"id": "expected_context_hash", "ok": ok, "expected": expected_context, "actual": actual_context, "chapter": int(chapter)})
        if not ok:
            raise KitError(
                f"{operation} refused: chapter context changed after the session was prepared. "
                f"expected_context_hash={expected_context} current_context_hash={actual_context}. "
                "Run prepare-session or build-context again before writing durable state."
            )
    return {
        "type": "write_session_guard",
        "checked_at": now_iso(),
        "project_identity": actual_identity,
        "project_state_sha256": actual_state,
        "chapter_context_hash": actual_context,
        "checks": checks,
    }


def build_write_session_check(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    expected_project_id: str = "",
    expected_state_sha256: str = "",
    expected_context_hash: str = "",
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    target = int(chapter) if chapter else None
    expected_project = str(expected_project_id or "").strip()
    expected_state = str(expected_state_sha256 or "").strip()
    expected_context = str(expected_context_hash or "").strip()
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    fingerprint = build_project_state_fingerprint(project)
    identity = fingerprint.get("project_identity") if isinstance(fingerprint.get("project_identity"), dict) else {}
    actual_project = str(identity.get("project_id") or fingerprint.get("project_id") or "").strip()
    actual_state = str(fingerprint.get("sha256") or "").strip()
    context_hash = ""
    context_payload: dict[str, Any] = {}
    context_summary: dict[str, Any] = {}

    add_check("project_initialized", bool(fingerprint.get("state_exists")), "blocker", "Project has .novel-agent state.")
    add_check("expected_project_id_present", bool(expected_project), "review", "Expected project_id from prepare-session is present.")
    add_check("expected_state_sha256_present", bool(expected_state), "review", "Expected project state sha256 from prepare-session is present.")
    needs_context = bool(target or expected_context)
    if needs_context:
        add_check("expected_context_hash_present", bool(expected_context), "review", "Expected chapter context hash from prepare-session is present.")
    if expected_context and not target:
        add_check("expected_context_hash_has_chapter", False, "blocker", "A target chapter is required when checking expected_context_hash.")

    if fingerprint.get("state_exists"):
        if expected_project:
            add_check(
                "expected_project_id_matches",
                bool(actual_project) and actual_project == expected_project,
                "blocker",
                "Expected project_id matches the current project state.",
                {"expected": expected_project, "actual": actual_project},
            )
        if expected_state:
            add_check(
                "expected_state_sha256_matches",
                bool(actual_state) and actual_state == expected_state,
                "blocker",
                "Expected project state sha256 matches the current tracked .novel-agent files.",
                {"expected": expected_state, "actual": actual_state},
            )
        if target:
            try:
                context = build_chapter_context(project, chapter=target)
                context_fingerprint = context.get("context_fingerprint") if isinstance(context.get("context_fingerprint"), dict) else {}
                context_hash = str(context_fingerprint.get("sha256") or payload_hash(context_fingerprint_payload(context)))
                context_payload = context_fingerprint_payload(context)
                context_summary = {
                    "characters": len(context.get("characters", [])),
                    "facts": len(context.get("facts", [])),
                    "sources": len(context.get("sources", [])),
                    "research": len(context.get("research", [])),
                    "contracts": len(context.get("contracts", [])),
                    "open_debts": len(context.get("open_debts", [])),
                }
                add_check("target_context_available", True, "blocker", f"Target chapter {target} context can be built.")
            except Exception as exc:
                add_check("target_context_available", False, "blocker", f"Target chapter {target} context cannot be built.", str(exc))
        if expected_context and target and context_hash:
            add_check(
                "expected_context_hash_matches",
                context_hash == expected_context,
                "blocker",
                "Expected chapter context hash matches the current target-chapter context.",
                {"expected": expected_context, "actual": context_hash, "chapter": target},
            )

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    failed_ids = {str(item.get("id") or "") for item in checks if not item.get("ok")}
    if "project_initialized" in failed_ids:
        status = "not_initialized"
    elif "expected_context_hash_has_chapter" in failed_ids:
        status = "missing_chapter"
    elif "expected_project_id_matches" in failed_ids:
        status = "project_mismatch"
    elif "expected_state_sha256_matches" in failed_ids:
        status = "stale_state"
    elif "expected_context_hash_matches" in failed_ids:
        status = "stale_context"
    elif failed_ids & {"expected_project_id_present", "expected_state_sha256_present", "expected_context_hash_present"}:
        status = "needs_expected_values"
    elif blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"

    guard_args: list[str] = []
    if actual_project:
        guard_args.extend(["--expected-project-id", actual_project])
    if actual_state:
        guard_args.extend(["--expected-state-sha256", actual_state])
    if context_hash:
        guard_args.extend(["--expected-context-hash", context_hash])

    recommended_commands = [
        shell_command(["python", kit_root() / "cli.py", "prepare-session", project, "--chapter", target or 1, "--format", "markdown"]),
    ]
    if target:
        recommended_commands.append(shell_command(["python", kit_root() / "cli.py", "build-context", project, "--chapter", target, "--format", "markdown"]))
    check_parts: list[object] = ["python", kit_root() / "cli.py", "write-session-check", project]
    if target:
        check_parts.extend(["--chapter", target])
    if actual_project:
        check_parts.extend(["--expected-project-id", actual_project])
    if actual_state:
        check_parts.extend(["--expected-state-sha256", actual_state])
    if context_hash:
        check_parts.extend(["--expected-context-hash", context_hash])
    check_parts.extend(["--format", "markdown"])
    recommended_commands.append(shell_command(check_parts))

    next_actions: list[str] = []
    if status == "ready":
        next_actions.append("Use the returned write_guard_arguments on the reviewed writer command.")
    elif status == "not_initialized":
        next_actions.append("Initialize or import the project before any writer operation.")
    elif status == "needs_expected_values":
        next_actions.append("Run prepare-session again and pass its project_id, state sha256, and chapter context hash into this check.")
    elif status == "missing_chapter":
        next_actions.append("Pass --chapter with --expected-context-hash.")
    elif status in {"project_mismatch", "stale_state", "stale_context"}:
        next_actions.append("Run prepare-session again for the target chapter, then retry the writer operation with the new guard arguments.")
    elif blockers:
        next_actions.append("Resolve blocker checks before writing durable state.")
    elif review_items:
        next_actions.append("Review failed checks before writing durable state.")
    else:
        next_actions.append("Review warnings, then use the write guard arguments if the author approves the writer command.")

    return {
        "ok": status == "ready",
        "type": "write_session_check",
        "generated_at": now_iso(),
        "status": status,
        "read_only": True,
        "writes_project_state": False,
        "writes_install_config": False,
        "writes_pack_files": False,
        "records_real_client_evidence": False,
        "project_dir": str(project),
        "state_dir": str(state),
        "target_chapter": target,
        "project_identity": identity,
        "project_state_fingerprint": fingerprint,
        "current": {
            "project_id": actual_project,
            "project_state_sha256": actual_state,
            "chapter_context_hash": context_hash,
            "chapter_context_summary": context_summary,
        },
        "expected": {
            "project_id": expected_project,
            "project_state_sha256": expected_state,
            "chapter_context_hash": expected_context,
        },
        "chapter_context_fingerprint": {
            "type": "chapter_context_fingerprint",
            "target_chapter": target,
            "sha256": context_hash,
            "payload": context_payload,
        } if target and context_hash else {},
        "write_guard_arguments": guard_args,
        "checks": checks,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": recommended_commands,
    }


def build_desktop_pack_freshness_payload(metadata: dict[str, Any], *, metadata_error: str = "") -> dict[str, Any]:
    project_dir = str(metadata.get("project_dir") or "").strip() if isinstance(metadata, dict) else ""
    baseline = metadata.get("project_state_fingerprint") if isinstance(metadata, dict) else {}
    if not isinstance(baseline, dict):
        baseline = {}
    result: dict[str, Any] = {
        "ok": False,
        "type": "desktop_pack_freshness",
        "generated_at": now_iso(),
        "local_only": True,
        "requires_server": False,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "project_dir": project_dir,
        "output_dir": metadata.get("output_dir") if isinstance(metadata, dict) else "",
        "platform": metadata.get("platform") if isinstance(metadata, dict) else "",
        "mode": metadata.get("mode") if isinstance(metadata, dict) else "",
        "target_chapter": metadata.get("target_chapter") if isinstance(metadata, dict) else None,
        "status": "pending",
        "baseline": baseline,
        "current": {},
        "comparison": {},
        "next_actions": [],
        "notes": [
            "This is a local read-only check.",
            "It compares the .novel-agent state fingerprint captured when the pack was generated with the current project state.",
            "It does not write project state, local MCP config, pack files, or desktop-client evidence.",
        ],
    }
    if metadata_error:
        result["status"] = "missing_metadata"
        result["metadata_error"] = metadata_error
        result["next_actions"] = ["Repair metadata.json or regenerate the desktop pack before using it."]
        return result
    if not project_dir:
        result["status"] = "missing_project_dir"
        result["next_actions"] = ["Regenerate the desktop pack so metadata.json records the project directory."]
        return result
    if not baseline:
        result["status"] = "no_baseline"
        result["next_actions"] = ["Regenerate the desktop pack with a current Long Novel Agent kit so project-state freshness can be checked."]
        return result
    project_path = Path(project_dir).expanduser()
    if not project_path.exists():
        result["status"] = "project_missing"
        result["next_actions"] = ["Move the pack back next to the original project or regenerate it on this machine from the current project directory."]
        return result
    current = build_project_state_fingerprint(project_path)
    result["current"] = current
    if not baseline.get("state_exists") and not current.get("state_exists"):
        result["ok"] = True
        result["status"] = "not_initialized"
        result["comparison"] = {
            "ok": True,
            "same_sha256": True,
            "baseline_file_count": 0,
            "current_file_count": 0,
            "added": [],
            "removed": [],
            "changed": [],
            "unchanged_count": 0,
        }
        result["next_actions"] = ["Initialize the project with quickstart or quickstart-from-wizard, then regenerate the desktop pack."]
        return result
    comparison = compare_project_state_fingerprints(baseline, current)
    result["comparison"] = comparison
    if comparison.get("ok"):
        result["ok"] = True
        result["status"] = "fresh"
        result["next_actions"] = ["The pack matches the current tracked .novel-agent state; continue with desktop-pack-readiness, pack-doctor, or the target chapter session."]
    else:
        result["status"] = "stale"
        result["next_actions"] = [
            "Regenerate the desktop pack before handing it to another local desktop agent.",
            "If the state change was intentional and the pack must still be used, run prepare-session from the live project before drafting.",
        ]
    return result


def build_desktop_pack_freshness_from_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    else:
        pack_path = pack_path.resolve()
    if not pack_path.exists() or not pack_path.is_dir():
        raise KitError(f"Desktop pack directory does not exist: {pack_path}")
    metadata, metadata_error = read_desktop_pack_json(pack_path, "metadata.json")
    report = build_desktop_pack_freshness_payload(metadata, metadata_error=metadata_error)
    report["source"] = "desktop_pack_directory"
    report["pack_dir"] = str(pack_path)
    return report


def render_desktop_pack_freshness_markdown(report: dict[str, Any]) -> str:
    comparison = report.get("comparison") if isinstance(report.get("comparison"), dict) else {}
    baseline = report.get("baseline") if isinstance(report.get("baseline"), dict) else {}
    current = report.get("current") if isinstance(report.get("current"), dict) else {}
    lines = [
        "# Desktop Pack Freshness",
        "",
        f"Status: `{report.get('status')}`",
        f"OK: `{report.get('ok')}`",
        f"Project: `{report.get('project_dir') or ''}`",
        f"Pack dir: `{report.get('pack_dir') or report.get('output_dir') or ''}`",
        f"Platform: {report.get('platform') or 'unknown'}",
        f"Mode: {report.get('mode') or 'unknown'}",
        f"Target chapter: {report.get('target_chapter') or 'unknown'}",
        "",
        "## Boundaries",
        "- Local-only: `true`",
        "- Requires server: `false`",
        "- Writes `.novel-agent/`: `false`",
        "- Writes local MCP config: `false`",
        "- Writes pack files: `false`",
        "- Records real desktop-client evidence: `false`",
        "",
        "## Fingerprints",
        f"- Baseline state exists: `{baseline.get('state_exists')}`",
        f"- Current state exists: `{current.get('state_exists')}`",
        f"- Baseline files: `{comparison.get('baseline_file_count', baseline.get('file_count', 0))}`",
        f"- Current files: `{comparison.get('current_file_count', current.get('file_count', 0))}`",
        f"- Baseline sha256: `{comparison.get('baseline_sha256') or baseline.get('sha256') or ''}`",
        f"- Current sha256: `{comparison.get('current_sha256') or current.get('sha256') or ''}`",
        "",
        "## Differences",
    ]
    changed = comparison.get("changed") if isinstance(comparison.get("changed"), list) else []
    added = comparison.get("added") if isinstance(comparison.get("added"), list) else []
    removed = comparison.get("removed") if isinstance(comparison.get("removed"), list) else []
    if not changed and not added and not removed:
        lines.append("- None")
    else:
        for name in added:
            lines.append(f"- Added: `{name}`")
        for name in removed:
            lines.append(f"- Removed: `{name}`")
        for item in changed:
            if isinstance(item, dict):
                lines.append(f"- Changed: `{item.get('name')}`")
    if report.get("metadata_error"):
        lines.extend(["", "## Metadata Error", f"- {report.get('metadata_error')}"])
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(["", "## Next Actions"])
    lines.extend(f"- {item}" for item in next_actions) if next_actions else lines.append("- None")
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(["", "## Notes"])
    lines.extend(f"- {item}" for item in notes) if notes else lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def build_chapter_session_freshness_payload(
    chapter_session: dict[str, Any],
    *,
    metadata: dict[str, Any] | None = None,
    chapter_session_error: str = "",
    metadata_error: str = "",
) -> dict[str, Any]:
    metadata = metadata if isinstance(metadata, dict) else {}
    if not isinstance(chapter_session, dict):
        chapter_session = {}
    project_dir = str(chapter_session.get("project_dir") or metadata.get("project_dir") or "").strip()
    baseline = chapter_session.get("project_state_fingerprint") if isinstance(chapter_session.get("project_state_fingerprint"), dict) else {}
    baseline_source = "chapter-session.json" if baseline else ""
    if not baseline:
        baseline = metadata.get("project_state_fingerprint") if isinstance(metadata.get("project_state_fingerprint"), dict) else {}
        baseline_source = "metadata.json" if baseline else ""
    target_chapter = chapter_session.get("target_chapter") or metadata.get("target_chapter")
    result: dict[str, Any] = {
        "ok": False,
        "type": "chapter_session_freshness",
        "generated_at": now_iso(),
        "local_only": True,
        "requires_server": False,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "project_dir": project_dir,
        "platform": chapter_session.get("platform") or metadata.get("platform"),
        "mode": chapter_session.get("mode") or metadata.get("mode"),
        "target_chapter": target_chapter,
        "chapter_session_type": chapter_session.get("type") or "",
        "chapter_session_status": chapter_session.get("status") or "",
        "status": "pending",
        "baseline_source": baseline_source,
        "baseline": baseline,
        "current": {},
        "comparison": {},
        "warnings": [],
        "next_actions": [],
        "notes": [
            "This is a local read-only check.",
            "It compares the project-state fingerprint captured in chapter-session.json with the current tracked .novel-agent files.",
            "It does not write project state, local MCP config, pack files, or desktop-client evidence.",
        ],
    }
    warnings: list[str] = []
    if metadata_error:
        warnings.append(f"metadata.json could not be read: {metadata_error}")
    if chapter_session_error:
        result["status"] = "missing_chapter_session"
        result["chapter_session_error"] = chapter_session_error
        result["next_actions"] = ["Regenerate the desktop pack or run prepare-session from the live project before drafting."]
        result["warnings"] = warnings
        return result
    if not project_dir:
        result["status"] = "missing_project_dir"
        result["next_actions"] = ["Regenerate the desktop pack or run prepare-session so the chapter session records the project directory."]
        result["warnings"] = warnings
        return result
    if not baseline:
        result["status"] = "no_baseline"
        result["next_actions"] = ["Regenerate the desktop pack or run prepare-session with a current Long Novel Agent kit so chapter-session freshness can be checked."]
        result["warnings"] = warnings
        return result
    project_path = Path(project_dir).expanduser()
    if not project_path.exists():
        result["status"] = "project_missing"
        result["next_actions"] = ["Move the pack back next to the original project or regenerate it on this machine from the current project directory."]
        result["warnings"] = warnings
        return result
    current = build_project_state_fingerprint(project_path)
    result["current"] = current
    if not baseline.get("state_exists") and not current.get("state_exists"):
        result["ok"] = True
        result["status"] = "not_initialized"
        result["comparison"] = {
            "ok": True,
            "same_sha256": True,
            "baseline_file_count": 0,
            "current_file_count": 0,
            "added": [],
            "removed": [],
            "changed": [],
            "unchanged_count": 0,
        }
        result["next_actions"] = ["Initialize the project with quickstart or quickstart-from-wizard, then regenerate the desktop pack."]
        result["warnings"] = warnings
        return result
    comparison = compare_project_state_fingerprints(baseline, current)
    result["comparison"] = comparison
    if comparison.get("ok"):
        result["ok"] = True
        result["status"] = "fresh"
        result["next_actions"] = ["The static chapter-session.json matches the current tracked .novel-agent state; continue with drafting gates or call prepare-session for a live packet."]
    else:
        result["status"] = "stale"
        result["next_actions"] = [
            "Run prepare-session for the target chapter before drafting or revising.",
            "Regenerate the desktop pack before handing this static chapter-session.json to another local desktop agent.",
        ]
    result["warnings"] = warnings
    return result


def build_chapter_session_freshness_from_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    else:
        pack_path = pack_path.resolve()
    if not pack_path.exists() or not pack_path.is_dir():
        raise KitError(f"Desktop pack directory does not exist: {pack_path}")
    metadata, metadata_error = read_desktop_pack_json(pack_path, "metadata.json")
    chapter_session, chapter_session_error = read_desktop_pack_json(pack_path, "chapter-session.json")
    report = build_chapter_session_freshness_payload(
        chapter_session,
        metadata=metadata,
        chapter_session_error=chapter_session_error,
        metadata_error=metadata_error,
    )
    report["source"] = "desktop_pack_directory"
    report["pack_dir"] = str(pack_path)
    return report


def render_chapter_session_freshness_markdown(report: dict[str, Any]) -> str:
    comparison = report.get("comparison") if isinstance(report.get("comparison"), dict) else {}
    baseline = report.get("baseline") if isinstance(report.get("baseline"), dict) else {}
    current = report.get("current") if isinstance(report.get("current"), dict) else {}
    lines = [
        "# Chapter Session Freshness",
        "",
        f"Status: `{report.get('status')}`",
        f"OK: `{report.get('ok')}`",
        f"Project: `{report.get('project_dir') or ''}`",
        f"Pack dir: `{report.get('pack_dir') or ''}`",
        f"Target chapter: {report.get('target_chapter') or 'unknown'}",
        f"Session type: `{report.get('chapter_session_type') or ''}`",
        f"Session status: `{report.get('chapter_session_status') or ''}`",
        f"Baseline source: `{report.get('baseline_source') or ''}`",
        "",
        "## Boundaries",
        "- Local-only: `true`",
        "- Requires server: `false`",
        "- Writes `.novel-agent/`: `false`",
        "- Writes local MCP config: `false`",
        "- Writes pack files: `false`",
        "- Records real desktop-client evidence: `false`",
        "",
        "## Fingerprints",
        f"- Baseline state exists: `{baseline.get('state_exists')}`",
        f"- Current state exists: `{current.get('state_exists')}`",
        f"- Baseline files: `{comparison.get('baseline_file_count', baseline.get('file_count', 0))}`",
        f"- Current files: `{comparison.get('current_file_count', current.get('file_count', 0))}`",
        f"- Baseline sha256: `{comparison.get('baseline_sha256') or baseline.get('sha256') or ''}`",
        f"- Current sha256: `{comparison.get('current_sha256') or current.get('sha256') or ''}`",
        "",
        "## Differences",
    ]
    changed = comparison.get("changed") if isinstance(comparison.get("changed"), list) else []
    added = comparison.get("added") if isinstance(comparison.get("added"), list) else []
    removed = comparison.get("removed") if isinstance(comparison.get("removed"), list) else []
    if not changed and not added and not removed:
        lines.append("- None")
    else:
        for name in added:
            lines.append(f"- Added: `{name}`")
        for name in removed:
            lines.append(f"- Removed: `{name}`")
        for item in changed:
            if isinstance(item, dict):
                lines.append(f"- Changed: `{item.get('name')}`")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    if warnings:
        lines.extend(["", "## Warnings"])
        lines.extend(f"- {item}" for item in warnings)
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(["", "## Next Actions"])
    lines.extend(f"- {item}" for item in next_actions) if next_actions else lines.append("- None")
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(["", "## Notes"])
    lines.extend(f"- {item}" for item in notes) if notes else lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def render_write_session_check_markdown(report: dict[str, Any]) -> str:
    current = report.get("current") if isinstance(report.get("current"), dict) else {}
    expected = report.get("expected") if isinstance(report.get("expected"), dict) else {}
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    lines = [
        "# Write Session Check",
        "",
        f"Status: `{report.get('status')}`",
        f"OK: `{report.get('ok')}`",
        f"Project: `{report.get('project_dir') or ''}`",
        f"Target chapter: {report.get('target_chapter') or 'none'}",
        f"Read-only: `{report.get('read_only')}`",
        "",
        "## Boundaries",
        "- Writes `.novel-agent/`: `false`",
        "- Writes local MCP config: `false`",
        "- Writes pack files: `false`",
        "- Records real desktop-client evidence: `false`",
        "",
        "## Expected",
        f"- Project ID: `{expected.get('project_id') or ''}`",
        f"- State sha256: `{expected.get('project_state_sha256') or ''}`",
        f"- Context hash: `{expected.get('chapter_context_hash') or ''}`",
        "",
        "## Current",
        f"- Project ID: `{current.get('project_id') or ''}`",
        f"- State sha256: `{current.get('project_state_sha256') or ''}`",
        f"- Context hash: `{current.get('chapter_context_hash') or ''}`",
    ]
    summary = current.get("chapter_context_summary") if isinstance(current.get("chapter_context_summary"), dict) else {}
    if summary:
        lines.extend(
            [
                f"- Characters: {summary.get('characters', 0)}",
                f"- Facts: {summary.get('facts', 0)}",
                f"- Sources: {summary.get('sources', 0)}",
                f"- Research: {summary.get('research', 0)}",
                f"- Contracts: {summary.get('contracts', 0)}",
                f"- Open debts: {summary.get('open_debts', 0)}",
            ]
        )
    for title, key in [("Blockers", "blockers"), ("Review Items", "review_items"), ("Warnings", "warnings")]:
        values = report.get(key) if isinstance(report.get(key), list) else []
        lines.extend(["", f"## {title}"])
        lines.extend(f"- {item}" for item in values or ["None"])
    lines.extend(["", "## Checks"])
    if checks:
        for item in checks:
            if not isinstance(item, dict):
                continue
            mark = "pass" if item.get("ok") else str(item.get("severity") or "check")
            lines.append(f"- {item.get('id')}: {mark} - {item.get('message')}")
    else:
        lines.append("- None")
    guard_args = report.get("write_guard_arguments") if isinstance(report.get("write_guard_arguments"), list) else []
    lines.extend(["", "## Write Guard Arguments"])
    lines.append("`" + " ".join(str(item) for item in guard_args) + "`" if guard_args else "- None")
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(["", "## Next Actions"])
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(["", "## Recommended Commands"])
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def safe_pack_entry_path(pack_dir: Path, name: str) -> Path | None:
    candidate = Path(name)
    if candidate.is_absolute() or any(part == ".." for part in candidate.parts):
        return None
    return pack_dir / candidate


def verify_desktop_pack_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    issues: list[dict[str, Any]] = []
    manifest_path = pack_path / PACK_MANIFEST_FILE
    checked = 0
    expected_count: int | None = None
    manifest: dict[str, Any] = {}
    if not pack_path.exists() or not pack_path.is_dir():
        issues.append({"file": str(pack_path), "type": "missing_pack_dir", "message": "Desktop pack directory does not exist."})
    elif not manifest_path.exists():
        issues.append({"file": PACK_MANIFEST_FILE, "type": "missing_manifest", "message": "pack-manifest.json is missing."})
    else:
        try:
            loaded = json.loads(manifest_path.read_text(encoding="utf-8"))
            if isinstance(loaded, dict):
                manifest = loaded
            else:
                issues.append({"file": PACK_MANIFEST_FILE, "type": "invalid_manifest", "message": "manifest root must be a JSON object."})
        except Exception as exc:
            issues.append({"file": PACK_MANIFEST_FILE, "type": "invalid_manifest", "message": str(exc)})
        files = manifest.get("files", []) if isinstance(manifest.get("files"), list) else []
        expected_count = manifest.get("file_count") if isinstance(manifest.get("file_count"), int) else None
        for entry in files:
            if not isinstance(entry, dict):
                continue
            name = str(entry.get("name") or "")
            if not name:
                continue
            checked += 1
            path = safe_pack_entry_path(pack_path, name)
            if path is None:
                issues.append({"file": name, "type": "invalid_path", "message": "Manifest file path must be relative and stay inside the pack directory."})
                continue
            if not path.exists():
                issues.append({"file": name, "type": "missing_file", "message": "File listed in manifest is missing."})
                continue
            expected_bytes = entry.get("bytes")
            actual_bytes = path.stat().st_size
            if isinstance(expected_bytes, int) and expected_bytes != actual_bytes:
                issues.append({"file": name, "type": "byte_mismatch", "expected": expected_bytes, "actual": actual_bytes})
            expected_hash = str(entry.get("sha256") or "")
            actual_hash = local_file_sha256(path)
            if expected_hash and expected_hash != actual_hash:
                issues.append({"file": name, "type": "sha256_mismatch", "expected": expected_hash, "actual": actual_hash})
        if expected_count is not None and expected_count != checked:
            issues.append({"file": PACK_MANIFEST_FILE, "type": "file_count_mismatch", "expected": expected_count, "actual": checked})
    return {
        "ok": not issues,
        "type": "desktop_pack_verify",
        "pack_dir": str(pack_path),
        "manifest_file": str(manifest_path),
        "manifest_type": manifest.get("type") if isinstance(manifest, dict) else None,
        "manifest_version": manifest.get("version") if isinstance(manifest, dict) else None,
        "expected_count": expected_count,
        "checked": checked,
        "issue_count": len(issues),
        "issues": issues,
    }


def read_desktop_pack_json(pack_path: Path, relative_name: str) -> tuple[dict[str, Any], str]:
    path = pack_path / relative_name
    if not path.exists():
        return {}, f"{relative_name} is missing."
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:
        return {}, str(exc)
    if not isinstance(payload, dict):
        return {}, f"{relative_name} root must be a JSON object."
    return payload, ""


def read_existing_desktop_pack_json(pack_path: Path, relative_name: str, errors: list[dict[str, str]]) -> dict[str, Any]:
    path = pack_path / relative_name
    if not path.exists():
        return {}
    payload, error = read_desktop_pack_json(pack_path, relative_name)
    if error:
        errors.append({"file": relative_name, "message": error})
        return {}
    return payload


def desktop_pack_file_entries_from_directory(pack_path: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for path in sorted(pack_path.rglob("*")):
        if not path.is_file():
            continue
        name = path.relative_to(pack_path).as_posix()
        rows.append({"name": name, "bytes": path.stat().st_size})
    return rows


def desktop_pack_commands_map(commands_json: dict[str, Any], metadata: dict[str, Any]) -> dict[str, str]:
    commands: dict[str, str] = {}
    by_key = commands_json.get("by_key")
    if isinstance(by_key, dict):
        for key, value in by_key.items():
            key_text = str(key or "").strip()
            value_text = str(value or "").strip()
            if key_text and value_text:
                commands[key_text] = value_text
    command_list = commands_json.get("commands")
    if isinstance(command_list, list):
        for item in command_list:
            if not isinstance(item, dict):
                continue
            key_text = str(item.get("key") or "").strip()
            value_text = str(item.get("command") or "").strip()
            if key_text and value_text:
                commands[key_text] = value_text
    metadata_commands = metadata.get("commands")
    if isinstance(metadata_commands, dict):
        for key, value in metadata_commands.items():
            key_text = str(key or "").strip()
            value_text = str(value or "").strip()
            if key_text and value_text and key_text not in commands:
                commands[key_text] = value_text
    return commands


