def desktop_pack_reference_issue(path: str, check: str, message: str, detail: Any = None) -> dict[str, Any]:
    row: dict[str, Any] = {"path": path, "check": check, "message": message}
    if detail not in (None, "", [], {}):
        row["detail"] = detail
    return row


def collect_desktop_pack_file_refs(value: Any, path: str = "$") -> list[dict[str, Any]]:
    refs: list[dict[str, Any]] = []
    if isinstance(value, dict):
        raw_name = value.get("name")
        if isinstance(raw_name, str) and raw_name.strip() and any(key in value for key in ("present", "required", "role", "description")):
            refs.append(
                {
                    "path": path,
                    "name": raw_name.strip(),
                    "present": value.get("present") if isinstance(value.get("present"), bool) else None,
                    "required": value.get("required") if isinstance(value.get("required"), bool) else True,
                }
            )
        for key, child in value.items():
            refs.extend(collect_desktop_pack_file_refs(child, f"{path}.{key}"))
    elif isinstance(value, list):
        for index, child in enumerate(value):
            refs.extend(collect_desktop_pack_file_refs(child, f"{path}[{index}]"))
    return refs


def desktop_pack_actual_file_names(pack_path: Path) -> set[str]:
    if not pack_path.exists() or not pack_path.is_dir():
        return set()
    return {path.relative_to(pack_path).as_posix() for path in pack_path.rglob("*") if path.is_file()}


def desktop_pack_manifest_file_names(manifest: dict[str, Any]) -> set[str]:
    names: set[str] = set()
    for entry in manifest.get("files", []) if isinstance(manifest.get("files"), list) else []:
        if not isinstance(entry, dict):
            continue
        name = str(entry.get("name") or "").strip()
        if name:
            names.add(name)
    return names


def desktop_pack_command_key_summary(commands_json: dict[str, Any]) -> dict[str, Any]:
    entries = commands_json.get("commands") if isinstance(commands_json.get("commands"), list) else []
    keys: list[str] = []
    duplicate_keys: set[str] = set()
    seen: set[str] = set()
    entry_by_key: dict[str, dict[str, Any]] = {}
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        key = str(entry.get("key") or "").strip()
        if not key:
            continue
        if key in seen:
            duplicate_keys.add(key)
        seen.add(key)
        keys.append(key)
        entry_by_key[key] = entry
    return {
        "entries": entries,
        "keys": set(keys),
        "entry_by_key": entry_by_key,
        "duplicate_keys": sorted(duplicate_keys),
    }


def collect_command_group_keys(groups: Any) -> tuple[set[str], list[str], list[dict[str, Any]]]:
    keys: list[str] = []
    issues: list[dict[str, Any]] = []
    for index, group in enumerate(groups if isinstance(groups, list) else []):
        if not isinstance(group, dict):
            issues.append(desktop_pack_reference_issue(f"$.groups[{index}]", "commands_group", "Command group must be an object."))
            continue
        group_keys = [str(key).strip() for key in group.get("command_keys", []) if str(key).strip()] if isinstance(group.get("command_keys"), list) else []
        keys.extend(group_keys)
        expected_count = group.get("command_count")
        if isinstance(expected_count, int) and expected_count != len(group_keys):
            issues.append(
                desktop_pack_reference_issue(
                    f"$.groups[{index}].command_count",
                    "commands_group",
                    "Command group count does not match command_keys length.",
                    {"expected": expected_count, "actual": len(group_keys), "id": group.get("id")},
                )
            )
    duplicates = sorted({key for key in keys if keys.count(key) > 1})
    return set(keys), duplicates, issues


def build_desktop_pack_reference_check(pack_path: Path, *, result_file: str) -> dict[str, Any]:
    actual_files = desktop_pack_actual_file_names(pack_path)
    issues: list[dict[str, Any]] = []
    checked_file_refs = 0
    checked_command_refs = 0

    manifest, manifest_error = read_desktop_pack_json(pack_path, PACK_MANIFEST_FILE)
    pack_index, pack_index_error = read_desktop_pack_json(pack_path, PACK_INDEX_FILE)
    commands_json, commands_error = read_desktop_pack_json(pack_path, "commands.json")
    commands_index, commands_index_error = read_desktop_pack_json(pack_path, DESKTOP_PACK_COMMANDS_INDEX_JSON_FILE)

    if manifest_error:
        issues.append(desktop_pack_reference_issue(f"$.{PACK_MANIFEST_FILE}", "manifest", manifest_error))
    if pack_index_error:
        issues.append(desktop_pack_reference_issue(f"$.{PACK_INDEX_FILE}", "pack_index", pack_index_error))
    if commands_error:
        issues.append(desktop_pack_reference_issue("$.commands.json", "commands", commands_error))
    if commands_index_error:
        issues.append(desktop_pack_reference_issue(f"$.{DESKTOP_PACK_COMMANDS_INDEX_JSON_FILE}", "commands_index", commands_index_error))

    manifest_files = desktop_pack_manifest_file_names(manifest)
    required_manifest_files = {
        PACK_INDEX_FILE,
        PACK_INDEX_SCHEMA_OUTPUT_FILE,
        DESKTOP_PACK_COMMANDS_INDEX_JSON_FILE,
        DESKTOP_PACK_COMMANDS_INDEX_SCHEMA_OUTPUT_FILE,
        "commands.json",
        "commands.schema.json",
        VERIFY_PACK_SCRIPT_FILE,
        DESKTOP_PACK_SCHEMA_CHECK_MD_FILE,
        DESKTOP_PACK_SCHEMA_CHECK_JSON_FILE,
        PACK_DOCTOR_FILE,
        "metadata.json",
    }
    for target in desktop_pack_schema_targets(result_file):
        required_manifest_files.add(target["json"])
        required_manifest_files.add(target["schema"])
    for name in sorted(required_manifest_files):
        if name in actual_files and name not in manifest_files:
            issues.append(desktop_pack_reference_issue(f"$.{PACK_MANIFEST_FILE}.files", "manifest", "Important generated file is not listed in pack-manifest.json.", {"file": name}))

    if pack_index:
        refs = collect_desktop_pack_file_refs(pack_index)
        checked_file_refs += len(refs)
        for ref in refs:
            name = str(ref.get("name") or "")
            exists = name in actual_files
            present = ref.get("present")
            required = bool(ref.get("required"))
            if present is not None and bool(present) != exists:
                issues.append(
                    desktop_pack_reference_issue(
                        str(ref.get("path") or "$"),
                        "pack_index_file_ref",
                        "pack-index file reference present flag does not match actual file.",
                        {"file": name, "present": present, "exists": exists},
                    )
                )
            if required and not exists:
                issues.append(desktop_pack_reference_issue(str(ref.get("path") or "$"), "pack_index_file_ref", "Required pack-index file reference is missing.", {"file": name}))

        for index, step in enumerate(pack_index.get("startup_order", []) if isinstance(pack_index.get("startup_order"), list) else []):
            if not isinstance(step, dict):
                continue
            read_name = str(step.get("read") or "").strip()
            if read_name:
                checked_file_refs += 1
                if read_name not in actual_files:
                    issues.append(desktop_pack_reference_issue(f"$.startup_order[{index}].read", "pack_index_startup_order", "Startup-order file is missing from the pack.", {"file": read_name}))

    command_summary = desktop_pack_command_key_summary(commands_json)
    command_keys: set[str] = command_summary["keys"]
    entry_by_key: dict[str, dict[str, Any]] = command_summary["entry_by_key"]
    if command_summary["duplicate_keys"]:
        issues.append(desktop_pack_reference_issue("$.commands", "commands", "commands.json contains duplicate command keys.", {"keys": command_summary["duplicate_keys"]}))
    root_count = commands_json.get("command_count")
    if isinstance(root_count, int) and root_count != len(command_keys):
        issues.append(desktop_pack_reference_issue("$.command_count", "commands", "commands.json command_count does not match unique command keys.", {"expected": root_count, "actual": len(command_keys)}))
    by_key = commands_json.get("by_key") if isinstance(commands_json.get("by_key"), dict) else {}
    by_key_set = {str(key).strip() for key in by_key if str(key).strip()}
    if by_key_set != command_keys:
        issues.append(desktop_pack_reference_issue("$.by_key", "commands", "commands.json by_key keys do not match commands list.", {"missing_in_by_key": sorted(command_keys - by_key_set), "extra_in_by_key": sorted(by_key_set - command_keys)}))

    group_key_set, duplicate_group_keys, group_issues = collect_command_group_keys(commands_json.get("groups"))
    issues.extend(group_issues)
    if duplicate_group_keys:
        issues.append(desktop_pack_reference_issue("$.groups", "commands", "Command keys appear in more than one commands.json group.", {"keys": duplicate_group_keys}))
    if group_key_set != command_keys:
        issues.append(desktop_pack_reference_issue("$.groups", "commands", "Command groups do not cover exactly the commands list.", {"missing_from_groups": sorted(command_keys - group_key_set), "extra_in_groups": sorted(group_key_set - command_keys)}))

    by_stage = commands_json.get("by_stage") if isinstance(commands_json.get("by_stage"), dict) else {}
    by_stage_keys: set[str] = set()
    for stage, keys in by_stage.items():
        if isinstance(keys, list):
            by_stage_keys.update(str(key).strip() for key in keys if str(key).strip())
            for key in keys:
                key_text = str(key).strip()
                expected_stage = str(entry_by_key.get(key_text, {}).get("stage") or "")
                if key_text in entry_by_key and expected_stage and expected_stage != str(stage):
                    issues.append(desktop_pack_reference_issue(f"$.by_stage.{stage}", "commands", "Command is listed under a stage that differs from its command entry.", {"key": key_text, "entry_stage": expected_stage, "stage_bucket": stage}))
    if by_stage_keys != command_keys:
        issues.append(desktop_pack_reference_issue("$.by_stage", "commands", "commands.json by_stage keys do not match commands list.", {"missing_from_by_stage": sorted(command_keys - by_stage_keys), "extra_in_by_stage": sorted(by_stage_keys - command_keys)}))

    if commands_index:
        index_count = commands_index.get("command_count")
        if isinstance(index_count, int) and index_count != len(command_keys):
            issues.append(desktop_pack_reference_issue("$.commands-index.command_count", "commands_index", "commands-index command_count does not match commands.json.", {"expected": index_count, "actual": len(command_keys)}))
        index_group_keys, index_duplicate_keys, index_group_issues = collect_command_group_keys(commands_index.get("groups"))
        issues.extend(
            desktop_pack_reference_issue(issue.get("path", "$").replace("$", "$.commands-index", 1), issue.get("check", "commands_index"), issue.get("message", ""), issue.get("detail"))
            for issue in index_group_issues
        )
        if index_duplicate_keys:
            issues.append(desktop_pack_reference_issue("$.commands-index.groups", "commands_index", "Command keys appear in more than one commands-index group.", {"keys": index_duplicate_keys}))
        if index_group_keys != command_keys:
            issues.append(desktop_pack_reference_issue("$.commands-index.groups", "commands_index", "commands-index groups do not cover exactly commands.json keys.", {"missing_from_index": sorted(command_keys - index_group_keys), "extra_in_index": sorted(index_group_keys - command_keys)}))
        for source in commands_index.get("source_files", []) if isinstance(commands_index.get("source_files"), list) else []:
            source_name = str(source or "").strip()
            if source_name:
                checked_file_refs += 1
                if source_name not in actual_files:
                    issues.append(desktop_pack_reference_issue("$.commands-index.source_files", "commands_index", "commands-index source file is missing from the pack.", {"file": source_name}))

    if pack_index:
        commands_section = pack_index.get("commands") if isinstance(pack_index.get("commands"), dict) else {}
        index_total = commands_section.get("total")
        if isinstance(index_total, int) and index_total != len(command_keys):
            issues.append(desktop_pack_reference_issue("$.commands.total", "pack_index_commands", "pack-index command total does not match commands.json.", {"expected": index_total, "actual": len(command_keys)}))
        for index, item in enumerate(commands_section.get("important", []) if isinstance(commands_section.get("important"), list) else []):
            if not isinstance(item, dict):
                continue
            key = str(item.get("key") or "").strip()
            if not key:
                continue
            checked_command_refs += 1
            present = item.get("present")
            exists = key in command_keys
            if isinstance(present, bool) and present != exists:
                issues.append(desktop_pack_reference_issue(f"$.commands.important[{index}]", "pack_index_commands", "pack-index important command present flag does not match commands.json.", {"key": key, "present": present, "exists": exists}))
            if not exists:
                issues.append(desktop_pack_reference_issue(f"$.commands.important[{index}]", "pack_index_commands", "pack-index important command is missing from commands.json.", {"key": key}))

    return {
        "ok": not issues,
        "status": "pass" if not issues else "reference_mismatch",
        "summary": {
            "issue_count": len(issues),
            "checked_file_refs": checked_file_refs,
            "checked_command_refs": checked_command_refs,
            "actual_file_count": len(actual_files),
            "manifest_file_count": len(manifest_files),
            "command_count": len(command_keys),
        },
        "issues": issues[:100],
        "truncated_issues": max(0, len(issues) - 100),
    }


def json_schema_type_matches(value: Any, expected_type: str) -> bool:
    if expected_type == "object":
        return isinstance(value, dict)
    if expected_type == "array":
        return isinstance(value, list)
    if expected_type == "string":
        return isinstance(value, str)
    if expected_type == "integer":
        return isinstance(value, int) and not isinstance(value, bool)
    if expected_type == "number":
        return (isinstance(value, int) or isinstance(value, float)) and not isinstance(value, bool)
    if expected_type == "boolean":
        return isinstance(value, bool)
    if expected_type == "null":
        return value is None
    return True


def json_schema_value_type(value: Any) -> str:
    if isinstance(value, dict):
        return "object"
    if isinstance(value, list):
        return "array"
    if isinstance(value, str):
        return "string"
    if isinstance(value, bool):
        return "boolean"
    if isinstance(value, int):
        return "integer"
    if isinstance(value, float):
        return "number"
    if value is None:
        return "null"
    return type(value).__name__


def json_schema_child_path(path: str, key: str) -> str:
    if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", key):
        return f"{path}.{key}"
    return f"{path}[{json.dumps(key, ensure_ascii=False)}]"


def resolve_local_schema_ref(root_schema: dict[str, Any], ref: str) -> dict[str, Any] | None:
    if not ref.startswith("#/"):
        return None
    current: Any = root_schema
    for raw_part in ref[2:].split("/"):
        part = raw_part.replace("~1", "/").replace("~0", "~")
        if not isinstance(current, dict) or part not in current:
            return None
        current = current[part]
    return current if isinstance(current, dict) else None


def validate_json_schema_subset(value: Any, schema: dict[str, Any], *, root_schema: dict[str, Any] | None = None, path: str = "$") -> list[dict[str, Any]]:
    root = root_schema if isinstance(root_schema, dict) else schema
    issues: list[dict[str, Any]] = []

    def add(keyword: str, message: str, detail: Any = None) -> None:
        row: dict[str, Any] = {"path": path, "keyword": keyword, "message": message}
        if detail not in (None, "", [], {}):
            row["detail"] = detail
        issues.append(row)

    ref = schema.get("$ref")
    if isinstance(ref, str) and ref:
        resolved = resolve_local_schema_ref(root, ref)
        if not resolved:
            add("$ref", f"Unsupported or missing local schema reference: {ref}")
            return issues
        return validate_json_schema_subset(value, resolved, root_schema=root, path=path)

    all_of = schema.get("allOf")
    if isinstance(all_of, list):
        for index, sub_schema in enumerate(all_of):
            if isinstance(sub_schema, dict):
                issues.extend(validate_json_schema_subset(value, sub_schema, root_schema=root, path=path))
            else:
                add("allOf", f"allOf[{index}] is not an object schema.")

    any_of = schema.get("anyOf")
    if isinstance(any_of, list):
        matches = 0
        for sub_schema in any_of:
            if isinstance(sub_schema, dict) and not validate_json_schema_subset(value, sub_schema, root_schema=root, path=path):
                matches += 1
        if matches == 0:
            add("anyOf", "Value did not match any allowed schema branch.")

    one_of = schema.get("oneOf")
    if isinstance(one_of, list):
        matches = 0
        for sub_schema in one_of:
            if isinstance(sub_schema, dict) and not validate_json_schema_subset(value, sub_schema, root_schema=root, path=path):
                matches += 1
        if matches != 1:
            add("oneOf", "Value must match exactly one allowed schema branch.", {"matches": matches})

    if_schema = schema.get("if")
    then_schema = schema.get("then")
    if isinstance(if_schema, dict) and isinstance(then_schema, dict):
        if not validate_json_schema_subset(value, if_schema, root_schema=root, path=path):
            issues.extend(validate_json_schema_subset(value, then_schema, root_schema=root, path=path))

    expected_type = schema.get("type")
    if isinstance(expected_type, str):
        allowed_types = [expected_type]
    elif isinstance(expected_type, list):
        allowed_types = [str(item) for item in expected_type]
    else:
        allowed_types = []
    if allowed_types and not any(json_schema_type_matches(value, item) for item in allowed_types):
        add("type", "Value has unexpected JSON type.", {"expected": allowed_types, "actual": json_schema_value_type(value)})
        return issues

    if "const" in schema and value != schema.get("const"):
        add("const", "Value does not match schema const.", {"expected": schema.get("const"), "actual": value})
    enum_values = schema.get("enum")
    if isinstance(enum_values, list) and value not in enum_values:
        add("enum", "Value is not in schema enum.", {"allowed": enum_values, "actual": value})
    if isinstance(value, str):
        min_length = schema.get("minLength")
        if isinstance(min_length, int) and len(value) < min_length:
            add("minLength", "String is shorter than required.", {"minimum": min_length, "actual": len(value)})
        pattern = schema.get("pattern")
        if isinstance(pattern, str):
            try:
                if not re.search(pattern, value):
                    add("pattern", "String does not match required pattern.", {"pattern": pattern})
            except re.error as exc:
                add("pattern", f"Schema pattern is invalid: {exc}")
    if (isinstance(value, int) or isinstance(value, float)) and not isinstance(value, bool):
        minimum = schema.get("minimum")
        if isinstance(minimum, (int, float)) and value < minimum:
            add("minimum", "Number is below schema minimum.", {"minimum": minimum, "actual": value})
    if isinstance(value, list):
        min_items = schema.get("minItems")
        if isinstance(min_items, int) and len(value) < min_items:
            add("minItems", "Array has too few items.", {"minimum": min_items, "actual": len(value)})
        item_schema = schema.get("items")
        if isinstance(item_schema, dict):
            for index, item in enumerate(value):
                issues.extend(validate_json_schema_subset(item, item_schema, root_schema=root, path=f"{path}[{index}]"))
    if isinstance(value, dict):
        required = schema.get("required")
        if isinstance(required, list):
            for key in required:
                key_text = str(key)
                if key_text not in value:
                    issues.append({"path": json_schema_child_path(path, key_text), "keyword": "required", "message": "Required property is missing."})
        properties = schema.get("properties")
        property_schemas = properties if isinstance(properties, dict) else {}
        for key, sub_schema in property_schemas.items():
            if key in value and isinstance(sub_schema, dict):
                issues.extend(validate_json_schema_subset(value[key], sub_schema, root_schema=root, path=json_schema_child_path(path, str(key))))
        additional = schema.get("additionalProperties", True)
        extra_keys = [key for key in value if key not in property_schemas]
        if additional is False and extra_keys:
            add("additionalProperties", "Object has properties not allowed by schema.", {"extra": sorted(str(key) for key in extra_keys)})
        elif isinstance(additional, dict):
            for key in extra_keys:
                issues.extend(validate_json_schema_subset(value[key], additional, root_schema=root, path=json_schema_child_path(path, str(key))))
    return issues


def build_desktop_pack_schema_check_from_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    else:
        pack_path = pack_path.resolve()
    if not pack_path.exists() or not pack_path.is_dir():
        raise KitError(f"Desktop pack directory does not exist: {pack_path}")

    metadata, metadata_error = read_desktop_pack_json(pack_path, "metadata.json")
    result_file = str(metadata.get("result_file") or "desktop-results.json") if not metadata_error else "desktop-results.json"
    rows: list[dict[str, Any]] = []
    issue_total = 0
    for target in desktop_pack_schema_targets(result_file):
        json_name = target["json"]
        schema_name = target["schema"]
        json_path = pack_path / json_name
        schema_path = pack_path / schema_name
        row: dict[str, Any] = {
            "label": target["label"],
            "json_file": json_name,
            "schema_file": schema_name,
            "ok": False,
            "status": "pending",
            "issues": [],
        }
        if not json_path.exists():
            row["status"] = "missing_json"
            row["issues"] = [{"path": "$", "keyword": "file", "message": f"{json_name} is missing."}]
            row["issue_count"] = 1
            issue_total += 1
            rows.append(row)
            continue
        if not schema_path.exists():
            row["status"] = "missing_schema"
            row["issues"] = [{"path": "$", "keyword": "file", "message": f"{schema_name} is missing."}]
            row["issue_count"] = 1
            issue_total += 1
            rows.append(row)
            continue
        try:
            payload = json.loads(json_path.read_text(encoding="utf-8"))
        except Exception as exc:
            row["status"] = "invalid_json"
            row["issues"] = [{"path": "$", "keyword": "json", "message": str(exc)}]
            row["issue_count"] = 1
            issue_total += 1
            rows.append(row)
            continue
        try:
            schema_payload = json.loads(schema_path.read_text(encoding="utf-8"))
        except Exception as exc:
            row["status"] = "invalid_schema"
            row["issues"] = [{"path": "$", "keyword": "schema_json", "message": str(exc)}]
            row["issue_count"] = 1
            issue_total += 1
            rows.append(row)
            continue
        if not isinstance(schema_payload, dict):
            row["status"] = "invalid_schema"
            row["issues"] = [{"path": "$", "keyword": "schema", "message": f"{schema_name} root must be an object."}]
            row["issue_count"] = 1
            issue_total += 1
            rows.append(row)
            continue
        issues = validate_json_schema_subset(payload, schema_payload)
        if isinstance(payload, dict):
            declared_schema = str(payload.get("$schema") or "")
            if declared_schema and declared_schema != schema_name:
                issues.append(
                    {
                        "path": "$.$schema",
                        "keyword": "$schema",
                        "message": "Payload points to a different local schema file.",
                        "detail": {"expected": schema_name, "actual": declared_schema},
                    }
                )
        else:
            issues.append({"path": "$", "keyword": "type", "message": "Payload root should be a JSON object for desktop-pack files."})
        row["ok"] = not issues
        row["status"] = "pass" if not issues else "schema_mismatch"
        row["schema_title"] = schema_payload.get("title")
        row["issue_count"] = len(issues)
        row["issues"] = issues[:50]
        if len(issues) > 50:
            row["truncated_issues"] = len(issues) - 50
        issue_total += len(issues)
        rows.append(row)

    failed = [row for row in rows if not row.get("ok")]
    missing = [row for row in rows if str(row.get("status")) in {"missing_json", "missing_schema"}]
    cross_reference = build_desktop_pack_reference_check(pack_path, result_file=result_file)
    reference_issue_count = int((cross_reference.get("summary") or {}).get("issue_count") or 0) if isinstance(cross_reference.get("summary"), dict) else 0
    return {
        "ok": not failed and not metadata_error and bool(cross_reference.get("ok")),
        "type": "desktop_pack_schema_check",
        "generated_at": now_iso(),
        "pack_dir": str(pack_path),
        "local_only": True,
        "requires_server": False,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "status": "ready" if not failed and not metadata_error and bool(cross_reference.get("ok")) else "needs_pack_repair",
        "metadata": {
            "project_dir": metadata.get("project_dir") if not metadata_error else None,
            "platform": metadata.get("platform") if not metadata_error else None,
            "mode": metadata.get("mode") if not metadata_error else None,
            "target_chapter": metadata.get("target_chapter") if not metadata_error else None,
            "result_file": result_file,
            "metadata_error": metadata_error,
        },
        "summary": {
            "target_count": len(rows),
            "passed": len(rows) - len(failed),
            "failed": len(failed),
            "missing": len(missing),
            "schema_issue_count": issue_total,
            "reference_issue_count": reference_issue_count,
            "issue_count": issue_total + reference_issue_count + (1 if metadata_error else 0),
        },
        "targets": rows,
        "cross_reference": cross_reference,
        "notes": [
            "This is a local read-only check of generated desktop-pack JSON files against the schema files shipped in the same pack.",
            "It also checks key cross-references among pack-index.json, commands.json, commands-index.json, and pack-manifest.json.",
            "It does not write .novel-agent/, local MCP config, pack files, or real desktop-client evidence.",
            "This validator covers the schema features used by this kit's generated desktop-pack schemas; it is not a general-purpose JSON Schema engine.",
        ],
    }


def render_desktop_pack_schema_check_markdown(report: dict[str, Any]) -> str:
    metadata = report.get("metadata") if isinstance(report.get("metadata"), dict) else {}
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Pack Schema Check",
        "",
        f"- OK: {bool(report.get('ok'))}",
        f"- Status: `{report.get('status')}`",
        f"- Pack dir: `{report.get('pack_dir')}`",
        f"- Project: `{metadata.get('project_dir') or ''}`",
        f"- Platform: {metadata.get('platform') or 'unknown'}",
        f"- Mode: {metadata.get('mode') or 'unknown'}",
        f"- Target chapter: {metadata.get('target_chapter') or 'unknown'}",
        f"- Targets: {summary.get('target_count', 0)}",
        f"- Passed: {summary.get('passed', 0)}",
        f"- Failed: {summary.get('failed', 0)}",
        f"- Missing: {summary.get('missing', 0)}",
        f"- Issues: {summary.get('issue_count', 0)}",
        "",
        "## Targets",
    ]
    for row in report.get("targets") if isinstance(report.get("targets"), list) else []:
        if not isinstance(row, dict):
            continue
        mark = "PASS" if row.get("ok") else str(row.get("status") or "issue").upper()
        lines.append(f"- {mark} `{row.get('json_file')}` -> `{row.get('schema_file')}`")
        issues = row.get("issues") if isinstance(row.get("issues"), list) else []
        for issue in issues[:5]:
            if not isinstance(issue, dict):
                continue
            detail = issue.get("detail")
            suffix = ""
            if detail not in (None, "", [], {}):
                detail_text = json.dumps(detail, ensure_ascii=False, sort_keys=True)
                if len(detail_text) > 240:
                    detail_text = detail_text[:237] + "..."
                suffix = f" `{detail_text}`"
            lines.append(f"  - `{issue.get('path')}` {issue.get('keyword')}: {issue.get('message')}{suffix}")
        if row.get("truncated_issues"):
            lines.append(f"  - Additional issues omitted: {row.get('truncated_issues')}")
    cross_reference = report.get("cross_reference") if isinstance(report.get("cross_reference"), dict) else {}
    cross_summary = cross_reference.get("summary") if isinstance(cross_reference.get("summary"), dict) else {}
    lines.extend(
        [
            "",
            "## Cross References",
            f"- OK: {bool(cross_reference.get('ok'))}",
            f"- Status: `{cross_reference.get('status') or 'unknown'}`",
            f"- Checked file references: {cross_summary.get('checked_file_refs', 0)}",
            f"- Checked command references: {cross_summary.get('checked_command_refs', 0)}",
            f"- Issues: {cross_summary.get('issue_count', 0)}",
        ]
    )
    cross_issues = cross_reference.get("issues") if isinstance(cross_reference.get("issues"), list) else []
    for issue in cross_issues[:20]:
        if not isinstance(issue, dict):
            continue
        detail = issue.get("detail")
        suffix = ""
        if detail not in (None, "", [], {}):
            detail_text = json.dumps(detail, ensure_ascii=False, sort_keys=True)
            if len(detail_text) > 240:
                detail_text = detail_text[:237] + "..."
            suffix = f" `{detail_text}`"
        lines.append(f"- `{issue.get('path')}` {issue.get('check')}: {issue.get('message')}{suffix}")
    if cross_reference.get("truncated_issues"):
        lines.append(f"- Additional cross-reference issues omitted: {cross_reference.get('truncated_issues')}")
    if metadata.get("metadata_error"):
        lines.extend(["", "## Metadata Error", f"- {metadata.get('metadata_error')}"])
    lines.extend(["", "## Notes"])
    lines.extend(f"- {item}" for item in split_list(report.get("notes")) or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def positive_int_or_default(value: Any, default: int = 1) -> int:
    try:
        parsed = int(value)
    except Exception:
        return default
    return parsed if parsed > 0 else default


def build_desktop_pack_troubleshooting_from_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    else:
        pack_path = pack_path.resolve()
    if not pack_path.exists() or not pack_path.is_dir():
        raise KitError(f"Desktop pack directory does not exist: {pack_path}")

    read_errors: list[dict[str, str]] = []
    metadata = read_existing_desktop_pack_json(pack_path, "metadata.json", read_errors)
    commands_json = read_existing_desktop_pack_json(pack_path, "commands.json", read_errors)
    commands = desktop_pack_commands_map(commands_json, metadata)
    mode = str(metadata.get("mode") or "read-only")
    if mode not in AGENT_TEMPLATE_MODES:
        mode = "read-only"
    payload = build_desktop_pack_troubleshooting_payload(
        {
            "generated_at": metadata.get("generated_at") or now_iso(),
            "project_dir": str(metadata.get("project_dir") or pack_path),
            "output_dir": str(pack_path),
            "platform": str(metadata.get("platform") or "unknown"),
            "mode": mode,
            "target_chapter": positive_int_or_default(metadata.get("target_chapter"), 1),
            "config_path": metadata.get("config_path") or "",
            "result_file": metadata.get("result_file") or "desktop-results.json",
            "commands": commands,
        }
    )
    payload["source"] = "desktop_pack_directory"
    payload["pack_dir"] = str(pack_path)
    return append_desktop_pack_troubleshooting_read_errors(payload, read_errors)


def append_desktop_pack_read_errors(payload: dict[str, Any], read_errors: list[dict[str, str]]) -> dict[str, Any]:
    if not read_errors:
        return payload
    checks = payload.get("checks") if isinstance(payload.get("checks"), list) else []
    checks.append(
        {
            "id": "json_inputs",
            "ok": False,
            "severity": "blocker",
            "message": "One or more desktop-pack JSON inputs could not be parsed.",
            "detail": {"errors": read_errors},
        }
    )
    payload["checks"] = checks
    blockers = [item for item in checks if isinstance(item, dict) and not item.get("ok") and item.get("severity") == "blocker"]
    warnings = [item for item in checks if isinstance(item, dict) and not item.get("ok") and item.get("severity") == "warning"]
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    summary["blocker_count"] = len(blockers)
    summary["warning_count"] = len(warnings)
    summary["read_error_count"] = len(read_errors)
    payload["summary"] = summary
    payload["ok"] = False
    payload["status"] = "needs_pack_repair"
    payload["read_errors"] = read_errors
    actions = payload.get("next_actions") if isinstance(payload.get("next_actions"), list) else []
    actions.insert(0, "Repair or regenerate invalid JSON files before handing this pack to another local desktop agent.")
    payload["next_actions"] = actions
    return payload


def build_desktop_pack_readiness_from_directory(pack_dir: str | Path) -> dict[str, Any]:
    pack_path = Path(pack_dir).expanduser()
    if not pack_path.is_absolute():
        pack_path = pack_path.resolve()
    else:
        pack_path = pack_path.resolve()
    if not pack_path.exists() or not pack_path.is_dir():
        raise KitError(f"Desktop pack directory does not exist: {pack_path}")

    read_errors: list[dict[str, str]] = []
    metadata = read_existing_desktop_pack_json(pack_path, "metadata.json", read_errors)
    commands_json = read_existing_desktop_pack_json(pack_path, "commands.json", read_errors)
    commands = desktop_pack_commands_map(commands_json, metadata)
    mode = str(metadata.get("mode") or "read-only")
    if mode not in AGENT_TEMPLATE_MODES:
        mode = "read-only"
    pack = {
        "project_dir": str(metadata.get("project_dir") or pack_path),
        "output_dir": str(pack_path),
        "platform": str(metadata.get("platform") or "unknown"),
        "mode": mode,
        "target_chapter": positive_int_or_default(metadata.get("target_chapter"), 1),
        "files": desktop_pack_file_entries_from_directory(pack_path),
        "commands": commands,
        "chapter_session_type": metadata.get("chapter_session_type"),
        "chapter_session_status": metadata.get("chapter_session_status"),
        "desktop_next_step_status": metadata.get("desktop_next_step_status"),
        "desktop_evidence_review_status": metadata.get("desktop_evidence_review_status"),
        "author_review_queue_status": metadata.get("author_review_queue_status"),
        "author_review_queue_summary": metadata.get("author_review_queue_summary"),
        "handoff_report_available": metadata.get("handoff_report_available"),
        "handoff_brief_status": metadata.get("handoff_brief_status"),
    }
    status = read_existing_desktop_pack_json(pack_path, "project-status.json", read_errors)
    author_review_queue = read_existing_desktop_pack_json(pack_path, "author-review-queue.json", read_errors)
    desktop_next_step = read_existing_desktop_pack_json(pack_path, "desktop-next-step.json", read_errors)
    desktop_evidence_review = read_existing_desktop_pack_json(pack_path, DESKTOP_EVIDENCE_REVIEW_JSON_FILE, read_errors)
    chapter_session = read_existing_desktop_pack_json(pack_path, "chapter-session.json", read_errors)
    handoff_report = read_existing_desktop_pack_json(pack_path, "handoff-report.json", read_errors)
    handoff_brief = read_existing_desktop_pack_json(pack_path, "handoff-brief.json", read_errors)
    pack_freshness = build_desktop_pack_freshness_payload(metadata)
    chapter_session_freshness_error = next(
        (
            str(item.get("message") or "")
            for item in read_errors
            if isinstance(item, dict) and item.get("file") == "chapter-session.json"
        ),
        "",
    )
    if not (pack_path / "chapter-session.json").exists():
        chapter_session_freshness_error = "chapter-session.json is missing."
    chapter_session_freshness = build_chapter_session_freshness_payload(
        chapter_session,
        metadata=metadata,
        chapter_session_error=chapter_session_freshness_error,
    )
    payload = build_desktop_pack_readiness_payload(
        pack,
        status=status,
        author_review_queue=author_review_queue,
        desktop_next_step=desktop_next_step,
        desktop_evidence_review=desktop_evidence_review,
        chapter_session=chapter_session,
        handoff_report=handoff_report,
        handoff_brief=handoff_brief,
        pack_freshness=pack_freshness,
        chapter_session_freshness=chapter_session_freshness,
    )
    payload["source"] = "desktop_pack_directory"
    payload["pack_dir"] = str(pack_path)
    return append_desktop_pack_read_errors(payload, read_errors)


def append_author_actions_read_errors(payload: dict[str, Any], read_errors: list[dict[str, str]]) -> dict[str, Any]:
    if not read_errors:
        return payload
    payload["ok"] = False
    payload["status"] = "blocked"
    payload["read_errors"] = read_errors
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    summary["read_error_count"] = len(read_errors)
    payload["summary"] = summary
    groups = payload.get("action_groups") if isinstance(payload.get("action_groups"), list) else []
    for group in groups:
        if not isinstance(group, dict):
            continue
        if group.get("id") == "start_here":
            group["status"] = "blocked"
            group["why"] = f"{group.get('why') or ''} Repair invalid JSON inputs before following this action list.".strip()
    notes = payload.get("notes") if isinstance(payload.get("notes"), list) else []
    notes.insert(0, "One or more desktop-pack JSON inputs could not be parsed; repair or regenerate the pack before using this checklist.")
    payload["notes"] = notes
    return payload


