def group_matches(text_lower: str, groups: list[list[str]]) -> tuple[bool, list[str]]:
    matched_terms: list[str] = []
    for group in groups:
        lowered = [term.lower() for term in group]
        if all(term in text_lower for term in lowered):
            matched_terms.extend(group)
            return True, unique_strings(matched_terms)
    return False, []


def add_json_payload(payloads: list[Any], seen: set[str], value: Any) -> None:
    if not isinstance(value, (dict, list)):
        return
    try:
        key = json.dumps(value, ensure_ascii=False, sort_keys=True)
    except TypeError:
        key = repr(value)
    if key in seen:
        return
    seen.add(key)
    payloads.append(value)


def extract_json_payloads_from_text(text: str, *, limit: int = 24) -> list[Any]:
    decoder = json.JSONDecoder()
    payloads: list[Any] = []
    seen: set[str] = set()
    candidates = [text.strip()]
    candidates.extend(match.group(1).strip() for match in re.finditer(r"```(?:json)?\s*([\s\S]*?)```", text, flags=re.IGNORECASE))
    for candidate in candidates:
        if not candidate:
            continue
        try:
            add_json_payload(payloads, seen, json.loads(candidate))
        except json.JSONDecodeError:
            pass
        if len(payloads) >= limit:
            return payloads[:limit]
    index = 0
    while index < len(text) and len(payloads) < limit:
        match = re.search(r"[\[{]", text[index:])
        if not match:
            break
        start = index + match.start()
        try:
            value, end = decoder.raw_decode(text[start:])
        except json.JSONDecodeError:
            index = start + 1
            continue
        add_json_payload(payloads, seen, value)
        index = start + max(int(end), 1)
    return payloads[:limit]


def nested_value(value: Any, key: str) -> Any:
    if isinstance(value, dict):
        if key in value:
            return value[key]
        for child in value.values():
            found = nested_value(child, key)
            if found is not None:
                return found
    elif isinstance(value, list):
        for child in value:
            found = nested_value(child, key)
            if found is not None:
                return found
    return None


def payload_type(value: Any) -> str:
    if isinstance(value, dict):
        content = value.get("structuredContent")
        if isinstance(content, dict) and content.get("type"):
            return str(content.get("type") or "")
        nested_content = nested_value(value, "structuredContent")
        if isinstance(nested_content, dict) and nested_content.get("type"):
            return str(nested_content.get("type") or "")
        if value.get("type"):
            return str(value.get("type") or "")
    return ""


def payload_content(value: Any) -> Any:
    if isinstance(value, dict) and isinstance(value.get("structuredContent"), dict):
        return value["structuredContent"]
    nested_content = nested_value(value, "structuredContent")
    if isinstance(nested_content, dict):
        return nested_content
    return value


def payload_has_all_terms(value: Any, terms: list[str]) -> bool:
    text_value = json.dumps(value, ensure_ascii=False, sort_keys=True).lower()
    return all(term.lower() in text_value for term in terms)


def summarize_json_payload_evidence(value: Any, *, max_chars: int = 420) -> str:
    content = payload_content(value)
    if isinstance(content, dict):
        details: list[str] = []
        if payload_type(value):
            details.append(f"type={payload_type(value)}")
        for key in ("ok", "status", "platform", "mode", "target_chapter", "chapter", "tool_count"):
            if key in content:
                details.append(f"{key}={content.get(key)}")
        if content.get("name"):
            details.append(f"name={content.get('name')}")
        if details:
            return redact_desktop_evidence_text("; ".join(details))[:max_chars]
    snippet = json.dumps(content, ensure_ascii=False, sort_keys=True)
    if len(snippet) > max_chars:
        snippet = snippet[: max_chars - 3].rstrip() + "..."
    return redact_desktop_evidence_text(snippet)


def extract_tools_from_payload(value: Any) -> list[str]:
    tools = nested_value(value, "tools")
    if not isinstance(tools, list):
        return []
    names: list[str] = []
    for tool in tools:
        if isinstance(tool, dict) and tool.get("name"):
            names.append(str(tool.get("name")))
        elif isinstance(tool, str):
            names.append(tool)
    return unique_strings(names)


