def desktop_evidence_quality_issue(check_id: str, evidence: str) -> dict[str, Any] | None:
    text = str(evidence or "").strip()
    if not text:
        return None
    lowered = re.sub(r"\s+", " ", text.lower()).strip(" .。:：;；,，`'\"[](){}")
    compact = re.sub(r"[\s._:：;；,，。`'\"!！?？\\/-]+", "", lowered)
    generic_values = {re.sub(r"[\s._:：;；,，。`'\"!！?？\\/-]+", "", item.lower()) for item in WEAK_DESKTOP_EVIDENCE_VALUES}
    if compact in generic_values:
        return {
            "type": "weak_evidence",
            "check_id": check_id,
            "message": "Evidence is too generic; include the real desktop client tool name, visible server name, returned status, or rejected-call detail.",
        }
    if len(text) < 18 and not any(term.lower() in lowered for term in DESKTOP_EVIDENCE_PROOF_TERMS):
        return {
            "type": "weak_evidence",
            "check_id": check_id,
            "message": "Evidence is too short to prove a real desktop client check; include a short tool-call or UI proof line.",
        }
    return None


DESKTOP_CHECK_BLOCKING_ISSUE_TYPES = {
    "missing_required_check",
    "required_check_not_passed",
    "missing_evidence",
    "weak_evidence",
    "missing_range_readiness_evidence",
    "missing_write_session_preflight_evidence",
    "missing_proposal_readiness_evidence",
    "missing_author_confirmation_evidence",
    "missing_acceptance_write_operation_evidence",
}


def build_record_desktop_check_command(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    install_config: str = "",
    chapter: int | None = None,
    results_reference: str | Path = "<results.json>",
) -> str:
    checklist = build_desktop_client_checklist(project_dir, platform=platform, mode=mode, install_config=install_config, chapter=chapter)
    parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "record-desktop-check",
        str(checklist.get("project_dir") or display_project_path(project_dir)),
        "--platform",
        str(checklist.get("platform") or platform),
        "--mode",
        str(checklist.get("mode") or mode),
    ]
    if install_config:
        parts.extend(["--install-config", install_config])
    parts.extend(
        [
            "--chapter",
            int(checklist.get("target_chapter") or chapter or 1),
            "--results",
            results_reference,
            "--agent-id",
            "<agent-id>",
            "--client-version",
            "<client-version>",
        ]
    )
    return shell_command(parts)


def validate_desktop_client_results(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
) -> dict[str, Any]:
    checklist = build_desktop_client_checklist(project_dir, platform=platform, mode=mode, install_config=install_config, chapter=chapter)
    expected = {str(item.get("id")): item for item in checklist.get("checklist", []) if isinstance(item, dict)}
    raw_results_text = json.dumps(results, ensure_ascii=False, sort_keys=True, default=str)
    safety_warnings = desktop_evidence_safety_warnings(raw_results_text)
    normalized = normalize_desktop_check_results(results)
    by_id = {item["id"]: item for item in normalized}
    issues: list[dict[str, Any]] = []
    for check_id, expected_item in expected.items():
        if not expected_item.get("required"):
            continue
        observed = by_id.get(check_id)
        if not observed:
            issues.append({"type": "missing_required_check", "check_id": check_id, "message": "Required desktop client check was not reported."})
            continue
        if observed.get("status") != "passed":
            issues.append({"type": "required_check_not_passed", "check_id": check_id, "status": observed.get("status"), "message": "Required desktop client check did not pass."})
        evidence = str(observed.get("evidence") or "").strip()
        if not evidence:
            issues.append({"type": "missing_evidence", "check_id": check_id, "message": "Required desktop client check needs evidence from the real client."})
        else:
            quality_issue = desktop_evidence_quality_issue(check_id, evidence)
            if quality_issue:
                issues.append(quality_issue)
            if check_id == "range_readiness_gate" and not desktop_evidence_mentions_range_readiness(evidence):
                issues.append(
                    {
                        "type": "missing_range_readiness_evidence",
                        "check_id": check_id,
                        "message": "Range readiness evidence must show build_chapter_range_readiness or chapter-range-readiness before multi-chapter handoff or presentation.",
                    }
                )
            elif checklist["mode"] == "writer" and check_id == "write_session_preflight_gate" and not desktop_evidence_mentions_write_session_check(evidence):
                issues.append(
                    {
                        "type": "missing_write_session_preflight_evidence",
                        "check_id": check_id,
                        "message": "Writer preflight evidence must show check_write_session or write-session-check before durable writer commands.",
                    }
                )
            elif checklist["mode"] == "writer" and check_id == "proposal_readiness_gate" and not desktop_evidence_mentions_proposal_readiness(evidence):
                issues.append(
                    {
                        "type": "missing_proposal_readiness_evidence",
                        "check_id": check_id,
                        "message": "Writer proposal readiness evidence must show build_proposal_readiness or proposal-readiness before applying updates.",
                    }
                )
            elif checklist["mode"] == "writer" and check_id == "acceptance_write_gate" and not desktop_evidence_mentions_author_confirmation(evidence):
                issues.append(
                    {
                        "type": "missing_author_confirmation_evidence",
                        "check_id": check_id,
                        "message": "Writer acceptance evidence must show author_confirmation or --author-confirmation for durable state writes.",
                    }
                )
            elif checklist["mode"] == "writer" and check_id == "acceptance_write_gate" and not desktop_evidence_mentions_acceptance_write_operation(evidence):
                issues.append(
                    {
                        "type": "missing_acceptance_write_operation_evidence",
                        "check_id": check_id,
                        "message": "Writer acceptance evidence must show a durable write command such as record_chapter, propose_after_write_updates, or apply_after_write_updates.",
                    }
                )
    unknown = sorted(check_id for check_id in by_id if check_id not in expected)
    for check_id in unknown:
        issues.append({"type": "unknown_check_id", "check_id": check_id, "message": "Check id is not part of the generated checklist."})
    issues.extend(safety_warnings)
    blocked_check_ids = {str(item.get("check_id") or "") for item in issues if item.get("type") in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES}
    passed_required = [
        check_id
        for check_id, expected_item in expected.items()
        if expected_item.get("required")
        and by_id.get(check_id, {}).get("status") == "passed"
        and bool(by_id.get(check_id, {}).get("evidence"))
        and check_id not in blocked_check_ids
    ]
    counts = {status: 0 for status in ("passed", "failed", "skipped", "not_checked")}
    for item in normalized:
        status = str(item.get("status") or "not_checked")
        counts[status] = counts.get(status, 0) + 1
    validation_ok = not any(item["type"] in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES for item in issues)
    return {
        "ok": validation_ok,
        "platform": checklist["platform"],
        "mode": checklist["mode"],
        "project_dir": str(project_root(project_dir)),
        "target_chapter": checklist["target_chapter"],
        "config_path": checklist.get("config_path") or "",
        "required_total": sum(1 for item in expected.values() if item.get("required")),
        "required_passed_with_evidence": len(passed_required),
        "required_check_ids": [check_id for check_id, item in expected.items() if item.get("required")],
        "unknown_check_ids": unknown,
        "counts": counts,
        "checks": normalized,
        "issues": issues,
        "safety_warnings": safety_warnings,
        "checklist": checklist.get("checklist", []),
    }


def build_desktop_results_doctor(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
    results_reference: str | Path = "<results.json>",
) -> dict[str, Any]:
    validation = validate_desktop_client_results(
        project_dir,
        platform=platform,
        mode=mode,
        results=results,
        install_config=install_config,
        chapter=chapter,
    )
    record_command = build_record_desktop_check_command(
        project_dir,
        platform=validation["platform"],
        mode=validation["mode"],
        install_config=install_config,
        chapter=validation["target_chapter"],
        results_reference=results_reference,
    )
    if validation["ok"]:
        status = "ready_to_record"
        actions = [
            "Review the short evidence one more time, then run record-desktop-check.",
            record_command,
        ]
    else:
        status = "needs_revision"
        actions = [
            "Fix every blocking issue in the result JSON before recording.",
            "Use result-json-guide.md and real-client-walkthrough.md to collect missing real desktop-client evidence.",
        ]
    return {
        "ok": validation["ok"],
        "type": "desktop_results_doctor",
        "generated_at": now_iso(),
        "status": status,
        "would_write_project_state": False,
        "platform": validation["platform"],
        "mode": validation["mode"],
        "project_dir": validation["project_dir"],
        "target_chapter": validation["target_chapter"],
        "config_path": validation["config_path"],
        "results_reference": str(results_reference),
        "required_total": validation["required_total"],
        "required_passed_with_evidence": validation["required_passed_with_evidence"],
        "counts": validation["counts"],
        "issues": validation["issues"],
        "safety_warnings": validation["safety_warnings"],
        "checks": validation["checks"],
        "record_command": record_command,
        "recommended_actions": actions,
        "validation": {
            "ok": validation["ok"],
            "issues": validation["issues"],
            "safety_warnings": validation["safety_warnings"],
        },
    }


def build_desktop_evidence_packet(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    evidence_text: str = "",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
    results_reference: str = "",
) -> dict[str, Any]:
    selected_platform = str(platform or "codex").strip().lower()
    selected_mode = str(mode or "read-only").strip().lower()
    checklist = build_desktop_client_checklist(project_dir, platform=selected_platform, mode=selected_mode, install_config=install_config, chapter=chapter)
    target = int(checklist.get("target_chapter") or chapter or 1)
    project = project_root(project_dir)
    evidence = str(evidence_text or "")
    source = "none"
    import_report: dict[str, Any] | None = None
    doctor: dict[str, Any] | None = None
    packet_results_reference = str(results_reference or "").strip()
    if evidence.strip():
        source = "evidence_text"
        if not packet_results_reference:
            packet_results_reference = f"imported-desktop-{selected_platform}-{selected_mode}-chapter-{target}-results.json"
        import_report = ingest_desktop_client_evidence(
            project,
            platform=selected_platform,
            mode=selected_mode,
            install_config=install_config,
            chapter=target,
            evidence_text=evidence,
        )
        doctor = build_desktop_results_doctor(
            project,
            platform=selected_platform,
            mode=selected_mode,
            results=import_report.get("results_payload"),
            install_config=install_config,
            chapter=target,
            results_reference=packet_results_reference,
        )
    elif results is not None:
        source = "results"
        packet_results_reference = packet_results_reference or "<results.json>"
        doctor = build_desktop_results_doctor(
            project,
            platform=selected_platform,
            mode=selected_mode,
            results=results,
            install_config=install_config,
            chapter=target,
            results_reference=packet_results_reference,
        )
    else:
        packet_results_reference = packet_results_reference or "<results.json>"

    if doctor:
        status = "ready_to_record" if doctor.get("ok") else "needs_revision"
        ok = bool(doctor.get("ok"))
    else:
        status = "needs_evidence"
        ok = False

    evidence_packet_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-evidence-packet",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--evidence",
        "<desktop-evidence.txt>",
        "--format",
        "markdown",
    ]
    if install_config:
        evidence_packet_parts.extend(["--install-config", install_config])
    ingest_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "ingest-desktop-evidence",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--evidence",
        "<desktop-evidence.txt>",
        "--output",
        packet_results_reference if packet_results_reference != "<results.json>" else "<imported-results.json>",
        "--format",
        "markdown",
    ]
    if install_config:
        ingest_parts.extend(["--install-config", install_config])
    doctor_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-results-doctor",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--results",
        packet_results_reference,
        "--format",
        "markdown",
    ]
    if install_config:
        doctor_parts.extend(["--install-config", install_config])
    record_command = build_record_desktop_check_command(
        project,
        platform=selected_platform,
        mode=selected_mode,
        install_config=install_config,
        chapter=target,
        results_reference=packet_results_reference,
    )

    next_actions: list[str] = []
    if status == "needs_evidence":
        next_actions.extend(
            [
                "Paste short real desktop-client proof into desktop-evidence.txt or pass an existing results JSON.",
                "Run this packet again before recording anything.",
            ]
        )
    elif status == "needs_revision":
        next_actions.extend(
            [
                "Fix missing required checks, missing evidence, writer readiness proof, author-confirmation proof, or safety warnings before recording.",
                "Use the imported results JSON only after reviewing match_details and running desktop-results-doctor.",
            ]
        )
    else:
        next_actions.append("Review the short evidence and run record-desktop-check if it is still correct.")

    return {
        "ok": ok,
        "type": "desktop_evidence_packet",
        "generated_at": now_iso(),
        "status": status,
        "source": source,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "platform": selected_platform,
        "mode": selected_mode,
        "project_dir": str(project),
        "target_chapter": target,
        "config_path": checklist.get("config_path") or "",
        "results_reference": packet_results_reference,
        "required_check_ids": [
            str(item.get("id") or "")
            for item in checklist.get("checklist", [])
            if isinstance(item, dict) and item.get("required")
        ],
        "import_report": import_report,
        "results_doctor": doctor,
        "checklist": checklist.get("checklist", []),
        "next_actions": next_actions,
        "recommended_commands": {
            "desktop_evidence_packet": shell_command(evidence_packet_parts),
            "ingest_evidence": shell_command(ingest_parts),
            "desktop_results_doctor": shell_command(doctor_parts),
            "record_desktop_check": record_command,
        },
    }


def build_desktop_evidence_review(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    evidence_text: str = "",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
    results_reference: str = "",
) -> dict[str, Any]:
    selected_platform = str(platform or "codex").strip().lower()
    selected_mode = str(mode or "read-only").strip().lower()
    project = project_root(project_dir)
    checklist = build_desktop_client_checklist(
        project,
        platform=selected_platform,
        mode=selected_mode,
        install_config=install_config,
        chapter=chapter,
    )
    target = int(checklist.get("target_chapter") or chapter or 1)
    evidence = str(evidence_text or "")
    session = build_desktop_evidence_session(
        project,
        platform=selected_platform,
        mode=selected_mode,
        install_config=install_config,
        chapter=target,
        results_file=str(results_reference or ""),
    )
    packet = build_desktop_evidence_packet(
        project,
        platform=selected_platform,
        mode=selected_mode,
        evidence_text=evidence_text,
        results=results,
        install_config=install_config,
        chapter=target,
        results_reference=results_reference,
    )
    state = project / STATE_DIR
    rows = read_jsonl(state / "desktop_verifications.jsonl") if state.exists() else []
    exact_record = latest_desktop_verification(rows, platform=selected_platform, mode=selected_mode, chapter=target)
    reusable_record = latest_desktop_verification_for_mode(rows, platform=selected_platform, mode=selected_mode, chapter=target)
    exact_status = real_desktop_verification_status(exact_record)
    reusable_status = real_desktop_verification_status(reusable_record)
    packet_doctor = packet.get("results_doctor") if isinstance(packet.get("results_doctor"), dict) else {}
    required_total = int(packet_doctor.get("required_total") or len(packet.get("required_check_ids") or []))
    passed_required = int(packet_doctor.get("required_passed_with_evidence") or 0)
    issues = packet_doctor.get("issues") if isinstance(packet_doctor.get("issues"), list) else []
    safety_warnings = packet_doctor.get("safety_warnings") if isinstance(packet_doctor.get("safety_warnings"), list) else []
    missing_required = [
        str(item.get("check_id") or item.get("id") or "")
        for item in issues
        if isinstance(item, dict) and item.get("type") in {"missing_required_check", "required_check_not_passed", "missing_evidence"}
    ]
    missing_required = [item for item in dict.fromkeys(missing_required) if item]
    if packet.get("ok"):
        if exact_status.get("status") == "passed":
            status = "recorded"
            ok = True
        else:
            status = "ready_to_record"
            ok = True
    elif packet.get("status") == "needs_evidence":
        if reusable_status.get("status") == "passed":
            status = "recorded_elsewhere"
            ok = True
        else:
            status = "needs_evidence"
            ok = False
    else:
        status = "needs_revision"
        ok = False

    review_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-evidence-review",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--format",
        "markdown",
    ]
    if install_config:
        review_parts.extend(["--install-config", install_config])
    if evidence.strip():
        review_parts.extend(["--evidence", "<desktop-evidence.txt>"])
    elif results is not None:
        review_parts.extend(["--results", results_reference or "<results.json>"])
    if results_reference:
        review_parts.extend(["--results-reference", results_reference])
    gaps_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-evidence-gaps",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--format",
        "markdown",
    ]
    if install_config:
        gaps_parts.extend(["--install-config", install_config])
    if evidence.strip():
        gaps_parts.extend(["--evidence", "<desktop-evidence.txt>"])
    elif results is not None:
        gaps_parts.extend(["--results", results_reference or "<results.json>"])
    if results_reference:
        gaps_parts.extend(["--results-reference", results_reference])

    next_actions: list[str] = []
    if status == "recorded":
        next_actions.append("Use the saved real desktop-client verification record for this platform, mode, and target chapter.")
    elif status == "recorded_elsewhere":
        next_actions.append("A reusable saved verification exists for this platform and mode, but not necessarily this exact target chapter.")
        next_actions.append("Record chapter-specific evidence if the handoff depends on target-chapter tool behavior.")
    elif status == "ready_to_record":
        next_actions.append("Review the evidence snippets, then run record-desktop-check.")
    elif status == "needs_revision":
        next_actions.append("Fix missing or weak evidence before recording.")
    else:
        next_actions.append("Collect real desktop-client proof with desktop-evidence-session, desktop-evidence-runbook, or checklist.md.")

    return {
        "$schema": DESKTOP_EVIDENCE_REVIEW_SCHEMA_OUTPUT_FILE,
        "ok": ok,
        "type": "desktop_evidence_review",
        "generated_at": now_iso(),
        "status": status,
        "local_only": True,
        "requires_server": False,
        "requires_real_desktop_client": True,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "platform": selected_platform,
        "mode": selected_mode,
        "project_dir": str(project),
        "target_chapter": target,
        "config_path": checklist.get("config_path") or "",
        "source": packet.get("source") or "none",
        "required_total": required_total,
        "required_passed_with_evidence": passed_required,
        "missing_required_check_ids": missing_required,
        "safety_warnings": safety_warnings,
        "evidence_session": {
            "required_check_ids": session.get("required_check_ids", []),
            "copy_prompt_count": len(session.get("copy_prompts") or []),
            "result_file": session.get("result_file") or "",
            "evidence_file": session.get("evidence_file") or "",
        },
        "evidence_packet": packet,
        "results_doctor": packet_doctor or None,
        "saved_verification": {
            "exact": exact_status,
            "reusable": reusable_status,
        },
        "next_actions": next_actions,
        "recommended_commands": {
            "desktop_evidence_review": shell_command(review_parts),
            "desktop_evidence_gaps": shell_command(gaps_parts),
            "desktop_evidence_session": shell_command(["python", kit_root() / "cli.py", "desktop-evidence-session", project, "--platform", selected_platform, "--mode", selected_mode, "--chapter", target, "--format", "markdown"]),
            "desktop_evidence_runbook": shell_command(["python", kit_root() / "cli.py", "desktop-evidence-runbook", project, "--platform", selected_platform, "--mode", selected_mode, "--chapter", target, "--format", "markdown"]),
            "desktop_evidence_packet": packet.get("recommended_commands", {}).get("desktop_evidence_packet", "") if isinstance(packet.get("recommended_commands"), dict) else "",
            "desktop_results_doctor": packet.get("recommended_commands", {}).get("desktop_results_doctor", "") if isinstance(packet.get("recommended_commands"), dict) else "",
            "record_desktop_check": packet.get("recommended_commands", {}).get("record_desktop_check", "") if isinstance(packet.get("recommended_commands"), dict) else "",
            "list_desktop_checks": shell_command(["python", kit_root() / "cli.py", "list-desktop-checks", project, "--platform", selected_platform]),
        },
    }


def desktop_evidence_gap_state(issue_types: set[str], observed: dict[str, Any] | None) -> str:
    if observed is None:
        return "missing_check"
    if str(observed.get("status") or "") != "passed":
        return "not_passed"
    if "missing_evidence" in issue_types:
        return "missing_evidence"
    if "weak_evidence" in issue_types:
        return "weak_evidence"
    special = {
        "missing_range_readiness_evidence",
        "missing_proposal_readiness_evidence",
        "missing_author_confirmation_evidence",
        "missing_acceptance_write_operation_evidence",
    }
    if issue_types & special:
        return "needs_specific_evidence"
    if issue_types:
        return "needs_review"
    return "passed"


def build_desktop_evidence_gaps(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    evidence_text: str = "",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
    results_reference: str = "",
) -> dict[str, Any]:
    review = build_desktop_evidence_review(
        project_dir,
        platform=platform,
        mode=mode,
        evidence_text=evidence_text,
        results=results,
        install_config=install_config,
        chapter=chapter,
        results_reference=results_reference,
    )
    packet = review.get("evidence_packet") if isinstance(review.get("evidence_packet"), dict) else {}
    checklist = packet.get("checklist") if isinstance(packet.get("checklist"), list) else []
    doctor = review.get("results_doctor") if isinstance(review.get("results_doctor"), dict) else {}
    checks = doctor.get("checks") if isinstance(doctor.get("checks"), list) else []
    issues = doctor.get("issues") if isinstance(doctor.get("issues"), list) else []
    session = review.get("evidence_session") if isinstance(review.get("evidence_session"), dict) else {}
    session_checks = build_desktop_evidence_session(
        review.get("project_dir"),
        platform=str(review.get("platform") or platform),
        mode=str(review.get("mode") or mode),
        install_config=str(review.get("config_path") or install_config or ""),
        chapter=int(review.get("target_chapter") or chapter or 1),
        results_file=str(session.get("result_file") or results_reference or ""),
    )
    prompt_by_id = {
        str(item.get("check_id") or ""): str(item.get("prompt") or "").strip()
        for item in session_checks.get("copy_prompts", [])
        if isinstance(item, dict)
    }
    session_check_by_id = {
        str(item.get("id") or ""): item
        for item in session_checks.get("checks", [])
        if isinstance(item, dict)
    }
    check_by_id = {str(item.get("id") or ""): item for item in checks if isinstance(item, dict)}
    issues_by_id: dict[str, list[dict[str, Any]]] = {}
    general_issues: list[dict[str, Any]] = []
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        check_id = str(issue.get("check_id") or issue.get("id") or "").strip()
        if check_id:
            issues_by_id.setdefault(check_id, []).append(issue)
        else:
            general_issues.append(issue)

    gaps: list[dict[str, Any]] = []
    passed_required: list[str] = []
    for expected in checklist:
        if not isinstance(expected, dict) or not expected.get("required"):
            continue
        check_id = str(expected.get("id") or "").strip()
        if not check_id:
            continue
        observed = check_by_id.get(check_id)
        check_issues = issues_by_id.get(check_id, [])
        issue_types = {str(item.get("type") or "") for item in check_issues if isinstance(item, dict)}
        state = desktop_evidence_gap_state(issue_types, observed)
        if state == "passed":
            passed_required.append(check_id)
        session_item = session_check_by_id.get(check_id, {})
        gaps.append(
            {
                "check_id": check_id,
                "phase": expected.get("phase") or session_item.get("phase"),
                "required": True,
                "state": state,
                "status": observed.get("status") if isinstance(observed, dict) else "missing",
                "action": expected.get("action") or session_item.get("action"),
                "expected": expected.get("expected") or session_item.get("expected"),
                "evidence": observed.get("evidence") if isinstance(observed, dict) else "",
                "evidence_needed": expected.get("evidence") or session_item.get("evidence_needed"),
                "issues": check_issues,
                "copy_prompt": prompt_by_id.get(check_id) or str(expected.get("prompt") or session_item.get("prompt") or "").strip(),
                "recommended_fix": desktop_evidence_gap_fix_text(check_id, state, check_issues),
            }
        )

    missing = [item["check_id"] for item in gaps if item.get("state") == "missing_check"]
    not_passed = [item["check_id"] for item in gaps if item.get("state") == "not_passed"]
    missing_evidence = [item["check_id"] for item in gaps if item.get("state") == "missing_evidence"]
    weak = [item["check_id"] for item in gaps if item.get("state") == "weak_evidence"]
    specific = [item["check_id"] for item in gaps if item.get("state") == "needs_specific_evidence"]
    review_needed = [item["check_id"] for item in gaps if item.get("state") == "needs_review"]
    blocking = [item for item in issues if isinstance(item, dict) and item.get("type") in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES]
    status = str(review.get("status") or "")
    if status in {"recorded", "recorded_elsewhere"} and not blocking:
        gap_status = status
    elif not gaps and packet.get("status") == "needs_evidence":
        gap_status = "needs_evidence"
    elif blocking or any(item.get("state") != "passed" for item in gaps):
        gap_status = "needs_revision" if packet.get("status") != "needs_evidence" else "needs_evidence"
    elif review.get("status") == "ready_to_record":
        gap_status = "ready_to_record"
    else:
        gap_status = status or "needs_evidence"

    recommended_commands = review.get("recommended_commands") if isinstance(review.get("recommended_commands"), dict) else {}
    gap_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-evidence-gaps",
        review.get("project_dir") or project_dir,
        "--platform",
        review.get("platform") or platform,
        "--mode",
        review.get("mode") or mode,
        "--chapter",
        int(review.get("target_chapter") or chapter or 1),
        "--format",
        "markdown",
    ]
    if install_config:
        gap_parts.extend(["--install-config", install_config])
    if evidence_text:
        gap_parts.extend(["--evidence", "<desktop-evidence.txt>"])
    elif results is not None:
        gap_parts.extend(["--results", results_reference or "<results.json>"])
    if results_reference:
        gap_parts.extend(["--results-reference", results_reference])
    recommended_commands["desktop_evidence_gaps"] = shell_command(gap_parts)

    return {
        "ok": gap_status in {"ready_to_record", "recorded", "recorded_elsewhere"},
        "type": "desktop_evidence_gaps",
        "generated_at": now_iso(),
        "status": gap_status,
        "local_only": True,
        "requires_server": False,
        "requires_real_desktop_client": True,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "platform": review.get("platform"),
        "mode": review.get("mode"),
        "project_dir": review.get("project_dir"),
        "target_chapter": review.get("target_chapter"),
        "config_path": review.get("config_path"),
        "source": review.get("source"),
        "result_file": session.get("result_file") or "",
        "evidence_file": session.get("evidence_file") or "",
        "required_total": len(gaps),
        "required_passed_with_evidence": len(passed_required),
        "summary": {
            "missing_check_count": len(missing),
            "not_passed_count": len(not_passed),
            "missing_evidence_count": len(missing_evidence),
            "weak_evidence_count": len(weak),
            "specific_evidence_count": len(specific),
            "review_needed_count": len(review_needed),
            "blocking_issue_count": len(blocking),
            "safety_warning_count": len(review.get("safety_warnings") if isinstance(review.get("safety_warnings"), list) else []),
        },
        "missing_check_ids": missing,
        "not_passed_check_ids": not_passed,
        "missing_evidence_check_ids": missing_evidence,
        "weak_evidence_check_ids": weak,
        "specific_evidence_check_ids": specific,
        "review_needed_check_ids": review_needed,
        "general_issues": general_issues,
        "safety_warnings": review.get("safety_warnings") if isinstance(review.get("safety_warnings"), list) else [],
        "gaps": gaps,
        "evidence_review": review,
        "next_actions": desktop_evidence_gap_next_actions(gap_status, gaps, review),
        "recommended_commands": recommended_commands,
    }


def desktop_evidence_gap_fix_text(check_id: str, state: str, issues: list[dict[str, Any]]) -> str:
    if state == "passed":
        return "No action needed for this required check."
    if state == "missing_check":
        return "Add this check id to the result JSON or paste real desktop-client evidence for it, then rerun the gap report."
    if state == "not_passed":
        return "Run the check again inside the real desktop client until the result can honestly be marked passed, or leave it failed and do not record as passing evidence."
    if state == "missing_evidence":
        return "Add a short proof line from the real desktop client: tool/server name, returned status, or rejected-call detail."
    if state == "weak_evidence":
        return "Replace generic words with concrete proof from the desktop client, such as the tool name and returned status."
    if state == "needs_specific_evidence":
        issue_types = {str(item.get("type") or "") for item in issues if isinstance(item, dict)}
        if "missing_range_readiness_evidence" in issue_types:
            return "Evidence must mention build_chapter_range_readiness or chapter-range-readiness."
        if "missing_write_session_preflight_evidence" in issue_types:
            return "Evidence must mention check_write_session or write-session-check."
        if "missing_proposal_readiness_evidence" in issue_types:
            return "Evidence must mention build_proposal_readiness or proposal-readiness."
        if "missing_author_confirmation_evidence" in issue_types:
            return "Evidence must mention author_confirmation or --author-confirmation."
        if "missing_acceptance_write_operation_evidence" in issue_types:
            return "Evidence must mention a durable writer command such as record_chapter, propose_after_write_updates, or apply_after_write_updates."
    return "Review the issue messages and rerun desktop-results-doctor after editing the evidence."


def desktop_evidence_gap_next_actions(status: str, gaps: list[dict[str, Any]], review: dict[str, Any]) -> list[str]:
    if status == "ready_to_record":
        return ["Review the evidence snippets once, then run record-desktop-check."]
    if status == "recorded":
        return ["Use the saved exact real desktop-client verification record for this chapter."]
    if status == "recorded_elsewhere":
        return ["A reusable platform/mode verification exists; record chapter-specific proof if this handoff depends on target-chapter behavior."]
    if status == "needs_evidence":
        return ["Open desktop-evidence-session.md, run the listed checks inside the real desktop client, and paste short proof into desktop-evidence.txt."]
    states = {str(item.get("state") or "") for item in gaps if isinstance(item, dict)}
    actions: list[str] = []
    if "missing_check" in states:
        actions.append("Add missing required check ids to the result JSON or collect evidence for them.")
    if "not_passed" in states:
        actions.append("Do not record failed required checks as passing evidence; rerun or fix them in the desktop client.")
    if "missing_evidence" in states or "weak_evidence" in states:
        actions.append("Replace missing or generic evidence with concrete tool-call or UI proof from the desktop client.")
    if "needs_specific_evidence" in states:
        actions.append("Add the required preflight, readiness, writer command, or author-confirmation tool name to the matching evidence line.")
    if not actions:
        actions.extend(review.get("next_actions") if isinstance(review.get("next_actions"), list) else [])
    actions.append("Rerun desktop-evidence-gaps or desktop-results-doctor before record-desktop-check.")
    return unique_strings(actions)


def latest_desktop_verification_for_mode(
    rows: list[dict[str, Any]],
    *,
    platform: str,
    mode: str,
    chapter: int | None = None,
) -> dict[str, Any]:
    if chapter:
        chapter_record = latest_desktop_verification(rows, platform=platform, mode=mode, chapter=chapter)
        if chapter_record:
            return chapter_record
    return latest_desktop_verification(rows, platform=platform, mode=mode)


def build_writer_mode_readiness(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    install_config: str = "",
    chapter: int | None = None,
    author_confirmation: str = "",
) -> dict[str, Any]:
    selected_platform = str(platform or "codex").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported writer mode readiness platform: {platform}")
    project = project_root(project_dir)
    state = project / STATE_DIR
    target = int(chapter or 1)
    confirmation = str(author_confirmation or "").strip()
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    if not state.exists():
        add_check("project_initialized", False, "blocker", "Project has no .novel-agent state.")
        return {
            "ok": False,
            "type": "writer_mode_readiness",
            "generated_at": now_iso(),
            "status": "blocked",
            "would_write_project_state": False,
            "would_write_install_config": False,
            "platform": selected_platform,
            "project_dir": str(project),
            "target_chapter": target,
            "config_path": "",
            "checks": checks,
            "blockers": [checks[0]["message"]],
            "review_items": [],
            "warnings": [],
            "read_only_verification": real_desktop_verification_status({}),
            "writer_verification": real_desktop_verification_status({}),
            "writer_setup_verification": {},
            "author_confirmation_present": bool(confirmation),
            "next_actions": ["Initialize or import the project before enabling writer mode."],
            "recommended_commands": [shell_command(["python", kit_root() / "cli.py", "quickstart", project, "--source", "auto", "--dry-run", "--format", "markdown"])],
        }

    project_state = project_status(project, chapter=chapter, platform=selected_platform)
    target = int(project_state.get("target_chapter") or target)
    data = load_state(project)
    rows = data.get("desktop_verifications", []) if isinstance(data.get("desktop_verifications"), list) else []
    read_only_record = latest_desktop_verification_for_mode(rows, platform=selected_platform, mode="read-only", chapter=target)
    writer_record = latest_desktop_verification_for_mode(rows, platform=selected_platform, mode="writer", chapter=target)
    read_only_status = real_desktop_verification_status(read_only_record)
    writer_status = real_desktop_verification_status(writer_record)
    writer_already_verified = writer_status.get("status") == "passed"
    setup = build_desktop_setup_guide(project, platform=selected_platform, mode="writer", install_config=install_config)
    config_path = str(setup.get("config_path") or "")
    setup_verification = verify_desktop_setup(project, platform=selected_platform, mode="writer", install_config=install_config, start_mcp_test=False)
    writer_config_ok = bool(setup_verification.get("ok"))
    counts = project_state.get("counts") if isinstance(project_state.get("counts"), dict) else {}
    pending_proposals = int(counts.get("pending_proposals") or 0)
    high_risk_proposals = int(counts.get("high_risk_proposals") or 0)
    project_readiness = str(project_state.get("readiness") or "unknown")

    add_check(
        "project_not_blocked",
        project_readiness != "blocked",
        "blocker",
        f"Project readiness is {project_readiness}.",
        {"readiness": project_readiness, "blockers": project_state.get("blockers", [])},
    )
    add_check(
        "read_only_real_client_verified",
        read_only_status.get("status") == "passed" or writer_already_verified,
        "blocker",
        "Read-only mode has a successful real desktop client verification record, or writer mode already has successful real-client proof.",
        {"read_only": read_only_status, "writer": writer_status},
    )
    add_check(
        "author_confirmed_writer_scope",
        bool(confirmation) or writer_already_verified,
        "review",
        "Author confirmed this desktop agent may enable writer mode and write .novel-agent state.",
        {"author_confirmation_present": bool(confirmation), "writer_already_verified": writer_already_verified},
    )
    add_check(
        "config_path_known",
        bool(config_path),
        "warning",
        "A local MCP config path is known for the writer install command.",
        {"config_path": config_path, "config_source": setup.get("config_source")},
    )
    add_check(
        "writer_config_ready_if_already_installed",
        writer_config_ok or not config_path,
        "warning",
        "Existing local MCP config already matches writer mode when checked.",
        {"verification_ok": writer_config_ok, "checks": setup_verification.get("checks", [])},
    )
    add_check(
        "pending_proposals_reviewed",
        pending_proposals == 0,
        "review",
        "No pending proposals need review before enabling writer mode.",
        {"pending_proposals": pending_proposals},
    )
    add_check(
        "high_risk_proposals_clear",
        high_risk_proposals == 0,
        "blocker",
        "No high-risk proposals are waiting for author review before enabling writer mode.",
        {"high_risk_proposals": high_risk_proposals},
    )
    add_check(
        "writer_verification_not_failed",
        writer_status.get("status") in {"missing", "passed"},
        "review",
        "Latest saved writer-mode real desktop client verification is not failed.",
        writer_status,
    )

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "blocked"
    elif writer_already_verified:
        status = "writer_verified"
    elif review_items:
        status = "needs_author_review" if review_items == ["Author confirmed this desktop agent may enable writer mode and write .novel-agent state."] else "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready_to_enable_writer"

    commands = setup.get("commands") if isinstance(setup.get("commands"), dict) else {}
    readiness_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "writer-mode-readiness",
        project,
        "--platform",
        selected_platform,
        "--chapter",
        target,
        "--format",
        "markdown",
    ]
    if config_path:
        readiness_parts.extend(["--install-config", config_path])
    if not confirmation:
        readiness_parts.extend(["--author-confirmation", "<author-approved writer mode scope>"])
    writer_checklist_parts: list[object] = ["python", kit_root() / "cli.py", "desktop-checklist", project, "--platform", selected_platform, "--mode", "writer", "--chapter", target, "--format", "markdown"]
    if config_path:
        writer_checklist_parts.extend(["--install-config", config_path])
    recommended_commands = [
        shell_command(readiness_parts),
        str(commands.get("print_mcp_config") or ""),
        str(commands.get("upgrade_install") or commands.get("merge_mcp_config") or ""),
        shell_command(writer_checklist_parts),
    ]
    if read_only_status.get("status") != "passed" and not writer_already_verified:
        recommended_commands.insert(0, shell_command(["python", kit_root() / "cli.py", "desktop-checklist", project, "--platform", selected_platform, "--mode", "read-only", "--chapter", target, "--format", "markdown"]))
    recommended_commands = [item for item in unique_strings(recommended_commands) if item]

    next_actions: list[str] = []
    if blockers:
        next_actions.append("Resolve blocker checks before enabling writer mode.")
    if read_only_status.get("status") != "passed" and not writer_already_verified:
        next_actions.append("Collect and record read-only real desktop client evidence first.")
    if not confirmation and writer_status.get("status") != "passed":
        next_actions.append(f"Read {WRITER_MODE_APPROVAL_MD_FILE} and {WRITER_MODE_APPROVAL_JSON_FILE} with the author, then rerun this check with --author-confirmation.")
    if status in {"ready_to_enable_writer", "ready_with_warnings"}:
        next_actions.append("Preview the writer MCP config, apply it only after review, then run the writer real-client checklist.")
    if status == "writer_verified":
        next_actions.append("Writer mode already has saved real desktop client evidence; keep using proposal readiness and author confirmation on durable writes.")

    return {
        "ok": status in {"ready_to_enable_writer", "ready_with_warnings", "writer_verified"},
        "type": "writer_mode_readiness",
        "generated_at": now_iso(),
        "status": status,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "platform": selected_platform,
        "project_dir": str(project),
        "target_chapter": target,
        "config_path": config_path,
        "project_status": project_state,
        "read_only_verification": read_only_status,
        "writer_verification": writer_status,
        "writer_setup_verification": setup_verification,
        "author_confirmation_present": bool(confirmation),
        "checks": checks,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": recommended_commands,
    }


def record_desktop_client_check(
    project_dir: str | Path,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    results: Any = None,
    install_config: str = "",
    chapter: int | None = None,
    agent_id: str = "",
    client_version: str = "",
    notes: str = "",
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    validation = validate_desktop_client_results(
        project_dir,
        platform=platform,
        mode=mode,
        results=results,
        install_config=install_config,
        chapter=chapter,
    )
    record = {
        "id": make_id("desktop-check"),
        "created_at": now_iso(),
        "platform": validation["platform"],
        "mode": validation["mode"],
        "project_dir": validation["project_dir"],
        "target_chapter": validation["target_chapter"],
        "config_path": validation["config_path"],
        "agent_id": agent_id.strip(),
        "client_version": client_version.strip(),
        "notes": notes.strip(),
        "ok": validation["ok"],
        "required_total": validation["required_total"],
        "required_passed_with_evidence": validation["required_passed_with_evidence"],
        "checks": validation["checks"],
        "issues": validation["issues"],
        "safety_warnings": validation["safety_warnings"],
    }
    append_jsonl(state / "desktop_verifications.jsonl", record)
    return {
        "ok": True,
        "record": record,
        "validation": {
            "ok": record["ok"],
            "issues": validation["issues"],
            "safety_warnings": validation["safety_warnings"],
        },
    }


def list_desktop_client_checks(project_dir: str | Path, *, platform: str = "", limit: int = 20) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "desktop_verifications.jsonl")
    selected = str(platform or "").strip().lower()
    if selected:
        rows = [row for row in rows if str(row.get("platform") or "").strip().lower() == selected]
    safe_limit = max(1, int(limit or 20))
    return {"ok": True, "records": rows[-safe_limit:]}


def resolve_activity_context_file(project: Path, value: str) -> tuple[Path, str]:
    raw = str(value or "").strip()
    if not raw:
        raise KitError("context file path is empty")
    path = Path(raw).expanduser()
    candidates = [path]
    if not path.is_absolute():
        candidates.insert(0, project / path)
    for candidate in candidates:
        if candidate.exists() and candidate.is_file():
            try:
                stored = candidate.resolve().relative_to(project.resolve()).as_posix()
            except ValueError:
                stored = str(candidate)
            return candidate, stored
    raise KitError(f"Context file not found: {raw}")


def record_agent_activity(
    project_dir: str | Path,
    *,
    agent_id: str,
    action: str,
    platform: str = "",
    chapter: int | None = None,
    summary: str = "",
    context_source: str = "",
    context_hash: str = "",
    context_file: str = "",
    files: Any = None,
    status: str = "done",
    handoff_to: str = "",
    notes: str = "",
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = ensure_state(project)
    normalized_agent_id = str(agent_id or "").strip()
    normalized_action = str(action or "").strip()
    if not normalized_agent_id:
        raise KitError("agent_id is required")
    if not normalized_action:
        raise KitError("action is required")
    context: dict[str, Any] = {
        "source": str(context_source or "").strip(),
        "hash": str(context_hash or "").strip(),
        "file": "",
    }
    if context_file:
        path, stored_path = resolve_activity_context_file(project, context_file)
        data = path.read_bytes()
        context.update({"file": stored_path, "hash": hashlib.sha256(data).hexdigest(), "bytes": len(data)})
    record = {
        "id": make_id("agent-activity"),
        "created_at": now_iso(),
        "agent_id": normalized_agent_id,
        "platform": str(platform or "").strip().lower(),
        "action": normalized_action,
        "status": str(status or "done").strip() or "done",
        "chapter": int(chapter) if chapter is not None else None,
        "summary": limit_text(str(summary or "").strip(), 1200),
        "context": context,
        "files": unique_strings(split_list(files)),
        "handoff_to": str(handoff_to or "").strip(),
        "notes": limit_text(str(notes or "").strip(), 2000),
    }
    append_jsonl(state / "agent_activity.jsonl", record)
    return {"ok": True, "type": "agent_activity_record", "record": record}


def list_agent_activity(
    project_dir: str | Path,
    *,
    agent_id: str = "",
    chapter: int | None = None,
    action: str = "",
    limit: int = 20,
) -> dict[str, Any]:
    state = ensure_state(project_dir)
    rows = read_jsonl(state / "agent_activity.jsonl")
    selected_agent = str(agent_id or "").strip()
    selected_action = str(action or "").strip().lower()
    if selected_agent:
        rows = [row for row in rows if str(row.get("agent_id") or "").strip() == selected_agent]
    if chapter is not None:
        rows = [row for row in rows if row.get("chapter") == int(chapter)]
    if selected_action:
        rows = [row for row in rows if str(row.get("action") or "").strip().lower() == selected_action]
    safe_limit = max(1, int(limit or 20))
    return {
        "ok": True,
        "type": "agent_activity",
        "filters": {"agent_id": selected_agent, "chapter": chapter, "action": selected_action},
        "records": rows[-safe_limit:],
    }


AGENT_ACTIVITY_REQUIRED_FILE_ACTIONS = {
    "draft",
    "revise",
    "check",
    "chapter-readiness",
    "chapter-delivery",
    "handoff",
}
WEAK_AGENT_ACTIVITY_SUMMARIES = {"ok", "done", "passed", "checked", "fixed", "updated", "complete", "completed"}


def normalize_agent_activity_action(value: Any) -> str:
    return re.sub(r"[_\s]+", "-", str(value or "").strip().lower())


def evaluate_agent_activity_record(record: dict[str, Any]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    record_id = str(record.get("id") or "")
    action = normalize_agent_activity_action(record.get("action"))
    summary = str(record.get("summary") or "").strip()
    summary_key = re.sub(r"\s+", " ", summary.lower())
    context = record.get("context") if isinstance(record.get("context"), dict) else {}
    files = record.get("files") if isinstance(record.get("files"), list) else []
    status = str(record.get("status") or "").strip().lower()

    if not summary or len(summary) < 18 or summary_key in WEAK_AGENT_ACTIVITY_SUMMARIES:
        issues.append(
            {
                "type": "weak_summary",
                "severity": "review",
                "record_id": record_id,
                "message": "Activity summary is missing or too generic for handoff.",
            }
        )
    if not (context.get("source") or context.get("hash") or context.get("file")):
        issues.append(
            {
                "type": "missing_context",
                "severity": "warning",
                "record_id": record_id,
                "message": "Activity does not name the context source or context hash used by the agent.",
            }
        )
    if action in AGENT_ACTIVITY_REQUIRED_FILE_ACTIONS and not files:
        issues.append(
            {
                "type": "missing_files",
                "severity": "warning",
                "record_id": record_id,
                "message": "Activity changed or checked writing state but did not list related files.",
            }
        )
    if status in {"failed", "blocked", "needs_revision", "needs-review"}:
        issues.append(
            {
                "type": "unfinished_status",
                "severity": "review",
                "record_id": record_id,
                "message": f"Activity status is {status}.",
            }
        )
    return issues


def build_agent_activity_quality(records: list[dict[str, Any]], missing_required: list[str], record_issues: list[dict[str, Any]]) -> dict[str, Any]:
    deductions: list[dict[str, Any]] = []

    def add_deduction(reason: str, points: int, message: str, detail: dict[str, Any] | None = None) -> None:
        deductions.append(
            {
                "reason": reason,
                "points": int(points),
                "message": message,
                "detail": detail or {},
            }
        )

    if not records:
        add_deduction("no_visible_activity", 100, "No target-visible activity records are available for handoff.")
    for action in missing_required:
        add_deduction(
            "missing_required_action",
            25,
            f"Required activity action is missing: {action}.",
            {"action": action},
        )
    for issue in record_issues:
        if not isinstance(issue, dict):
            continue
        severity = str(issue.get("severity") or "").strip().lower()
        points = 20 if severity == "review" else 10
        add_deduction(
            str(issue.get("type") or "activity_issue"),
            points,
            str(issue.get("message") or "Activity record needs review."),
            {
                "severity": severity or "warning",
                "record_id": str(issue.get("record_id") or ""),
            },
        )

    total_deduction = min(100, sum(int(item.get("points") or 0) for item in deductions))
    score = max(0, 100 - total_deduction)
    if score >= 95:
        rating = "excellent"
    elif score >= 85:
        rating = "ready"
    elif score >= 70:
        rating = "usable_with_warnings"
    elif score >= 50:
        rating = "needs_review"
    else:
        rating = "blocked"
    return {
        "score": score,
        "rating": rating,
        "deduction_total": total_deduction,
        "deductions": deductions,
        "thresholds": {
            "excellent": 95,
            "ready": 85,
            "usable_with_warnings": 70,
            "needs_review": 50,
        },
    }


def build_agent_activity_report(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    agent_id: str = "",
    required_actions: Any = None,
    limit: int = 20,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = ensure_state(project)
    rows = read_jsonl(state / "agent_activity.jsonl")
    selected_agent = str(agent_id or "").strip()
    if chapter is not None:
        rows = visible_recent_agent_activity(rows, chapter=int(chapter), limit=max(len(rows), 1))
    if selected_agent:
        rows = [row for row in rows if isinstance(row, dict) and str(row.get("agent_id") or "").strip() == selected_agent]
    rows = [row for row in rows if isinstance(row, dict)]
    safe_limit = max(1, int(limit or 20))
    records = rows[-safe_limit:]
    required = [normalize_agent_activity_action(item) for item in split_list(required_actions)]
    required = [item for item in required if item]
    action_counts: dict[str, int] = {}
    for row in records:
        action = normalize_agent_activity_action(row.get("action"))
        if action:
            action_counts[action] = action_counts.get(action, 0) + 1
    missing_required = [item for item in required if action_counts.get(item, 0) <= 0]
    record_issues: list[dict[str, Any]] = []
    for row in records:
        record_issues.extend(evaluate_agent_activity_record(row))
    handoff_quality = build_agent_activity_quality(records, missing_required, record_issues)

    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    add_check(
        "activity_present",
        bool(records),
        "blocker",
        "Target-visible agent activity exists for this project and filter.",
        {"records": len(records), "chapter": chapter, "agent_id": selected_agent},
    )
    if required:
        add_check(
            "required_actions_present",
            not missing_required,
            "review",
            "Required agent activity actions are present.",
            {"required": required, "missing": missing_required, "action_counts": action_counts},
        )
    review_issue_count = sum(1 for item in record_issues if item.get("severity") == "review")
    warning_issue_count = sum(1 for item in record_issues if item.get("severity") == "warning")
    add_check(
        "activity_quality",
        review_issue_count == 0,
        "review",
        "Activity summaries and statuses are specific enough for handoff.",
        {"review_issues": review_issue_count},
    )
    add_check(
        "activity_evidence",
        warning_issue_count == 0,
        "warning",
        "Activity entries name context source and related files when expected.",
        {"warning_issues": warning_issue_count},
    )

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    next_actions: list[str] = []
    if not records:
        next_actions.append("Record a concise agent activity entry after prepare, draft, revise, check, or handoff work.")
    if missing_required:
        next_actions.append("Record or review the missing required activity actions before handoff.")
    if review_issue_count:
        next_actions.append("Replace generic activity summaries with specific work, context, and handoff notes.")
    if warning_issue_count:
        next_actions.append("Add context source, context file/hash, or related files to the activity record when possible.")
    if int(handoff_quality.get("score") or 0) < 85 and records:
        next_actions.append("Improve activity records until the handoff quality score is at least 85 before a multi-agent takeover.")
    if not next_actions:
        next_actions.append("Activity records are usable as handoff evidence for the selected chapter and filters.")
    return {
        "ok": status in {"ready", "ready_with_warnings"},
        "type": "agent_activity_report",
        "generated_at": now_iso(),
        "status": status,
        "project_dir": str(project),
        "state_dir": str(state),
        "filters": {"agent_id": selected_agent, "chapter": chapter, "required_actions": required, "limit": safe_limit},
        "records": records,
        "action_counts": dict(sorted(action_counts.items())),
        "missing_required_actions": missing_required,
        "record_issues": record_issues,
        "handoff_quality": handoff_quality,
        "quality_score": handoff_quality["score"],
        "checks": checks,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": [
            shell_command(["python", "cli.py", "list-agent-activity", project, "--chapter", chapter, "--format", "markdown"])
            if chapter is not None
            else shell_command(["python", "cli.py", "list-agent-activity", project, "--format", "markdown"]),
            shell_command(["python", "cli.py", "record-agent-activity", project, "--agent-id", selected_agent or "<agent-id>", "--action", "<action>", "--chapter", chapter or "<chapter>", "--summary", "<specific-summary>", "--context-source", "prepare_chapter_session", "--format", "markdown"]),
        ],
    }


def resolve_project_reference(project: Path, value: Any) -> Path:
    raw = str(value or "").strip()
    path = Path(raw).expanduser()
    if not path.is_absolute():
        path = project / path
    return path


def inspect_agent_activity_references(project: Path, records: list[dict[str, Any]]) -> list[dict[str, Any]]:
    issues: list[dict[str, Any]] = []
    for row in records:
        if not isinstance(row, dict):
            continue
        record_id = str(row.get("id") or "")
        context = row.get("context") if isinstance(row.get("context"), dict) else {}
        context_file = str(context.get("file") or "").strip()
        context_hash = str(context.get("hash") or "").strip()
        if context_file:
            path = resolve_project_reference(project, context_file)
            if not path.exists() or not path.is_file():
                issues.append(
                    {
                        "type": "missing_context_file",
                        "severity": "review",
                        "record_id": record_id,
                        "path": context_file,
                        "message": "Activity context file is missing, so the next agent cannot verify the recorded context.",
                    }
                )
            elif context_hash:
                actual_hash = hashlib.sha256(path.read_bytes()).hexdigest()
                if actual_hash != context_hash:
                    issues.append(
                        {
                            "type": "context_hash_mismatch",
                            "severity": "review",
                            "record_id": record_id,
                            "path": context_file,
                            "expected": context_hash,
                            "actual": actual_hash,
                            "message": "Activity context file hash no longer matches the recorded context hash.",
                        }
                    )
        files = row.get("files") if isinstance(row.get("files"), list) else []
        for item in files:
            raw = str(item or "").strip()
            if not raw:
                continue
            path = resolve_project_reference(project, raw)
            if not path.exists():
                issues.append(
                    {
                        "type": "missing_related_file",
                        "severity": "warning",
                        "record_id": record_id,
                        "path": raw,
                        "message": "Activity references a file that does not exist in this project directory.",
                    }
                )
    return issues


def context_fingerprint_payload(context: dict[str, Any]) -> dict[str, Any]:
    previous = context.get("previous_chapter") if isinstance(context.get("previous_chapter"), dict) else {}
    return {
        "target_chapter": context.get("target_chapter"),
        "project": context.get("project"),
        "previous_chapter": {
            "id": previous.get("id"),
            "chapter": previous.get("chapter"),
            "hash": previous.get("hash"),
            "text_units": previous.get("text_units"),
            "tail": previous.get("tail"),
            "handoff": previous.get("handoff"),
        },
        "handoff": context.get("handoff"),
        "rules": context.get("rules"),
        "characters": context.get("characters"),
        "open_debts": context.get("open_debts"),
        "contracts": context.get("contracts"),
        "facts": context.get("facts"),
        "sources": context.get("sources"),
        "research": context.get("research"),
        "resolved_conflicts": context.get("resolved_conflicts"),
        "chapter_contract": context.get("chapter_contract"),
        "style_profile": context.get("style_profile"),
    }


def build_handoff_integrity_report(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    agent_id: str = "",
    required_actions: Any = None,
    expected_context_hash: str = "",
    limit: int = 20,
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    if not state.exists():
        add_check("project_initialized", False, "blocker", "Project has no .novel-agent state.")
        return {
            "ok": False,
            "type": "handoff_integrity_report",
            "generated_at": now_iso(),
            "status": "blocked",
            "project_dir": str(project),
            "state_dir": str(state),
            "target_chapter": chapter,
            "checks": checks,
            "blockers": [checks[0]["message"]],
            "review_items": [],
            "warnings": [],
            "next_actions": ["Initialize or import the project before checking handoff integrity."],
            "recommended_commands": [shell_command(["python", kit_root() / "cli.py", "quickstart", project, "--source", "auto", "--dry-run", "--format", "markdown"])],
        }

    data = load_state(project)
    target = next_target_chapter(data, chapter=chapter)
    context = build_chapter_context(project, chapter=target)
    fingerprint_payload = context_fingerprint_payload(context)
    context_hash = payload_hash(fingerprint_payload)
    handoff_report = build_handoff_report(project, chapter=target, include_context=include_context)
    activity_report = build_agent_activity_report(
        project,
        chapter=target,
        agent_id=agent_id,
        required_actions=required_actions,
        limit=limit,
    )
    records = activity_report.get("records") if isinstance(activity_report.get("records"), list) else []
    reference_issues = inspect_agent_activity_references(project, records)
    reference_review_count = sum(1 for item in reference_issues if item.get("severity") == "review")
    reference_warning_count = sum(1 for item in reference_issues if item.get("severity") == "warning")
    pending = handoff_report.get("pending_proposals") if isinstance(handoff_report.get("pending_proposals"), list) else []
    high_risk = handoff_report.get("high_risk_proposals") if isinstance(handoff_report.get("high_risk_proposals"), list) else []
    handoff_text = str(handoff_report.get("handoff") or "").strip()
    has_real_handoff = bool(handoff_text and "No accepted chapter has been recorded yet." not in handoff_text)
    selected_agent = str(agent_id or "").strip()
    expected_hash = str(expected_context_hash or "").strip()
    activity_context_hashes = unique_strings(
        [
            str((row.get("context") or {}).get("hash") or "").strip()
            for row in records
            if isinstance(row, dict) and isinstance(row.get("context"), dict)
        ]
    )

    add_check("target_context_available", bool(context.get("project")), "blocker", f"Target chapter {target} context can be built.")
    add_check(
        "handoff_report_target_matches",
        int(handoff_report.get("target_chapter") or 0) == target,
        "blocker",
        "Handoff report target chapter matches this integrity check.",
        {"handoff_target": handoff_report.get("target_chapter"), "target": target},
    )
    add_check(
        "handoff_text_present",
        target <= 1 or has_real_handoff,
        "warning",
        "Latest accepted chapter or handoff.md contains handoff text.",
    )
    add_check(
        "activity_report_usable",
        activity_report.get("status") in {"ready", "ready_with_warnings"},
        "review",
        "Target-visible agent activity is usable for handoff.",
        {"activity_status": activity_report.get("status"), "records": len(records), "missing_required_actions": activity_report.get("missing_required_actions", [])},
    )
    add_check(
        "activity_references_intact",
        reference_review_count == 0,
        "review",
        "Activity context files still exist and match recorded hashes.",
        {"review_issues": reference_review_count},
    )
    add_check(
        "activity_related_files_exist",
        reference_warning_count == 0,
        "warning",
        "Activity related files still exist in this project directory.",
        {"warning_issues": reference_warning_count},
    )
    if expected_hash:
        add_check(
            "expected_context_hash_matches",
            expected_hash == context_hash,
            "review",
            "Expected context hash matches the current target-chapter context fingerprint.",
            {"expected": expected_hash, "actual": context_hash, "activity_context_hashes": activity_context_hashes},
        )
    add_check("pending_proposals_clear", not pending, "review", "No pending proposal blocks this handoff.", {"pending": len(pending)})
    add_check("high_risk_proposals_clear", not high_risk, "blocker", "No high-risk proposal blocks this handoff.", {"high_risk": len(high_risk)})

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    next_actions: list[str] = []
    if blockers:
        next_actions.append("Resolve blocker checks before the next desktop agent drafts from this handoff.")
    if review_items:
        next_actions.append("Review activity records, pending proposals, or context hash mismatches before accepting the handoff.")
    if warnings:
        next_actions.append("Check missing handoff text or referenced files before relying on the previous agent's work.")
    if not next_actions:
        next_actions.append("Handoff material is consistent enough for the next desktop agent to call prepare-session and draft.")
    recommended = [
        shell_command(["python", kit_root() / "cli.py", "prepare-session", project, "--chapter", target, "--format", "markdown"]),
        shell_command(["python", kit_root() / "cli.py", "handoff-report", project, "--chapter", target, "--format", "markdown"]),
        shell_command(["python", kit_root() / "cli.py", "agent-activity-report", project, "--chapter", target, "--format", "markdown"]),
        shell_command(["python", kit_root() / "cli.py", "handoff-readiness", project, "--chapter", target, "--incoming-agent-id", selected_agent or "<incoming-agent-id>", "--format", "markdown"]),
    ]
    report: dict[str, Any] = {
        "ok": status in {"ready", "ready_with_warnings"},
        "type": "handoff_integrity_report",
        "generated_at": now_iso(),
        "status": status,
        "project_dir": str(project),
        "state_dir": str(state),
        "target_chapter": target,
        "agent_id": selected_agent,
        "read_only": True,
        "writes_project_state": False,
        "current_context": {
            "fingerprint": context_hash,
            "payload": fingerprint_payload,
            "summary": {
                "characters": len(context.get("characters", [])),
                "facts": len(context.get("facts", [])),
                "sources": len(context.get("sources", [])),
                "research": len(context.get("research", [])),
                "contracts": len(context.get("contracts", [])),
                "open_debts": len(context.get("open_debts", [])),
            },
        },
        "expected_context_hash": expected_hash,
        "activity_context_hashes": activity_context_hashes,
        "handoff_report": handoff_report,
        "activity_report": activity_report,
        "reference_issues": reference_issues,
        "checks": checks,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": recommended,
    }
    if include_context:
        report["chapter_context"] = context
    return report


def range_pending_proposals(data: dict[str, Any], *, start_chapter: int, end_chapter: int) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    pending = [
        row
        for row in data.get("proposals", [])
        if isinstance(row, dict)
        and start_chapter <= int(row.get("chapter") or 0) <= end_chapter
        and str(row.get("status") or "proposed").lower() in {"proposed", "pending", "needs_revision"}
    ]
    high_risk = [
        row
        for row in pending
        if str(((row.get("risk") or {}).get("level") if isinstance(row.get("risk"), dict) else "") or "").lower() == "high"
    ]
    return pending, high_risk


def build_handoff_range_report(
    project_dir: str | Path,
    *,
    start_chapter: int,
    end_chapter: int,
    handoff_chapter: int | None = None,
    draft_dir: str = "chapters",
    file_template: str = "{chapter:03d}.md",
    agent_id: str = "",
    required_actions: Any = None,
    expected_context_hash: str = "",
    limit: int = 20,
    include_context: bool = False,
) -> dict[str, Any]:
    if start_chapter < 1 or end_chapter < 1:
        raise KitError("Chapter numbers must be positive.")
    if end_chapter < start_chapter:
        raise KitError("End chapter must be greater than or equal to start chapter.")
    target = int(handoff_chapter or (end_chapter + 1))
    project = project_root(project_dir)
    data = load_state(project)
    range_report = build_chapter_range_readiness(
        project,
        start_chapter=start_chapter,
        end_chapter=end_chapter,
        draft_dir=draft_dir,
        file_template=file_template,
    )
    integrity_report = build_handoff_integrity_report(
        project,
        chapter=target,
        agent_id=agent_id,
        required_actions=required_actions,
        expected_context_hash=expected_context_hash,
        limit=limit,
        include_context=include_context,
    )
    pending, high_risk = range_pending_proposals(data, start_chapter=start_chapter, end_chapter=end_chapter)
    range_status = str(range_report.get("status") or "")
    integrity_status = str(integrity_report.get("status") or "")
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    range_ok = bool(range_report.get("ready_to_present"))
    if range_status in {"needs_files", "needs_revision", "error", "missing"}:
        range_severity = "blocker"
    elif range_status == "review":
        range_severity = "review"
    elif range_status == "ready_with_notes":
        range_severity = "warning"
    else:
        range_severity = "review"
    add_check(
        "chapter_range_ready",
        range_ok,
        range_severity,
        "Draft chapter range is ready enough for author presentation or handoff.",
        {
            "range_status": range_status,
            "problem_chapters": (range_report.get("summary") or {}).get("problem_chapters") if isinstance(range_report.get("summary"), dict) else [],
        },
    )
    if integrity_status == "blocked":
        integrity_severity = "blocker"
    elif integrity_status == "needs_review":
        integrity_severity = "review"
    elif integrity_status == "ready_with_warnings":
        integrity_severity = "warning"
    else:
        integrity_severity = "review"
    add_check(
        "handoff_integrity_ready",
        integrity_status in {"ready", "ready_with_warnings"},
        integrity_severity,
        "Handoff material for the next target chapter is internally consistent.",
        {"handoff_status": integrity_status, "handoff_chapter": target},
    )
    add_check(
        "range_pending_proposals_clear",
        not pending,
        "review",
        "No pending post-write proposals exist inside this chapter range.",
        {"pending": len(pending)},
    )
    add_check(
        "range_high_risk_proposals_clear",
        not high_risk,
        "blocker",
        "No high-risk pending proposal exists inside this chapter range.",
        {"high_risk": len(high_risk)},
    )
    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    next_actions: list[str] = []
    if not range_ok:
        next_actions.append("Fix the chapter range readiness issues before presenting or handing off these chapters.")
    if pending:
        next_actions.append("Review or apply pending post-write proposals for chapters in the handoff range.")
    if integrity_status not in {"ready", "ready_with_warnings"}:
        next_actions.append("Resolve handoff integrity review items before the next desktop agent drafts from this handoff.")
    if not next_actions:
        next_actions.append("The chapter range and handoff material are ready for the next desktop agent's takeover workflow.")
    recommended = {
        "rerun_handoff_range_report": shell_command(
            [
                "python",
                kit_root() / "cli.py",
                "handoff-range-report",
                project,
                "--start",
                start_chapter,
                "--end",
                end_chapter,
                "--handoff-chapter",
                target,
                "--draft-dir",
                draft_dir,
                "--file-template",
                file_template,
                "--format",
                "markdown",
            ]
        ),
        "chapter_range_readiness": shell_command(
            [
                "python",
                kit_root() / "cli.py",
                "chapter-range-readiness",
                project,
                "--start",
                start_chapter,
                "--end",
                end_chapter,
                "--draft-dir",
                draft_dir,
                "--file-template",
                file_template,
                "--format",
                "markdown",
            ]
        ),
        "handoff_integrity": shell_command(["python", kit_root() / "cli.py", "handoff-integrity", project, "--chapter", target, "--format", "markdown"]),
        "handoff_report": shell_command(["python", kit_root() / "cli.py", "handoff-report", project, "--chapter", target, "--format", "markdown"]),
        "agent_activity_report": shell_command(["python", kit_root() / "cli.py", "agent-activity-report", project, "--chapter", target, "--format", "markdown"]),
    }
    if pending:
        first_id = str(pending[0].get("id") or "<proposal-id>")
        recommended["proposal_readiness"] = shell_command(["python", kit_root() / "cli.py", "proposal-readiness", project, "--proposal-id", first_id, "--format", "markdown"])
    return {
        "ok": status in {"ready", "ready_with_warnings"},
        "type": "handoff_range_report",
        "generated_at": now_iso(),
        "status": status,
        "project_dir": str(project),
        "range": {"start": start_chapter, "end": end_chapter},
        "handoff_chapter": target,
        "read_only": True,
        "writes_project_state": False,
        "chapter_range_readiness": range_report,
        "handoff_integrity": integrity_report,
        "pending_range_proposals": pending,
        "pending_range_proposals_count": len(pending),
        "high_risk_range_proposals_count": len(high_risk),
        "checks": checks,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": recommended,
    }


def detect_quickstart_source(project: Path, source: str) -> str:
    selected = (source or "auto").strip().lower()
    if selected not in QUICKSTART_SOURCES:
        raise KitError(f"Unsupported quickstart source: {source}")
    if selected == "auto":
        return "import-gaoxia" if (project / "project.json").exists() else "init"
    return selected


def quickstart_project(
    project_dir: str | Path,
    *,
    source: str = "auto",
    title: str | None = None,
    target_chapters: int | None = None,
    target_words: int | None = None,
    required_phrases: Any = None,
    forbidden_phrases: Any = None,
    future_markers: Any = None,
    rule_notes: Any = None,
    style_note: str = "",
    source_summary: str = "",
    source_path: str = "",
    chapter_range: str = "",
    agent_id: str = "",
    platform: str = "generic",
    mode: str = "writer",
    capabilities: Any = None,
    agent_notes: str = "",
    append_import: bool = False,
    chapter: int | None = None,
    install_config: str = "",
    start_mcp_test: bool = False,
    summary_only: bool = True,
    dry_run: bool = False,
    force: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    selected_source = detect_quickstart_source(project, source)
    selected_mode = (mode or "writer").strip().lower()
    selected_platform = (platform or "generic").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported quickstart platform: {platform}")
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported quickstart mode: {mode}")
    selected_capabilities = split_list(capabilities) or default_agent_capabilities(selected_mode)
    selected_agent_id = agent_id.strip() or f"{selected_platform}-local"
    import_gaoxia = selected_source == "import-gaoxia"
    plan = init_wizard_plan(
        project,
        title=title,
        target_chapters=target_chapters,
        target_words=target_words,
        required_phrases=required_phrases,
        forbidden_phrases=forbidden_phrases,
        future_markers=future_markers,
        rule_notes=rule_notes,
        style_note=style_note,
        source_summary=source_summary,
        source_path=source_path,
        chapter_range=chapter_range,
        agent_id=selected_agent_id,
        platform=selected_platform,
        capabilities=selected_capabilities,
        import_gaoxia=import_gaoxia,
        append_import=append_import,
        force=force,
    )
    template = build_agent_template(platform=selected_platform, mode=selected_mode)
    report: dict[str, Any] = {
        "ok": True,
        "type": "quickstart_report",
        "generated_at": now_iso(),
        "dry_run": dry_run,
        "project_dir": str(project),
        "state_dir": str(project / STATE_DIR),
        "selected_source": selected_source,
        "platform": selected_platform,
        "mode": selected_mode,
        "plan": plan,
        "agent_template": {
            "workflow": template.get("workflow", []),
            "capabilities_to_declare": template.get("capabilities_to_declare", []),
            "mcp_start_mode": template.get("mcp_start_mode"),
            "installation_hint": template.get("installation_hint"),
        },
        "recommended_commands": [
            shell_command(["python", "cli.py", "quickstart", project, "--source", selected_source, "--platform", selected_platform, "--mode", selected_mode]),
        ],
    }
    if install_config:
        report["recommended_commands"].append(
            shell_command(["python", "cli.py", "doctor", project, "--install-config", install_config, "--start-mcp-test"])
        )
    report["recommended_commands"].append(
        shell_command(["python", "cli.py", "prepare-session", project, "--platform", selected_platform, "--mode", selected_mode, "--format", "markdown"])
    )
    if dry_run:
        if import_gaoxia and (project / "project.json").exists():
            report["gaoxia_scan"] = import_gaoxia_project(project, dry_run=True)
        report["doctor"] = doctor(None, install_config=install_config, start_mcp_test=False) if install_config else doctor(None)
        return report

    state = ensure_state(project, create=True)
    with state_write_lock(state, "quickstart"):
        bootstrap = init_wizard(
            project,
            title=title,
            target_chapters=target_chapters,
            target_words=target_words,
            required_phrases=required_phrases,
            forbidden_phrases=forbidden_phrases,
            future_markers=future_markers,
            rule_notes=rule_notes,
            style_note=style_note,
            source_summary=source_summary,
            source_path=source_path,
            chapter_range=chapter_range,
            agent_id=selected_agent_id,
            platform=selected_platform,
            capabilities=selected_capabilities,
            agent_notes=agent_notes,
            import_gaoxia=import_gaoxia,
            append_import=append_import,
            dry_run=False,
            force=force,
        )
        migration = migrate_state(state, operation="quickstart")
        audit = audit_state_change(state, "quickstart", bootstrap, migration=migration)
    target = chapter or next_target_chapter(load_state(project))
    session = prepare_chapter_session(
        project,
        chapter=target,
        platform=selected_platform,
        mode=selected_mode,
        include_context=not summary_only,
    )
    health = doctor(project, install_config=install_config, start_mcp_test=start_mcp_test)
    report.update(
        {
            "ok": bool(bootstrap.get("ok")) and bool(session.get("ok")) and bool(health.get("ok")),
            "bootstrap": bootstrap,
            "target_chapter": target,
            "chapter_session": session,
            "doctor": health,
            "warnings": unique_strings(split_list(plan.get("warnings")) + split_list(session.get("warnings"))),
            "audit_id": audit["id"],
        }
    )
    report["recommended_commands"].extend(
        [
            shell_command(["python", "cli.py", "build-context", project, "--chapter", target, "--format", "markdown"]),
            shell_command(["python", "cli.py", "check-chapter", project, "--chapter", target, "--file", f"chapters/{target:03d}.md"]),
        ]
    )
    return report


def latest_chapter_record(rows: list[dict[str, Any]]) -> dict[str, Any] | None:
    if not rows:
        return None
    return max(rows, key=lambda row: int(row.get("chapter", 0) or 0))


def visible_recent_agent_activity(rows: list[dict[str, Any]], *, chapter: int | None = None, limit: int = 5) -> list[dict[str, Any]]:
    target = int(chapter) if chapter is not None else None
    selected: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        raw_chapter = row.get("chapter")
        if target is not None and raw_chapter is not None:
            try:
                row_chapter = int(raw_chapter)
            except (TypeError, ValueError):
                row_chapter = target
            if row_chapter > target:
                continue
        selected.append(row)
    safe_limit = max(1, int(limit or 5))
    return selected[-safe_limit:]


def build_next_agent_handoff_brief(
    project_dir: str | Path,
    *,
    target: int,
    context: dict[str, Any],
    handoff_text: str,
    latest_chapter: dict[str, Any] | None,
    recent_activity: list[dict[str, Any]],
    pending_proposals: list[dict[str, Any]],
    high_risk_proposals: list[dict[str, Any]],
) -> dict[str, Any]:
    project = project_root(project_dir)
    latest_number = int((latest_chapter or {}).get("chapter") or 0)
    blockers: list[str] = []
    review_items: list[str] = []
    warnings: list[str] = []
    if high_risk_proposals:
        blockers.append(f"{len(high_risk_proposals)} high-risk proposal(s) require author review before takeover.")
    if pending_proposals:
        review_items.append(f"{len(pending_proposals)} pending proposal(s) should be reviewed before drafting.")
    if target > 1 and not latest_number:
        warnings.append("Target chapter is greater than 1 but no accepted previous chapter is recorded.")
    if target > 1 and not str(handoff_text or "").strip():
        warnings.append("No latest handoff text is available for the target chapter.")
    if not recent_activity:
        warnings.append("No recent desktop agent activity is recorded for this target chapter.")
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    project_title = str((context.get("project") or {}).get("title") or project.name)
    target_file = f"chapters/{target:03d}.md"
    prompt_lines = [
        f"You are taking over chapter {target} of \"{project_title}\".",
        "Use long-novel-agent state as the durable continuity source; do not rely on chat history alone.",
        "Before drafting or revising, call prepare_chapter_session or build_chapter_context for the target chapter.",
        "Review handoff text, recent_agent_activity, pending proposals, visible rules, open debts, and chapter contracts.",
        "Do not record a chapter, apply a proposal, or write durable continuity state until the author has accepted the chapter and provided the required confirmation.",
    ]
    if handoff_text:
        compact_handoff = re.sub(r"\s+", " ", handoff_text).strip()
        prompt_lines.append("Current handoff: " + compact_handoff[:500])
    return {
        "status": status,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "copy_prompt": "\n".join(prompt_lines),
        "must_read": [
            ".novel-agent/handoff.md",
            ".novel-agent/agent_activity.jsonl",
            ".novel-agent/proposals.jsonl",
            ".novel-agent/facts.jsonl",
            ".novel-agent/contracts.jsonl",
            target_file,
        ],
        "startup_sequence": [
            "Run handoff_readiness if this is a takeover from another desktop agent.",
            "Run prepare_session, or build_context if only chapter context is needed.",
            "Draft or revise using the returned target-chapter context.",
            "Run chapter_readiness before presenting the chapter as ready.",
            "After meaningful work, record a concise agent activity entry.",
        ],
        "write_boundaries": [
            "Read-only work may inspect reports, context, contracts, proposals, facts, and recent activity.",
            "record_agent_activity writes only .novel-agent/agent_activity.jsonl and should be reviewed.",
            "record_chapter, source/fact/conflict writes, style samples, and proposal application require author confirmation.",
            "Do not paste full manuscripts or full context packets into evidence or activity summaries.",
        ],
        "first_commands": [
            {
                "key": "handoff_readiness",
                "when": "takeover gate",
                "command": f"python cli.py handoff-readiness {project} --chapter {target} --incoming-agent-id <agent-id> --incoming-platform <platform> --mode writer --format markdown",
                "writes_project_state": False,
            },
            {
                "key": "prepare_session",
                "when": "chapter startup",
                "command": f"python cli.py prepare-session {project} --chapter {target} --platform <platform> --mode writer --format markdown",
                "writes_project_state": False,
            },
            {
                "key": "build_context",
                "when": "drafting context",
                "command": f"python cli.py build-context {project} --chapter {target} --format markdown",
                "writes_project_state": False,
            },
            {
                "key": "chapter_readiness",
                "when": "before author review",
                "command": f"python cli.py chapter-readiness {project} --chapter {target} --file {target_file} --format markdown",
                "writes_project_state": False,
            },
            {
                "key": "record_agent_activity",
                "when": "after meaningful prepare, draft, revise, check, or handoff work",
                "command": f"python cli.py record-agent-activity {project} --agent-id <agent-id> --platform <platform> --action <prepare-session|draft|revise|check|handoff> --chapter {target} --summary <short-summary> --context-source prepare_chapter_session --file {target_file} --status done --format markdown",
                "writes_project_state": True,
                "review_required": True,
            },
        ],
    }


def build_handoff_report(project_dir: str | Path, *, chapter: int | None = None, include_context: bool = False) -> dict[str, Any]:
    data = load_state(project_dir)
    latest = latest_chapter_record(data["chapters"])
    latest_chapter = int(latest.get("chapter") or 0) if latest else int(data["manifest"].get("current_chapter") or 0)
    target = chapter or max(1, latest_chapter + 1)
    context = build_chapter_context(project_dir, chapter=target)
    handoff_text = data["handoff"].strip()
    latest_handoff = str((latest or {}).get("handoff") or "").strip()
    if latest_handoff and (not handoff_text or "No accepted chapter has been recorded yet." in handoff_text):
        handoff_text = latest_handoff
    pending_proposals = [
        row
        for row in data["proposals"]
        if str(row.get("status") or "proposed").lower() in {"proposed", "pending", "needs_revision"}
    ]
    high_risk = [
        row
        for row in pending_proposals
        if str(((row.get("risk") or {}).get("level") if isinstance(row.get("risk"), dict) else "") or "").lower() == "high"
    ]
    activity_rows = data.get("agent_activity", []) if isinstance(data.get("agent_activity"), list) else []
    recent_activity = visible_recent_agent_activity(activity_rows, chapter=target, limit=5)
    next_agent_brief = build_next_agent_handoff_brief(
        project_dir,
        target=target,
        context=context,
        handoff_text=handoff_text,
        latest_chapter=latest,
        recent_activity=recent_activity,
        pending_proposals=pending_proposals,
        high_risk_proposals=high_risk,
    )
    report: dict[str, Any] = {
        "ok": True,
        "type": "handoff_report",
        "generated_at": now_iso(),
        "project_dir": str(project_root(project_dir)),
        "state_dir": str(state_root(project_dir)),
        "target_chapter": target,
        "project": context["project"],
        "latest_accepted_chapter": latest or {},
        "handoff": handoff_text,
        "visible_rules": {
            "required_phrases": context["rules"]["required_phrases"],
            "forbidden_phrases": context["rules"]["forbidden_phrases"],
            "future_markers": context["rules"]["future_markers"],
        },
        "open_debts": context["open_debts"],
        "open_contracts": context["contracts"],
        "resolved_conflicts": context["resolved_conflicts"],
        "visible_fact_count": len(context["facts"]),
        "visible_source_count": len(context["sources"]),
        "visible_research_count": len(context["research"]),
        "agent_capabilities": context.get("agent_capabilities", []),
        "recent_agent_activity": recent_activity,
        "pending_proposals": pending_proposals,
        "high_risk_proposals": high_risk,
        "next_agent_brief": next_agent_brief,
        "required_workflow": [
            f"Review recent_agent_activity and handoff before drafting chapter {target}.",
            f"build-context --chapter {target} before drafting or revising.",
            f"chapter-readiness --chapter {target} before presenting the draft as ready; use check-chapter and diff-contract only when needed.",
            "record-chapter only after the author accepts the chapter, with --author-confirmation or MCP author_confirmation.",
            "proposal-template, propose-after-write, validate-proposal, diff-proposal, and apply-after-write after acceptance; writer writes need author confirmation.",
        ],
        "recommended_commands": [
            f"python cli.py build-context {project_root(project_dir)} --chapter {target} --format markdown",
            f"python cli.py chapter-readiness {project_root(project_dir)} --chapter {target} --file chapters/{target:03d}.md --format markdown",
            f"python cli.py proposal-template {project_root(project_dir)} --chapter {target} --file chapters/{target:03d}.md",
        ],
    }
    if include_context:
        report["chapter_context"] = context
    else:
        report["chapter_context_summary"] = {
            "previous_tail": (context.get("previous_chapter") or {}).get("tail") or "",
            "characters": len(context["characters"]),
            "facts": len(context["facts"]),
            "sources": len(context["sources"]),
            "research": len(context["research"]),
            "style_profile": context.get("style_profile", {}),
        }
    return report


def continuity_coverage_report(project_dir: str | Path) -> dict[str, Any]:
    data = load_state(project_dir)
    project = project_root(project_dir)
    manifest = data["manifest"] if isinstance(data["manifest"], dict) else {}
    chapters = data["chapters"]
    latest = latest_chapter_record(chapters)
    current_chapter = int(manifest.get("current_chapter") or 0)
    latest_chapter = int((latest or {}).get("chapter") or current_chapter or 0)
    target_chapter = max(1, latest_chapter + 1)
    active_facts = [row for row in data["facts"] if fact_active(row)]
    pending_proposals = [
        row
        for row in data["proposals"]
        if str(row.get("status") or "proposed").lower() in {"proposed", "pending", "needs_revision"}
    ]
    high_risk_proposals = [
        row
        for row in pending_proposals
        if str(((row.get("risk") or {}).get("level") if isinstance(row.get("risk"), dict) else "") or "").lower() == "high"
    ]
    target_context = build_chapter_context(project, chapter=target_chapter) if data["manifest"] else {}
    fact_coverage = fact_coverage_summary(active_facts)
    style_payload = data["style_profile"] if isinstance(data["style_profile"], dict) else {}
    style_profile = style_payload.get("profile", {}) if isinstance(style_payload.get("profile"), dict) else {}
    handoff_text = data["handoff"].strip()
    latest_handoff = str((latest or {}).get("handoff") or "").strip()
    has_handoff = bool(latest_handoff or (handoff_text and "No accepted chapter has been recorded yet." not in handoff_text))
    warnings: list[str] = []
    if chapters and not active_facts:
        warnings.append("accepted chapters exist but active facts are empty")
    if current_chapter and latest_chapter and current_chapter > latest_chapter:
        warnings.append("manifest current_chapter is ahead of recorded chapters")
    if latest_chapter and not has_handoff:
        warnings.append("latest accepted chapter has no handoff text")
    if pending_proposals:
        warnings.append(f"{len(pending_proposals)} proposal(s) are waiting for review")
    if high_risk_proposals:
        warnings.append(f"{len(high_risk_proposals)} high-risk proposal(s) need author review")
    if latest_chapter >= 2 and int(style_profile.get("sample_count") or 0) < 2:
        warnings.append("style profile has fewer than two accepted chapter samples")
    if not data["agents"]:
        warnings.append("no host agent capability declaration recorded")
    if not any(fact_coverage["checks"].values()) and active_facts:
        warnings.append("active facts exist but none are in timeline, ownership, location, relationship, or life-state categories")
    return {
        "target_chapter": target_chapter,
        "chapters": {
            "recorded": len(chapters),
            "manifest_current_chapter": current_chapter,
            "latest_recorded_chapter": latest_chapter,
            "latest_has_handoff": has_handoff,
        },
        "facts": fact_coverage,
        "open_threads": {
            "debts": len(target_context.get("open_debts", [])) if isinstance(target_context, dict) else 0,
            "contracts": len(target_context.get("contracts", [])) if isinstance(target_context, dict) else 0,
            "pending_proposals": len(pending_proposals),
            "high_risk_proposals": len(high_risk_proposals),
        },
        "sources": {
            "visible_sources": len(target_context.get("sources", [])) if isinstance(target_context, dict) else 0,
            "visible_research": len(target_context.get("research", [])) if isinstance(target_context, dict) else 0,
        },
        "style": {
            "sample_count": int(style_profile.get("sample_count") or 0),
            "avg_sentence_units": style_profile.get("avg_sentence_units"),
            "dialogue_line_ratio": style_profile.get("dialogue_line_ratio"),
        },
        "agents": len(data["agents"]),
        "warnings": warnings,
        "recommended_commands": [
            f"python cli.py build-context {project} --chapter {target_chapter} --format markdown",
            f"python cli.py list-open-threads {project} --chapter {target_chapter}",
            f"python cli.py handoff-report {project} --chapter {target_chapter} --format markdown",
        ],
    }


def continuity_audit_action(
    action_id: str,
    priority: str,
    title: str,
    reason: str,
    *,
    command: str = "",
    source_check: str = "",
    details: Any = None,
) -> dict[str, Any]:
    action: dict[str, Any] = {
        "id": action_id,
        "priority": priority,
        "title": title,
        "reason": reason,
    }
    if command:
        action["command"] = command
    if source_check:
        action["source_check"] = source_check
    if details is not None:
        action["details"] = details
    return action


def build_continuity_action_plan(actions: list[dict[str, Any]]) -> dict[str, Any]:
    groups: dict[str, list[dict[str, Any]]] = {
        "must_fix": [],
        "review": [],
        "improve": [],
    }
    for action in actions:
        if not isinstance(action, dict):
            continue
        priority = str(action.get("priority") or "improve").strip()
        if priority not in groups:
            priority = "improve"
        groups[priority].append(action)
    return {
        "summary": {
            "must_fix": len(groups["must_fix"]),
            "review": len(groups["review"]),
            "improve": len(groups["improve"]),
            "total": sum(len(value) for value in groups.values()),
        },
        "must_fix": groups["must_fix"],
        "review": groups["review"],
        "improve": groups["improve"],
    }


def build_continuity_audit(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    platform: str = "",
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    if not state.exists():
        action_plan = build_continuity_action_plan(
            [
                continuity_audit_action(
                    "initialize_project_state",
                    "must_fix",
                    "Initialize or import .novel-agent state",
                    "The project has no durable continuity state, so chapter-safe context cannot be trusted yet.",
                    command=f"python cli.py quickstart {project} --source auto --dry-run --format markdown",
                    source_check="state_initialized",
                    details={"state_dir": str(state)},
                )
            ]
        )
        return {
            "type": "continuity_audit",
            "generated_at": now_iso(),
            "ok": False,
            "status": "blocked",
            "project_dir": str(project),
            "state_dir": str(state),
            "target_chapter": chapter or 1,
            "checks": [
                {
                    "id": "state_initialized",
                    "ok": False,
                    "severity": "blocker",
                    "message": "Project has no .novel-agent state.",
                    "detail": str(state),
                }
            ],
            "summary": {},
            "pending_proposals": [],
            "warnings": [],
            "blockers": ["Project has no .novel-agent state."],
            "review_items": [],
            "action_plan": action_plan,
            "recommended_commands": [
                f"python cli.py quickstart {project} --source auto --dry-run --format markdown",
                f"python cli.py init-wizard {project} --dry-run",
            ],
        }

    data = load_state(project)
    coverage = continuity_coverage_report(project)
    target = chapter or int(coverage.get("target_chapter") or 1)
    context = build_chapter_context(project, chapter=target)
    chapters = data["chapters"] if isinstance(data.get("chapters"), list) else []
    facts = [row for row in data["facts"] if isinstance(row, dict) and fact_active(row)]
    proposals = data["proposals"] if isinstance(data.get("proposals"), list) else []
    sources = data["sources"] if isinstance(data.get("sources"), list) else []
    research = data["research"] if isinstance(data.get("research"), list) else []
    desktop_rows = data.get("desktop_verifications", []) if isinstance(data.get("desktop_verifications"), list) else []
    chapter_numbers = sorted(int(row.get("chapter")) for row in chapters if isinstance(row, dict) and str(row.get("chapter") or "").isdigit())
    latest_chapter = chapter_numbers[-1] if chapter_numbers else 0
    missing_chapters = [number for number in range(1, latest_chapter + 1) if number not in set(chapter_numbers)]
    duplicate_chapters = sorted(number for number in set(chapter_numbers) if chapter_numbers.count(number) > 1)
    facts_without_evidence = [
        row
        for row in facts
        if not first_nonempty(row.get("evidence"), row.get("source_path")) and not split_list(row.get("source_ids"))
    ]
    facts_without_chapter_range = [
        row
        for row in facts
        if not row.get("chapter_ranges") and not row.get("chapter_range") and not row.get("reveal_after_chapter")
    ]
    unbounded_sources = [
        row
        for row in sources
        if isinstance(row, dict) and not row.get("chapter_ranges") and not row.get("chapter_range") and not row.get("reveal_after_chapter")
    ]
    unbounded_research = [
        row
        for row in research
        if isinstance(row, dict) and not row.get("chapter_ranges") and not row.get("chapter_range") and not row.get("reveal_after_chapter")
    ]
    pending = [
        row
        for row in proposals
        if isinstance(row, dict) and str(row.get("status") or "proposed").lower() in {"proposed", "pending", "needs_revision"}
    ]
    pending_reviews: list[dict[str, Any]] = []
    pending_error_count = 0
    pending_warning_count = 0
    high_risk_count = 0
    for row in pending:
        validation = validate_proposal_payload(state, row, require_evidence=True)
        risk = assess_proposal_risk(row)
        errors = sum(1 for issue in validation.get("issues", []) if issue.get("severity") == "error")
        warnings = sum(1 for issue in validation.get("issues", []) if issue.get("severity") == "warning")
        pending_error_count += errors
        pending_warning_count += warnings
        if risk.get("level") == "high":
            high_risk_count += 1
        pending_reviews.append(
            {
                "id": row.get("id"),
                "chapter": row.get("chapter"),
                "status": row.get("status") or "proposed",
                "risk_level": risk.get("level"),
                "validation_status": validation.get("status"),
                "errors": errors,
                "warnings": warnings,
            }
        )
    latest_desktop = latest_desktop_verification(desktop_rows, platform=platform)
    fact_checks = ((coverage.get("facts") or {}).get("checks") or {}) if isinstance(coverage.get("facts"), dict) else {}

    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    add_check("state_initialized", True, "blocker", ".novel-agent state exists.", str(state))
    add_check("chapter_sequence", not missing_chapters and not duplicate_chapters, "warning", "Accepted chapter records are sequential and unique.", {"missing": missing_chapters, "duplicates": duplicate_chapters})
    add_check("target_context_available", bool(context.get("project")), "blocker", f"Chapter {target} context can be built.")
    add_check("latest_handoff_present", bool((coverage.get("chapters") or {}).get("latest_has_handoff") or target <= 1), "warning", "Latest accepted chapter has handoff text.")
    add_check("pending_proposals_clear", not pending, "review", "No pending proposal waits for author review.", {"pending": len(pending), "errors": pending_error_count, "warnings": pending_warning_count})
    add_check("high_risk_proposals_clear", high_risk_count == 0, "blocker", "No high-risk proposal waits for author review.", {"high_risk": high_risk_count})
    add_check("fact_evidence_present", not facts_without_evidence, "warning", "Active facts have evidence, source path, or source ids.", {"missing": len(facts_without_evidence)})
    add_check("fact_chapter_bounds_present", not facts_without_chapter_range, "warning", "Active facts have chapter visibility bounds or reveal boundary.", {"missing": len(facts_without_chapter_range)})
    add_check(
        "structured_fact_categories_present",
        any(int(value or 0) for value in fact_checks.values()),
        "warning",
        "At least one active fact supports structured continuity checks.",
        fact_checks,
    )
    add_check("source_chapter_bounds_present", not unbounded_sources and not unbounded_research, "warning", "Sources and research have chapter visibility bounds or reveal boundary.", {"sources": len(unbounded_sources), "research": len(unbounded_research)})
    add_check("agent_declared", bool(data.get("agents")), "warning", "At least one host-agent capability declaration exists.", {"agents": len(data.get("agents") or [])})
    add_check("desktop_client_verified", bool(latest_desktop and latest_desktop.get("ok")), "warning", "A successful real desktop client verification record exists for the selected platform.", latest_desktop or {"platform": platform or "any"})
    add_check("style_samples_present", int(((coverage.get("style") or {}).get("sample_count")) or 0) >= 2 or latest_chapter < 2, "warning", "Style profile has at least two accepted chapter samples once multiple chapters exist.", coverage.get("style"))

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    commands = [
        f"python cli.py prepare-session {project} --chapter {target} --platform {platform or 'codex'} --format markdown",
        f"python cli.py build-context {project} --chapter {target} --format markdown",
        f"python cli.py handoff-report {project} --chapter {target} --format markdown",
        f"python cli.py list-open-threads {project} --chapter {target}",
    ]
    for row in pending_reviews[:3]:
        proposal_id = str(row.get("id") or "").strip()
        if proposal_id:
            commands.append(f"python cli.py proposal-review {project} --proposal-id {proposal_id} --format markdown")
    if not latest_desktop:
        commands.append(f"python cli.py desktop-checklist {project} --chapter {target} --platform {platform or 'codex'} --format markdown")
    actions: list[dict[str, Any]] = []
    if not context.get("project"):
        actions.append(
            continuity_audit_action(
                "repair_context_read_path",
                "must_fix",
                "Repair chapter context read path",
                f"Chapter {target} context did not build, so drafting should wait.",
                command=f"python cli.py doctor {project}",
                source_check="target_context_available",
            )
        )
    high_risk_pending = [row for row in pending_reviews if row.get("risk_level") == "high"]
    for row in high_risk_pending[:3]:
        proposal_id = str(row.get("id") or "").strip()
        actions.append(
            continuity_audit_action(
                f"review_high_risk_proposal_{proposal_id or len(actions) + 1}",
                "must_fix",
                "Review high-risk proposal before continuing",
                "High-risk continuity changes can alter canon and need author review before further writing.",
                command=f"python cli.py proposal-review {project} --proposal-id {proposal_id} --format markdown" if proposal_id else "",
                source_check="high_risk_proposals_clear",
                details=row,
            )
        )
    if len(high_risk_pending) > 3:
        actions.append(
            continuity_audit_action(
                "review_remaining_high_risk_proposals",
                "must_fix",
                "Review remaining high-risk proposals",
                f"{len(high_risk_pending) - 3} more high-risk proposal(s) are waiting after the first three listed actions.",
                command=f"python cli.py list-open-threads {project} --chapter {target}",
                source_check="high_risk_proposals_clear",
            )
        )
    for row in pending_reviews[:3]:
        proposal_id = str(row.get("id") or "").strip()
        actions.append(
            continuity_audit_action(
                f"review_pending_proposal_{proposal_id or len(actions) + 1}",
                "review",
                "Review pending proposal",
                "Pending post-write updates should be accepted, revised, or rejected before another agent treats them as canon.",
                command=f"python cli.py proposal-review {project} --proposal-id {proposal_id} --format markdown" if proposal_id else "",
                source_check="pending_proposals_clear",
                details=row,
            )
        )
    if len(pending_reviews) > 3:
        actions.append(
            continuity_audit_action(
                "review_remaining_pending_proposals",
                "review",
                "Review remaining pending proposals",
                f"{len(pending_reviews) - 3} more pending proposal(s) are waiting after the first three listed actions.",
                command=f"python cli.py list-open-threads {project} --chapter {target}",
                source_check="pending_proposals_clear",
            )
        )
    if pending_error_count:
        actions.append(
            continuity_audit_action(
                "fix_pending_proposal_validation",
                "review",
                "Fix proposal validation errors",
                f"Pending proposals contain {pending_error_count} validation error(s).",
                command=f"python cli.py list-open-threads {project} --chapter {target}",
                source_check="pending_proposals_clear",
            )
        )
    if missing_chapters or duplicate_chapters:
        actions.append(
            continuity_audit_action(
                "review_chapter_sequence",
                "review",
                "Review accepted chapter sequence",
                "Chapter gaps or duplicate records can make handoff and rolling context unreliable.",
                command=f"python cli.py continuity-audit {project} --chapter {target} --platform {platform or 'codex'} --include-context --format markdown",
                source_check="chapter_sequence",
                details={"missing": missing_chapters, "duplicates": duplicate_chapters},
            )
        )
    if not ((coverage.get("chapters") or {}).get("latest_has_handoff") or target <= 1):
        actions.append(
            continuity_audit_action(
                "add_latest_handoff",
                "review",
                "Add latest chapter handoff",
                "The next agent lacks an explicit handoff from the latest accepted chapter.",
                command=f"python cli.py handoff-report {project} --chapter {target} --format markdown",
                source_check="latest_handoff_present",
            )
        )
    if facts_without_evidence:
        actions.append(
            continuity_audit_action(
                "add_fact_evidence",
                "improve",
                "Add evidence to active facts",
                f"{len(facts_without_evidence)} active fact(s) lack evidence, source path, or source ids.",
                command=f"python cli.py list-facts {project} --chapter {target}",
                source_check="fact_evidence_present",
                details={"missing": [row.get("id") or row.get("subject") for row in facts_without_evidence[:20]]},
            )
        )
    if facts_without_chapter_range:
        actions.append(
            continuity_audit_action(
                "add_fact_visibility_bounds",
                "improve",
                "Add chapter visibility bounds to active facts",
                f"{len(facts_without_chapter_range)} active fact(s) have no chapter range or reveal boundary.",
                command=f"python cli.py list-facts {project} --chapter {target}",
                source_check="fact_chapter_bounds_present",
                details={"missing": [row.get("id") or row.get("subject") for row in facts_without_chapter_range[:20]]},
            )
        )
    if unbounded_sources or unbounded_research:
        actions.append(
            continuity_audit_action(
                "add_source_visibility_bounds",
                "improve",
                "Add chapter boundaries to sources and research",
                f"{len(unbounded_sources)} source(s) and {len(unbounded_research)} research note(s) have no chapter range or reveal boundary.",
                command=f"python cli.py source-intake-template {project} --platform {platform or 'codex'} --format markdown",
                source_check="source_chapter_bounds_present",
            )
        )
    if not any(int(value or 0) for value in fact_checks.values()):
        actions.append(
            continuity_audit_action(
                "add_structured_fact_categories",
                "improve",
                "Add structured continuity facts",
                "No active fact currently supports timeline, ownership, location, relationship, or life-state checks.",
                command=f"python cli.py add-fact {project} --kind prop --subject SUBJECT --predicate holder --object OBJECT --chapter-range {target}+ --author-confirmation \"Author approved this continuity fact.\"",
                source_check="structured_fact_categories_present",
            )
        )
    if not data.get("agents"):
        actions.append(
            continuity_audit_action(
                "declare_host_agent",
                "improve",
                "Declare host-agent capabilities",
                "The project has no saved agent capability declaration for future handoff.",
                command=f"python cli.py declare-agent {project} --agent-id codex-local --platform {platform or 'codex'} --capabilities mcp,cli,file-read,file-write",
                source_check="agent_declared",
            )
        )
    if not latest_desktop:
        actions.append(
            continuity_audit_action(
                "record_real_desktop_evidence",
                "improve",
                "Record real desktop-client evidence",
                "No saved real desktop-client verification record exists for the selected platform.",
                command=f"python cli.py desktop-checklist {project} --chapter {target} --platform {platform or 'codex'} --format markdown",
                source_check="desktop_client_verified",
            )
        )
    elif not latest_desktop.get("ok"):
        actions.append(
            continuity_audit_action(
                "repair_real_desktop_evidence",
                "review",
                "Review failed real desktop-client evidence",
                "The latest real desktop-client verification record has unresolved issues.",
                command=f"python cli.py list-desktop-checks {project} --platform {platform or 'codex'}",
                source_check="desktop_client_verified",
                details=latest_desktop,
            )
        )
    if not (int(((coverage.get("style") or {}).get("sample_count")) or 0) >= 2 or latest_chapter < 2):
        actions.append(
            continuity_audit_action(
                "add_style_samples",
                "improve",
                "Record more accepted style samples",
                "Multiple accepted chapters exist, but the style profile has fewer than two samples.",
                command=f"python cli.py record-style {project} --chapter {latest_chapter} --file chapters/{latest_chapter:03d}.md --author-confirmation \"Author approved this style sample.\"",
                source_check="style_samples_present",
                details=coverage.get("style"),
            )
        )
    action_plan = build_continuity_action_plan(actions)
    report: dict[str, Any] = {
        "type": "continuity_audit",
        "generated_at": now_iso(),
        "ok": status in {"ready", "ready_with_warnings"},
        "status": status,
        "project_dir": str(project),
        "state_dir": str(state),
        "target_chapter": target,
        "summary": {
            "latest_recorded_chapter": latest_chapter,
            "recorded_chapters": len(chapters),
            "missing_chapters": len(missing_chapters),
            "duplicate_chapters": len(duplicate_chapters),
            "active_facts": len(facts),
            "facts_without_evidence": len(facts_without_evidence),
            "facts_without_chapter_bounds": len(facts_without_chapter_range),
            "pending_proposals": len(pending),
            "high_risk_proposals": high_risk_count,
            "visible_sources": len(context.get("sources", [])),
            "visible_research": len(context.get("research", [])),
            "open_debts": len(context.get("open_debts", [])),
            "contracts": len(context.get("contracts", [])),
        },
        "checks": checks,
        "coverage": coverage,
        "pending_proposals": pending_reviews,
        "chapter_sequence": {
            "recorded": chapter_numbers,
            "missing": missing_chapters,
            "duplicates": duplicate_chapters,
        },
        "fact_issues": {
            "without_evidence": [row.get("id") or row.get("subject") for row in facts_without_evidence[:20]],
            "without_chapter_bounds": [row.get("id") or row.get("subject") for row in facts_without_chapter_range[:20]],
        },
        "source_issues": {
            "unbounded_sources": [row.get("id") or row.get("title") for row in unbounded_sources[:20]],
            "unbounded_research": [row.get("id") or row.get("title") for row in unbounded_research[:20]],
        },
        "latest_desktop_verification": latest_desktop,
        "blockers": blockers,
        "review_items": review_items,
        "warnings": warnings,
        "action_plan": action_plan,
        "recommended_commands": commands,
    }
    if include_context:
        report["chapter_context"] = context
    return report


def latest_desktop_verification(
    rows: list[dict[str, Any]],
    *,
    platform: str = "",
    mode: str = "",
    chapter: int | None = None,
) -> dict[str, Any]:
    selected = str(platform or "").strip().lower()
    selected_mode = str(mode or "").strip().lower()
    candidates = rows
    if selected:
        candidates = [row for row in rows if str(row.get("platform") or "").strip().lower() == selected]
    if selected_mode:
        candidates = [row for row in candidates if str(row.get("mode") or "").strip().lower() == selected_mode]
    if chapter:
        target = int(chapter)
        candidates = [row for row in candidates if row.get("target_chapter") == target]
    if not candidates:
        return {}
    return candidates[-1]


def summarize_desktop_verification_issues(record: dict[str, Any]) -> list[dict[str, str]]:
    issues = record.get("issues") if isinstance(record.get("issues"), list) else []
    summary: list[dict[str, str]] = []
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        issue_type = str(issue.get("type") or "unknown_issue")
        check_id = str(issue.get("check_id") or "")
        message = str(issue.get("message") or "").strip()
        if not message:
            if issue_type == "missing_author_confirmation_evidence":
                message = "Writer acceptance evidence must show author_confirmation or --author-confirmation for durable state writes."
            elif issue_type == "missing_acceptance_write_operation_evidence":
                message = "Writer acceptance evidence must show a durable write command such as record_chapter, propose_after_write_updates, or apply_after_write_updates."
            elif issue_type == "missing_proposal_readiness_evidence":
                message = "Writer proposal readiness evidence must show build_proposal_readiness or proposal-readiness before applying updates."
            elif issue_type == "missing_range_readiness_evidence":
                message = "Range readiness evidence must show build_chapter_range_readiness or chapter-range-readiness before multi-chapter handoff or presentation."
            elif issue_type == "missing_evidence":
                message = "Required desktop client check needs evidence from the real client."
            elif issue_type == "weak_evidence":
                message = "Required desktop client evidence is too generic; include a real tool name, visible server name, returned status, or rejected-call detail."
            elif issue_type == "required_check_not_passed":
                status = str(issue.get("status") or "not passed")
                message = f"Required desktop client check did not pass: {status}."
            elif issue_type == "missing_required_check":
                message = "Required desktop client check is missing from the submitted results."
            else:
                message = issue_type.replace("_", " ")
        summary.append({"type": issue_type, "check_id": check_id, "message": message})
    return summary


def real_desktop_verification_status(record: dict[str, Any]) -> dict[str, Any]:
    if not record:
        return {
            "status": "missing",
            "proof_level": "none",
            "is_real_client_evidence": False,
            "issue_count": 0,
            "issue_summary": [],
            "message": "No real desktop client verification record has been saved.",
        }
    issues = record.get("issues") if isinstance(record.get("issues"), list) else []
    issue_summary = summarize_desktop_verification_issues(record)
    return {
        "status": "passed" if record.get("ok") else "failed",
        "proof_level": "real_desktop_client",
        "is_real_client_evidence": True,
        "record_id": record.get("id") or "",
        "platform": record.get("platform") or "",
        "mode": record.get("mode") or "",
        "created_at": record.get("created_at") or "",
        "target_chapter": record.get("target_chapter"),
        "required_total": record.get("required_total"),
        "required_passed_with_evidence": record.get("required_passed_with_evidence"),
        "issues": issues,
        "issue_count": len(issues),
        "issue_summary": issue_summary,
        "message": "Latest saved real desktop client verification passed." if record.get("ok") else "Latest saved real desktop client verification has issues.",
    }


def local_mcp_config_verification_status(checks: list[dict[str, Any]]) -> dict[str, Any]:
    if not checks:
        return {
            "status": "not_checked",
            "proof_level": "none",
            "is_real_client_evidence": False,
            "message": "No local MCP config check was requested.",
        }
    failed = [item for item in checks if isinstance(item, dict) and not item.get("ok")]
    checked_stdio_start = any(str(item.get("name") or "") == "install_config_mcp_start" for item in checks if isinstance(item, dict))
    return {
        "status": "passed" if not failed else "failed",
        "proof_level": "local_mcp_config",
        "is_real_client_evidence": False,
        "checked_stdio_start": checked_stdio_start,
        "checks_total": len(checks),
        "failed_count": len(failed),
        "failed_checks": [str(item.get("name") or "") for item in failed],
        "message": "Local MCP config check passed, but it is not real desktop client evidence."
        if not failed
        else "Local MCP config check failed; this is still separate from real desktop client evidence.",
    }


def build_verification_status(latest_desktop: dict[str, Any], install_checks: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "real_desktop_client": real_desktop_verification_status(latest_desktop),
        "local_mcp_config": local_mcp_config_verification_status(install_checks),
    }


def normalize_desktop_matrix_platforms(platforms: Any = None, platform: str = "") -> list[str]:
    requested = split_list(platforms)
    if platform:
        requested.extend(split_list(platform))
    normalized = unique_strings([item.strip().lower() for item in requested if item.strip()])
    invalid = sorted(set(normalized) - AGENT_TEMPLATE_PLATFORMS)
    if invalid:
        raise KitError(f"Unsupported desktop verification platform(s): {', '.join(invalid)}")
    if not normalized:
        return list(DESKTOP_VERIFICATION_MATRIX_PLATFORMS)
    return [item for item in DESKTOP_VERIFICATION_MATRIX_PLATFORMS if item in normalized]


def normalize_desktop_matrix_modes(modes: Any = None, mode: str = "") -> list[str]:
    requested = split_list(modes)
    if mode:
        requested.extend(split_list(mode))
    normalized = unique_strings([item.strip().lower() for item in requested if item.strip()])
    invalid = sorted(set(normalized) - AGENT_TEMPLATE_MODES)
    if invalid:
        raise KitError(f"Unsupported desktop verification mode(s): {', '.join(invalid)}")
    if not normalized:
        return list(DESKTOP_VERIFICATION_MATRIX_MODES)
    return [item for item in DESKTOP_VERIFICATION_MATRIX_MODES if item in normalized]


def desktop_matrix_coverage(
    project_dir: str | Path,
    record: dict[str, Any],
    *,
    platform: str,
    mode: str,
    chapter: int | None = None,
) -> dict[str, Any]:
    record_target = record.get("target_chapter") if isinstance(record, dict) else None
    try:
        target = int(record_target or chapter or 1)
    except (TypeError, ValueError):
        target = int(chapter or 1)
    checklist = build_desktop_client_checklist(project_dir, platform=platform, mode=mode, chapter=target)
    required_ids = [
        str(item.get("id") or "").strip()
        for item in checklist.get("checklist", [])
        if isinstance(item, dict) and item.get("required") and str(item.get("id") or "").strip()
    ]
    checks = record.get("checks") if isinstance(record.get("checks"), list) else []
    by_id = {
        str(item.get("id") or "").strip(): item
        for item in checks
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    issues = record.get("issues") if isinstance(record.get("issues"), list) else []
    missing_ids: list[str] = []
    failed_ids: list[str] = []
    missing_evidence_ids: list[str] = []
    weak_ids: list[str] = []
    specific_ids: list[str] = []
    review_ids: list[str] = []
    issue_counts: dict[str, int] = {}
    for check_id in required_ids:
        observed = by_id.get(check_id)
        if not observed:
            missing_ids.append(check_id)
            continue
        if str(observed.get("status") or "").strip().lower() != "passed":
            failed_ids.append(check_id)
        if not str(observed.get("evidence") or "").strip():
            missing_evidence_ids.append(check_id)
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        issue_type = str(issue.get("type") or "unknown_issue")
        check_id = str(issue.get("check_id") or "").strip()
        issue_counts[issue_type] = issue_counts.get(issue_type, 0) + 1
        if not check_id:
            continue
        if issue_type == "missing_required_check":
            missing_ids.append(check_id)
        elif issue_type == "required_check_not_passed":
            failed_ids.append(check_id)
        elif issue_type == "missing_evidence":
            missing_evidence_ids.append(check_id)
        elif issue_type == "weak_evidence":
            weak_ids.append(check_id)
        elif issue_type in {
            "missing_range_readiness_evidence",
            "missing_proposal_readiness_evidence",
            "missing_author_confirmation_evidence",
            "missing_acceptance_write_operation_evidence",
        }:
            specific_ids.append(check_id)
        elif issue_type in {"unknown_check_id", "sensitive_evidence"}:
            review_ids.append(check_id)
    required_total = int(record.get("required_total") or len(required_ids) or 0) if record else len(required_ids)
    passed = int(record.get("required_passed_with_evidence") or 0) if record else 0
    missing_ids = unique_strings([item for item in missing_ids if item in required_ids])
    failed_ids = unique_strings([item for item in failed_ids if item in required_ids])
    missing_evidence_ids = unique_strings([item for item in missing_evidence_ids if item in required_ids])
    weak_ids = unique_strings([item for item in weak_ids if item in required_ids])
    specific_ids = unique_strings([item for item in specific_ids if item in required_ids])
    review_ids = unique_strings(review_ids)
    blocking_ids = unique_strings(missing_ids + failed_ids + missing_evidence_ids + weak_ids + specific_ids)
    if not record:
        coverage_status = "missing"
    elif record.get("ok"):
        coverage_status = "complete"
    elif blocking_ids:
        coverage_status = "incomplete"
    else:
        coverage_status = "needs_review"
    return {
        "status": coverage_status,
        "target_chapter": target,
        "required_total": required_total,
        "required_passed_with_evidence": passed,
        "required_check_ids": required_ids,
        "missing_required_check_ids": missing_ids,
        "failed_required_check_ids": failed_ids,
        "missing_evidence_check_ids": missing_evidence_ids,
        "weak_evidence_check_ids": weak_ids,
        "needs_specific_evidence_check_ids": specific_ids,
        "needs_review_check_ids": review_ids,
        "blocking_check_ids": blocking_ids,
        "issue_counts": issue_counts,
    }


def desktop_matrix_cell(
    rows: list[dict[str, Any]],
    *,
    project_dir: str | Path,
    platform: str,
    mode: str,
    chapter: int | None = None,
) -> dict[str, Any]:
    record = latest_desktop_verification(rows, platform=platform, mode=mode, chapter=chapter)
    status = real_desktop_verification_status(record)
    coverage = desktop_matrix_coverage(project_dir, record, platform=platform, mode=mode, chapter=chapter)
    return {
        "platform": platform,
        "mode": mode,
        "status": status.get("status") or "missing",
        "coverage_status": coverage.get("status"),
        "proof_level": status.get("proof_level") or "none",
        "is_real_client_evidence": bool(status.get("is_real_client_evidence")),
        "record_id": status.get("record_id") or "",
        "created_at": status.get("created_at") or "",
        "target_chapter": status.get("target_chapter"),
        "agent_id": record.get("agent_id") or "",
        "client_version": record.get("client_version") or "",
        "required_total": status.get("required_total") or coverage.get("required_total"),
        "required_passed_with_evidence": status.get("required_passed_with_evidence") or coverage.get("required_passed_with_evidence"),
        "missing_required_check_ids": coverage.get("missing_required_check_ids", []),
        "failed_required_check_ids": coverage.get("failed_required_check_ids", []),
        "missing_evidence_check_ids": coverage.get("missing_evidence_check_ids", []),
        "weak_evidence_check_ids": coverage.get("weak_evidence_check_ids", []),
        "needs_specific_evidence_check_ids": coverage.get("needs_specific_evidence_check_ids", []),
        "blocking_check_ids": coverage.get("blocking_check_ids", []),
        "coverage": coverage,
        "issue_count": int(status.get("issue_count") or 0),
        "issue_summary": status.get("issue_summary") if isinstance(status.get("issue_summary"), list) else [],
        "message": status.get("message") or "",
    }


def build_desktop_verification_matrix(
    project_dir: str | Path,
    *,
    platform: str = "",
    platforms: Any = None,
    mode: str = "",
    modes: Any = None,
    chapter: int | None = None,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    selected_platforms = normalize_desktop_matrix_platforms(platforms, platform)
    selected_modes = normalize_desktop_matrix_modes(modes, mode)
    target = int(chapter) if chapter else None
    rows = read_jsonl(state / "desktop_verifications.jsonl") if state.exists() else []
    rows_for_totals = [
        row
        for row in rows
        if str(row.get("platform") or "").strip().lower() in selected_platforms
        and str(row.get("mode") or "").strip().lower() in selected_modes
        and (not target or row.get("target_chapter") == target)
    ]
    cells = [
        desktop_matrix_cell(rows, project_dir=project, platform=item_platform, mode=item_mode, chapter=target)
        for item_platform in selected_platforms
        for item_mode in selected_modes
    ]
    status_counts: dict[str, int] = {}
    for cell in cells:
        status_key = str(cell.get("status") or "missing")
        status_counts[status_key] = status_counts.get(status_key, 0) + 1
    recommended_actions: list[str] = []
    for cell in cells:
        status_key = str(cell.get("status") or "missing")
        if status_key == "passed":
            continue
        action_chapter = target or 1
        if status_key == "missing":
            recommended_actions.append(
                shell_command(
                    [
                        "python",
                        "cli.py",
                        "desktop-checklist",
                        project,
                        "--platform",
                        cell["platform"],
                        "--mode",
                        cell["mode"],
                        "--chapter",
                        action_chapter,
                        "--format",
                        "markdown",
                    ]
                )
            )
        else:
            recommended_actions.append(shell_command(["python", "cli.py", "list-desktop-checks", project, "--platform", cell["platform"], "--limit", 5]))
    required_checks_total = sum(int((cell.get("coverage") or {}).get("required_total") or 0) for cell in cells if isinstance(cell.get("coverage"), dict))
    required_checks_passed = sum(int((cell.get("coverage") or {}).get("required_passed_with_evidence") or 0) for cell in cells if isinstance(cell.get("coverage"), dict))
    cells_with_gaps = sum(1 for cell in cells if cell.get("status") != "passed" or (cell.get("blocking_check_ids") or []))
    missing_required_checks = sum(len(cell.get("missing_required_check_ids") or []) for cell in cells)
    failed_required_checks = sum(len(cell.get("failed_required_check_ids") or []) for cell in cells)
    weak_evidence_checks = sum(len(cell.get("weak_evidence_check_ids") or []) for cell in cells)
    needs_specific_evidence_checks = sum(len(cell.get("needs_specific_evidence_check_ids") or []) for cell in cells)
    return {
        "type": "desktop_verification_matrix",
        "generated_at": now_iso(),
        "ok": bool(state.exists()) and all(cell.get("status") == "passed" for cell in cells),
        "project_dir": str(project),
        "state_dir": str(state),
        "filters": {
            "platforms": selected_platforms,
            "modes": selected_modes,
            "chapter": target,
        },
        "totals": {
            "records_considered": len(rows_for_totals),
            "cells": len(cells),
            "passed": status_counts.get("passed", 0),
            "failed": status_counts.get("failed", 0),
            "missing": status_counts.get("missing", 0),
            "required_checks_total": required_checks_total,
            "required_checks_passed": required_checks_passed,
            "cells_with_gaps": cells_with_gaps,
            "missing_required_checks": missing_required_checks,
            "failed_required_checks": failed_required_checks,
            "weak_evidence_checks": weak_evidence_checks,
            "needs_specific_evidence_checks": needs_specific_evidence_checks,
        },
        "matrix": cells,
        "warnings": [] if state.exists() else ["missing .novel-agent state"],
        "recommended_actions": unique_strings(recommended_actions)[:12],
    }


def normalize_capability_name(value: Any) -> str:
    raw = str(value or "").strip().lower()
    cn_aliases = {
        "文件读取": "file_read",
        "读文件": "file_read",
        "文件写入": "file_write",
        "写文件": "file_write",
        "网页检索": "web",
        "联网检索": "web",
        "长上下文": "long_context",
    }
    if raw in cn_aliases:
        return cn_aliases[raw]
    key = re.sub(r"[^a-z0-9]+", "_", raw).strip("_")
    aliases = {
        "filesystem_read": "file_read",
        "file_reader": "file_read",
        "file_reading": "file_read",
        "files_read": "file_read",
        "read_file": "file_read",
        "read_files": "file_read",
        "filesystem_write": "file_write",
        "file_writer": "file_write",
        "file_writing": "file_write",
        "files_write": "file_write",
        "write_file": "file_write",
        "write_files": "file_write",
        "model_context": "long_context",
        "longcontext": "long_context",
        "long_context_window": "long_context",
        "browser": "web",
        "web_search": "web",
        "search": "web",
        "pdf": "pdf_ocr",
        "ocr": "pdf_ocr",
        "pdf_ocr_parsing": "pdf_ocr",
    }
    return aliases.get(key, key)


def default_handoff_capabilities(mode: str) -> list[str]:
    selected = str(mode or "writer").strip().lower()
    if selected == "read-only":
        return ["mcp", "file_read"]
    return ["mcp", "file_read", "file_write"]


def find_agent_declaration(
    agents: list[dict[str, Any]],
    *,
    agent_id: str = "",
    platform: str = "",
) -> dict[str, Any]:
    selected_id = str(agent_id or "").strip()
    selected_platform = str(platform or "").strip().lower()
    candidates = [row for row in agents if isinstance(row, dict)]
    if selected_id:
        candidates = [row for row in candidates if str(row.get("id") or "").strip() == selected_id]
    if selected_platform:
        candidates = [row for row in candidates if str(row.get("platform") or "").strip().lower() == selected_platform]
    return candidates[-1] if candidates else {}


def project_status(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    platform: str = "",
    install_config: str = "",
    include_author_review_queue: bool = True,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state = project / STATE_DIR
    matrix_platform = platform if str(platform or "").strip().lower() in AGENT_TEMPLATE_PLATFORMS else ""
    if not state.exists():
        return {
            "type": "project_status",
            "generated_at": now_iso(),
            "ok": False,
            "readiness": "not_initialized",
            "project_dir": str(project),
            "state_dir": str(state),
            "target_chapter": chapter or 1,
            "blockers": ["missing .novel-agent state"],
            "warnings": [],
            "counts": {},
            "latest_desktop_verification": {},
            "desktop_verification_matrix": build_desktop_verification_matrix(project, platform=matrix_platform, chapter=chapter),
            "latest_agent_activity": {},
            "verification_status": build_verification_status({}, []),
            "recommended_commands": [
                f"python cli.py quickstart {project} --source auto --dry-run --format markdown",
                f"python cli.py init-wizard {project} --dry-run",
            ],
            "next_actions": [
                "Run quickstart dry-run, then initialize or import the project before writing.",
            ],
        }

    data = load_state(project)
    manifest = data["manifest"] if isinstance(data["manifest"], dict) else {}
    chapters = data["chapters"]
    coverage = continuity_coverage_report(project)
    target = chapter or int(coverage.get("target_chapter") or 1)
    latest = latest_chapter_record(chapters) or {}
    pending_proposals = int(((coverage.get("open_threads") or {}).get("pending_proposals")) or 0)
    high_risk_proposals = int(((coverage.get("open_threads") or {}).get("high_risk_proposals")) or 0)
    lock_dir = state / LOCK_DIR_NAME
    lock_active = lock_dir.exists() and not stale_lock(lock_dir)
    try:
        schema_version = int(manifest.get("state_schema_version") or 0)
    except (TypeError, ValueError):
        schema_version = 0
    desktop_rows = data.get("desktop_verifications", []) if isinstance(data.get("desktop_verifications"), list) else []
    activity_rows = data.get("agent_activity", []) if isinstance(data.get("agent_activity"), list) else []
    latest_desktop = latest_desktop_verification(desktop_rows, platform=platform)
    latest_activity = activity_rows[-1] if activity_rows else {}
    install_checks: list[dict[str, Any]] = []
    if install_config:
        install_checks = inspect_install_config(install_config, start_mcp_test=False, project_dir=project)
    verification_status = build_verification_status(latest_desktop, install_checks)
    desktop_matrix = build_desktop_verification_matrix(project, platform=matrix_platform)
    blockers: list[str] = []
    warnings: list[str] = []
    if lock_active:
        blockers.append("state write lock is active")
    if schema_version != STATE_SCHEMA_VERSION:
        blockers.append(f"state_schema_version is {schema_version}, expected {STATE_SCHEMA_VERSION}")
    if high_risk_proposals:
        blockers.append(f"{high_risk_proposals} high-risk proposal(s) need author review")
    if pending_proposals and not high_risk_proposals:
        warnings.append(f"{pending_proposals} proposal(s) are waiting for review")
    coverage_warnings = coverage.get("warnings", []) if isinstance(coverage.get("warnings"), list) else []
    for warning in coverage_warnings:
        text = str(warning).strip()
        if text and text not in warnings and text not in blockers:
            warnings.append(text)
    if not latest_desktop:
        warnings.append("no real desktop client verification record")
    elif not latest_desktop.get("ok"):
        warnings.append("latest real desktop client verification has unresolved issues")
    failed_install_checks = [item for item in install_checks if isinstance(item, dict) and not item.get("ok")]
    if failed_install_checks:
        warnings.append(f"{len(failed_install_checks)} install config check(s) failed")
    author_queue_status: dict[str, Any] = {}
    if include_author_review_queue:
        try:
            author_queue = build_author_review_queue(
                project,
                chapter=target,
                platform=matrix_platform or platform or "codex",
                mode="read-only",
                install_config=install_config,
                include_writer_mode=False,
                limit=5,
            )
            author_queue_items = author_queue.get("items") if isinstance(author_queue.get("items"), list) else []
            author_queue_status = {
                "status": author_queue.get("status"),
                "ok": author_queue.get("ok"),
                "summary": author_queue.get("summary"),
                "top_items": [
                    {
                        "id": item.get("id"),
                        "priority": item.get("priority"),
                        "category": item.get("category"),
                        "title": item.get("title"),
                        "message": item.get("message"),
                    }
                    for item in author_queue_items[:5]
                    if isinstance(item, dict)
                ],
                "recommended_command": author_review_queue_command(
                    project,
                    target=target,
                    platform=matrix_platform or platform or "codex",
                    mode="read-only",
                ),
            }
            queue_summary = author_queue_status.get("summary") if isinstance(author_queue_status.get("summary"), dict) else {}
            if author_queue.get("status") == "blocked":
                blockers.append(f"author review queue has {queue_summary.get('blockers', 0)} blocker(s)")
            elif author_queue.get("status") == "needs_author_review":
                warnings.append(f"author review queue has {queue_summary.get('review', 0)} author-review item(s)")
            elif author_queue.get("status") == "ready_with_warnings":
                warnings.append(f"author review queue has {queue_summary.get('warnings', 0)} warning(s)")
        except KitError as exc:
            author_queue_status = {
                "status": "error",
                "ok": False,
                "summary": {},
                "top_items": [],
                "error": str(exc),
            }
            warnings.append(f"author review queue unavailable: {exc}")
    if blockers:
        readiness = "blocked"
    elif pending_proposals:
        readiness = "needs_review"
    elif warnings:
        readiness = "ready_with_warnings"
    else:
        readiness = "ready"
    commands = [
        author_queue_status.get("recommended_command") or f"python cli.py author-review-queue {project} --chapter {target} --platform {matrix_platform or platform or 'codex'} --format markdown",
        f"python cli.py continuity-audit {project} --chapter {target} --platform {matrix_platform or platform or 'codex'} --format markdown",
        f"python cli.py prepare-session {project} --chapter {target} --format markdown",
        f"python cli.py build-context {project} --chapter {target} --format markdown",
        f"python cli.py handoff-report {project} --chapter {target} --format markdown",
        f"python cli.py desktop-checklist {project} --chapter {target} --format markdown",
        shell_command(["python", "cli.py", "desktop-matrix", project, *(["--platform", matrix_platform] if matrix_platform else []), "--format", "markdown"]),
        f"python cli.py list-agent-activity {project} --limit 20 --format markdown",
    ]
    if pending_proposals:
        commands.insert(0, f"python cli.py list-audit {project} --limit 20")
    next_actions: list[str] = []
    if readiness == "blocked":
        next_actions.append("Resolve blockers before writing or accepting chapters.")
    if pending_proposals:
        next_actions.append("Review pending proposals before continuing long-term state changes.")
    if not latest_desktop:
        next_actions.append("Run desktop-checklist in the real desktop client and record evidence.")
    if not data["agents"]:
        next_actions.append("Declare host agent capabilities.")
    if not next_actions:
        next_actions.append("Open a chapter session and build chapter context before drafting.")
    return {
        "type": "project_status",
        "generated_at": now_iso(),
        "ok": readiness in {"ready", "ready_with_warnings"},
        "readiness": readiness,
        "project_dir": str(project),
        "state_dir": str(state),
        "target_chapter": target,
        "manifest": {
            "title": manifest.get("title") or project.name,
            "current_chapter": manifest.get("current_chapter"),
            "target_chapters": manifest.get("target_chapters"),
            "state_schema_version": schema_version,
            "kit_version": manifest.get("kit_version"),
        },
        "latest_accepted_chapter": {
            "chapter": latest.get("chapter"),
            "title": latest.get("title") or "",
            "has_handoff": bool(str(latest.get("handoff") or "").strip()),
        },
        "counts": {
            "chapters": len(chapters),
            "facts": int((coverage.get("facts") or {}).get("active_total") or 0),
            "sources": len(data["sources"]),
            "research": len(data["research"]),
            "contracts": len(data["contracts"]),
            "debts": len(data.get("debts", {}).get("debts", [])) if isinstance(data.get("debts"), dict) else 0,
            "pending_proposals": pending_proposals,
            "high_risk_proposals": high_risk_proposals,
            "agents": len(data["agents"]),
            "desktop_verifications": len(desktop_rows),
            "agent_activity": len(activity_rows),
        },
        "coverage": coverage,
        "latest_desktop_verification": latest_desktop,
        "desktop_verification_matrix": desktop_matrix,
        "latest_agent_activity": latest_activity,
        "author_review_queue": author_queue_status,
        "verification_status": verification_status,
        "install_config_checks": install_checks,
        "blockers": blockers,
        "warnings": warnings,
        "next_actions": next_actions,
        "recommended_commands": commands,
    }


def desktop_next_step_action(
    action_id: str,
    title: str,
    reason: str,
    *,
    command: str = "",
    file: str = "",
    writes_project_state: bool = False,
    writes_install_config: bool = False,
    writes_pack_files: bool = False,
    records_real_client_evidence: bool = False,
    requires_author_confirmation: bool = False,
    requires_review: bool = False,
) -> dict[str, Any]:
    return {
        "id": action_id,
        "title": title,
        "reason": reason,
        "command": command,
        "file": file,
        "writes_project_state": bool(writes_project_state),
        "writes_install_config": bool(writes_install_config),
        "writes_pack_files": bool(writes_pack_files),
        "records_real_client_evidence": bool(records_real_client_evidence),
        "requires_author_confirmation": bool(requires_author_confirmation),
        "requires_review": bool(requires_review),
    }


def build_desktop_next_step(
    project_dir: str | Path | None = None,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    install_config: str = "",
    install_target: str = "",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
    chapter: int | None = None,
    include_session: bool = False,
) -> dict[str, Any]:
    selected_platform = (platform or "codex").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported desktop next-step platform: {platform}")
    selected_mode = (mode or "read-only").strip().lower()
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported desktop next-step mode: {mode}")
    selected_tool_profile = normalize_mcp_tool_profile(tool_profile)

    setup = build_desktop_setup_guide(
        project_dir,
        platform=selected_platform,
        mode=selected_mode,
        install_config=install_config,
        install_target=install_target,
        tool_profile=selected_tool_profile,
    )
    project = Path(str(setup.get("project_dir") or display_project_path(project_dir))).expanduser()
    config_path = str(setup.get("config_path") or "")
    setup_commands = setup.get("commands") if isinstance(setup.get("commands"), dict) else {}
    setup_verification: dict[str, Any] = {}
    if config_path:
        setup_verification = verify_desktop_setup(
            project,
            platform=selected_platform,
            mode=selected_mode,
            install_config=config_path,
            install_target=install_target,
            tool_profile=selected_tool_profile,
            start_mcp_test=False,
        )

    status = project_status(project, chapter=chapter, platform=selected_platform, install_config=config_path)
    target = int(status.get("target_chapter") or chapter or 1)
    state_initialized = status.get("readiness") != "not_initialized"
    author_queue = status.get("author_review_queue") if isinstance(status.get("author_review_queue"), dict) else {}
    verification_status = status.get("verification_status") if isinstance(status.get("verification_status"), dict) else {}
    local_status = verification_status.get("local_mcp_config") if isinstance(verification_status.get("local_mcp_config"), dict) else {}
    real_client_status = verification_status.get("real_desktop_client") if isinstance(verification_status.get("real_desktop_client"), dict) else {}
    if setup_verification:
        raw_setup_checks = setup_verification.get("raw_install_checks") if isinstance(setup_verification.get("raw_install_checks"), list) else []
        local_status = local_mcp_config_verification_status(raw_setup_checks)

    real_mode_status: dict[str, Any] = {}
    if state_initialized:
        data = load_state(project)
        desktop_rows = data.get("desktop_verifications", []) if isinstance(data.get("desktop_verifications"), list) else []
        latest_for_mode = latest_desktop_verification(desktop_rows, platform=selected_platform, mode=selected_mode, chapter=target)
        if not latest_for_mode:
            latest_for_mode = latest_desktop_verification(desktop_rows, platform=selected_platform, mode=selected_mode)
        real_mode_status = real_desktop_verification_status(latest_for_mode)
    else:
        real_mode_status = {
            "status": "missing",
            "proof_level": "none",
            "is_real_client_evidence": False,
            "message": "Project is not initialized, so no selected-mode desktop client evidence can be checked.",
        }

    desktop_verify_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-verify",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--format",
        "markdown",
    ]
    if selected_tool_profile != DEFAULT_MCP_TOOL_PROFILE:
        desktop_verify_parts.extend(["--tool-profile", selected_tool_profile])
    if config_path:
        desktop_verify_parts.extend(["--install-config", config_path, "--start-mcp-test"])
    if install_target:
        desktop_verify_parts.extend(["--install-target", install_target])
    checklist_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "desktop-checklist",
        project,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--chapter",
        target,
        "--format",
        "markdown",
    ]
    if selected_tool_profile != DEFAULT_MCP_TOOL_PROFILE:
        checklist_parts.extend(["--tool-profile", selected_tool_profile])
    if config_path:
        checklist_parts.extend(["--install-config", config_path])
    if install_target:
        checklist_parts.extend(["--install-target", install_target])
    prepare_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "prepare-session",
        project,
        "--chapter",
        target,
        "--platform",
        selected_platform,
        "--mode",
        selected_mode,
        "--format",
        "markdown",
    ]
    project_status_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "project-status",
        project,
        "--chapter",
        target,
        "--platform",
        selected_platform,
        "--format",
        "markdown",
    ]
    if config_path:
        project_status_parts.extend(["--install-config", config_path])
    quickstart_command = str(setup_commands.get("quickstart_dry_run") or "").strip()
    author_queue_command = author_review_queue_command(
        project,
        target=target,
        platform=selected_platform,
        mode=selected_mode,
        install_config=config_path,
        include_writer_mode=selected_mode == "writer",
    )
    writer_readiness_parts: list[object] = [
        "python",
        kit_root() / "cli.py",
        "writer-mode-readiness",
        project,
        "--platform",
        selected_platform,
        "--chapter",
        target,
        "--author-confirmation",
        "<author-approved writer mode scope>",
        "--format",
        "markdown",
    ]
    if config_path:
        writer_readiness_parts.extend(["--install-config", config_path])

    actions: list[dict[str, Any]] = []
    install_action = desktop_next_step_action(
        "verify_or_install_local_mcp",
        "Verify or install the local MCP entry",
        "The desktop client needs a working local long-novel-agent MCP entry before it can use this kit.",
        command=(setup_verification.get("recommended_actions") or [setup_commands.get("merge_mcp_config") or setup_commands.get("print_mcp_config") or ""])[0]
        if setup_verification
        else str(setup_commands.get("merge_mcp_config") or setup_commands.get("print_mcp_config") or ""),
        file="setup.md",
        writes_install_config=True,
        requires_review=True,
    )
    verify_action = desktop_next_step_action(
        "desktop_verify",
        "Run the local setup verification",
        "This checks the MCP config path, server entry, installed kit files, selected mode, and optional stdio startup.",
        command=shell_command(desktop_verify_parts),
        file="client-compatibility.md",
    )
    quickstart_action = desktop_next_step_action(
        "quickstart_project",
        "Initialize or import the novel project",
        "The project has no .novel-agent state yet, so chapter context and continuity checks cannot run.",
        command=quickstart_command,
        file="project-wizard.md",
        writes_project_state=True,
        requires_review=True,
    )
    author_action = desktop_next_step_action(
        "author_review_queue",
        "Review author-gated items",
        "Pending proposals, conflicts, writer authorization, or range acceptance can block durable state changes.",
        command=author_queue_command,
        file="author-review-queue.md",
    )
    checklist_action = desktop_next_step_action(
        "desktop_checklist",
        "Collect real desktop client evidence",
        "Local CLI verification is not the same as proof that the GUI desktop agent can see and call the tools.",
        command=shell_command(checklist_parts),
        file="checklist.md",
    )
    writer_action = desktop_next_step_action(
        "writer_mode_readiness",
        "Check writer mode authorization",
        "Writer mode exposes durable .novel-agent writes and should be enabled only after author approval and read-only proof.",
        command=shell_command(writer_readiness_parts),
        file=f"{WRITER_MODE_APPROVAL_MD_FILE} / {WRITER_MODE_APPROVAL_JSON_FILE}",
        requires_author_confirmation=True,
    )
    prepare_action = desktop_next_step_action(
        "prepare_session",
        "Open the target chapter session",
        "Before drafting, the agent should load the chapter packet instead of relying on chat history.",
        command=shell_command(prepare_parts),
        file="chapter-session.md",
    )
    status_action = desktop_next_step_action(
        "project_status",
        "Read the project status report",
        "Use this when multiple checks disagree or the agent needs a full read-only status snapshot.",
        command=shell_command(project_status_parts),
        file="project-status.md",
    )

    local_config_failed = bool(setup_verification) and not bool(setup_verification.get("ok"))
    local_config_missing = not bool(config_path)
    author_status = str(author_queue.get("status") or "").strip()
    real_mode_missing = real_mode_status.get("status") != "passed"
    if local_config_missing:
        next_status = "needs_install_config"
        primary = install_action
        actions.extend([install_action, verify_action])
    elif local_config_failed:
        next_status = "needs_local_install"
        primary = install_action
        actions.extend([install_action, verify_action])
    elif not state_initialized:
        next_status = "needs_project_initialization"
        primary = quickstart_action
        actions.extend([quickstart_action, verify_action])
    elif author_status in {"blocked", "needs_author_review"}:
        next_status = "needs_author_review"
        primary = author_action
        actions.extend([author_action, status_action])
    elif selected_mode == "writer" and real_mode_missing:
        next_status = "writer_mode_needs_evidence"
        primary = writer_action
        actions.extend([writer_action, checklist_action, author_action])
    elif real_mode_missing:
        next_status = "needs_real_client_evidence"
        primary = checklist_action
        actions.extend([checklist_action, verify_action, prepare_action])
    elif status.get("readiness") == "blocked":
        next_status = "blocked"
        primary = status_action
        actions.extend([status_action, author_action])
    elif status.get("readiness") == "needs_review":
        next_status = "needs_review"
        primary = author_action
        actions.extend([author_action, prepare_action])
    else:
        next_status = "ready_for_chapter_session"
        primary = prepare_action
        actions.extend([prepare_action, checklist_action, status_action])

    deduped_actions: list[dict[str, Any]] = []
    seen_action_ids: set[str] = set()
    for action in actions:
        action_id = str(action.get("id") or "")
        if not action_id or action_id in seen_action_ids:
            continue
        seen_action_ids.add(action_id)
        deduped_actions.append(action)

    session_summary: dict[str, Any] = {}
    if include_session and state_initialized and next_status in {"ready_for_chapter_session", "needs_real_client_evidence", "needs_review"}:
        try:
            session = prepare_chapter_session(project, chapter=target, platform=selected_platform, mode=selected_mode, include_context=False)
            session_summary = {
                "type": session.get("type"),
                "status": session.get("status"),
                "target_chapter": session.get("target_chapter"),
                "warnings": session.get("warnings") if isinstance(session.get("warnings"), list) else [],
                "tool_gates": session.get("tool_gates") if isinstance(session.get("tool_gates"), list) else [],
            }
        except KitError as exc:
            session_summary = {"error": str(exc)}

    return {
        "$schema": DESKTOP_NEXT_STEP_SCHEMA_OUTPUT_FILE,
        "ok": next_status in {"ready_for_chapter_session", "needs_real_client_evidence", "needs_review"},
        "type": "desktop_next_step",
        "generated_at": now_iso(),
        "local_only": True,
        "requires_server": False,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "platform": selected_platform,
        "mode": selected_mode,
        "tool_profile": selected_tool_profile,
        "project_dir": str(project),
        "target_chapter": target,
        "config_path": config_path,
        "status": next_status,
        "primary_action": primary,
        "actions": deduped_actions,
        "state_initialized": state_initialized,
        "setup_verification": setup_verification,
        "project_status": status,
        "author_review_queue": author_queue,
        "verification_status": {
            "local_mcp_config": local_status,
            "real_desktop_client": real_client_status,
            "selected_platform_mode": real_mode_status,
        },
        "chapter_session": session_summary,
        "recommended_commands": [
            shell_command(desktop_verify_parts),
            quickstart_command,
            author_queue_command,
            shell_command(checklist_parts),
            shell_command(prepare_parts),
            shell_command(project_status_parts),
        ],
        "notes": [
            "This report is read-only. It does not write .novel-agent/, change MCP config, write pack files, or record real desktop-client evidence.",
            "Local MCP verification is separate from real GUI desktop-client evidence.",
        ],
    }


def desktop_diagnostic_check(
    check_id: str,
    title: str,
    ok: bool,
    severity: str,
    message: str,
    *,
    detail: Any = None,
    command: str = "",
    file: str = "",
) -> dict[str, Any]:
    return {
        "id": check_id,
        "title": title,
        "ok": bool(ok),
        "severity": severity,
        "message": message,
        "detail": detail,
        "command": command,
        "file": file,
    }


def desktop_diagnostic_status_from_checks(checks: list[dict[str, Any]]) -> str:
    failed = [item for item in checks if isinstance(item, dict) and not item.get("ok")]
    if any(str(item.get("severity") or "") == "blocker" for item in failed):
        return "blocked"
    if any(str(item.get("severity") or "") == "review" for item in failed):
        return "needs_review"
    if any(str(item.get("severity") or "") == "warning" for item in failed):
        return "ready_with_warnings"
    return "ready"


def build_desktop_diagnostics(
    project_dir: str | Path | None = None,
    *,
    platform: str = "codex",
    mode: str = "read-only",
    install_config: str = "",
    install_target: str = "",
    tool_profile: str = DEFAULT_MCP_TOOL_PROFILE,
    chapter: int | None = None,
    pack_dir: str | Path | None = None,
    include_session: bool = False,
) -> dict[str, Any]:
    selected_platform = (platform or "codex").strip().lower()
    if selected_platform not in AGENT_TEMPLATE_PLATFORMS:
        raise KitError(f"Unsupported desktop diagnostics platform: {platform}")
    selected_mode = (mode or "read-only").strip().lower()
    if selected_mode not in AGENT_TEMPLATE_MODES:
        raise KitError(f"Unsupported desktop diagnostics mode: {mode}")
    selected_tool_profile = normalize_mcp_tool_profile(tool_profile)

    next_step = build_desktop_next_step(
        project_dir,
        platform=selected_platform,
        mode=selected_mode,
        install_config=install_config,
        install_target=install_target,
        tool_profile=selected_tool_profile,
        chapter=chapter,
        include_session=include_session,
    )
    project = Path(str(next_step.get("project_dir") or display_project_path(project_dir))).expanduser()
    target = int(next_step.get("target_chapter") or chapter or 1)
    config_path = str(next_step.get("config_path") or "")
    project_state = next_step.get("project_status") if isinstance(next_step.get("project_status"), dict) else {}
    setup_verification = next_step.get("setup_verification") if isinstance(next_step.get("setup_verification"), dict) else {}
    verification = next_step.get("verification_status") if isinstance(next_step.get("verification_status"), dict) else {}
    author_queue = next_step.get("author_review_queue") if isinstance(next_step.get("author_review_queue"), dict) else {}
    primary_action = next_step.get("primary_action") if isinstance(next_step.get("primary_action"), dict) else {}
    commands = next_step.get("recommended_commands") if isinstance(next_step.get("recommended_commands"), list) else []

    checks: list[dict[str, Any]] = []
    checks.append(
        desktop_diagnostic_check(
            "local_mcp_config",
            "Local MCP config",
            bool(config_path) and (not setup_verification or bool(setup_verification.get("ok"))),
            "blocker",
            "Local MCP config is available and matches the requested mode/profile.",
            detail=setup_verification or {"config_path": config_path, "status": "not_checked"},
            command=str(commands[0] or "") if commands else "",
            file="setup.md",
        )
    )
    checks.append(
        desktop_diagnostic_check(
            "project_state",
            "Novel project state",
            bool(next_step.get("state_initialized")),
            "blocker",
            "Project has initialized .novel-agent state.",
            detail={"readiness": project_state.get("readiness"), "blockers": project_state.get("blockers", [])},
            command=str((primary_action.get("command") if primary_action.get("id") == "quickstart_project" else "") or ""),
            file="project-wizard.md",
        )
    )
    project_ready = project_state.get("readiness") in {"ready", "ready_with_warnings"}
    checks.append(
        desktop_diagnostic_check(
            "project_readiness",
            "Project readiness",
            bool(project_ready),
            "review" if project_state.get("readiness") == "needs_review" else "blocker",
            f"Project readiness is {project_state.get('readiness') or 'unknown'}.",
            detail={"readiness": project_state.get("readiness"), "warnings": project_state.get("warnings", [])},
            command=next((str(item) for item in commands if "project-status" in str(item)), ""),
            file="project-status.json",
        )
    )
    author_status = str(author_queue.get("status") or "unknown")
    checks.append(
        desktop_diagnostic_check(
            "author_review_queue",
            "Author review queue",
            author_status not in {"blocked", "needs_author_review"},
            "review",
            f"Author review queue status is {author_status}.",
            detail={
                "status": author_status,
                "blockers": author_queue.get("blockers", []),
                "review_items": author_queue.get("review_items", []),
            },
            command=next((str(item) for item in commands if "author-review-queue" in str(item)), ""),
            file="author-review-queue.json",
        )
    )
    selected_mode_status = verification.get("selected_platform_mode") if isinstance(verification.get("selected_platform_mode"), dict) else {}
    checks.append(
        desktop_diagnostic_check(
            "real_desktop_client_evidence",
            "Real desktop client evidence",
            selected_mode_status.get("status") == "passed",
            "warning",
            f"Selected platform/mode evidence status is {selected_mode_status.get('status') or 'missing'}.",
            detail=selected_mode_status,
            command=next((str(item) for item in commands if "desktop-checklist" in str(item)), ""),
            file="desktop-evidence-review.json",
        )
    )
    if selected_mode == "writer":
        writer_action = primary_action if primary_action.get("id") == "writer_mode_readiness" else {}
        checks.append(
            desktop_diagnostic_check(
                "writer_authorization",
                "Writer mode authorization",
                selected_mode_status.get("status") == "passed" and author_status not in {"blocked", "needs_author_review"},
                "review",
                "Writer mode needs real writer evidence and no blocking author-review items.",
                detail={"selected_platform_mode": selected_mode_status, "author_review_queue": author_status},
                command=str(writer_action.get("command") or ""),
                file=f"{WRITER_MODE_APPROVAL_JSON_FILE}",
            )
        )

    pack_path = Path(pack_dir).expanduser().resolve() if pack_dir else None
    pack_doctor: dict[str, Any] = {}
    pack_readiness: dict[str, Any] = {}
    if pack_path:
        try:
            pack_doctor = doctor_desktop_pack_directory(pack_path)
            checks.append(
                desktop_diagnostic_check(
                    "desktop_pack_doctor",
                    "Desktop pack doctor",
                    bool(pack_doctor.get("ok")),
                    "warning",
                    f"Desktop pack doctor status is {pack_doctor.get('status') or 'unknown'}.",
                    detail={"blocker_count": pack_doctor.get("blocker_count"), "warning_count": pack_doctor.get("warning_count")},
                    command=shell_command(["python", kit_root() / "cli.py", "pack-doctor", pack_path, "--format", "markdown"]),
                    file=PACK_DOCTOR_JSON_FILE,
                )
            )
        except KitError as exc:
            checks.append(
                desktop_diagnostic_check(
                    "desktop_pack_doctor",
                    "Desktop pack doctor",
                    False,
                    "warning",
                    f"Desktop pack doctor could not read the pack: {exc}",
                    detail={"error": str(exc)},
                    command=shell_command(["python", kit_root() / "cli.py", "pack-doctor", pack_path, "--format", "markdown"]),
                    file=PACK_DOCTOR_JSON_FILE,
                )
            )
        try:
            pack_readiness = build_desktop_pack_readiness_from_directory(pack_path)
            checks.append(
                desktop_diagnostic_check(
                    "desktop_pack_readiness",
                    "Desktop pack readiness",
                    bool(pack_readiness.get("ok")),
                    "review",
                    f"Desktop pack readiness status is {pack_readiness.get('status') or 'unknown'}.",
                    detail={"status": pack_readiness.get("status"), "blockers": pack_readiness.get("blockers", [])},
                    command=shell_command(["python", kit_root() / "cli.py", "desktop-pack-readiness", pack_path, "--format", "markdown"]),
                    file=DESKTOP_PACK_READINESS_JSON_FILE,
                )
            )
        except KitError as exc:
            checks.append(
                desktop_diagnostic_check(
                    "desktop_pack_readiness",
                    "Desktop pack readiness",
                    False,
                    "review",
                    f"Desktop pack readiness could not read the pack: {exc}",
                    detail={"error": str(exc)},
                    command=shell_command(["python", kit_root() / "cli.py", "desktop-pack-readiness", pack_path, "--format", "markdown"]),
                    file=DESKTOP_PACK_READINESS_JSON_FILE,
                )
            )

    status = desktop_diagnostic_status_from_checks(checks)
    failed = [item for item in checks if isinstance(item, dict) and not item.get("ok")]
    recommended_actions: list[dict[str, Any]] = []
    if primary_action:
        recommended_actions.append(primary_action)
    for item in failed:
        command = str(item.get("command") or "").strip()
        if command:
            recommended_actions.append(
                {
                    "id": str(item.get("id") or ""),
                    "title": str(item.get("title") or ""),
                    "reason": str(item.get("message") or ""),
                    "command": command,
                    "file": str(item.get("file") or ""),
                    "writes_project_state": False,
                    "writes_install_config": False,
                    "writes_pack_files": False,
                    "records_real_client_evidence": False,
                    "requires_author_confirmation": False,
                    "requires_review": str(item.get("severity") or "") in {"blocker", "review"},
                }
            )
    deduped_actions: list[dict[str, Any]] = []
    seen_actions: set[tuple[str, str]] = set()
    for action in recommended_actions:
        key = (str(action.get("id") or ""), str(action.get("command") or ""))
        if key in seen_actions:
            continue
        seen_actions.add(key)
        deduped_actions.append(action)

    return {
        "ok": status in {"ready", "ready_with_warnings"},
        "type": "desktop_diagnostics",
        "generated_at": now_iso(),
        "local_only": True,
        "requires_server": False,
        "would_write_project_state": False,
        "would_write_install_config": False,
        "would_write_pack_files": False,
        "records_real_client_evidence": False,
        "platform": selected_platform,
        "mode": selected_mode,
        "tool_profile": selected_tool_profile,
        "project_dir": str(project),
        "target_chapter": target,
        "config_path": config_path,
        "pack_dir": str(pack_path) if pack_path else "",
        "status": status,
        "next_step_status": next_step.get("status"),
        "primary_action": primary_action,
        "checks": checks,
        "blockers": [str(item.get("message") or "") for item in failed if str(item.get("severity") or "") == "blocker"],
        "review_items": [str(item.get("message") or "") for item in failed if str(item.get("severity") or "") == "review"],
        "warnings": [str(item.get("message") or "") for item in failed if str(item.get("severity") or "") == "warning"],
        "recommended_actions": deduped_actions,
        "recommended_commands": [str(item.get("command") or "") for item in deduped_actions if str(item.get("command") or "").strip()],
        "reports": {
            "desktop_next_step": next_step,
            "project_status": project_state,
            "setup_verification": setup_verification,
            "author_review_queue": author_queue,
            "pack_doctor": pack_doctor,
            "desktop_pack_readiness": pack_readiness,
        },
        "notes": [
            "This diagnostics report is read-only. It does not write .novel-agent/, change local MCP config, write pack files, or record real desktop-client evidence.",
            "Real GUI desktop-client evidence still has to come from the desktop app itself.",
        ],
    }


def verify_handoff_readiness(
    project_dir: str | Path,
    *,
    chapter: int | None = None,
    incoming_agent_id: str = "",
    incoming_platform: str = "",
    outgoing_agent_id: str = "",
    mode: str = "writer",
    required_capabilities: Any = None,
    install_config: str = "",
    include_context: bool = False,
) -> dict[str, Any]:
    project = project_root(project_dir)
    project_state = project_status(project, chapter=chapter, platform=incoming_platform, install_config=install_config)
    target = int(project_state.get("target_chapter") or chapter or 1)
    checks: list[dict[str, Any]] = []

    def add_check(check_id: str, ok: bool, severity: str, message: str, detail: Any = None) -> None:
        checks.append({"id": check_id, "ok": bool(ok), "severity": severity, "message": message, "detail": detail})

    if project_state.get("readiness") == "not_initialized":
        add_check("project_initialized", False, "blocker", "Project has no .novel-agent state.")
        return {
            "type": "handoff_readiness",
            "generated_at": now_iso(),
            "ok": False,
            "status": "blocked",
            "project_dir": str(project),
            "target_chapter": target,
            "mode": mode,
            "checks": checks,
            "blockers": [checks[0]["message"]],
            "warnings": [],
            "review_items": [],
            "project_status": project_state,
            "handoff_report": {},
            "recent_agent_activity": [],
            "incoming_agent": {},
            "outgoing_agent": {},
            "latest_desktop_verification": {},
            "verification_status": project_state.get("verification_status", {}),
            "next_actions": ["Initialize or import the project before assigning it to another desktop agent."],
            "recommended_commands": project_state.get("recommended_commands", []),
        }

    data = load_state(project)
    report = build_handoff_report(project, chapter=target, include_context=include_context)
    recent_activity = report.get("recent_agent_activity") if isinstance(report.get("recent_agent_activity"), list) else []
    agents = data["agents"] if isinstance(data.get("agents"), list) else []
    incoming = find_agent_declaration(agents, agent_id=incoming_agent_id, platform=incoming_platform)
    outgoing = find_agent_declaration(agents, agent_id=outgoing_agent_id) if outgoing_agent_id else {}
    required = split_list(required_capabilities) or default_handoff_capabilities(mode)
    normalized_required = [normalize_capability_name(item) for item in required if normalize_capability_name(item)]
    incoming_caps = [normalize_capability_name(item) for item in split_list(incoming.get("capabilities"))] if incoming else []
    missing_caps = [item for item in normalized_required if item not in incoming_caps]
    desktop_rows = data.get("desktop_verifications", []) if isinstance(data.get("desktop_verifications"), list) else []
    desktop = latest_desktop_verification(desktop_rows, platform=incoming_platform)
    verification_status = project_state.get("verification_status") if isinstance(project_state.get("verification_status"), dict) else build_verification_status(desktop, [])
    real_client_status = verification_status.get("real_desktop_client") if isinstance(verification_status.get("real_desktop_client"), dict) else {}
    local_config_status = verification_status.get("local_mcp_config") if isinstance(verification_status.get("local_mcp_config"), dict) else {}
    pending = report.get("pending_proposals") if isinstance(report.get("pending_proposals"), list) else []
    high_risk = report.get("high_risk_proposals") if isinstance(report.get("high_risk_proposals"), list) else []
    latest = report.get("latest_accepted_chapter") if isinstance(report.get("latest_accepted_chapter"), dict) else {}
    latest_chapter = int(latest.get("chapter") or 0)
    handoff_text = str(report.get("handoff") or "").strip()
    has_real_handoff = bool(handoff_text and "No accepted chapter has been recorded yet." not in handoff_text)

    project_ready = project_state.get("readiness") in {"ready", "ready_with_warnings"}
    add_check(
        "project_ready",
        project_ready,
        "review" if project_state.get("readiness") == "needs_review" else "blocker",
        f"Project readiness is {project_state.get('readiness')}.",
        {"readiness": project_state.get("readiness"), "blockers": project_state.get("blockers", [])},
    )
    add_check("target_context_available", bool(report.get("project")), "blocker", f"Target chapter {target} context can be built.")
    add_check(
        "accepted_chapter_available",
        target <= 1 or bool(latest_chapter),
        "warning",
        "A prior accepted chapter exists for this handoff.",
        {"latest_chapter": latest_chapter},
    )
    add_check(
        "handoff_text_present",
        target <= 1 or not latest_chapter or has_real_handoff,
        "warning",
        "Latest accepted chapter or handoff.md contains handoff text.",
    )
    add_check(
        "incoming_agent_declared",
        bool(incoming),
        "warning",
        "Incoming desktop agent has a capability declaration.",
        {"incoming_agent_id": incoming_agent_id, "incoming_platform": incoming_platform},
    )
    add_check(
        "incoming_agent_capabilities",
        bool(incoming) and not missing_caps,
        "blocker",
        "Incoming desktop agent has required capabilities.",
        {"required": normalized_required, "present": incoming_caps, "missing": missing_caps},
    )
    if outgoing_agent_id:
        outgoing_activity = [
            row
            for row in recent_activity
            if isinstance(row, dict) and str(row.get("agent_id") or "") == outgoing_agent_id
        ]
        add_check(
            "outgoing_agent_declared",
            bool(outgoing),
            "warning",
            "Outgoing desktop agent declaration is present.",
            {"outgoing_agent_id": outgoing_agent_id},
        )
        add_check(
            "outgoing_agent_activity_visible",
            bool(outgoing_activity),
            "warning",
            "Outgoing desktop agent has target-visible activity in recent handoff history.",
            {"outgoing_agent_id": outgoing_agent_id, "recent_activity_count": len(recent_activity), "matched": len(outgoing_activity)},
        )
    add_check(
        "desktop_client_verified",
        real_client_status.get("status") == "passed",
        "warning",
        "Incoming platform has a successful real desktop client verification record.",
        real_client_status,
    )
    add_check("pending_proposals_clear", not pending, "review", "No pending proposal blocks handoff.", {"pending": len(pending)})
    add_check("high_risk_proposals_clear", not high_risk, "blocker", "No high-risk proposal blocks handoff.", {"high_risk": len(high_risk)})
    failed_install_checks = [
        item
        for item in project_state.get("install_config_checks", [])
        if isinstance(item, dict) and not item.get("ok")
    ]
    if install_config:
        add_check(
            "install_config_valid",
            not failed_install_checks,
            "warning",
            "Optional local MCP install config checks passed; this does not replace real desktop client evidence.",
            {"failed": failed_install_checks, "local_mcp_config": local_config_status},
        )

    blockers = [item["message"] for item in checks if not item["ok"] and item["severity"] == "blocker"]
    review_items = [item["message"] for item in checks if not item["ok"] and item["severity"] == "review"]
    warnings = [item["message"] for item in checks if not item["ok"] and item["severity"] == "warning"]
    for warning in project_state.get("warnings", []):
        text = str(warning).strip()
        if text and text not in warnings and text not in blockers and text not in review_items:
            warnings.append(text)
    if blockers:
        status = "blocked"
    elif review_items:
        status = "needs_review"
    elif warnings:
        status = "ready_with_warnings"
    else:
        status = "ready"
    commands = [
        f"python cli.py project-status {project} --chapter {target} --platform {incoming_platform or 'codex'} --format markdown",
        f"python cli.py prepare-session {project} --chapter {target} --platform {incoming_platform or 'codex'} --mode {mode} --format markdown",
        f"python cli.py handoff-report {project} --chapter {target} --format markdown",
        f"python cli.py desktop-checklist {project} --chapter {target} --platform {incoming_platform or 'codex'} --mode {mode} --format markdown",
    ]
    if not incoming:
        commands.insert(0, f"python cli.py declare-agent {project} --agent-id <agent-id> --platform {incoming_platform or 'codex'} --capabilities mcp,file_read,file_write")
    if not desktop or not desktop.get("ok"):
        commands.append(f"python cli.py record-desktop-check {project} --platform {incoming_platform or 'codex'} --mode {mode} --chapter {target} --results <results.json>")
    next_actions: list[str] = []
    if blockers:
        next_actions.append("Resolve blocker checks before the incoming agent drafts or accepts chapters.")
    if review_items:
        next_actions.append("Review pending proposals before assigning the next writing step.")
    if warnings:
        next_actions.append("Inspect warnings and decide whether they are acceptable for this handoff.")
    if not next_actions:
        next_actions.append("Incoming agent can open the chapter session and build chapter context before drafting.")
    return {
        "type": "handoff_readiness",
        "generated_at": now_iso(),
        "ok": status in {"ready", "ready_with_warnings"},
        "status": status,
        "project_dir": str(project),
        "target_chapter": target,
        "mode": mode,
        "incoming_agent": incoming,
        "outgoing_agent": outgoing,
        "required_capabilities": normalized_required,
        "missing_capabilities": missing_caps,
        "latest_desktop_verification": desktop,
        "verification_status": verification_status,
        "checks": checks,
        "blockers": blockers,
        "warnings": warnings,
        "review_items": review_items,
        "project_status": project_state,
        "handoff_report": report,
        "recent_agent_activity": recent_activity,
        "next_actions": next_actions,
        "recommended_commands": commands,
    }


def fact_coverage_summary(facts: list[dict[str, Any]]) -> dict[str, Any]:
    kind_counts: dict[str, int] = {}
    checks = {
        "prop_ownership": 0,
        "timeline_order": 0,
        "location_state": 0,
        "relationship_state": 0,
        "life_state": 0,
    }
    for fact in facts:
        kind = str(fact.get("kind") or "fact").strip() or "fact"
        kind_counts[kind] = kind_counts.get(kind, 0) + 1
        predicate = fact_predicate(fact)
        object_value = str(fact.get("object") or "")
        if predicate in OWNERSHIP_PREDICATES:
            checks["prop_ownership"] += 1
        if predicate in TIMELINE_BEFORE_PREDICATES or predicate in TIMELINE_AFTER_PREDICATES:
            checks["timeline_order"] += 1
        if fact_matches(fact, kinds=LOCATION_FACT_KINDS, predicates=LOCATION_PREDICATES):
            checks["location_state"] += 1
        if fact_matches(fact, kinds=RELATIONSHIP_FACT_KINDS, predicates=RELATIONSHIP_PREDICATES):
            checks["relationship_state"] += 1
        if fact_matches(fact, kinds=LIFE_STATUS_KINDS, predicates=LIFE_STATUS_PREDICATES) and life_status_category(object_value):
            checks["life_state"] += 1
    return {
        "active_total": len(facts),
        "kind_counts": dict(sorted(kind_counts.items())),
        "checks": checks,
    }


def extract_mcp_servers(config_path: Path) -> dict[str, Any]:
    text = config_path.read_text(encoding="utf-8")
    stripped = text.lstrip()
    if stripped.startswith("{"):
        payload = json.loads(text)
        servers = payload.get("mcpServers", {}) if isinstance(payload, dict) else {}
        return servers if isinstance(servers, dict) else {}
    if tomllib is not None:
        try:
            payload = tomllib.loads(text)
            servers = payload.get("mcp_servers", {}) if isinstance(payload, dict) else {}
            return servers if isinstance(servers, dict) else {}
        except Exception:
            pass
    match = re.search(r"(?ms)^\[mcp_servers\.long-novel-agent\]\s*(.*?)(?=^\[|\Z)", text)
    if not match:
        return {}
    body = match.group(1)
    command_match = re.search(r"(?m)^\s*command\s*=\s*(.+?)\s*$", body)
    args_match = re.search(r"(?ms)^\s*args\s*=\s*(\[[^\n]*(?:\n.*?)*?\])\s*$", body)
    entry: dict[str, Any] = {}
    if command_match:
        try:
            entry["command"] = json.loads(command_match.group(1).strip())
        except json.JSONDecodeError:
            entry["command"] = command_match.group(1).strip().strip("\"'")
    if args_match:
        try:
            entry["args"] = json.loads(args_match.group(1).strip())
        except json.JSONDecodeError:
            entry["args"] = []
    return {"long-novel-agent": entry}


def resolve_command_path(command: str) -> str:
    if not command:
        return ""
    expanded = Path(command).expanduser()
    if expanded.is_absolute() or os.sep in command:
        return str(expanded)
    found = shutil.which(command)
    return found or str(expanded)


def read_kit_version_from_cli(cli_path: Path) -> str:
    try:
        text = cli_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return ""
    match = re.search(r"(?m)^KIT_VERSION\s*=\s*[\"']([^\"']+)[\"']", text)
    return match.group(1).strip() if match else ""


def inspect_installed_kit_from_server(server_path: Path | None) -> dict[str, Any]:
    expected = KIT_VERSION
    source_skill_path = Path(__file__).resolve().parent / "SKILL.md"
    expected_skill_sha256 = local_file_sha256(source_skill_path) if source_skill_path.exists() else ""
    if server_path is None:
        return {
            "ok": False,
            "path": "",
            "server_py": "",
            "cli_py": "",
            "skill_md": "",
            "source_skill_md": str(source_skill_path),
            "server_exists": False,
            "cli_exists": False,
            "skill_exists": False,
            "installed_version": "",
            "expected_version": expected,
            "version_matches": False,
            "installed_skill_sha256": "",
            "expected_skill_sha256": expected_skill_sha256,
            "skill_content_matches_source": False,
            "message": "No server.py path was found in the MCP config.",
        }
    kit_root = server_path.expanduser().resolve().parent
    cli_path = kit_root / "cli.py"
    skill_path = kit_root / "SKILL.md"
    server_exists = server_path.exists()
    cli_exists = cli_path.exists()
    skill_exists = skill_path.exists()
    installed_version = read_kit_version_from_cli(cli_path) if cli_exists else ""
    version_matches = bool(installed_version) and installed_version == expected
    installed_skill_sha256 = local_file_sha256(skill_path) if skill_exists else ""
    skill_content_matches_source = bool(installed_skill_sha256 and expected_skill_sha256 and installed_skill_sha256 == expected_skill_sha256)
    ok = server_exists and cli_exists and skill_exists and version_matches and skill_content_matches_source
    return {
        "ok": ok,
        "path": str(kit_root),
        "server_py": str(server_path),
        "cli_py": str(cli_path),
        "skill_md": str(skill_path),
        "source_skill_md": str(source_skill_path),
        "server_exists": server_exists,
        "cli_exists": cli_exists,
        "skill_exists": skill_exists,
        "installed_version": installed_version,
        "expected_version": expected,
        "version_matches": version_matches,
        "installed_skill_sha256": installed_skill_sha256,
        "expected_skill_sha256": expected_skill_sha256,
        "skill_content_matches_source": skill_content_matches_source,
        "message": "Installed kit matches this source version." if ok else "Installed kit differs from this source version or is incomplete.",
    }


def start_mcp_server_check(command: str, args: list[str], *, project_dir: str | Path | None = None) -> dict[str, Any]:
    messages = [
        {"jsonrpc": "2.0", "id": 1, "method": "initialize", "params": {"protocolVersion": "2025-06-18"}},
        {"jsonrpc": "2.0", "method": "notifications/initialized", "params": {}},
        {"jsonrpc": "2.0", "id": 2, "method": "tools/list", "params": {}},
    ]
    project_path = project_root(project_dir) if project_dir else None
    if project_path and (project_path / STATE_DIR).exists():
        mode = "read-only" if "--read-only" in args else "writer"
        messages.append(
            {
                "jsonrpc": "2.0",
                "id": 3,
                "method": "tools/call",
                "params": {
                    "name": "prepare_chapter_session",
                    "arguments": {
                        "project_dir": str(project_path),
                        "platform": "generic",
                        "mode": mode,
                        "include_context": False,
                    },
                },
            }
        )
    payload = "".join(json.dumps(message, ensure_ascii=False) + "\n" for message in messages)
    try:
        proc = subprocess.run(
            [command, *args],
            input=payload,
            text=True,
            capture_output=True,
            timeout=8,
            check=False,
        )
    except (OSError, subprocess.TimeoutExpired) as exc:
        return {"ok": False, "detail": str(exc)}
    replies = []
    for line in proc.stdout.splitlines():
        if not line.strip():
            continue
        try:
            replies.append(json.loads(line))
        except json.JSONDecodeError:
            return {"ok": False, "detail": f"invalid JSON-RPC output: {line[:160]}"}
    tool_reply = next((reply for reply in replies if reply.get("id") == 2), {})
    init_reply = next((reply for reply in replies if reply.get("id") == 1), {})
    server_info = ((init_reply.get("result") or {}).get("serverInfo") or {}) if isinstance(init_reply, dict) else {}
    tools = ((tool_reply.get("result") or {}).get("tools") or []) if isinstance(tool_reply, dict) else []
    tool_names = [str(tool.get("name") or "") for tool in tools if isinstance(tool, dict)]
    tool_call_detail: dict[str, Any] = {"skipped": True}
    tool_call_ok = True
    if project_path and (project_path / STATE_DIR).exists():
        call_reply = next((reply for reply in replies if reply.get("id") == 3), {})
        structured = ((call_reply.get("result") or {}).get("structuredContent") or {}) if isinstance(call_reply, dict) else {}
        tool_call_ok = isinstance(structured, dict) and structured.get("type") == "chapter_session_packet"
        tool_call_detail = {
            "skipped": False,
            "ok": tool_call_ok,
            "type": structured.get("type") if isinstance(structured, dict) else "",
            "target_chapter": structured.get("target_chapter") if isinstance(structured, dict) else None,
            "is_error": bool(((call_reply.get("result") or {}).get("isError")) if isinstance(call_reply, dict) else True),
        }
    ok = (
        proc.returncode == 0
        and "build_chapter_context" in tool_names
        and "prepare_chapter_session" in tool_names
        and "check_chapter" in tool_names
        and tool_call_ok
    )
    return {
        "ok": ok,
        "detail": {
            "returncode": proc.returncode,
            "server_info": server_info if isinstance(server_info, dict) else {},
            "tool_count": len(tool_names),
            "prepare_chapter_session": tool_call_detail,
            "stderr": proc.stderr.strip()[:500],
        },
    }


def inspect_install_config(config_path: str | Path, *, start_mcp_test: bool = False, project_dir: str | Path | None = None) -> list[dict[str, Any]]:
    path = Path(config_path).expanduser().resolve()
    checks: list[dict[str, Any]] = []
    checks.append({"name": "install_config", "ok": path.exists(), "detail": str(path)})
    if not path.exists():
        return checks
    try:
        servers = extract_mcp_servers(path)
    except (OSError, json.JSONDecodeError) as exc:
        checks.append({"name": "install_config_parse", "ok": False, "detail": str(exc)})
        return checks
    entry = servers.get("long-novel-agent") if isinstance(servers, dict) else None
    checks.append({"name": "install_config_server:long-novel-agent", "ok": isinstance(entry, dict), "detail": sorted(servers) if isinstance(servers, dict) else []})
    if not isinstance(entry, dict):
        return checks
    command = str(entry.get("command") or "").strip()
    args = entry.get("args") if isinstance(entry.get("args"), list) else []
    args = [str(item) for item in args]
    command_path = resolve_command_path(command)
    checks.append({"name": "install_config_command", "ok": bool(command) and Path(command_path).exists(), "detail": command_path or command})
    checks.append({"name": "install_config_args", "ok": bool(args), "detail": args})
    server_arg = next((item for item in args if item.endswith("server.py")), "")
    server_path = Path(server_arg).expanduser()
    if server_arg and not server_path.is_absolute():
        server_path = (path.parent / server_path).resolve()
    checks.append({"name": "install_config_server_py", "ok": bool(server_arg) and server_path.exists(), "detail": str(server_path) if server_arg else ""})
    installed_detail = inspect_installed_kit_from_server(server_path if server_arg else None)
    checks.append({"name": "install_config_installed_kit", "ok": bool(installed_detail.get("ok")), "detail": installed_detail})
    checks.append({"name": "install_config_read_only", "ok": True, "detail": "--read-only" in args})
    profile = DEFAULT_MCP_TOOL_PROFILE
    if "--tool-profile" in args:
        profile_index = args.index("--tool-profile") + 1
        if profile_index < len(args):
            profile = args[profile_index]
    checks.append({"name": "install_config_tool_profile", "ok": profile in MCP_TOOL_PROFILES, "detail": profile})
    if start_mcp_test:
        if command and Path(command_path).exists() and server_arg and server_path.exists():
            check = start_mcp_server_check(command_path, args, project_dir=project_dir)
            checks.append({"name": "install_config_mcp_start", "ok": bool(check.get("ok")), "detail": check.get("detail")})
        else:
            checks.append({"name": "install_config_mcp_start", "ok": False, "detail": "command or server.py path is invalid"})
    return checks


def doctor(project_dir: str | Path | None = None, *, install_config: str = "", start_mcp_test: bool = False) -> dict[str, Any]:
    kit_dir = Path(__file__).resolve().parent
    checks: list[dict[str, Any]] = []
    py_ok = sys.version_info >= (3, 10)
    checks.append({"name": "python_version", "ok": py_ok, "detail": sys.version.split()[0]})
    for name in ("SKILL.md", "cli.py", "server.py", "install.py", "agents/openai.yaml"):
        path = kit_dir / name
        checks.append({"name": f"skill_file:{name}", "ok": path.exists(), "detail": str(path)})
    try:
        import server  # type: ignore

        tool_names = {tool.get("name") for tool in server.TOOLS}
        expected = {
            "init_project",
            "init_wizard",
            "quickstart_project",
            "import_gaoxia_project",
            "audit_gaoxia_import",
            "export_state_package",
            "import_state_package",
            "get_agent_template",
            "build_desktop_setup_guide",
            "verify_desktop_setup",
            "build_desktop_client_checklist",
            "build_source_intake_template",
            "validate_source_intake",
            "build_desktop_evidence_packet",
            "build_writer_mode_readiness",
            "record_desktop_client_check",
            "list_desktop_client_checks",
            "get_desktop_verification_matrix",
            "get_project_status",
            "build_continuity_audit",
            "verify_handoff_readiness",
            "add_source_summary",
            "add_research_note",
            "declare_agent_capabilities",
            "list_agent_capabilities",
            "resolve_conflict",
            "add_fact",
            "update_fact",
            "list_facts",
            "supersede_fact",
            "build_chapter_context",
            "prepare_chapter_session",
            "record_chapter",
            "record_style_sample",
            "check_chapter",
            "diff_chapter_contract",
            "build_chapter_readiness",
            "build_chapter_acceptance_plan",
            "build_chapter_range_readiness",
            "propose_after_write_updates",
            "build_proposal_template",
            "get_proposal_schema",
            "validate_proposal",
            "diff_proposal",
            "build_proposal_review",
            "build_proposal_readiness",
            "apply_after_write_updates",
            "reject_proposal",
            "create_snapshot",
            "list_snapshots",
            "restore_snapshot",
            "list_audit",
            "update_after_write",
            "list_open_threads",
            "build_handoff_report",
            "doctor",
        }
        missing = sorted(expected - tool_names)
        checks.append({"name": "mcp_tool_table", "ok": not missing, "detail": {"missing": missing, "count": len(tool_names)}})
    except Exception as exc:
        checks.append({"name": "mcp_tool_table", "ok": False, "detail": str(exc)})
    checks.append({"name": "proposal_schema", "ok": proposal_schema_path().exists(), "detail": str(proposal_schema_path())})
    if project_dir:
        project = project_root(project_dir)
        state = project / STATE_DIR
        checks.append({"name": "project_dir", "ok": project.exists(), "detail": str(project)})
        checks.append({"name": "state_dir", "ok": state.exists(), "detail": str(state)})
        if state.exists():
            lock_dir = state / LOCK_DIR_NAME
            checks.append({"name": "state_lock", "ok": not lock_dir.exists() or stale_lock(lock_dir), "detail": read_lock_detail(lock_dir) if lock_dir.exists() else "unlocked"})
            for name in REQUIRED_JSON_FILES + REQUIRED_TEXT_FILES + REQUIRED_JSONL_FILES:
                path = state / name
                checks.append({"name": f"state_file:{name}", "ok": path.exists(), "detail": str(path)})
            manifest = read_json(state / "manifest.json", {})
            try:
                schema_version = int(manifest.get("state_schema_version") or 0) if isinstance(manifest, dict) else 0
            except (TypeError, ValueError):
                schema_version = 0
            checks.append({"name": "state_schema_version", "ok": schema_version == STATE_SCHEMA_VERSION, "detail": schema_version})
            writable = False
            try:
                probe = state / ".doctor-write-test"
                probe.write_text("ok", encoding="utf-8")
                probe.unlink()
                writable = True
            except OSError:
                writable = False
            checks.append({"name": "state_writable", "ok": writable, "detail": str(state)})
            try:
                coverage = continuity_coverage_report(project)
                checks.append({"name": "continuity_coverage", "ok": True, "detail": coverage})
            except Exception as exc:
                checks.append({"name": "continuity_coverage", "ok": False, "detail": str(exc)})
    if install_config:
        checks.extend(inspect_install_config(install_config, start_mcp_test=start_mcp_test, project_dir=project_dir))
    elif start_mcp_test:
        check = start_mcp_server_check(sys.executable, [str(kit_dir / "server.py")], project_dir=project_dir)
        checks.append({"name": "current_kit_mcp_start", "ok": bool(check.get("ok")), "detail": check.get("detail")})
    return {"ok": all(item["ok"] for item in checks), "checks": checks}


def render_context_budget_markdown_lines(budget: Any) -> list[str]:
    if not isinstance(budget, dict) or not budget:
        return ["- Status: unknown"]
    total = budget.get("total") if isinstance(budget.get("total"), dict) else {}
    counts = budget.get("counts") if isinstance(budget.get("counts"), dict) else {}
    lines = [
        f"- Status: {budget.get('status') or 'unknown'}",
        f"- Needs compression: {budget.get('needs_compression')}",
        f"- Chars: {total.get('chars', 0)}",
        f"- Bytes: {total.get('bytes', 0)}",
        f"- Text units: {total.get('text_units', 0)}",
        f"- Facts: {counts.get('facts', 0)}",
        f"- Open debts: {counts.get('open_debts', 0)}",
        f"- Sources: {counts.get('sources', 0)}",
        f"- Research: {counts.get('research', 0)}",
    ]
    warnings = budget.get("warnings") if isinstance(budget.get("warnings"), list) else []
    lines.append("- Warnings: " + ("; ".join(str(item) for item in warnings) if warnings else "None"))
    sections = budget.get("sections") if isinstance(budget.get("sections"), list) else []
    if sections:
        lines.append("- Largest sections:")
        for row in sections[:5]:
            if not isinstance(row, dict):
                continue
            lines.append(f"  - {row.get('name')}: {row.get('chars', 0)} chars / {row.get('items', 0)} item(s)")
    recommendations = budget.get("recommendations") if isinstance(budget.get("recommendations"), list) else []
    if recommendations:
        lines.append("- Recommendations:")
        lines.extend(f"  - {item}" for item in recommendations[:4])
    return lines


def render_context_brief_markdown_lines(brief: Any) -> list[str]:
    if not isinstance(brief, dict) or not brief:
        return ["- Status: unavailable"]
    size = brief.get("size") if isinstance(brief.get("size"), dict) else {}
    counts = brief.get("counts") if isinstance(brief.get("counts"), dict) else {}
    previous = brief.get("previous_chapter") if isinstance(brief.get("previous_chapter"), dict) else {}
    contract = brief.get("chapter_contract") if isinstance(brief.get("chapter_contract"), dict) else {}
    lines = [
        f"- Type: {brief.get('type') or 'chapter_context_brief'}",
        f"- Budget status: {brief.get('budget_status') or 'unknown'}",
        f"- Chars: {size.get('chars', 0)}",
        f"- Previous chapter: {previous.get('chapter') or 'None'}",
        f"- Handoff: {brief.get('handoff') or 'None'}",
        f"- Facts in brief: {counts.get('facts_in_brief', 0)} / {counts.get('facts_total', 0)}",
        f"- Open debts in brief: {counts.get('open_debts_in_brief', 0)} / {counts.get('open_debts_total', 0)}",
        f"- Sources in brief: {counts.get('sources_in_brief', 0)} / {counts.get('sources_total', 0)}",
        f"- Research in brief: {counts.get('research_in_brief', 0)} / {counts.get('research_total', 0)}",
        f"- Contracts in brief: {counts.get('contracts_in_brief', 0)} / {counts.get('contracts_total', 0)}",
    ]
    required = split_list(brief.get("required"))
    forbidden = split_list(brief.get("forbidden"))
    future = split_list(brief.get("future_markers"))
    lines.append("- Required: " + (", ".join(required[:8]) if required else "None"))
    lines.append("- Forbidden: " + (", ".join(forbidden[:8]) if forbidden else "None"))
    lines.append("- Future markers: " + (", ".join(future[:8]) if future else "None"))
    focus = split_list(contract.get("continuity_focus"))
    if focus:
        lines.append("- Continuity focus:")
        lines.extend(f"  - {item}" for item in focus[:6])
    facts = brief.get("high_priority_facts") if isinstance(brief.get("high_priority_facts"), list) else []
    if facts:
        lines.append("- High-priority facts:")
        for item in facts[:8]:
            if not isinstance(item, dict):
                continue
            subject = item.get("subject") or item.get("id") or "fact"
            predicate = item.get("predicate") or ""
            obj = item.get("object") or ""
            kind = item.get("kind") or ""
            lines.append(f"  - {kind} {subject} {predicate} {obj}".strip())
    debts = brief.get("open_debts") if isinstance(brief.get("open_debts"), list) else []
    if debts:
        lines.append("- Open debts:")
        for item in debts[:6]:
            if isinstance(item, dict):
                lines.append(f"  - {item.get('title') or item.get('id')}: {item.get('detail') or item.get('status') or ''}".rstrip())
    return lines


def render_context_brief_markdown(brief: dict[str, Any]) -> str:
    project = brief.get("project") if isinstance(brief.get("project"), dict) else {}
    budget = brief.get("context_budget_summary") if isinstance(brief.get("context_budget_summary"), dict) else {}
    lines = [
        f"# Chapter {brief.get('target_chapter') or 'Unknown'} Context Brief",
        "",
        "## Project",
        f"- Title: {project.get('title') or project.get('name') or 'Unknown'}",
        f"- Current chapter: {project.get('current_chapter') or 'Unknown'}",
        "",
        "## Budget Summary",
        f"- Status: {budget.get('status') or brief.get('budget_status') or 'unknown'}",
        f"- Needs compression: {budget.get('needs_compression')}",
        f"- Chars: {budget.get('chars', 0)}",
        f"- Text units: {budget.get('text_units', 0)}",
        f"- Facts: {budget.get('facts', 0)}",
        f"- Open debts: {budget.get('open_debts', 0)}",
        "",
        "## Read First",
    ]
    lines.extend(render_context_brief_markdown_lines(brief))
    return "\n".join(lines).rstrip() + "\n"


def render_context_markdown(context: dict[str, Any]) -> str:
    fingerprint = context.get("context_fingerprint") if isinstance(context.get("context_fingerprint"), dict) else {}
    lines = [
        f"# Chapter {context['target_chapter']} Context",
        "",
        "## Project",
        json.dumps(context["project"], ensure_ascii=False, indent=2),
        "",
        "## Context Fingerprint",
        f"- SHA256: `{fingerprint.get('sha256') or ''}`",
        "",
        "## Context Budget",
    ]
    lines.extend(render_context_budget_markdown_lines(context.get("context_budget")))
    lines.extend([
        "",
        "## Context Brief",
    ])
    lines.extend(render_context_brief_markdown_lines(context.get("context_brief")))
    lines.extend([
        "",
        "## Previous Chapter Tail",
        (context.get("previous_chapter") or {}).get("tail") or "No previous accepted chapter.",
        "",
        "## Required",
    ])
    lines.extend(f"- {item}" for item in context["rules"]["required_phrases"] or ["None"])
    lines.append("")
    lines.append("## Forbidden")
    lines.extend(f"- {item}" for item in context["rules"]["forbidden_phrases"] or ["None"])
    lines.append("")
    lines.append("## Future Markers To Avoid")
    lines.extend(f"- {item}" for item in context["rules"]["future_markers"] or ["None"])
    lines.append("")
    lines.append("## Characters")
    lines.append(json.dumps(context["characters"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Open Debts")
    lines.append(json.dumps(context["open_debts"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Facts")
    lines.append(json.dumps(context["facts"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Agent Capabilities")
    lines.append(json.dumps(context.get("agent_capabilities", []), ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Style Profile")
    lines.append(json.dumps(context.get("style_profile", {}), ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Sources")
    lines.append(json.dumps(context["sources"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Research")
    lines.append(json.dumps(context["research"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Resolved Conflicts")
    lines.append(json.dumps(context["resolved_conflicts"], ensure_ascii=False, indent=2))
    lines.append("")
    lines.append("## Handoff")
    lines.append(context.get("handoff") or "No handoff yet.")
    lines.append("")
    lines.append("## Style")
    lines.append(context.get("style") or "No style notes yet.")
    return "\n".join(lines) + "\n"


def render_handoff_markdown(suggestions: dict[str, Any]) -> str:
    handoff = suggestions["next_handoff"]
    lines = [
        "# Handoff",
        "",
        f"Updated: {now_iso()}",
        f"Source chapter: {suggestions['chapter']}",
        "",
        "## Previous Tail",
        handoff["previous_tail"],
        "",
        "## Continuity Focus",
    ]
    lines.extend(f"- {item}" for item in handoff["continuity_focus"] or ["No recorded focus."])
    lines.append("")
    lines.append("## Open Questions")
    lines.extend(f"- {item}" for item in handoff["open_questions"])
    return "\n".join(lines) + "\n"


def render_handoff_report_markdown(report: dict[str, Any]) -> str:
    project = report.get("project") if isinstance(report.get("project"), dict) else {}
    latest = report.get("latest_accepted_chapter") if isinstance(report.get("latest_accepted_chapter"), dict) else {}
    summary = report.get("chapter_context_summary") if isinstance(report.get("chapter_context_summary"), dict) else {}
    rules = report.get("visible_rules") if isinstance(report.get("visible_rules"), dict) else {}
    brief = report.get("next_agent_brief") if isinstance(report.get("next_agent_brief"), dict) else {}
    lines = [
        "# Long Novel Agent Handoff Report",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {project.get('title') or Path(str(report.get('project_dir'))).name}",
        f"Target chapter: {report.get('target_chapter')}",
        f"State dir: {report.get('state_dir')}",
        "",
        "## Latest Accepted Chapter",
        f"- Chapter: {latest.get('chapter') or 'None'}",
        f"- Title: {latest.get('title') or ''}",
        f"- Tail: {summary.get('previous_tail') or latest.get('tail') or 'No previous accepted chapter.'}",
        "",
        "## Handoff",
        str(report.get("handoff") or "No handoff yet."),
        "",
    ]
    if brief:
        lines.extend(
            [
                "## Next Agent Brief",
                f"- Status: {brief.get('status') or 'unknown'}",
                f"- Blockers: {len(brief.get('blockers') or [])}",
                f"- Review items: {len(brief.get('review_items') or [])}",
                f"- Warnings: {len(brief.get('warnings') or [])}",
                "",
                "### Copy Prompt",
                "```text",
                str(brief.get("copy_prompt") or "").strip(),
                "```",
                "",
                "### Must Read",
            ]
        )
        lines.extend(f"- `{item}`" for item in split_list(brief.get("must_read")) or ["None"])
        lines.append("")
        lines.append("### Startup Sequence")
        lines.extend(f"- {item}" for item in split_list(brief.get("startup_sequence")) or ["None"])
        lines.append("")
        lines.append("### Write Boundaries")
        lines.extend(f"- {item}" for item in split_list(brief.get("write_boundaries")) or ["None"])
        first_commands = brief.get("first_commands") if isinstance(brief.get("first_commands"), list) else []
        if first_commands:
            lines.append("")
            lines.append("### First Commands")
            for item in first_commands:
                if not isinstance(item, dict):
                    continue
                label = f"{item.get('key') or 'command'}"
                when = item.get("when")
                write_text = "writes state" if item.get("writes_project_state") else "read-only"
                lines.append(f"- `{label}` ({when or 'as needed'}, {write_text}): `{item.get('command') or ''}`")
        lines.append("")
    lines.extend(
        [
            "## Visible Rules",
            "- Required: " + ", ".join(split_list(rules.get("required_phrases")) or ["None"]),
            "- Forbidden: " + ", ".join(split_list(rules.get("forbidden_phrases")) or ["None"]),
            "- Future markers: " + ", ".join(split_list(rules.get("future_markers")) or ["None"]),
            "",
            "## Open Debts",
        ]
    )
    debts = report.get("open_debts") if isinstance(report.get("open_debts"), list) else []
    if debts:
        lines.extend(f"- {item.get('title') or item.get('debt_content') or item.get('id')}" for item in debts if isinstance(item, dict))
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Open Contracts")
    contracts = report.get("open_contracts") if isinstance(report.get("open_contracts"), list) else []
    if contracts:
        lines.extend(f"- {item.get('title') or item.get('objective') or item.get('id')}" for item in contracts if isinstance(item, dict))
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Pending Proposals")
    proposals = report.get("pending_proposals") if isinstance(report.get("pending_proposals"), list) else []
    if proposals:
        for proposal in proposals:
            if not isinstance(proposal, dict):
                continue
            risk = proposal.get("risk") if isinstance(proposal.get("risk"), dict) else {}
            lines.append(f"- {proposal.get('id')} chapter {proposal.get('chapter')} status={proposal.get('status')} risk={risk.get('level') or 'low'}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Recent Agent Activity")
    activity = report.get("recent_agent_activity") if isinstance(report.get("recent_agent_activity"), list) else []
    if activity:
        for row in activity:
            if not isinstance(row, dict):
                continue
            context = row.get("context") if isinstance(row.get("context"), dict) else {}
            files = row.get("files") if isinstance(row.get("files"), list) else []
            lines.append(
                f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | chapter {row.get('chapter') or 'none'} | {row.get('status')}"
            )
            if row.get("summary"):
                lines.append(f"  Summary: {row.get('summary')}")
            if context.get("hash") or context.get("source"):
                lines.append(f"  Context: {context.get('source') or ''} {context.get('hash') or ''}".rstrip())
            if files:
                lines.append(f"  Files: {', '.join(str(item) for item in files)}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Required Workflow")
    workflow = report.get("required_workflow") if isinstance(report.get("required_workflow"), list) else split_list(report.get("required_workflow"))
    lines.extend(f"- {item}" for item in workflow)
    lines.append("")
    lines.append("## Recommended Commands")
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else split_list(report.get("recommended_commands"))
    lines.extend(f"- `{item}`" for item in commands)
    return "\n".join(lines) + "\n"


def build_handoff_brief_packet(project_dir: str | Path, *, chapter_session: dict[str, Any], target: int) -> dict[str, Any]:
    report = chapter_session.get("handoff_report") if isinstance(chapter_session.get("handoff_report"), dict) else {}
    brief = report.get("next_agent_brief") if isinstance(report.get("next_agent_brief"), dict) else {}
    if not report:
        project = project_root(project_dir)
        brief = {
            "status": "pending",
            "blockers": ["Project state is not initialized, so no handoff report is available."],
            "review_items": [],
            "warnings": [],
            "copy_prompt": (
                f"You are taking over chapter {target}. Initialize or import the local project state first, "
                "then regenerate the desktop pack or call prepare_chapter_session."
            ),
            "must_read": [STARTER_BRIEF_JSON_FILE, "START_HERE.md", "project-wizard.json", DESKTOP_PACK_COMMANDS_INDEX_JSON_FILE, "commands.json", "author-review-queue.md", "chapter-session.md"],
            "startup_sequence": [
                "Initialize or import the project with quickstart or quickstart-from-wizard.",
                "Regenerate this desktop pack after .novel-agent state exists.",
                "Run prepare_session before drafting.",
            ],
            "write_boundaries": [
                "Do not draft from this pending packet.",
                "Do not write durable continuity state until the project is initialized and the author has confirmed writer actions.",
            ],
            "first_commands": [],
        }
        return {
            "type": "handoff_brief",
            "generated_at": now_iso(),
            "project_dir": str(project),
            "target_chapter": target,
            "status": "pending",
            "read_only": True,
            "handoff_report_available": False,
            "next_agent_brief": brief,
            "warnings": brief["blockers"],
        }
    pending_proposals = report.get("pending_proposals") if isinstance(report.get("pending_proposals"), list) else []
    high_risk_proposals = report.get("high_risk_proposals") if isinstance(report.get("high_risk_proposals"), list) else []
    return {
        "type": "handoff_brief",
        "generated_at": now_iso(),
        "project_dir": report.get("project_dir") or str(project_root(project_dir)),
        "state_dir": report.get("state_dir"),
        "target_chapter": report.get("target_chapter") or target,
        "status": brief.get("status") or "unknown",
        "read_only": True,
        "handoff_report_available": True,
        "project": report.get("project") if isinstance(report.get("project"), dict) else {},
        "latest_accepted_chapter": report.get("latest_accepted_chapter") if isinstance(report.get("latest_accepted_chapter"), dict) else {},
        "handoff": report.get("handoff") or "",
        "recent_agent_activity": report.get("recent_agent_activity") if isinstance(report.get("recent_agent_activity"), list) else [],
        "pending_proposals_count": len(pending_proposals),
        "high_risk_proposals_count": len(high_risk_proposals),
        "next_agent_brief": brief,
        "source": "handoff_report.next_agent_brief",
    }


def build_static_handoff_report_packet(project_dir: str | Path, *, chapter_session: dict[str, Any], target: int) -> dict[str, Any]:
    report = chapter_session.get("handoff_report") if isinstance(chapter_session.get("handoff_report"), dict) else {}
    if report:
        static_report = dict(report)
        static_report["read_only"] = True
        static_report.setdefault("source", "prepare_chapter_session.handoff_report")
        return static_report
    project = project_root(project_dir)
    return {
        "ok": False,
        "type": "handoff_report",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "state_dir": str(state_root(project)),
        "target_chapter": target,
        "status": "pending",
        "read_only": True,
        "source": "desktop_pack_pending_state",
        "warnings": ["Project state is not initialized, so no handoff report is available."],
        "next_actions": [
            "Run quickstart or quickstart-from-wizard before writing.",
            "After initialization, regenerate this pack or run prepare-session for the target chapter.",
        ],
        "recommended_commands": [
            f"python cli.py quickstart {project} --source auto --dry-run --format markdown",
            f"python cli.py init-wizard {project} --dry-run",
            f"python cli.py prepare-session {project} --chapter {target} --format markdown",
        ],
    }


def render_handoff_brief_markdown(packet: dict[str, Any]) -> str:
    brief = packet.get("next_agent_brief") if isinstance(packet.get("next_agent_brief"), dict) else {}
    project = packet.get("project") if isinstance(packet.get("project"), dict) else {}
    latest = packet.get("latest_accepted_chapter") if isinstance(packet.get("latest_accepted_chapter"), dict) else {}
    lines = [
        "# Long Novel Agent Handoff Brief",
        "",
        f"Generated: {packet.get('generated_at')}",
        f"Project: {project.get('title') or Path(str(packet.get('project_dir'))).name}",
        f"Target chapter: {packet.get('target_chapter')}",
        f"Status: {packet.get('status')}",
        f"Read-only: {packet.get('read_only')}",
        "",
        "## Copy Prompt",
        "```text",
        str(brief.get("copy_prompt") or "").strip(),
        "```",
        "",
        "## Latest Accepted Chapter",
        f"- Chapter: {latest.get('chapter') or 'None'}",
        f"- Title: {latest.get('title') or ''}",
        "",
        "## Handoff",
        str(packet.get("handoff") or "No handoff yet."),
        "",
        "## Must Read",
    ]
    lines.extend(f"- `{item}`" for item in split_list(brief.get("must_read")) or ["None"])
    lines.append("")
    lines.append("## Startup Sequence")
    lines.extend(f"- {item}" for item in split_list(brief.get("startup_sequence")) or ["None"])
    lines.append("")
    lines.append("## Write Boundaries")
    lines.extend(f"- {item}" for item in split_list(brief.get("write_boundaries")) or ["None"])
    blockers = split_list(brief.get("blockers"))
    review_items = split_list(brief.get("review_items"))
    warnings = split_list(brief.get("warnings"))
    if blockers or review_items or warnings:
        lines.append("")
        lines.append("## Attention")
        lines.extend(f"- Blocker: {item}" for item in blockers)
        lines.extend(f"- Review: {item}" for item in review_items)
        lines.extend(f"- Warning: {item}" for item in warnings)
    activity = packet.get("recent_agent_activity") if isinstance(packet.get("recent_agent_activity"), list) else []
    lines.append("")
    lines.append("## Recent Agent Activity")
    if activity:
        for row in activity[:5]:
            if not isinstance(row, dict):
                continue
            lines.append(f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | {row.get('status')}")
    else:
        lines.append("- None")
    first_commands = brief.get("first_commands") if isinstance(brief.get("first_commands"), list) else []
    lines.append("")
    lines.append("## First Commands")
    if first_commands:
        for item in first_commands:
            if not isinstance(item, dict):
                continue
            write_text = "writes state" if item.get("writes_project_state") else "read-only"
            lines.append(f"- `{item.get('key') or 'command'}` ({item.get('when') or 'as needed'}, {write_text}): `{item.get('command') or ''}`")
    else:
        lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def render_gaoxia_import_audit_markdown(report: dict[str, Any]) -> str:
    source_inventory = report.get("source_inventory") if isinstance(report.get("source_inventory"), dict) else {}
    source_counts = source_inventory.get("counts") if isinstance(source_inventory.get("counts"), dict) else {}
    imported_state = report.get("imported_state") if isinstance(report.get("imported_state"), dict) else {}
    imported_counts = imported_state.get("counts") if isinstance(imported_state.get("counts"), dict) else {}
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Gaoxia Import Audit",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"State: {report.get('state_dir')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Target chapter: {report.get('target_chapter') or 'None'}",
        "",
        "## Summary",
        f"- Must fix: {summary.get('must_fix', 0)}",
        f"- Review: {summary.get('review', 0)}",
        f"- Warnings: {summary.get('warnings', 0)}",
        f"- Imported chapters: {summary.get('imported_chapters', imported_counts.get('chapters', 0))} / {summary.get('expected_chapters', source_counts.get('chapters', 0))}",
        f"- Visible imported sources: {summary.get('visible_imported_sources', 0)}",
        f"- Visible imported facts: {summary.get('visible_imported_facts', 0)}",
        f"- Stale chapters: {summary.get('stale_chapters', 0)}",
        f"- Stale source files: {summary.get('stale_source_files', 0)}",
        f"- Stale payloads: {summary.get('stale_payloads', 0)}",
        f"- Missing source hashes: {summary.get('unknown_source_hashes', 0)}",
        "",
        "## Source Inventory",
    ]
    for key in (
        "architecture_sources",
        "chapters",
        "vault_notes",
        "project_memory_entries",
        "narrative_debts",
        "character_arcs",
        "chapter_contracts",
        "chapter_cards",
        "estimated_facts",
    ):
        lines.append(f"- {key}: {source_counts.get(key, 0)}")
    lines.extend(["", "## Imported State"])
    for key in (
        "architecture_sources",
        "chapters",
        "vault_notes",
        "project_memory_entries",
        "narrative_debts",
        "character_arcs",
        "chapter_contracts",
        "chapter_cards",
        "facts",
    ):
        lines.append(f"- {key}: {imported_counts.get(key, 0)}")
    lines.extend(["", "## Checks"])
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    if checks:
        for item in checks:
            if not isinstance(item, dict):
                continue
            marker = "pass" if item.get("ok") else str(item.get("severity") or "issue")
            lines.append(f"- [{marker}] {item.get('id')}: {item.get('message')}")
            detail = item.get("detail")
            if detail not in (None, "", [], {}):
                lines.append(f"  Detail: {json.dumps(detail, ensure_ascii=False)[:500]}")
    else:
        lines.append("- None")
    action_plan = report.get("action_plan") if isinstance(report.get("action_plan"), dict) else {}
    lines.extend(["", "## Action Plan"])
    for group, title in (("must_fix", "Must Fix"), ("review", "Review"), ("improve", "Improve")):
        lines.append(f"### {title}")
        rows = action_plan.get(group) if isinstance(action_plan.get(group), list) else []
        if not rows:
            lines.append("- None")
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            lines.append(f"- {row.get('title')}: {row.get('reason')}")
            if row.get("command"):
                lines.append(f"  Command: `{row.get('command')}`")
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines) + "\n"


def render_chapter_session_markdown(packet: dict[str, Any]) -> str:
    context = packet.get("chapter_context") if isinstance(packet.get("chapter_context"), dict) else {}
    if not context:
        context = packet.get("chapter_context_summary") if isinstance(packet.get("chapter_context_summary"), dict) else {}
    handoff = packet.get("handoff_report") if isinstance(packet.get("handoff_report"), dict) else {}
    health = packet.get("health") if isinstance(packet.get("health"), dict) else {}
    gates = packet.get("tool_gates") if isinstance(packet.get("tool_gates"), dict) else {}
    author_queue = packet.get("author_review_queue") if isinstance(packet.get("author_review_queue"), dict) else {}
    author_queue_summary = author_queue.get("summary") if isinstance(author_queue.get("summary"), dict) else {}
    rules = context.get("rules") if isinstance(context.get("rules"), dict) else {}
    context_budget = context.get("context_budget") if isinstance(context.get("context_budget"), dict) else {}
    context_brief = context.get("context_brief") if isinstance(context.get("context_brief"), dict) else {}
    latest = handoff.get("latest_accepted_chapter") if isinstance(handoff.get("latest_accepted_chapter"), dict) else {}
    activity = packet.get("recent_agent_activity") if isinstance(packet.get("recent_agent_activity"), list) else []
    before_draft = [str(item) for item in gates.get("before_draft", []) if str(item).strip()] if isinstance(gates.get("before_draft"), list) else split_list(gates.get("before_draft"))
    before_ready = [str(item) for item in gates.get("before_ready", []) if str(item).strip()] if isinstance(gates.get("before_ready"), list) else split_list(gates.get("before_ready"))
    after_revision = [str(item) for item in gates.get("after_revision", []) if str(item).strip()] if isinstance(gates.get("after_revision"), list) else split_list(gates.get("after_revision"))
    after_acceptance = [str(item) for item in gates.get("after_author_acceptance", []) if str(item).strip()] if isinstance(gates.get("after_author_acceptance"), list) else split_list(gates.get("after_author_acceptance"))
    handoff_tools = [str(item) for item in gates.get("handoff", []) if str(item).strip()] if isinstance(gates.get("handoff"), list) else split_list(gates.get("handoff"))
    identity = packet.get("project_identity") if isinstance(packet.get("project_identity"), dict) else {}
    state_fingerprint = packet.get("project_state_fingerprint") if isinstance(packet.get("project_state_fingerprint"), dict) else {}
    context_fingerprint = packet.get("chapter_context_fingerprint") if isinstance(packet.get("chapter_context_fingerprint"), dict) else {}
    lines = [
        "# Long Novel Agent Chapter Session",
        "",
        f"Generated: {packet.get('generated_at')}",
        f"Project: {Path(str(packet.get('project_dir'))).name}",
        f"Target chapter: {packet.get('target_chapter')}",
        f"Platform: {packet.get('platform')}",
        f"Mode: {packet.get('mode')}",
        f"Status: {packet.get('status')}",
        f"Project ID: `{identity.get('project_id') or state_fingerprint.get('project_id') or ''}`",
        f"State SHA256: `{state_fingerprint.get('sha256') or ''}`",
        f"Context SHA256: `{context_fingerprint.get('sha256') or ''}`",
        "",
        "## Warnings",
    ]
    warnings = packet.get("warnings") if isinstance(packet.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(["", "## Context Budget"])
    lines.extend(render_context_budget_markdown_lines(context_budget))
    lines.extend(["", "## Context Brief"])
    lines.extend(render_context_brief_markdown_lines(context_brief))
    lines.extend(
        [
            "",
            "## Author Review Queue",
            f"- Status: {author_queue.get('status') or 'unknown'}",
            f"- Total: {author_queue_summary.get('total', 0)}",
            f"- Blockers: {author_queue_summary.get('blockers', 0)}",
            f"- Review: {author_queue_summary.get('review', 0)}",
            f"- Warnings: {author_queue_summary.get('warnings', 0)}",
        ]
    )
    queue_items = author_queue.get("items") if isinstance(author_queue.get("items"), list) else []
    if queue_items:
        lines.append("- First items:")
        for item in queue_items[:5]:
            if not isinstance(item, dict):
                continue
            lines.append(f"  - [{item.get('priority')}] {item.get('category')}: {item.get('title')} - {item.get('message')}")
    queue_commands = author_queue.get("recommended_commands") if isinstance(author_queue.get("recommended_commands"), dict) else {}
    if queue_commands.get("rerun_author_review_queue"):
        lines.append(f"- Command: `{queue_commands.get('rerun_author_review_queue')}`")
    lines.extend(
        [
            "",
            "## Required Tool Gates",
            "### Before Draft",
        ]
    )
    lines.extend(f"- {item}" for item in before_draft or ["Use chapter_context."])
    lines.extend(
        [
            "",
            "### Before Ready",
        ]
    )
    lines.extend(f"- {item}" for item in before_ready or ["None"])
    lines.extend(
        [
            "",
            "### After Revision",
        ]
    )
    lines.extend(f"- {item}" for item in after_revision or ["None"])
    lines.extend(
        [
            "",
            "### After Author Acceptance",
        ]
    )
    lines.extend(f"- {item}" for item in after_acceptance or ["None"])
    lines.extend(
        [
            "",
            "### Handoff",
        ]
    )
    lines.extend(f"- {item}" for item in handoff_tools or ["None"])
    lines.extend(
        [
            "",
            "## Health",
            f"- OK: {health.get('ok')}",
            f"- Failed checks: {len(health.get('failed_checks') or [])}",
            "",
            "## Latest Accepted Chapter",
            f"- Chapter: {latest.get('chapter') or 'None'}",
            f"- Tail: {(context.get('previous_chapter') or {}).get('tail') if isinstance(context.get('previous_chapter'), dict) else context.get('previous_tail') or latest.get('tail') or 'No previous accepted chapter.'}",
            "",
            "## Recent Agent Activity",
        ]
    )
    if activity:
        for row in activity:
            if not isinstance(row, dict):
                continue
            row_context = row.get("context") if isinstance(row.get("context"), dict) else {}
            lines.append(
                f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | chapter {row.get('chapter') or 'none'} | {row.get('status')}"
            )
            if row.get("summary"):
                lines.append(f"  Summary: {row.get('summary')}")
            if row_context.get("hash") or row_context.get("source"):
                lines.append(f"  Context: {row_context.get('source') or ''} {row_context.get('hash') or ''}".rstrip())
    else:
        lines.append("- None")
    lines.extend(
        [
            "",
            "## Visible Rules",
            "- Required: " + ", ".join(split_list(rules.get("required_phrases") or context.get("required_phrases")) or ["None"]),
            "- Forbidden: " + ", ".join(split_list(rules.get("forbidden_phrases") or context.get("forbidden_phrases")) or ["None"]),
            "- Future markers: " + ", ".join(split_list(rules.get("future_markers") or context.get("future_markers")) or ["None"]),
            "",
            "## Open Work",
            f"- Debts: {len(context.get('open_debts') or []) if isinstance(context.get('open_debts'), list) else context.get('open_debts', 0)}",
            f"- Contracts: {len(context.get('contracts') or []) if isinstance(context.get('contracts'), list) else context.get('contracts', 0)}",
            f"- Pending proposals: {len(handoff.get('pending_proposals') or [])}",
            "",
            "## Recommended Commands",
        ]
    )
    commands = packet.get("recommended_commands") if isinstance(packet.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands)
    return "\n".join(lines) + "\n"


def build_pending_chapter_session_packet(
    project_dir: str | Path,
    *,
    chapter: int,
    platform: str,
    mode: str,
) -> dict[str, Any]:
    project = project_root(project_dir)
    state_fingerprint = build_project_state_fingerprint(project)
    return {
        "ok": False,
        "type": "chapter_session_pending",
        "generated_at": now_iso(),
        "project_dir": str(project),
        "state_dir": str(state_root(project)),
        "project_identity": state_fingerprint.get("project_identity") if isinstance(state_fingerprint.get("project_identity"), dict) else project_identity_payload(project, {}),
        "project_state_fingerprint": state_fingerprint,
        "chapter_context_fingerprint": {},
        "target_chapter": chapter,
        "platform": platform,
        "mode": mode,
        "status": "not_initialized",
        "warnings": ["missing .novel-agent state"],
        "next_actions": [
            "Run quickstart or quickstart-from-wizard before writing.",
            "After initialization, regenerate this pack or run prepare-session for the target chapter.",
        ],
        "recommended_commands": [
            f"python cli.py quickstart {project} --source auto --dry-run --format markdown",
            f"python cli.py init-wizard {project} --dry-run",
            f"python cli.py prepare-session {project} --chapter {chapter} --platform {platform} --mode {mode} --format markdown",
        ],
    }


def render_desktop_pack_chapter_session(packet: dict[str, Any]) -> str:
    if packet.get("type") == "chapter_session_packet":
        return render_chapter_session_markdown(packet)
    lines = [
        "# Long Novel Agent Chapter Session",
        "",
        f"Generated: {packet.get('generated_at')}",
        f"Project: {Path(str(packet.get('project_dir'))).name}",
        f"Target chapter: {packet.get('target_chapter')}",
        f"Platform: {packet.get('platform')}",
        f"Mode: {packet.get('mode')}",
        f"Status: {packet.get('status')}",
        "",
        "## Warnings",
    ]
    warnings = packet.get("warnings") if isinstance(packet.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(["", "## Next Actions"])
    actions = packet.get("next_actions") if isinstance(packet.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in actions or ["Initialize the project before writing."])
    lines.extend(["", "## Recommended Commands"])
    commands = packet.get("recommended_commands") if isinstance(packet.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines) + "\n"


def render_project_status_markdown(status: dict[str, Any]) -> str:
    manifest = status.get("manifest") if isinstance(status.get("manifest"), dict) else {}
    latest = status.get("latest_accepted_chapter") if isinstance(status.get("latest_accepted_chapter"), dict) else {}
    counts = status.get("counts") if isinstance(status.get("counts"), dict) else {}
    desktop = status.get("latest_desktop_verification") if isinstance(status.get("latest_desktop_verification"), dict) else {}
    activity = status.get("latest_agent_activity") if isinstance(status.get("latest_agent_activity"), dict) else {}
    verification = status.get("verification_status") if isinstance(status.get("verification_status"), dict) else {}
    real_client = verification.get("real_desktop_client") if isinstance(verification.get("real_desktop_client"), dict) else {}
    local_config = verification.get("local_mcp_config") if isinstance(verification.get("local_mcp_config"), dict) else {}
    author_queue = status.get("author_review_queue") if isinstance(status.get("author_review_queue"), dict) else {}
    author_queue_summary = author_queue.get("summary") if isinstance(author_queue.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Project Status",
        "",
        f"Generated: {status.get('generated_at')}",
        f"Project: {manifest.get('title') or Path(str(status.get('project_dir'))).name}",
        f"Readiness: {status.get('readiness')}",
        f"Target chapter: {status.get('target_chapter')}",
        f"State dir: {status.get('state_dir')}",
        "",
        "## Blockers",
    ]
    blockers = status.get("blockers") if isinstance(status.get("blockers"), list) else []
    lines.extend(f"- {item}" for item in blockers or ["None"])
    lines.append("")
    lines.append("## Warnings")
    warnings = status.get("warnings") if isinstance(status.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(
        [
            "",
            "## Author Review Queue",
            f"- Status: {author_queue.get('status') or 'unknown'}",
            f"- Total: {author_queue_summary.get('total', 0)}",
            f"- Blockers: {author_queue_summary.get('blockers', 0)}",
            f"- Review: {author_queue_summary.get('review', 0)}",
            f"- Warnings: {author_queue_summary.get('warnings', 0)}",
        ]
    )
    top_items = author_queue.get("top_items") if isinstance(author_queue.get("top_items"), list) else []
    if top_items:
        lines.append("- Top items:")
        for item in top_items:
            if not isinstance(item, dict):
                continue
            lines.append(f"  - [{item.get('priority')}] {item.get('category')}: {item.get('title')} - {item.get('message')}")
    if author_queue.get("recommended_command"):
        lines.append(f"- Command: `{author_queue.get('recommended_command')}`")
    lines.extend(
        [
            "",
            "## Counts",
            f"- Chapters: {counts.get('chapters', 0)}",
            f"- Facts: {counts.get('facts', 0)}",
            f"- Sources: {counts.get('sources', 0)}",
            f"- Research notes: {counts.get('research', 0)}",
            f"- Pending proposals: {counts.get('pending_proposals', 0)}",
            f"- High-risk proposals: {counts.get('high_risk_proposals', 0)}",
            f"- Agent declarations: {counts.get('agents', 0)}",
            f"- Desktop verifications: {counts.get('desktop_verifications', 0)}",
            f"- Agent activity: {counts.get('agent_activity', 0)}",
            "",
            "## Latest Accepted Chapter",
            f"- Chapter: {latest.get('chapter') or 'None'}",
            f"- Title: {latest.get('title') or ''}",
            f"- Has handoff: {latest.get('has_handoff')}",
            "",
            "## Verification Evidence",
            f"- Local MCP config check: {local_config.get('status') or 'not_checked'}; real client evidence: {local_config.get('is_real_client_evidence')}",
            f"- Local MCP config note: {local_config.get('message') or ''}",
            f"- Real desktop client check: {real_client.get('status') or 'missing'}; real client evidence: {real_client.get('is_real_client_evidence')}",
            f"- Real desktop client note: {real_client.get('message') or ''}",
        ]
    )
    real_issue_summary = real_client.get("issue_summary") if isinstance(real_client.get("issue_summary"), list) else []
    if real_issue_summary:
        lines.append("- Real desktop client issues:")
        for issue in real_issue_summary[:8]:
            if not isinstance(issue, dict):
                continue
            check_label = issue.get("check_id") or "unknown_check"
            lines.append(f"  - {check_label}: {issue.get('message') or issue.get('type') or ''}")
    matrix = status.get("desktop_verification_matrix") if isinstance(status.get("desktop_verification_matrix"), dict) else {}
    matrix_totals = matrix.get("totals") if isinstance(matrix.get("totals"), dict) else {}
    matrix_cells = matrix.get("matrix") if isinstance(matrix.get("matrix"), list) else []
    lines.extend(
        [
            "",
            "## Desktop Verification Matrix",
            f"- Passed: {matrix_totals.get('passed', 0)}",
            f"- Failed: {matrix_totals.get('failed', 0)}",
            f"- Missing: {matrix_totals.get('missing', 0)}",
        ]
    )
    if matrix_cells:
        for cell in matrix_cells[:8]:
            if not isinstance(cell, dict):
                continue
            issues = cell.get("issue_summary") if isinstance(cell.get("issue_summary"), list) else []
            issue_note = ""
            if issues:
                first = issues[0] if isinstance(issues[0], dict) else {}
                issue_note = f"; issue: {first.get('message') or first.get('type') or ''}"
            lines.append(
                f"- {cell.get('platform')} / {cell.get('mode')}: {cell.get('status')} "
                f"(chapter {cell.get('target_chapter') or 'all'}, record {cell.get('record_id') or 'none'}){issue_note}"
            )
    else:
        lines.append("- None")
    lines.extend(["", "## Latest Desktop Verification"])
    if desktop:
        lines.extend(
            [
                f"- ID: {desktop.get('id')}",
                f"- Platform: {desktop.get('platform')}",
                f"- Mode: {desktop.get('mode')}",
                f"- OK: {desktop.get('ok')}",
                f"- Created: {desktop.get('created_at')}",
            ]
        )
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Latest Agent Activity")
    if activity:
        context = activity.get("context") if isinstance(activity.get("context"), dict) else {}
        lines.extend(
            [
                f"- ID: {activity.get('id')}",
                f"- Agent: {activity.get('agent_id')}",
                f"- Platform: {activity.get('platform')}",
                f"- Action: {activity.get('action')}",
                f"- Chapter: {activity.get('chapter') or 'None'}",
                f"- Status: {activity.get('status')}",
                f"- Context hash: {context.get('hash') or ''}",
                f"- Summary: {activity.get('summary') or ''}",
            ]
        )
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Next Actions")
    next_actions = status.get("next_actions") if isinstance(status.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    lines.append("")
    lines.append("## Recommended Commands")
    commands = status.get("recommended_commands") if isinstance(status.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines) + "\n"


def render_desktop_next_step_markdown(report: dict[str, Any]) -> str:
    primary = report.get("primary_action") if isinstance(report.get("primary_action"), dict) else {}
    verification = report.get("verification_status") if isinstance(report.get("verification_status"), dict) else {}
    local_status = verification.get("local_mcp_config") if isinstance(verification.get("local_mcp_config"), dict) else {}
    real_status = verification.get("real_desktop_client") if isinstance(verification.get("real_desktop_client"), dict) else {}
    selected_status = verification.get("selected_platform_mode") if isinstance(verification.get("selected_platform_mode"), dict) else {}
    project_state = report.get("project_status") if isinstance(report.get("project_status"), dict) else {}
    author_queue = report.get("author_review_queue") if isinstance(report.get("author_review_queue"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Next Step",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Project: {report.get('project_dir')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"MCP tool profile: {report.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        "",
        "## Write Boundaries",
        f"- Writes project state: {report.get('would_write_project_state')}",
        f"- Writes install config: {report.get('would_write_install_config')}",
        f"- Writes pack files: {report.get('would_write_pack_files')}",
        f"- Records real client evidence: {report.get('records_real_client_evidence')}",
        "",
        "## Primary Action",
        f"- ID: {primary.get('id') or 'None'}",
        f"- Title: {primary.get('title') or 'None'}",
        f"- Reason: {primary.get('reason') or 'None'}",
        f"- File: `{primary.get('file') or 'None'}`",
        f"- Command: `{primary.get('command') or 'None'}`",
        f"- Writes project state: {primary.get('writes_project_state')}",
        f"- Writes install config: {primary.get('writes_install_config')}",
        f"- Requires author confirmation: {primary.get('requires_author_confirmation')}",
        "",
        "## Action Queue",
    ]
    actions = report.get("actions") if isinstance(report.get("actions"), list) else []
    if actions:
        for action in actions:
            if not isinstance(action, dict):
                continue
            lines.append(f"- {action.get('id')}: {action.get('title')} - {action.get('reason')}")
            if action.get("command"):
                lines.append(f"  Command: `{action.get('command')}`")
    else:
        lines.append("- None")
    lines.extend(
        [
            "",
            "## Status Summary",
            f"- Project readiness: {project_state.get('readiness') or 'unknown'}",
            f"- State initialized: {report.get('state_initialized')}",
            f"- Local MCP config: {local_status.get('status') or 'not_checked'}",
            f"- Real desktop client: {real_status.get('status') or 'missing'}",
            f"- Selected platform/mode evidence: {selected_status.get('status') or 'missing'}",
            f"- Author review queue: {author_queue.get('status') or 'unknown'}",
            "",
            "## Blockers",
        ]
    )
    blockers = project_state.get("blockers") if isinstance(project_state.get("blockers"), list) else []
    lines.extend(f"- {item}" for item in blockers or ["None"])
    lines.append("")
    lines.append("## Warnings")
    warnings = project_state.get("warnings") if isinstance(project_state.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    setup_verification = report.get("setup_verification") if isinstance(report.get("setup_verification"), dict) else {}
    setup_actions = setup_verification.get("recommended_actions") if isinstance(setup_verification.get("recommended_actions"), list) else []
    if setup_actions:
        lines.extend(["", "## Setup Actions"])
        lines.extend(f"- `{item}`" for item in setup_actions)
    session = report.get("chapter_session") if isinstance(report.get("chapter_session"), dict) else {}
    if session:
        lines.extend(["", "## Chapter Session"])
        if session.get("error"):
            lines.append(f"- Error: {session.get('error')}")
        else:
            lines.extend(
                [
                    f"- Type: {session.get('type')}",
                    f"- Status: {session.get('status')}",
                    f"- Target chapter: {session.get('target_chapter')}",
                ]
            )
            session_warnings = session.get("warnings") if isinstance(session.get("warnings"), list) else []
            if session_warnings:
                lines.append("- Warnings:")
                lines.extend(f"  - {item}" for item in session_warnings[:8])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands if str(item).strip())
    if not commands:
        lines.append("- None")
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(["", "## Notes"])
    lines.extend(f"- {item}" for item in notes or ["None"])
    return "\n".join(lines).rstrip() + "\n"


