def render_continuity_audit_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Continuity Audit",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        "",
        "## Summary",
        f"- Latest recorded chapter: {summary.get('latest_recorded_chapter', 0)}",
        f"- Recorded chapters: {summary.get('recorded_chapters', 0)}",
        f"- Missing chapters: {summary.get('missing_chapters', 0)}",
        f"- Duplicate chapters: {summary.get('duplicate_chapters', 0)}",
        f"- Active facts: {summary.get('active_facts', 0)}",
        f"- Facts without evidence: {summary.get('facts_without_evidence', 0)}",
        f"- Facts without chapter bounds: {summary.get('facts_without_chapter_bounds', 0)}",
        f"- Pending proposals: {summary.get('pending_proposals', 0)}",
        f"- High-risk proposals: {summary.get('high_risk_proposals', 0)}",
        f"- Visible sources: {summary.get('visible_sources', 0)}",
        f"- Visible research: {summary.get('visible_research', 0)}",
        f"- Open debts: {summary.get('open_debts', 0)}",
        f"- Contracts: {summary.get('contracts', 0)}",
        "",
        "## Action Plan",
    ]
    action_plan = report.get("action_plan") if isinstance(report.get("action_plan"), dict) else {}
    action_labels = [
        ("must_fix", "Must Fix"),
        ("review", "Review"),
        ("improve", "Improve"),
    ]
    for key, label in action_labels:
        lines.append(f"### {label}")
        actions = action_plan.get(key) if isinstance(action_plan.get(key), list) else []
        if actions:
            for action in actions:
                if not isinstance(action, dict):
                    continue
                title = action.get("title") or action.get("id") or "Action"
                reason = action.get("reason") or ""
                lines.append(f"- {title}: {reason}")
                command = str(action.get("command") or "").strip()
                if command:
                    lines.append(f"  Command: `{command}`")
        else:
            lines.append("- None")
        lines.append("")
    lines.extend(
        [
        "## Blockers",
        ]
    )
    blockers = report.get("blockers") if isinstance(report.get("blockers"), list) else []
    lines.extend(f"- {item}" for item in blockers or ["None"])
    lines.append("")
    lines.append("## Review Items")
    review_items = report.get("review_items") if isinstance(report.get("review_items"), list) else []
    lines.extend(f"- {item}" for item in review_items or ["None"])
    lines.append("")
    lines.append("## Warnings")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(["", "## Checks"])
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    for item in checks:
        if not isinstance(item, dict):
            continue
        mark = "pass" if item.get("ok") else str(item.get("severity") or "check")
        lines.append(f"- {item.get('id')}: {mark} - {item.get('message')}")
    if not checks:
        lines.append("- None")
    pending = report.get("pending_proposals") if isinstance(report.get("pending_proposals"), list) else []
    lines.extend(["", "## Pending Proposals"])
    if pending:
        for item in pending:
            if not isinstance(item, dict):
                continue
            lines.append(
                f"- {item.get('id')} chapter {item.get('chapter')}: status={item.get('status')}, "
                f"risk={item.get('risk_level')}, validation={item.get('validation_status')}, "
                f"errors={item.get('errors', 0)}, warnings={item.get('warnings', 0)}"
            )
    else:
        lines.append("- None")
    sequence = report.get("chapter_sequence") if isinstance(report.get("chapter_sequence"), dict) else {}
    missing = sequence.get("missing") if isinstance(sequence.get("missing"), list) else []
    duplicates = sequence.get("duplicates") if isinstance(sequence.get("duplicates"), list) else []
    lines.extend(
        [
            "",
            "## Chapter Sequence",
            "- Missing: " + (", ".join(str(item) for item in missing) if missing else "None"),
            "- Duplicates: " + (", ".join(str(item) for item in duplicates) if duplicates else "None"),
            "",
            "## Recommended Commands",
        ]
    )
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_verification_matrix_markdown(report: dict[str, Any]) -> str:
    totals = report.get("totals") if isinstance(report.get("totals"), dict) else {}
    filters = report.get("filters") if isinstance(report.get("filters"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Verification Matrix",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Chapter filter: {filters.get('chapter') or 'All'}",
        f"OK: {report.get('ok')}",
        "",
        "## Totals",
        f"- Records considered: {totals.get('records_considered', 0)}",
        f"- Cells: {totals.get('cells', 0)}",
        f"- Passed: {totals.get('passed', 0)}",
        f"- Failed: {totals.get('failed', 0)}",
        f"- Missing: {totals.get('missing', 0)}",
        f"- Required checks passed: {totals.get('required_checks_passed', 0)} / {totals.get('required_checks_total', 0)}",
        f"- Cells with gaps: {totals.get('cells_with_gaps', 0)}",
        f"- Missing required checks: {totals.get('missing_required_checks', 0)}",
        f"- Failed required checks: {totals.get('failed_required_checks', 0)}",
        f"- Weak evidence checks: {totals.get('weak_evidence_checks', 0)}",
        f"- Needs specific evidence checks: {totals.get('needs_specific_evidence_checks', 0)}",
        "",
        "## Matrix",
        "| Platform | Mode | Status | Required | Gaps | Chapter | Client | Issues |",
        "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ]
    cells = report.get("matrix") if isinstance(report.get("matrix"), list) else []
    for cell in cells:
        if not isinstance(cell, dict):
            continue
        client_bits = [str(cell.get("agent_id") or "").strip(), str(cell.get("client_version") or "").strip()]
        client = " / ".join([item for item in client_bits if item]) or "None"
        issues = cell.get("issue_summary") if isinstance(cell.get("issue_summary"), list) else []
        issue_text = "None"
        if issues:
            first = issues[0] if isinstance(issues[0], dict) else {}
            issue_text = str(first.get("message") or first.get("type") or "issue")
            if len(issues) > 1:
                issue_text += f" (+{len(issues) - 1})"
        coverage = cell.get("coverage") if isinstance(cell.get("coverage"), dict) else {}
        required_total = int(coverage.get("required_total") or cell.get("required_total") or 0)
        required_passed = int(coverage.get("required_passed_with_evidence") or cell.get("required_passed_with_evidence") or 0)
        gap_parts: list[str] = []
        missing = len(coverage.get("missing_required_check_ids") or [])
        failed = len(coverage.get("failed_required_check_ids") or [])
        missing_evidence = len(coverage.get("missing_evidence_check_ids") or [])
        weak = len(coverage.get("weak_evidence_check_ids") or [])
        specific = len(coverage.get("needs_specific_evidence_check_ids") or [])
        if missing:
            gap_parts.append(f"missing {missing}")
        if failed:
            gap_parts.append(f"failed {failed}")
        if missing_evidence:
            gap_parts.append(f"no evidence {missing_evidence}")
        if weak:
            gap_parts.append(f"weak {weak}")
        if specific:
            gap_parts.append(f"specific {specific}")
        gap_text = ", ".join(gap_parts) if gap_parts else "None"
        lines.append(
            f"| {cell.get('platform')} | {cell.get('mode')} | {cell.get('status')} | {required_passed}/{required_total} | {gap_text} | {cell.get('target_chapter') or 'All'} | {client} | {issue_text} |"
        )
    lines.extend(["", "## Warnings"])
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(["", "## Recommended Actions"])
    actions = report.get("recommended_actions") if isinstance(report.get("recommended_actions"), list) else []
    lines.extend(f"- `{item}`" if str(item).startswith("python ") else f"- {item}" for item in actions or ["None"])
    return "\n".join(lines) + "\n"


def render_agent_activity_markdown(payload: dict[str, Any]) -> str:
    filters = payload.get("filters") if isinstance(payload.get("filters"), dict) else {}
    records = payload.get("records") if isinstance(payload.get("records"), list) else []
    lines = [
        "# Long Novel Agent Activity",
        "",
        f"Agent filter: {filters.get('agent_id') or 'all'}",
        f"Chapter filter: {filters.get('chapter') or 'all'}",
        f"Action filter: {filters.get('action') or 'all'}",
        f"Records: {len(records)}",
        "",
        "## Activity",
    ]
    if not records:
        lines.append("- None")
    for row in records:
        if not isinstance(row, dict):
            continue
        context = row.get("context") if isinstance(row.get("context"), dict) else {}
        files = row.get("files") if isinstance(row.get("files"), list) else []
        lines.extend(
            [
                f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | chapter {row.get('chapter') or 'none'} | {row.get('status')}",
                f"  Summary: {row.get('summary') or ''}",
                f"  Context: {context.get('source') or ''} {context.get('hash') or ''}".rstrip(),
                f"  Files: {', '.join(str(item) for item in files) if files else 'None'}",
            ]
        )
    return "\n".join(lines).rstrip() + "\n"


def render_agent_activity_report_markdown(report: dict[str, Any]) -> str:
    filters = report.get("filters") if isinstance(report.get("filters"), dict) else {}
    records = report.get("records") if isinstance(report.get("records"), list) else []
    issues = report.get("record_issues") if isinstance(report.get("record_issues"), list) else []
    action_counts = report.get("action_counts") if isinstance(report.get("action_counts"), dict) else {}
    handoff_quality = report.get("handoff_quality") if isinstance(report.get("handoff_quality"), dict) else {}
    quality_deductions = handoff_quality.get("deductions") if isinstance(handoff_quality.get("deductions"), list) else []
    lines = [
        "# Long Novel Agent Activity Report",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Agent filter: {filters.get('agent_id') or 'all'}",
        f"Chapter filter: {filters.get('chapter') or 'all'}",
        f"Records: {len(records)}",
        "",
        "## Action Counts",
    ]
    if action_counts:
        lines.extend(f"- {key}: {value}" for key, value in sorted(action_counts.items()))
    else:
        lines.append("- None")
    lines.extend(
        [
            "",
            "## Handoff Quality",
            f"- Score: {handoff_quality.get('score', report.get('quality_score', 0))}",
            f"- Rating: {handoff_quality.get('rating') or 'unknown'}",
            f"- Deduction total: {handoff_quality.get('deduction_total', 0)}",
        ]
    )
    if quality_deductions:
        lines.append("- Deductions:")
        for item in quality_deductions:
            if not isinstance(item, dict):
                continue
            lines.append(f"  - -{item.get('points', 0)} {item.get('reason')}: {item.get('message')}")
    else:
        lines.append("- Deductions: None")
    for title, key in [("Blockers", "blockers"), ("Review Items", "review_items"), ("Warnings", "warnings")]:
        values = report.get(key) if isinstance(report.get(key), list) else []
        lines.extend(["", f"## {title}"])
        lines.extend(f"- {item}" for item in values or ["None"])
    lines.extend(["", "## Record Issues"])
    if issues:
        for item in issues:
            if not isinstance(item, dict):
                continue
            lines.append(f"- {item.get('severity')} | {item.get('type')} | {item.get('record_id') or 'unknown'}: {item.get('message')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Recent Records"])
    if records:
        for row in records:
            if not isinstance(row, dict):
                continue
            context = row.get("context") if isinstance(row.get("context"), dict) else {}
            files = row.get("files") if isinstance(row.get("files"), list) else []
            lines.append(
                f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | chapter {row.get('chapter') or 'none'} | {row.get('status')}"
            )
            if row.get("summary"):
                lines.append(f"  Summary: {row.get('summary')}")
            if context.get("source") or context.get("hash") or context.get("file"):
                context_bits = [str(context.get("source") or "").strip(), str(context.get("file") or "").strip(), str(context.get("hash") or "").strip()]
                lines.append("  Context: " + " ".join(item for item in context_bits if item))
            if files:
                lines.append(f"  Files: {', '.join(str(item) for item in files)}")
    else:
        lines.append("- None")
    lines.extend(["", "## Next Actions"])
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_handoff_integrity_markdown(report: dict[str, Any]) -> str:
    context = report.get("current_context") if isinstance(report.get("current_context"), dict) else {}
    summary = context.get("summary") if isinstance(context.get("summary"), dict) else {}
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    reference_issues = report.get("reference_issues") if isinstance(report.get("reference_issues"), list) else []
    lines = [
        "# Long Novel Agent Handoff Integrity",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Read-only: {report.get('read_only')}",
        "",
        "## Current Context",
        f"- Fingerprint: `{context.get('fingerprint') or ''}`",
        f"- Expected hash: `{report.get('expected_context_hash') or ''}`",
        f"- Characters: {summary.get('characters', 0)}",
        f"- Facts: {summary.get('facts', 0)}",
        f"- Sources: {summary.get('sources', 0)}",
        f"- Research: {summary.get('research', 0)}",
        f"- Contracts: {summary.get('contracts', 0)}",
        f"- Open debts: {summary.get('open_debts', 0)}",
    ]
    activity_hashes = report.get("activity_context_hashes") if isinstance(report.get("activity_context_hashes"), list) else []
    lines.extend(["", "## Activity Context Hashes"])
    lines.extend(f"- `{item}`" for item in activity_hashes or ["None"])
    for title, key in [("Blockers", "blockers"), ("Review Items", "review_items"), ("Warnings", "warnings")]:
        values = report.get(key) if isinstance(report.get(key), list) else []
        lines.extend(["", f"## {title}"])
        lines.extend(f"- {item}" for item in values or ["None"])
    lines.extend(["", "## Checks"])
    if checks:
        for item in checks:
            if not isinstance(item, dict):
                continue
            mark = "pass" if item.get("ok") else str(item.get("severity") or "check")
            lines.append(f"- {item.get('id')}: {mark} - {item.get('message')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Reference Issues"])
    if reference_issues:
        for item in reference_issues:
            if not isinstance(item, dict):
                continue
            path = str(item.get("path") or "").strip()
            path_suffix = f" ({path})" if path else ""
            lines.append(f"- {item.get('severity')} | {item.get('type')} | {item.get('record_id') or 'unknown'}{path_suffix}: {item.get('message')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Next Actions"])
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_handoff_range_report_markdown(report: dict[str, Any]) -> str:
    range_info = report.get("range") if isinstance(report.get("range"), dict) else {}
    range_report = report.get("chapter_range_readiness") if isinstance(report.get("chapter_range_readiness"), dict) else {}
    range_summary = range_report.get("summary") if isinstance(range_report.get("summary"), dict) else {}
    integrity = report.get("handoff_integrity") if isinstance(report.get("handoff_integrity"), dict) else {}
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    pending = report.get("pending_range_proposals") if isinstance(report.get("pending_range_proposals"), list) else []
    lines = [
        "# Long Novel Agent Handoff Range Report",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Range: {range_info.get('start')} - {range_info.get('end')}",
        f"Handoff chapter: {report.get('handoff_chapter')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Read-only: {report.get('read_only')}",
        "",
        "## Chapter Range",
        f"- Status: {range_report.get('status')}",
        f"- Ready to present: {range_report.get('ready_to_present')}",
        f"- Score: {range_report.get('score')}",
        f"- Average score: {range_report.get('average_score')}",
        f"- Chapters: {range_summary.get('chapters', 0)}",
        f"- Problem chapters: {', '.join(str(item) for item in range_summary.get('problem_chapters', []) or []) or 'None'}",
        "",
        "## Handoff Integrity",
        f"- Status: {integrity.get('status')}",
        f"- Target chapter: {integrity.get('target_chapter')}",
        f"- Context fingerprint: `{((integrity.get('current_context') or {}).get('fingerprint') if isinstance(integrity.get('current_context'), dict) else '') or ''}`",
        f"- Blockers: {len(integrity.get('blockers') if isinstance(integrity.get('blockers'), list) else [])}",
        f"- Review items: {len(integrity.get('review_items') if isinstance(integrity.get('review_items'), list) else [])}",
        f"- Warnings: {len(integrity.get('warnings') if isinstance(integrity.get('warnings'), list) else [])}",
        "",
        "## Range Proposals",
        f"- Pending: {report.get('pending_range_proposals_count', 0)}",
        f"- High risk: {report.get('high_risk_range_proposals_count', 0)}",
    ]
    if pending:
        for item in pending[:10]:
            if not isinstance(item, dict):
                continue
            risk = item.get("risk") if isinstance(item.get("risk"), dict) else {}
            lines.append(f"- {item.get('id') or 'proposal'} | chapter {item.get('chapter')} | {item.get('status') or 'proposed'} | risk {risk.get('level') or 'unknown'}")
    for title, key in [("Blockers", "blockers"), ("Review Items", "review_items"), ("Warnings", "warnings")]:
        values = report.get(key) if isinstance(report.get(key), list) else []
        lines.extend(["", f"## {title}"])
        lines.extend(f"- {item}" for item in values or ["None"])
    lines.extend(["", "## Checks"])
    if checks:
        for item in checks:
            if not isinstance(item, dict):
                continue
            mark = "pass" if item.get("ok") else str(item.get("severity") or "check")
            lines.append(f"- {item.get('id')}: {mark} - {item.get('message')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Next Actions"])
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def render_handoff_readiness_markdown(report: dict[str, Any]) -> str:
    incoming = report.get("incoming_agent") if isinstance(report.get("incoming_agent"), dict) else {}
    outgoing = report.get("outgoing_agent") if isinstance(report.get("outgoing_agent"), dict) else {}
    activity = report.get("recent_agent_activity") if isinstance(report.get("recent_agent_activity"), list) else []
    desktop = report.get("latest_desktop_verification") if isinstance(report.get("latest_desktop_verification"), dict) else {}
    verification = report.get("verification_status") if isinstance(report.get("verification_status"), dict) else {}
    real_client = verification.get("real_desktop_client") if isinstance(verification.get("real_desktop_client"), dict) else {}
    local_config = verification.get("local_mcp_config") if isinstance(verification.get("local_mcp_config"), dict) else {}
    lines = [
        "# Long Novel Agent Handoff Readiness",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {Path(str(report.get('project_dir'))).name}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Mode: {report.get('mode')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        "",
        "## Incoming Agent",
        f"- ID: {incoming.get('id') or 'None'}",
        f"- Platform: {incoming.get('platform') or 'None'}",
        "- Capabilities: " + ", ".join(split_list(incoming.get("capabilities")) or ["None"]),
        "- Missing required: " + ", ".join(split_list(report.get("missing_capabilities")) or ["None"]),
        "",
        "## Outgoing Agent",
        f"- ID: {outgoing.get('id') or 'None'}",
        f"- Platform: {outgoing.get('platform') or 'None'}",
        "",
        "## Recent Agent Activity",
    ]
    if activity:
        for row in activity:
            if not isinstance(row, dict):
                continue
            row_context = row.get("context") if isinstance(row.get("context"), dict) else {}
            files = row.get("files") if isinstance(row.get("files"), list) else []
            lines.append(
                f"- {row.get('created_at')} | {row.get('agent_id')} | {row.get('action')} | chapter {row.get('chapter') or 'none'} | {row.get('status')}"
            )
            if row.get("summary"):
                lines.append(f"  Summary: {row.get('summary')}")
            if row_context.get("hash") or row_context.get("source"):
                lines.append(f"  Context: {row_context.get('source') or ''} {row_context.get('hash') or ''}".rstrip())
            if files:
                lines.append(f"  Files: {', '.join(str(item) for item in files)}")
    else:
        lines.append("- None")
    lines.extend(
        [
            "",
            "## Verification Evidence",
            f"- Local MCP config check: {local_config.get('status') or 'not_checked'}; real client evidence: {local_config.get('is_real_client_evidence')}",
            f"- Local MCP config note: {local_config.get('message') or ''}",
            f"- Real desktop client check: {real_client.get('status') or 'missing'}; real client evidence: {real_client.get('is_real_client_evidence')}",
            f"- Real desktop client note: {real_client.get('message') or ''}",
        ]
    )
    real_issue_summary = real_client.get("issue_summary") if isinstance(real_client.get("issue_summary"), list) else []
    if real_issue_summary:
        lines.append("- Real desktop client issues:")
        for issue in real_issue_summary[:8]:
            if not isinstance(issue, dict):
                continue
            check_label = issue.get("check_id") or "unknown_check"
            lines.append(f"  - {check_label}: {issue.get('message') or issue.get('type') or ''}")
    lines.extend(["", "## Latest Desktop Verification"])
    if desktop:
        lines.extend(
            [
                f"- ID: {desktop.get('id')}",
                f"- Platform: {desktop.get('platform')}",
                f"- Mode: {desktop.get('mode')}",
                f"- OK: {desktop.get('ok')}",
                f"- Created: {desktop.get('created_at')}",
            ]
        )
    else:
        lines.append("- None")
    lines.extend(["", "## Checks"])
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    for item in checks:
        if not isinstance(item, dict):
            continue
        mark = "PASS" if item.get("ok") else "FAIL"
        lines.append(f"- {mark} [{item.get('severity')}] {item.get('id')}: {item.get('message')}")
    lines.append("")
    lines.append("## Blockers")
    blockers = report.get("blockers") if isinstance(report.get("blockers"), list) else []
    lines.extend(f"- {item}" for item in blockers or ["None"])
    lines.append("")
    lines.append("## Review Items")
    review_items = report.get("review_items") if isinstance(report.get("review_items"), list) else []
    lines.extend(f"- {item}" for item in review_items or ["None"])
    lines.append("")
    lines.append("## Warnings")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.append("")
    lines.append("## Next Actions")
    next_actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in next_actions or ["None"])
    lines.append("")
    lines.append("## Recommended Commands")
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines) + "\n"


def render_quickstart_markdown(report: dict[str, Any]) -> str:
    session = report.get("chapter_session") if isinstance(report.get("chapter_session"), dict) else {}
    doctor_result = report.get("doctor") if isinstance(report.get("doctor"), dict) else {}
    plan = report.get("plan") if isinstance(report.get("plan"), dict) else {}
    lines = [
        "# Long Novel Agent Quickstart",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {Path(str(report.get('project_dir'))).name}",
        f"State dir: {report.get('state_dir')}",
        f"Source: {report.get('selected_source')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"Dry run: {report.get('dry_run')}",
        f"OK: {report.get('ok')}",
        "",
        "## Planned Operations",
    ]
    operations = plan.get("operations") if isinstance(plan.get("operations"), list) else []
    lines.extend(f"- {item}" for item in operations or ["None"])
    lines.append("")
    lines.append("## Target Chapter")
    lines.append(str(report.get("target_chapter") or session.get("target_chapter") or "Not prepared in dry-run mode."))
    lines.append("")
    lines.append("## Warnings")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else plan.get("warnings") if isinstance(plan.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.append("")
    lines.append("## Doctor")
    lines.append(f"- OK: {doctor_result.get('ok') if doctor_result else 'Not run'}")
    lines.append(f"- Checks: {len(doctor_result.get('checks') or []) if doctor_result else 0}")
    lines.append("")
    lines.append("## Recommended Commands")
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), list) else []
    lines.extend(f"- `{item}`" for item in commands or ["None"])
    return "\n".join(lines) + "\n"


def render_quickstart_from_wizard_markdown(report: dict[str, Any]) -> str:
    normalized = report.get("normalized") if isinstance(report.get("normalized"), dict) else {}
    project = normalized.get("project") if isinstance(normalized.get("project"), dict) else {}
    agent = normalized.get("agent") if isinstance(normalized.get("agent"), dict) else {}
    quickstart = report.get("quickstart") if isinstance(report.get("quickstart"), dict) else {}
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    lines = [
        "# Long Novel Agent Quickstart From Wizard",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Answers: {report.get('answers_path')}",
        f"Project: {normalized.get('project_dir') or quickstart.get('project_dir')}",
        f"Apply: {report.get('apply')}",
        f"Dry run: {report.get('dry_run')}",
        f"OK: {report.get('ok')}",
        "",
        "## Parsed Answers",
        f"- Title: {project.get('title') or '(folder name)'}",
        f"- Source: {project.get('source')}",
        f"- Target chapters: {project.get('target_chapters')}",
        f"- Target words: {project.get('target_words')}",
        f"- First chapter: {project.get('first_chapter')}",
        f"- Agent: {agent.get('id')} / {agent.get('platform')} / {agent.get('mode')}",
        "",
        "## Warnings",
    ]
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.extend(
        [
            "",
            "## Quickstart",
            f"- Source: {quickstart.get('selected_source')}",
            f"- Dry run: {quickstart.get('dry_run')}",
            f"- State dir: {quickstart.get('state_dir')}",
            f"- Audit id: {quickstart.get('audit_id') or 'Not written'}",
            "",
            "## Commands",
        ]
    )
    for key in ("apply", "prepare_session"):
        command = str(commands.get(key) or "").strip()
        if command:
            lines.append(f"- {key}: `{command}`")
    return "\n".join(lines).rstrip() + "\n"


