def render_desktop_onboarding_markdown(report: dict[str, Any]) -> str:
    next_step = report.get("next_step") if isinstance(report.get("next_step"), dict) else {}
    commands = report.get("commands") if isinstance(report.get("commands"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Onboarding",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"MCP tool profile: {report.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Set manually in the desktop app'}",
        f"Project state exists: {report.get('state_exists')}",
        f"OK: {report.get('ok')}",
        "",
        "## Next Step",
        f"- {next_step.get('title') or 'Ready'} ({next_step.get('status') or 'done'})",
        "",
        "## Steps",
    ]
    steps = report.get("steps") if isinstance(report.get("steps"), list) else []
    for step in steps:
        if not isinstance(step, dict):
            continue
        lines.extend(
            [
                f"### {step.get('title')}",
                f"- ID: {step.get('id')}",
                f"- Status: {step.get('status')}",
                f"- Goal: {step.get('goal')}",
            ]
        )
        writes = [item for item in step.get("writes", []) if item] if isinstance(step.get("writes"), list) else []
        if writes:
            lines.append("- Writes: " + ", ".join(writes))
        step_commands = [item for item in step.get("commands", []) if item] if isinstance(step.get("commands"), list) else []
        if step_commands:
            lines.append("- Commands:")
            lines.extend(f"  - `{item}`" for item in step_commands)
        notes = [item for item in step.get("notes", []) if item] if isinstance(step.get("notes"), list) else []
        if notes:
            lines.append("- Notes:")
            lines.extend(f"  - {item}" for item in notes)
        lines.append("")
    lines.extend(
        [
            "## Command Shortcuts",
            f"- Merge MCP config: `{commands.get('merge_mcp_config') or 'Set config path manually, then rerun desktop-onboard with --install-config.'}`",
            f"- Quickstart dry run: `{commands.get('quickstart_dry_run') or 'None'}`",
            f"- Quickstart write: `{commands.get('quickstart') or 'None'}`",
            f"- Doctor: `{commands.get('doctor') or 'Pass --install-config to generate this command.'}`",
            f"- Desktop checklist: `{commands.get('desktop_checklist') or 'None'}`",
            f"- Import evidence text: `{commands.get('ingest_evidence') or 'None'}`",
            f"- Record desktop check: `{commands.get('record_desktop_check') or 'None'}`",
            f"- Prepare session: `{commands.get('prepare_session') or 'None'}`",
            f"- Project status: `{commands.get('project_status') or 'None'}`",
            "",
            "## Notes",
        ]
    )
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(f"- {item}" for item in notes or ["None"])
    if report.get("guide_written_path"):
        lines.extend(["", f"Guide written: `{report.get('guide_written_path')}`"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_bootstrap_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Desktop Bootstrap",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Applied: {report.get('applied')}",
        f"OK: {report.get('ok')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        f"Install target: {report.get('install_target') or 'Default'}",
        f"Start MCP test: {report.get('start_mcp_test')}",
        "",
        "## Steps",
    ]
    steps = report.get("steps") if isinstance(report.get("steps"), list) else []
    for step in steps:
        if not isinstance(step, dict):
            continue
        lines.extend(
            [
                f"### {step.get('title')}",
                f"- ID: {step.get('id')}",
                f"- Status: {step.get('status')}",
                f"- Command: `{step.get('command') or 'None'}`",
            ]
        )
        if "return_code" in step:
            lines.append(f"- Return code: {step.get('return_code')}")
        writes = [item for item in step.get("writes", []) if item] if isinstance(step.get("writes"), list) else []
        if writes:
            lines.append("- Writes: " + ", ".join(writes))
        stderr_tail = str(step.get("stderr_tail") or "").strip()
        if stderr_tail:
            lines.append("- Stderr tail:")
            lines.append("```text")
            lines.append(stderr_tail)
            lines.append("```")
        lines.append("")
    lines.append("## Warnings")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.extend(f"- {item}" for item in warnings or ["None"])
    lines.append("")
    lines.append("## Notes")
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(f"- {item}" for item in notes or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_verification_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Desktop Verification",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Platform: {report.get('platform')}",
        f"Expected mode: {report.get('mode')}",
        f"Expected tool profile: {report.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}",
        f"Project: {report.get('project_dir')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        f"Start MCP test: {report.get('start_mcp_test')}",
        f"OK: {report.get('ok')}",
        "",
        "## Checks",
    ]
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    for item in checks:
        if not isinstance(item, dict):
            continue
        mark = "PASS" if item.get("ok") else "FAIL"
        lines.append(f"- {mark} {item.get('name')}: {item.get('detail')}")
    lines.append("")
    lines.append("## Recommended Actions")
    actions = report.get("recommended_actions") if isinstance(report.get("recommended_actions"), list) else []
    lines.extend(f"- `{item}`" if str(item).startswith("python ") else f"- {item}" for item in actions or ["None"])
    return "\n".join(lines) + "\n"


def render_desktop_client_checklist_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Desktop Client Checklist",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"MCP tool profile: {report.get('tool_profile') or DEFAULT_MCP_TOOL_PROFILE}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        "",
        f"Note: {report.get('not_proof')}",
        "",
        "## Evidence Pack",
    ]
    evidence_pack = report.get("evidence_pack") if isinstance(report.get("evidence_pack"), dict) else {}
    lines.extend(
        [
            f"- Result file: `{evidence_pack.get('result_file') or 'desktop-results.json'}`",
            f"- Required evidence count: {evidence_pack.get('required_evidence_count', 0)}",
            f"- Record command: `{evidence_pack.get('record_command') or 'None'}`",
        ]
    )
    if evidence_pack.get("template_path"):
        lines.append(f"- Written template: `{evidence_pack.get('template_path')}`")
    rules = evidence_pack.get("evidence_rules") if isinstance(evidence_pack.get("evidence_rules"), list) else []
    lines.extend(f"- {item}" for item in rules or ["Fill every required check with real desktop-client evidence."])
    if evidence_pack.get("results_payload"):
        lines.extend(
            [
                "",
                "Save this JSON as the result file after filling evidence:",
                "",
                "```json",
                json.dumps(evidence_pack.get("results_payload"), ensure_ascii=False, indent=2),
                "```",
            ]
        )
    lines.extend(
        [
            "",
            "## Required Checks",
        ]
    )
    checklist = report.get("checklist") if isinstance(report.get("checklist"), list) else []
    for item in checklist:
        if not isinstance(item, dict):
            continue
        lines.extend(
            [
                f"### {item.get('id')}",
                f"- Phase: {item.get('phase')}",
                f"- Required: {item.get('required')}",
                f"- Action: {item.get('action')}",
                f"- Expected: {item.get('expected')}",
                f"- Evidence: {item.get('evidence')}",
            ]
        )
        if item.get("command"):
            lines.append(f"- Command: `{item.get('command')}`")
        if item.get("prompt"):
            lines.append(f"- Prompt: {item.get('prompt')}")
        lines.append("")
    lines.append("## Manual Result Template")
    template = report.get("manual_result_template") if isinstance(report.get("manual_result_template"), list) else []
    lines.extend(f"- {item.get('id')}: {item.get('status')}" for item in template if isinstance(item, dict))
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_evidence_import_markdown(report: dict[str, Any]) -> str:
    source = report.get("source_summary") if isinstance(report.get("source_summary"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Evidence Import",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"OK: {report.get('ok')}",
        f"Note: {report.get('not_proof')}",
        "",
        "## Source",
        f"- Characters: {source.get('characters', 0)}",
        f"- Match characters: {source.get('match_characters', source.get('characters', 0))}",
        f"- Non-empty lines: {source.get('lines', 0)}",
        f"- Match lines: {source.get('match_lines', source.get('lines', 0))}",
        f"- Scratchpad template detected: {source.get('scratchpad_template_detected', False)}",
        f"- Scratchpad filled sections: {', '.join(str(item) for item in source.get('scratchpad_filled_sections', [])[:12]) if isinstance(source.get('scratchpad_filled_sections'), list) and source.get('scratchpad_filled_sections') else 'None'}",
        f"- Redaction applied: {source.get('redaction_applied')}",
        f"- Detected JSON payloads: {source.get('detected_json_payloads', 0)}",
        f"- Detected result checks: {source.get('detected_result_checks', 0)}",
        f"- Detected tool names: {source.get('detected_tool_name_count', 0)}",
        f"- Warnings: {source.get('warning_count', 0)}",
        "",
        "## Matched Checks",
    ]
    tool_names = source.get("detected_tool_names") if isinstance(source.get("detected_tool_names"), list) else []
    if tool_names:
        insert_at = lines.index("## Matched Checks") - 1
        lines[insert_at:insert_at] = [f"- Tool names: {', '.join(str(item) for item in tool_names[:12])}"]
        if len(tool_names) > 12:
            lines.insert(insert_at + 1, f"- Tool names omitted: {len(tool_names) - 12}")
    matched = report.get("matched_check_ids") if isinstance(report.get("matched_check_ids"), list) else []
    lines.extend(f"- {item}" for item in matched or ["None"])
    details = report.get("match_details") if isinstance(report.get("match_details"), list) else []
    lines.append("")
    lines.append("## Match Details")
    if details:
        for item in details:
            if not isinstance(item, dict):
                continue
            lines.append(f"- {item.get('id')}: {item.get('source')} ({item.get('reason') or 'matched'})")
    else:
        lines.append("- None")
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    lines.append("")
    lines.append("## Warnings")
    if warnings:
        for warning in warnings:
            if not isinstance(warning, dict):
                continue
            lines.append(f"- {warning.get('code')}: {warning.get('message')}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Missing Required Checks")
    missing = report.get("missing_required_check_ids") if isinstance(report.get("missing_required_check_ids"), list) else []
    lines.extend(f"- {item}" for item in missing or ["None"])
    if report.get("output_path"):
        lines.extend(["", f"Output written: `{report.get('output_path')}`"])
    lines.extend(
        [
            "",
            "## Record Command",
            f"`{report.get('record_command') or 'None'}`",
            "",
            "## Results Payload",
            "```json",
            json.dumps(report.get("results_payload") or {}, ensure_ascii=False, indent=2),
            "```",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_evidence_sanitizer_markdown(report: dict[str, Any]) -> str:
    source = report.get("source_summary") if isinstance(report.get("source_summary"), dict) else {}
    truncation = report.get("truncation") if isinstance(report.get("truncation"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Evidence Sanitizer",
        "",
        f"Generated: {report.get('generated_at')}",
        f"OK: {report.get('ok')}",
        f"Project: {report.get('project_dir')}",
        f"Writes project state: {report.get('would_write_project_state')}",
        f"Writes install config: {report.get('would_write_install_config')}",
        f"Writes pack files: {report.get('would_write_pack_files')}",
        f"Writes output file: {report.get('writes_output_file')}",
        "",
        "## Source",
        f"- Characters: {source.get('characters', 0)}",
        f"- Non-empty lines: {source.get('lines', 0)}",
        f"- Redaction applied: {source.get('redaction_applied')}",
        f"- Sanitized characters: {source.get('sanitized_characters', 0)}",
        f"- Warnings: {source.get('warning_count', 0)}",
        "",
        "## Truncation",
        f"- Max line characters: {truncation.get('max_line_chars')}",
        f"- Max total characters: {truncation.get('max_total_chars')}",
        f"- Truncated lines: {truncation.get('line_truncation_count', 0)}",
        f"- Total truncated: {truncation.get('total_truncated', False)}",
        "",
        "## Warnings",
    ]
    warnings = report.get("warnings") if isinstance(report.get("warnings"), list) else []
    if warnings:
        for warning in warnings:
            if not isinstance(warning, dict):
                continue
            lines.append(f"- {warning.get('code') or warning.get('type')}: {warning.get('message')}")
    else:
        lines.append("- None")
    if report.get("output_path"):
        lines.extend(["", f"Output written: `{report.get('output_path')}`"])
    actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(["", "## Next Actions"])
    lines.extend(f"- {item}" for item in actions or ["None"])
    lines.extend(
        [
            "",
            "## Sanitized Text",
            "```text",
            str(report.get("sanitized_text") or ""),
            "```",
        ]
    )
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_results_doctor_markdown(report: dict[str, Any]) -> str:
    counts = report.get("counts") if isinstance(report.get("counts"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Results Doctor",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        f"Result file: `{report.get('results_reference') or '<results.json>'}`",
        f"Writes project state: {report.get('would_write_project_state')}",
        "",
        "## Evidence Summary",
        f"- Required checks: {report.get('required_total', 0)}",
        f"- Required passed with evidence: {report.get('required_passed_with_evidence', 0)}",
        f"- Passed: {counts.get('passed', 0)}",
        f"- Failed: {counts.get('failed', 0)}",
        f"- Skipped: {counts.get('skipped', 0)}",
        f"- Not checked: {counts.get('not_checked', 0)}",
        "",
        "## Blocking Issues",
    ]
    issues = report.get("issues") if isinstance(report.get("issues"), list) else []
    blocking = [item for item in issues if isinstance(item, dict) and item.get("type") in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES]
    if blocking:
        for item in blocking:
            lines.append(f"- {item.get('check_id') or item.get('type')}: {item.get('message')}")
    else:
        lines.append("- None")
    warnings = report.get("safety_warnings") if isinstance(report.get("safety_warnings"), list) else []
    lines.append("")
    lines.append("## Safety Warnings")
    if warnings:
        for warning in warnings:
            if not isinstance(warning, dict):
                continue
            lines.append(f"- {warning.get('code') or warning.get('type')}: {warning.get('message')}")
    else:
        lines.append("- None")
    non_blocking = [item for item in issues if isinstance(item, dict) and item.get("type") not in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES and item not in warnings]
    if non_blocking:
        lines.append("")
        lines.append("## Other Issues")
        for item in non_blocking:
            lines.append(f"- {item.get('check_id') or item.get('type')}: {item.get('message')}")
    lines.append("")
    lines.append("## Recommended Actions")
    actions = report.get("recommended_actions") if isinstance(report.get("recommended_actions"), list) else []
    lines.extend(f"- `{item}`" if str(item).startswith("python ") else f"- {item}" for item in actions or ["None"])
    if report.get("record_command"):
        lines.extend(["", "## Record Command", f"`{report.get('record_command')}`"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_evidence_packet_markdown(report: dict[str, Any]) -> str:
    import_report = report.get("import_report") if isinstance(report.get("import_report"), dict) else {}
    doctor = report.get("results_doctor") if isinstance(report.get("results_doctor"), dict) else {}
    source_summary = import_report.get("source_summary") if isinstance(import_report.get("source_summary"), dict) else {}
    counts = doctor.get("counts") if isinstance(doctor.get("counts"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Evidence Packet",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Status: {report.get('status')}",
        f"OK: {report.get('ok')}",
        f"Source: {report.get('source')}",
        f"Platform: {report.get('platform')}",
        f"Mode: {report.get('mode')}",
        f"Project: {report.get('project_dir')}",
        f"Target chapter: {report.get('target_chapter')}",
        f"Config: {report.get('config_path') or 'Unknown'}",
        f"Result file: `{report.get('results_reference') or '<results.json>'}`",
        f"Writes project state: {report.get('would_write_project_state')}",
        f"Writes install config: {report.get('would_write_install_config')}",
        f"Writes pack files: {report.get('would_write_pack_files')}",
        "",
        "## Required Check IDs",
    ]
    required = report.get("required_check_ids") if isinstance(report.get("required_check_ids"), list) else []
    lines.extend(f"- `{item}`" for item in required or ["None"])
    lines.extend(["", "## Evidence Import"])
    if import_report:
        lines.extend(
            [
                f"- Characters: {source_summary.get('characters', 0)}",
                f"- Match characters: {source_summary.get('match_characters', source_summary.get('characters', 0))}",
                f"- Non-empty lines: {source_summary.get('lines', 0)}",
                f"- Match lines: {source_summary.get('match_lines', source_summary.get('lines', 0))}",
                f"- Scratchpad template detected: {source_summary.get('scratchpad_template_detected', False)}",
                f"- Detected JSON payloads: {source_summary.get('detected_json_payloads', 0)}",
                f"- Detected result checks: {source_summary.get('detected_result_checks', 0)}",
                f"- Safety warnings: {source_summary.get('warning_count', 0)}",
                "- Matched checks:",
            ]
        )
        matched = import_report.get("matched_check_ids") if isinstance(import_report.get("matched_check_ids"), list) else []
        lines.extend(f"  - `{item}`" for item in matched or ["None"])
        missing = import_report.get("missing_required_check_ids") if isinstance(import_report.get("missing_required_check_ids"), list) else []
        lines.append("- Missing required checks:")
        lines.extend(f"  - `{item}`" for item in missing or ["None"])
    else:
        lines.append("- No evidence text was imported in this packet.")
    lines.extend(["", "## Results Doctor"])
    if doctor:
        lines.extend(
            [
                f"- Status: {doctor.get('status')}",
                f"- Required checks: {doctor.get('required_total', 0)}",
                f"- Required passed with evidence: {doctor.get('required_passed_with_evidence', 0)}",
                f"- Passed: {counts.get('passed', 0)}",
                f"- Failed: {counts.get('failed', 0)}",
                f"- Skipped: {counts.get('skipped', 0)}",
                f"- Not checked: {counts.get('not_checked', 0)}",
            ]
        )
        issues = doctor.get("issues") if isinstance(doctor.get("issues"), list) else []
        blocking = [item for item in issues if isinstance(item, dict) and item.get("type") in DESKTOP_CHECK_BLOCKING_ISSUE_TYPES]
        lines.append("- Blocking issues:")
        if blocking:
            for item in blocking:
                lines.append(f"  - {item.get('check_id') or item.get('type')}: {item.get('message')}")
        else:
            lines.append("  - None")
        warnings = doctor.get("safety_warnings") if isinstance(doctor.get("safety_warnings"), list) else []
        lines.append("- Safety warnings:")
        if warnings:
            for warning in warnings:
                if isinstance(warning, dict):
                    lines.append(f"  - {warning.get('code') or warning.get('type')}: {warning.get('message')}")
        else:
            lines.append("  - None")
    else:
        lines.append("- No results JSON was checked in this packet.")
    lines.extend(["", "## Next Actions"])
    actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in actions or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for key, command in commands.items():
            lines.append(f"- {key}: `{command}`")
    else:
        lines.append("- None")
    if import_report.get("results_payload"):
        lines.extend(
            [
                "",
                "## Imported Results Payload",
                "```json",
                json.dumps(import_report.get("results_payload"), ensure_ascii=False, indent=2),
                "```",
            ]
        )
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_evidence_review_markdown(report: dict[str, Any]) -> str:
    packet = report.get("evidence_packet") if isinstance(report.get("evidence_packet"), dict) else {}
