        "\n".join(command_items),
        "</ul>",
        "</section>",
        "<section>",
        "<h2>Related Files</h2>",
        "<ul>",
        f'<li><a href="{DESKTOP_EVIDENCE_REVIEW_JSON_FILE}">{DESKTOP_EVIDENCE_REVIEW_JSON_FILE}</a></li>',
        f'<li><a href="{DESKTOP_EVIDENCE_REVIEW_SCHEMA_OUTPUT_FILE}">{DESKTOP_EVIDENCE_REVIEW_SCHEMA_OUTPUT_FILE}</a></li>',
        f'<li><a href="{DESKTOP_EVIDENCE_GAPS_MD_FILE}">{DESKTOP_EVIDENCE_GAPS_MD_FILE}</a></li>',
        f'<li><a href="{DESKTOP_EVIDENCE_SESSION_MD_FILE}">{DESKTOP_EVIDENCE_SESSION_MD_FILE}</a></li>',
        f'<li><a href="{DESKTOP_EVIDENCE_RUNBOOK_MD_FILE}">{DESKTOP_EVIDENCE_RUNBOOK_MD_FILE}</a></li>',
        "</ul>",
        "</section>",
        "<section>",
        "<h2>Local File Recheck</h2>",
        '<p class="muted">Load local files to recheck evidence in this browser. Nothing is uploaded, written to the novel project, or recorded by this page; downloading happens only when you click the download button.</p>',
        '<div class="file-grid">',
        '<div class="file-box"><label for="resultsFile">Results JSON</label><input id="resultsFile" type="file" accept=".json,application/json"></div>',
        '<div class="file-box"><label for="evidenceFile">Evidence text</label><input id="evidenceFile" type="file" accept=".txt,.md,text/plain,text/markdown"></div>',
        '<div class="file-box"><label for="reviewFile">Review JSON, optional</label><input id="reviewFile" type="file" accept=".json,application/json"></div>',
        "</div>",
        '<div id="localReviewSummary" class="local-output notice">No local files loaded yet.</div>',
        '<div id="localEvidenceImport" class="muted"></div>',
        '<div class="generated-preview">',
        '<label for="localResultsPreview"><strong>Local results preview from evidence text</strong></label>',
        '<textarea id="localResultsPreview" readonly placeholder="Load structured evidence text to preview a results JSON draft. This page does not save or record it."></textarea>',
        '<div class="action-row">',
        '<button id="copyResultsPreview" type="button" disabled>Copy preview JSON</button>',
        '<button id="downloadResultsPreview" type="button" disabled>Download preview JSON</button>',
        '<span id="localPreviewActionStatus" class="muted"></span>',
        "</div>",
        "</div>",
        '<div id="localReviewIssues"></div>',
        '<div id="localReviewChecks"></div>',
        "</section>",
        "</main>",
        "<script>",
        f"const INITIAL_REPORT = {embedded_report_json};",
        "let activeReport = INITIAL_REPORT;",
        "let loadedResults = null;",
        "let loadedEvidenceText = '';",
        "let generatedPreviewPayload = null;",
        "const weakEvidenceValues = new Set(['ok','okay','pass','passed','success','succeeded','done','complete','completed','true','yes','y','checked','verified','ready','n/a','na','none','无','有','是','否','已完成','完成','通过','成功','可以','正常','已检查','确认']);",
        "const proofTerms = ['long-novel-agent','mcp','tool','tools','prepare_chapter_session','build_chapter_context','build_chapter_delivery_packet','build_chapter_readiness','build_chapter_revision_comparison','build_chapter_range_readiness','check_write_session','write-session-check','write_session_check','check_chapter','diff_chapter_contract','record_chapter','propose_after_write_updates','apply_after_write_updates','author_confirmation','desktop-verify','desktop-next-step','desktop-results-doctor','chapter_session_packet','chapter_context','chapter_delivery_packet','chapter_readiness','chapter_range_readiness','returned','status','visible','hidden','rejected','unavailable','工具','调用','返回','状态','可见','隐藏','拒绝','不可用','重启','重新加载','作者确认'];",
        "function escapeHtml(value) { return String(value ?? '').replace(/[&<>\"']/g, (char) => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[char])); }",
        "function compactEvidence(value) { return String(value || '').toLowerCase().replace(/[\\s._:：;；,，。`'\"!！?？\\\\/\\-]+/g, ''); }",
        "function objectOrEmpty(value) { return value && typeof value === 'object' && !Array.isArray(value) ? value : {}; }",
        "function statusClass(value) { const text = String(value || '').toLowerCase(); if (['ready_to_record','recorded','recorded_elsewhere','passed','ready'].includes(text)) return 'status-good'; if (['needs_revision','failed','blocked'].includes(text)) return 'status-bad'; return 'status-warn'; }",
        "function normalizeResults(payload) { const raw = Array.isArray(payload) ? payload : Array.isArray(objectOrEmpty(payload).checks) ? payload.checks : Array.isArray(objectOrEmpty(payload).manual_result_template) ? payload.manual_result_template : (payload && typeof payload === 'object' ? [payload] : []); return raw.filter((item) => item && typeof item === 'object').map((item) => { const rawStatus = String(item.status || 'not_checked').trim().toLowerCase(); let status = ['pass','ok','success','succeeded'].includes(rawStatus) ? 'passed' : ['fail','error'].includes(rawStatus) ? 'failed' : rawStatus; if (!['passed','failed','skipped','not_checked'].includes(status)) status = 'not_checked'; return { id: String(item.id || '').trim(), status, evidence: String(item.evidence || '').trim(), notes: String(item.notes || '').trim() }; }).filter((item) => item.id); }",
        "function localSafetyWarnings(text, label) { const warnings = []; const value = String(text || ''); const patterns = [/Bearer\\s+[A-Za-z0-9._\\-]{16,}/i, /\\bsk-[A-Za-z0-9_\\-]{10,}\\b/i, /(?:api[_-]?key|access[_-]?token|auth[_-]?token)\\s*[:=]\\s*['\"]?[A-Za-z0-9._\\-]{12,}/i]; patterns.forEach((pattern) => { if (pattern.test(value)) warnings.push({type: 'safety_warning', check_id: label, message: 'Possible secret token or API key found. Remove it before recording evidence.'}); }); const longLine = value.split(/\\r?\\n/).find((line) => line.length > 2000); if (longLine) warnings.push({type: 'safety_warning', check_id: label, message: 'A very long line was found. Keep only short proof snippets, not full logs or manuscript text.'}); if (value.length > 100000) warnings.push({type: 'safety_warning', check_id: label, message: 'File is very large. Evidence should be short and redacted.'}); return warnings; }",
        "function weakEvidenceIssue(checkId, evidence) { const text = String(evidence || '').trim(); if (!text) return null; const lower = text.toLowerCase().replace(/\\s+/g, ' ').replace(/^[ .。:：;；,，`'\"[\\](){}]+|[ .。:：;；,，`'\"[\\](){}]+$/g, ''); if (weakEvidenceValues.has(compactEvidence(lower))) return {type: 'weak_evidence', check_id: checkId, message: 'Evidence is too generic; include a real desktop client tool name, visible server name, returned status, or rejected-call detail.'}; if (text.length < 18 && !proofTerms.some((term) => lower.includes(term.toLowerCase()))) return {type: 'weak_evidence', check_id: checkId, message: 'Evidence is too short to prove a real desktop client check.'}; return null; }",
        "function requiredIdsFromReport(report) { const session = objectOrEmpty(report.evidence_session); const packet = objectOrEmpty(report.evidence_packet); if (Array.isArray(session.required_check_ids) && session.required_check_ids.length) return session.required_check_ids.map(String); if (Array.isArray(packet.required_check_ids) && packet.required_check_ids.length) return packet.required_check_ids.map(String); return []; }",
        "function expectedById(report) { const packet = objectOrEmpty(report.evidence_packet); const rows = Array.isArray(packet.checklist) ? packet.checklist : []; const map = {}; rows.forEach((item) => { if (item && item.id) map[String(item.id)] = item; }); return map; }",
        "function parseStructuredEvidenceText(text, report) { const required = new Set(requiredIdsFromReport(report)); const expected = expectedById(report); const allowed = new Set([...required, ...Object.keys(expected)]); const lines = String(text || '').split(/\\r?\\n/); const checks = []; const seen = new Set(); let currentId = ''; let collecting = false; let buffer = []; let sectionCount = 0; let emptyEvidenceSections = 0; const headerPattern = /^(?:[-*]\\s*)?(?:check\\s*id|检查\\s*ID)\\s*[:：]\\s*([a-z][a-z0-9_]*)\\s*$/i; const markdownPattern = /^#{2,6}\\s+([a-z][a-z0-9_]*)\\s*$/i; const evidencePattern = /^(?:[-*]\\s*)?(?:evidence|证据)\\s*[:：]\\s*(.*)$/i; const stopPattern = /^(?:#{1,6}\\s+|(?:[-*]\\s*)?(?:required|phase|action|expected|prompt|notes|command|useful command|evidence to paste|check id|检查\\s*ID|要求|阶段|动作|预期|提示|备注|命令)\\s*[:：])/i; function acceptId(candidate) { const id = String(candidate || '').trim(); if (!id || id === 'freeform') return ''; if (allowed.size && !allowed.has(id)) return ''; return id; } function flush() { if (!currentId || !collecting) return; const evidence = buffer.join('\\n').trim(); sectionCount += 1; if (!evidence) { emptyEvidenceSections += 1; return; } if (seen.has(currentId)) return; seen.add(currentId); checks.push({id: currentId, status: 'passed', evidence, notes: 'Imported locally from structured evidence text in desktop-evidence-review.html. Review before recording.'}); } lines.forEach((line) => { const header = line.match(headerPattern) || line.match(markdownPattern); if (header) { flush(); currentId = acceptId(header[1]); collecting = false; buffer = []; return; } const evidence = line.match(evidencePattern); if (evidence && currentId) { flush(); collecting = true; buffer = []; if (evidence[1]) buffer.push(evidence[1]); return; } if (collecting) { if (stopPattern.test(line)) { flush(); collecting = false; buffer = []; const nextHeader = line.match(headerPattern) || line.match(markdownPattern); currentId = nextHeader ? acceptId(nextHeader[1]) : currentId; return; } buffer.push(line); } }); flush(); const payload = checks.length ? {checks, generated_by: 'desktop-evidence-review.html', generated_from: 'structured_evidence_text', generated_at: new Date().toISOString(), review_before_recording: true} : null; return {payload, checks, sectionCount, emptyEvidenceSections}; }",
        "function setPreviewActionsEnabled(enabled) { ['copyResultsPreview','downloadResultsPreview'].forEach((id) => { const button = document.getElementById(id); if (button) button.disabled = !enabled; }); if (!enabled) document.getElementById('localPreviewActionStatus').textContent = ''; }",
        "function renderLocalResultsPreview(parsed) { const box = document.getElementById('localEvidenceImport'); const preview = document.getElementById('localResultsPreview'); generatedPreviewPayload = parsed && parsed.payload ? parsed.payload : null; if (!generatedPreviewPayload) { preview.value = ''; box.textContent = loadedEvidenceText ? 'Structured evidence text was loaded, but this browser did not find filled Check ID / Evidence sections for this checklist.' : ''; setPreviewActionsEnabled(false); return; } preview.value = JSON.stringify(generatedPreviewPayload, null, 2); box.textContent = 'Generated a local results preview from evidence text: ' + parsed.checks.length + ' check(s). Review it before using record-desktop-check.'; setPreviewActionsEnabled(true); }",
        "function previewFilename() { const session = objectOrEmpty((activeReport || INITIAL_REPORT).evidence_session); const raw = String(session.result_file || 'desktop-results-preview.json').split(/[\\\\/]/).pop() || 'desktop-results-preview.json'; return raw.endsWith('.json') ? raw.replace(/\\.json$/i, '.preview.json') : raw + '.preview.json'; }",
        "async function copyResultsPreview() { const status = document.getElementById('localPreviewActionStatus'); const text = document.getElementById('localResultsPreview').value; if (!generatedPreviewPayload || !text) { status.textContent = 'No preview JSON to copy.'; return; } if (!navigator.clipboard || !navigator.clipboard.writeText) { status.textContent = 'Clipboard is not available. Select the preview text and copy it manually.'; return; } await navigator.clipboard.writeText(text); status.textContent = 'Preview JSON copied.'; }",
        "function downloadResultsPreview() { const status = document.getElementById('localPreviewActionStatus'); const text = document.getElementById('localResultsPreview').value; if (!generatedPreviewPayload || !text) { status.textContent = 'No preview JSON to download.'; return; } if (typeof Blob === 'undefined' || typeof URL === 'undefined' || !URL.createObjectURL) { status.textContent = 'Download is not supported by this browser. Copy the preview JSON instead.'; return; } const blob = new Blob([text + '\\n'], {type: 'application/json'}); const url = URL.createObjectURL(blob); const link = document.createElement('a'); link.href = url; link.download = previewFilename(); link.rel = 'noopener'; document.body.appendChild(link); link.click(); link.remove(); URL.revokeObjectURL(url); status.textContent = 'Preview JSON download started: ' + link.download; }",
        "function analyzeLoadedFiles() { const report = activeReport || INITIAL_REPORT; const requiredIds = requiredIdsFromReport(report); const expected = expectedById(report); const issues = []; const parsedEvidence = loadedEvidenceText ? parseStructuredEvidenceText(loadedEvidenceText, report) : {payload:null, checks:[], sectionCount:0, emptyEvidenceSections:0}; renderLocalResultsPreview(parsedEvidence); const effectiveResults = loadedResults || parsedEvidence.payload; const normalized = effectiveResults ? normalizeResults(effectiveResults) : []; const byId = {}; normalized.forEach((item) => { byId[item.id] = item; }); if (!loadedResults && !loadedEvidenceText) { renderLocalReview([], [], 'No local files loaded yet.', 'notice'); return; } if (!requiredIds.length) issues.push({type: 'missing_required_ids', check_id: 'review', message: 'The review report did not include required check IDs.'}); if (loadedResults && !normalized.length) issues.push({type: 'invalid_results', check_id: 'results', message: 'Results JSON did not contain checks, manual_result_template, or a check object with id.'}); if (!loadedResults && loadedEvidenceText && !parsedEvidence.payload) issues.push({type: 'no_structured_evidence_matches', check_id: 'evidence_text', message: 'No filled Check ID / Evidence sections matched this checklist. Use ingest_evidence for freeform transcripts or load Results JSON.'}); requiredIds.forEach((checkId) => { const observed = byId[checkId]; if (!observed) { issues.push({type: 'missing_required_check', check_id: checkId, message: 'Required check is missing from Results JSON.'}); return; } if (observed.status !== 'passed') issues.push({type: 'required_check_not_passed', check_id: checkId, message: 'Required check is not passed.'}); if (!observed.evidence) issues.push({type: 'missing_evidence', check_id: checkId, message: 'Required check needs real desktop-client evidence.'}); const weak = weakEvidenceIssue(checkId, observed.evidence); if (weak) issues.push(weak); if (checkId === 'range_readiness_gate' && !/build_chapter_range_readiness|chapter-range-readiness/i.test(observed.evidence)) issues.push({type: 'missing_range_readiness_evidence', check_id: checkId, message: 'Evidence must mention build_chapter_range_readiness or chapter-range-readiness.'}); if (String(report.mode || '').toLowerCase() === 'writer' && checkId === 'write_session_preflight_gate' && !/check_write_session|write-session-check|write_session_check/i.test(observed.evidence)) issues.push({type: 'missing_write_session_preflight_evidence', check_id: checkId, message: 'Writer evidence must mention check_write_session or write-session-check.'}); if (String(report.mode || '').toLowerCase() === 'writer' && checkId === 'proposal_readiness_gate' && !/build_proposal_readiness|proposal-readiness/i.test(observed.evidence)) issues.push({type: 'missing_proposal_readiness_evidence', check_id: checkId, message: 'Writer evidence must mention build_proposal_readiness or proposal-readiness.'}); if (String(report.mode || '').toLowerCase() === 'writer' && checkId === 'acceptance_write_gate' && !/author_confirmation|--author-confirmation/i.test(observed.evidence)) issues.push({type: 'missing_author_confirmation_evidence', check_id: checkId, message: 'Writer acceptance evidence must include author_confirmation or --author-confirmation.'}); if (String(report.mode || '').toLowerCase() === 'writer' && checkId === 'acceptance_write_gate' && !/(record_chapter|record-chapter|propose_after_write_updates|propose-after-write|apply_after_write_updates|apply-after-write)/i.test(observed.evidence)) issues.push({type: 'missing_acceptance_write_operation_evidence', check_id: checkId, message: 'Writer acceptance evidence must show a durable write command such as record_chapter, propose_after_write_updates, or apply_after_write_updates.'}); }); normalized.forEach((item) => { if (!expected[item.id] && !requiredIds.includes(item.id)) issues.push({type: 'unknown_check_id', check_id: item.id, message: 'Check ID is not in the generated checklist.'}); }); if (loadedResults) issues.push(...localSafetyWarnings(JSON.stringify(loadedResults), 'results')); if (loadedEvidenceText) { issues.push(...localSafetyWarnings(loadedEvidenceText, 'evidence_text')); if (parsedEvidence.emptyEvidenceSections) issues.push({type: 'empty_evidence_scratchpad_sections', check_id: 'evidence_text', message: parsedEvidence.emptyEvidenceSections + ' scratchpad evidence section(s) look empty.'}); } const blockingTypes = new Set(['missing_required_ids','invalid_results','missing_required_check','required_check_not_passed','missing_evidence','weak_evidence','missing_range_readiness_evidence','missing_write_session_preflight_evidence','missing_proposal_readiness_evidence','missing_author_confirmation_evidence','missing_acceptance_write_operation_evidence','no_structured_evidence_matches']); const blocking = issues.filter((item) => blockingTypes.has(item.type)); const passedRequired = requiredIds.filter((id) => byId[id] && byId[id].status === 'passed' && byId[id].evidence && !blocking.some((issue) => issue.check_id === id)).length; let label = ''; let css = 'notice'; if (!effectiveResults) { label = 'Evidence text loaded, but no structured results preview was generated. Use ingest_evidence or load Results JSON for per-check readiness.'; } else if (!loadedResults && parsedEvidence.payload && blocking.length) { label = 'Evidence text produced a local results preview. Needs revision: ' + passedRequired + '/' + requiredIds.length + ' required checks have usable evidence.'; css = 'notice bad'; } else if (!loadedResults && parsedEvidence.payload) { label = 'Evidence text produced a local results preview. Ready to record after human review: ' + passedRequired + '/' + requiredIds.length + ' required checks have usable evidence.'; css = 'notice good'; } else if (blocking.length) { label = 'Needs revision: ' + passedRequired + '/' + requiredIds.length + ' required checks have usable evidence.'; css = 'notice bad'; } else { label = 'Ready to record after human review: ' + passedRequired + '/' + requiredIds.length + ' required checks have usable evidence.'; css = 'notice good'; } renderLocalReview(issues, normalized, label, css); }",
        "function renderLocalReview(issues, checks, label, css) { const summary = document.getElementById('localReviewSummary'); const issueBox = document.getElementById('localReviewIssues'); const checkBox = document.getElementById('localReviewChecks'); summary.className = 'local-output ' + css; summary.textContent = label; if (!issues.length) { issueBox.innerHTML = '<h3>Local Issues</h3><p class=\"muted\">None found by this browser check.</p>'; } else { issueBox.innerHTML = '<h3>Local Issues</h3><ul>' + issues.map((item) => '<li><span class=\"pill\">' + escapeHtml(item.type) + '</span><code>' + escapeHtml(item.check_id || '') + '</code> ' + escapeHtml(item.message || '') + '</li>').join('') + '</ul>'; } if (!checks.length) { checkBox.innerHTML = '<h3>Loaded Checks</h3><p class=\"muted\">No result checks loaded.</p>'; return; } const rows = checks.map((item) => '<tr><td><code>' + escapeHtml(item.id) + '</code></td><td class=\"' + statusClass(item.status) + '\">' + escapeHtml(item.status) + '</td><td>' + escapeHtml(item.evidence || '') + '</td><td>' + escapeHtml(item.notes || '') + '</td></tr>').join(''); checkBox.innerHTML = '<h3>Loaded Checks</h3><table class=\"review-table\"><thead><tr><th>ID</th><th>Status</th><th>Evidence</th><th>Notes</th></tr></thead><tbody>' + rows + '</tbody></table>'; }",
        "async function readLocalFile(input, asJson) { const file = input.files && input.files[0]; if (!file) return null; const text = await file.text(); return asJson ? JSON.parse(text) : text; }",
