        "document.getElementById('evidenceFile').addEventListener('change', async (event) => { try { loadedEvidenceText = await readLocalFile(event.target, false) || ''; analyzeLoadedFiles(); } catch (error) { renderLocalReview([{type:'invalid_text', check_id:'evidence_text', message:error.message}], [], 'Evidence text could not be read.', 'notice bad'); } });",
        "document.getElementById('reviewFile').addEventListener('change', async (event) => { try { const payload = await readLocalFile(event.target, true); if (payload && payload.type === 'desktop_evidence_review') activeReport = payload; analyzeLoadedFiles(); } catch (error) { renderLocalReview([{type:'invalid_json', check_id:'review', message:error.message}], [], 'Review JSON could not be parsed.', 'notice bad'); } });",
