def render_standalone_runtime_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Standalone Runtime",
        "",
        f"Generated: {report.get('generated_at')}",
        f"OK: {report.get('ok')}",
        f"Status: {report.get('status')}",
        f"Applied: {report.get('applied')}",
        f"Target OS: {report.get('target_os')}",
        f"Output dir: `{report.get('output_dir')}`",
        f"PyInstaller available: {report.get('pyinstaller_available')}",
        "",
        "## Runtime Files",
    ]
    runtime_files = report.get("runtime_files") if isinstance(report.get("runtime_files"), dict) else {}
    if runtime_files:
        for name, path in runtime_files.items():
            lines.append(f"- {name}: `{path}`")
    else:
        lines.append("- None")
    lines.extend(["", "## Build Commands"])
    commands = report.get("commands") if isinstance(report.get("commands"), list) else []
    for item in commands:
        if isinstance(item, dict):
            lines.append(f"- {item.get('id')}: `{item.get('command')}`")
    if not commands:
        lines.append("- None")
    runs = report.get("runs") if isinstance(report.get("runs"), list) else []
    if runs:
        lines.extend(["", "## Runs"])
        for item in runs:
            if isinstance(item, dict):
                lines.append(f"- {item.get('id')}: returncode={item.get('returncode')} output_exists={item.get('output_exists')}")
    lines.extend(["", "## Next Actions"])
    actions = report.get("next_actions") if isinstance(report.get("next_actions"), list) else []
    lines.extend(f"- {item}" for item in actions or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_handoff_bundle_markdown(bundle: dict[str, Any]) -> str:
    runtime = bundle.get("runtime") if isinstance(bundle.get("runtime"), dict) else {}
    cli = runtime.get("cli") if isinstance(runtime.get("cli"), dict) else {}
    mcp = runtime.get("mcp") if isinstance(runtime.get("mcp"), dict) else {}
    snapshot = bundle.get("project_snapshot") if isinstance(bundle.get("project_snapshot"), dict) else {}
    lines = [
        "# Long Novel Agent Desktop Handoff Bundle",
        "",
        f"Generated: {bundle.get('generated_at')}",
        f"OK: {bundle.get('ok')}",
        f"Status: {bundle.get('status')}",
        f"Bundle dir: `{bundle.get('bundle_dir')}`",
        f"Project snapshot: `{bundle.get('project_dir')}`",
        f"Pack dir: `{bundle.get('pack_dir')}`",
        f"Platform: {bundle.get('platform')}",
        f"Mode: {bundle.get('mode')}",
        f"Target OS: {bundle.get('target_os')}",
        f"Target chapter: {bundle.get('target_chapter')}",
        "",
        "## Runtime",
        f"- CLI: {cli.get('status')} `{cli.get('target')}`",
        f"- MCP: {mcp.get('status')} `{mcp.get('target')}`",
        "",
        "## Project Snapshot",
        f"- Files: {snapshot.get('file_count', 0)}",
        f"- Bytes: {snapshot.get('bytes', 0)}",
        f"- Skipped: {snapshot.get('skipped_count', 0)}",
        "",
        "## Commands",
    ]
    commands = bundle.get("commands") if isinstance(bundle.get("commands"), dict) else {}
    if commands:
        for key, command in commands.items():
            lines.append(f"- {key}: `{command}`")
    else:
        lines.append("- None")
    archive = bundle.get("archive") if isinstance(bundle.get("archive"), dict) else {}
    if archive:
        lines.extend(
            [
                "",
                "## Archive",
                f"- Path: `{archive.get('path')}`",
                f"- Files: {archive.get('file_count')}",
                f"- Bytes: {archive.get('bytes')}",
                f"- SHA256: `{archive.get('sha256')}`",
            ]
        )
    lines.extend(["", "## Next"])
    if bundle.get("ok"):
        lines.append("- Copy or unzip the bundle on the target computer, then open `START_HERE.md` or run the top-level launcher.")
    else:
        lines.append("- Add missing runtime files under `runtime/` or recreate the bundle with `--runtime-dir` before giving it to a non-technical user.")
    lines.append("- Give `agent-read-me-first.md` to the local desktop agent.")
    lines.extend(["", "## Notes"])
    notes = bundle.get("notes") if isinstance(bundle.get("notes"), list) else []
    lines.extend(f"- {item}" for item in notes or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_rebind_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Desktop Pack Kit Rebind",
        "",
        f"Generated: {report.get('generated_at')}",
        f"OK: {report.get('ok')}",
        f"Status: {report.get('status')}",
        f"Applied: {report.get('applied')}",
        f"Pack dir: {report.get('pack_dir')}",
        f"Kit dir: {report.get('kit_dir')}",
        f"Kit version: {report.get('kit_version')}",
        "",
        "## Replacement Plan",
    ]
    replacements = report.get("replacements") if isinstance(report.get("replacements"), list) else []
    if replacements:
        for item in replacements:
            if isinstance(item, dict):
                lines.append(f"- `{item.get('from')}` -> `{item.get('to')}`")
    else:
        lines.append("- No Kit path changes needed.")
    lines.extend(
        [
            "",
            "## Files",
            f"- Planned files: {report.get('planned_file_count', 0)}",
            f"- Planned replacements: {report.get('planned_replacement_count', 0)}",
        ]
    )
    files = report.get("written_files") if report.get("applied") else report.get("planned_files")
    if isinstance(files, list) and files:
        for item in files:
            if isinstance(item, dict):
                lines.append(f"- `{item.get('name')}` replacements={item.get('replacement_count')}")
    else:
        lines.append("- None")
    verify_before = report.get("verify_before") if isinstance(report.get("verify_before"), dict) else {}
    verify_after = report.get("verify_after") if isinstance(report.get("verify_after"), dict) else {}
    doctor_after = report.get("doctor_after") if isinstance(report.get("doctor_after"), dict) else {}
    lines.extend(
        [
            "",
            "## Checks",
            f"- Verify before: {verify_before.get('ok')}",
        ]
    )
    if verify_after:
        lines.append(f"- Verify after: {verify_after.get('ok')}")
    if doctor_after:
        lines.append(f"- Pack doctor after: {doctor_after.get('ok')}")
        lines.append(f"- Command Kit paths after: {doctor_after.get('command_kit_paths_ok')}")
    notes = report.get("notes") if isinstance(report.get("notes"), list) else []
    lines.extend(["", "## Notes"])
    lines.extend(f"- {item}" for item in notes or ["None"])
    return "\n".join(lines).rstrip() + "\n"


def render_desktop_pack_markdown(pack: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Desktop Pack",
        "",
        f"Generated: {pack.get('generated_at')}",
        f"OK: {pack.get('ok')}",
        f"Platform: {pack.get('platform')}",
        f"Mode: {pack.get('mode')}",
        f"Project: {pack.get('project_dir')}",
        f"Target chapter: {pack.get('target_chapter')}",
        f"Output dir: {pack.get('output_dir')}",
        f"Result file: {pack.get('result_file')}",
        "",
        "## Written Files",
    ]
    written = pack.get("written_files") if isinstance(pack.get("written_files"), list) else []
    for item in written:
        if not isinstance(item, dict):
            continue
        lines.append(f"- `{item.get('name')}` ({item.get('bytes')} bytes)")
    if not written:
        lines.append("- None")
    archive = pack.get("archive") if isinstance(pack.get("archive"), dict) else {}
    if archive:
        lines.extend(
            [
                "",
                "## Archive",
                f"- Path: `{archive.get('path')}`",
                f"- Root: `{archive.get('root_name')}`",
                f"- Files: {archive.get('file_count')}",
                f"- Bytes: {archive.get('bytes')}",
                f"- SHA256: `{archive.get('sha256')}`",
            ]
        )
    lines.extend(["", "## Notes"])
    notes = pack.get("notes") if isinstance(pack.get("notes"), list) else []
    lines.extend(f"- {item}" for item in notes or ["None"])
    lines.extend(["", "## Next"])
    lines.append("- Open `START_HERE.md` in the generated pack directory.")
    lines.append("- Fill the result JSON only after checking inside the desktop client, then run `desktop-results-doctor` before recording.")
    return "\n".join(lines).rstrip() + "\n"


def render_proposal_review_markdown(review: dict[str, Any]) -> str:
    summary = review.get("summary") if isinstance(review.get("summary"), dict) else {}
    validation = review.get("validation") if isinstance(review.get("validation"), dict) else {}
    risk = review.get("risk") if isinstance(review.get("risk"), dict) else {}
    diff = review.get("diff") if isinstance(review.get("diff"), dict) else {}
    lines = [
        "# Long Novel Agent Proposal Review",
        "",
        f"Generated: {review.get('generated_at')}",
        f"Project: {review.get('project_dir')}",
        f"Proposal: {review.get('proposal_id') or review.get('source')}",
        f"Chapter: {review.get('chapter') or 'unknown'}",
        f"Status: {review.get('proposal_status')}",
        f"Validation: {summary.get('validation_status')}",
        f"Risk: {summary.get('risk_level')}",
        f"Ready to apply: {review.get('ready_to_apply')}",
        f"Author review required: {review.get('author_review_required')}",
        "",
        "## Issue Summary",
        f"- Errors: {summary.get('errors', 0)}",
        f"- Warnings: {summary.get('warnings', 0)}",
        "",
        "## Issues",
    ]
    issues = validation.get("issues") if isinstance(validation.get("issues"), list) else []
    if issues:
        for issue in issues:
            if not isinstance(issue, dict):
                continue
            lines.append(f"- {issue.get('severity')}: {issue.get('type')} - {issue.get('message')}")
    else:
        lines.append("- None")
    risk_items = risk.get("items") if isinstance(risk.get("items"), list) else []
    lines.extend(["", "## Risk Items"])
    if risk_items:
        for item in risk_items:
            if not isinstance(item, dict):
                continue
            lines.append(f"- {item.get('level')}: {item.get('category')} in {item.get('section')}[{item.get('index')}] - {item.get('matched')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Diff Counts"])
    for key in (
        "facts_create",
        "facts_update",
        "characters_create",
        "characters_update",
        "debts_create",
        "debts_update",
        "handoff_update",
    ):
        lines.append(f"- {key}: {summary.get(key, 0)}")
    lines.extend(["", "## Handoff Preview"])
    handoff = diff.get("handoff") if isinstance(diff.get("handoff"), dict) else {}
    lines.append(str(handoff.get("preview") or "No handoff change."))
    lines.extend(["", "## Commands"])
    commands = review.get("commands") if isinstance(review.get("commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    lines.extend(["", "## Next Steps"])
    next_steps = review.get("next_steps") if isinstance(review.get("next_steps"), list) else []
    lines.extend(f"- {item}" for item in next_steps or ["None"])
    written = review.get("written_files") if isinstance(review.get("written_files"), list) else []
    if written:
        lines.extend(["", "## Written Files"])
        for item in written:
            if isinstance(item, dict):
                lines.append(f"- `{item.get('name')}` ({item.get('bytes')} bytes)")
    if review.get("output_dir"):
        lines.extend(["", f"Output dir: `{review.get('output_dir')}`"])
    return "\n".join(lines).rstrip() + "\n"


def render_proposal_readiness_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Proposal Readiness",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Proposal: {report.get('proposal_id') or 'inline'}",
        f"Chapter: {report.get('chapter') or 'unknown'}",
        f"Proposal status: {report.get('proposal_status')}",
        f"Readiness status: {report.get('status')}",
        f"Ready to apply: {report.get('ready_to_apply')}",
        f"Author review required: {report.get('author_review_required')}",
        f"Score: {report.get('score')}",
        "",
        "## Summary",
        f"- Must fix: {summary.get('must_fix', 0)}",
        f"- Review: {summary.get('review', 0)}",
        f"- Improve: {summary.get('improve', 0)}",
        f"- Errors: {summary.get('errors', 0)}",
        f"- Warnings: {summary.get('warnings', 0)}",
        f"- Risk level: {summary.get('risk_level')}",
        f"- High risk: {summary.get('high_risk', 0)}",
        f"- Medium risk: {summary.get('medium_risk', 0)}",
        "",
        "## Must Fix",
    ]
    for item in report.get("must_fix", []) if isinstance(report.get("must_fix"), list) else []:
        if isinstance(item, dict):
            lines.append(f"- {item.get('type')}: {item.get('message')}")
            if item.get("suggested_fix"):
                lines.append(f"  Suggested fix: {item.get('suggested_fix')}")
    if not (report.get("must_fix") if isinstance(report.get("must_fix"), list) else []):
        lines.append("- None")
    lines.append("")
    lines.append("## Review")
    review_items = report.get("review") if isinstance(report.get("review"), list) else []
    if review_items:
        for item in review_items:
            if isinstance(item, dict):
                lines.append(f"- {item.get('type')}: {item.get('message')}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Improve")
    improve = report.get("improve") if isinstance(report.get("improve"), list) else []
    if improve:
        for item in improve:
            if isinstance(item, dict):
                lines.append(f"- {item.get('type')}: {item.get('message')}")
    else:
        lines.append("- None")
    lines.extend(["", "## Diff Counts"])
    for key in (
        "facts_create",
        "facts_update",
        "characters_create",
        "characters_update",
        "debts_create",
        "debts_update",
        "handoff_update",
    ):
        lines.append(f"- {key}: {summary.get(key, 0)}")
    lines.extend(["", "## Action Plan"])
    action_plan = report.get("action_plan") if isinstance(report.get("action_plan"), dict) else {}
    for group, title in (("must_fix", "Must Fix"), ("review", "Review"), ("improve", "Improve")):
        rows = action_plan.get(group) if isinstance(action_plan.get(group), list) else []
        lines.append(f"### {title}")
        if not rows:
            lines.append("- None")
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            lines.append(f"- {row.get('title')}: {row.get('reason')}")
            if row.get("command"):
                lines.append(f"  Command: `{row.get('command')}`")
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def render_proposal_review_commands_text(review: dict[str, Any]) -> str:
    lines = [
        "# Long Novel Agent Proposal Review Commands",
        "",
        f"Project: {review.get('project_dir')}",
        f"Proposal: {review.get('proposal_id') or review.get('source')}",
        "",
    ]
    commands = review.get("commands") if isinstance(review.get("commands"), dict) else {}
    for name, command in commands.items():
        lines.extend([f"## {name}", str(command), ""])
    return "\n".join(lines).rstrip() + "\n"


def render_proposal_review_html(review: dict[str, Any]) -> str:
    summary = review.get("summary") if isinstance(review.get("summary"), dict) else {}
    validation = review.get("validation") if isinstance(review.get("validation"), dict) else {}
    risk = review.get("risk") if isinstance(review.get("risk"), dict) else {}
    commands = review.get("commands") if isinstance(review.get("commands"), dict) else {}

    def esc(value: Any) -> str:
        return html.escape(str(value if value is not None else ""))

    issue_rows: list[str] = []
    for issue in validation.get("issues", []) if isinstance(validation.get("issues"), list) else []:
        if not isinstance(issue, dict):
            continue
        issue_rows.append(
            "<tr>"
            f"<td>{esc(issue.get('severity'))}</td>"
            f"<td>{esc(issue.get('type'))}</td>"
            f"<td>{esc(issue.get('message'))}</td>"
            "</tr>"
        )
    if not issue_rows:
        issue_rows.append('<tr><td colspan="3">No validation issues.</td></tr>')
    risk_rows: list[str] = []
    for item in risk.get("items", []) if isinstance(risk.get("items"), list) else []:
        if not isinstance(item, dict):
            continue
        risk_rows.append(
            "<tr>"
            f"<td>{esc(item.get('level'))}</td>"
            f"<td>{esc(item.get('category'))}</td>"
            f"<td>{esc(item.get('section'))}[{esc(item.get('index'))}]</td>"
            f"<td>{esc(item.get('matched'))}</td>"
            "</tr>"
        )
    if not risk_rows:
        risk_rows.append('<tr><td colspan="4">No matched risk item.</td></tr>')
    command_blocks = "\n".join(
        f"<section><h3>{esc(name)}</h3><pre>{esc(command)}</pre></section>"
        for name, command in commands.items()
    ) or "<p>No command available.</p>"
    review_json = html.escape(json.dumps(review, ensure_ascii=False, indent=2))
    return f"""<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Long Novel Agent Proposal Review</title>
  <style>
    body {{ font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; margin: 32px; color: #1f2933; background: #f8fafc; }}
    main {{ max-width: 1120px; margin: 0 auto; }}
    h1, h2, h3 {{ color: #102a43; }}
    .grid {{ display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 12px; margin: 16px 0 24px; }}
    .metric, section {{ background: #fff; border: 1px solid #d9e2ec; border-radius: 8px; padding: 14px; }}
    .metric strong {{ display: block; color: #52606d; font-size: 12px; text-transform: uppercase; margin-bottom: 6px; }}
    table {{ width: 100%; border-collapse: collapse; background: #fff; margin: 12px 0 24px; }}
    th, td {{ border: 1px solid #d9e2ec; padding: 8px; text-align: left; vertical-align: top; }}
    th {{ background: #eef2f7; }}
    pre {{ white-space: pre-wrap; word-break: break-word; background: #111827; color: #f9fafb; padding: 12px; border-radius: 6px; overflow: auto; }}
    details {{ margin: 16px 0; }}
  </style>
</head>
<body>
<main>
  <h1>Long Novel Agent Proposal Review</h1>
  <div class="grid">
    <div class="metric"><strong>Project</strong>{esc(review.get('project_dir'))}</div>
    <div class="metric"><strong>Proposal</strong>{esc(review.get('proposal_id') or review.get('source'))}</div>
    <div class="metric"><strong>Chapter</strong>{esc(review.get('chapter') or 'unknown')}</div>
    <div class="metric"><strong>Validation</strong>{esc(summary.get('validation_status'))}</div>
    <div class="metric"><strong>Risk</strong>{esc(summary.get('risk_level'))}</div>
    <div class="metric"><strong>Ready to apply</strong>{esc(review.get('ready_to_apply'))}</div>
    <div class="metric"><strong>Author review</strong>{esc(review.get('author_review_required'))}</div>
  </div>
  <h2>Validation Issues</h2>
  <table><thead><tr><th>Severity</th><th>Type</th><th>Message</th></tr></thead><tbody>{''.join(issue_rows)}</tbody></table>
  <h2>Risk Items</h2>
  <table><thead><tr><th>Level</th><th>Category</th><th>Location</th><th>Matched</th></tr></thead><tbody>{''.join(risk_rows)}</tbody></table>
  <h2>Commands</h2>
  {command_blocks}
  <details>
    <summary>Full review JSON</summary>
    <pre>{review_json}</pre>
  </details>
</main>
</body>
</html>
"""


def render_chapter_readiness_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Long Novel Agent Chapter Readiness",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Chapter: {report.get('chapter')}",
        f"File: {report.get('file')}",
        f"Status: {report.get('status')}",
        f"Ready to present: {report.get('ready_to_present')}",
        f"Score: {report.get('score')}",
        f"Text units: {report.get('text_units')}",
        "",
        "## Summary",
        f"- Must fix: {summary.get('must_fix', 0)}",
        f"- Review: {summary.get('review', 0)}",
        f"- Improve: {summary.get('improve', 0)}",
        f"- Check status: {summary.get('check_status')}",
        f"- Contract status: {summary.get('contract_status')}",
        "",
        "## Revision Plan",
    ]
    lines.extend(render_revision_plan(report.get("revision_plan")))
    lines.extend([
        "",
        "## Must Fix Before Acceptance",
    ])
    lines.extend(render_readiness_items(report.get("must_fix")))
    lines.extend(["", "## Review With Author"])
    lines.extend(render_readiness_items(report.get("review")))
    lines.extend(["", "## Improvement Notes"])
    lines.extend(render_readiness_items(report.get("improve")))
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    lines.extend(["", "## Next"])
    if report.get("status") == "needs_revision":
        lines.append("- Revise the chapter, then run this chapter-readiness report again.")
    elif report.get("status") == "review":
        lines.append("- Ask the author to decide whether the review items are acceptable before recording the chapter.")
    elif report.get("status") == "ready_with_notes":
        lines.append("- The chapter has no blocking continuity issue, but improvement notes should be considered before author acceptance.")
    else:
        lines.append("- If the author accepts this chapter, record it and create a post-write proposal template.")
    return "\n".join(lines).rstrip() + "\n"


def render_chapter_delivery_markdown(report: dict[str, Any]) -> str:
    draft = report.get("draft") if isinstance(report.get("draft"), dict) else {}
    readiness = report.get("readiness") if isinstance(report.get("readiness"), dict) else {}
    readiness_summary = report.get("readiness_summary") if isinstance(report.get("readiness_summary"), dict) else {}
    revision_prompt = report.get("revision_prompt") if isinstance(report.get("revision_prompt"), dict) else {}
    handoff = report.get("handoff_report") if isinstance(report.get("handoff_report"), dict) else {}
    lines = [
        "# Long Novel Agent Chapter Delivery",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Chapter: {report.get('chapter')}",
        f"File: {report.get('file')}",
        f"Status: {report.get('status')}",
        f"Ready to present: {report.get('ready_to_present')}",
        f"Read-only: {report.get('read_only')}",
        f"Writes project state: {report.get('writes_project_state')}",
        "",
        "## Draft",
        f"- SHA256: `{draft.get('sha256') or ''}`",
        f"- Bytes: {draft.get('bytes') or 0}",
        f"- Text units: {draft.get('text_units') or 0}",
        f"- Tail preview: {draft.get('tail_preview') or ''}",
        "",
        "## Readiness",
        f"- Status: {readiness.get('status')}",
        f"- Score: {readiness.get('score')}",
        f"- Must fix: {readiness_summary.get('must_fix', 0)}",
        f"- Review: {readiness_summary.get('review', 0)}",
        f"- Improve: {readiness_summary.get('improve', 0)}",
        "",
        "## Revision Plan",
    ]
    lines.extend(render_revision_plan(revision_prompt.get("revision_plan") or readiness.get("revision_plan")))
    prompt_text = str(revision_prompt.get("prompt_markdown") or "").strip()
    if prompt_text and report.get("ready_to_present") is not True:
        lines.extend(["", "## Copyable Revision Prompt", "```markdown", prompt_text, "```"])
    lines.extend([
        "",
        "## Delivery Gates",
    ])
    gates = report.get("delivery_gates") if isinstance(report.get("delivery_gates"), list) else []
    if gates:
        for gate in gates:
            if not isinstance(gate, dict):
                continue
            lines.append(
                f"- {gate.get('id')}: status={gate.get('status')}, required={gate.get('required')}, passed={gate.get('passed')}"
            )
    else:
        lines.append("- None")
    lines.extend(
        [
            "",
            "## Handoff",
            f"- Target chapter in handoff report: {handoff.get('target_chapter') or 'unknown'}",
            f"- Latest accepted chapter: {(handoff.get('latest_accepted_chapter') or {}).get('chapter') if isinstance(handoff.get('latest_accepted_chapter'), dict) else 'None'}",
            f"- Pending proposals: {report.get('pending_proposals_count', 0)}",
            f"- High-risk proposals: {report.get('high_risk_proposals_count', 0)}",
            "",
            "## Write Operations Not Performed",
        ]
    )
    operations = report.get("write_operations_not_performed") if isinstance(report.get("write_operations_not_performed"), list) else []
    lines.extend(f"- {item}" for item in operations or ["None"])
    lines.extend(["", "## Next Steps"])
    next_steps = report.get("next_steps") if isinstance(report.get("next_steps"), list) else []
    lines.extend(f"- {item}" for item in next_steps or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


def render_chapter_range_readiness_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    range_info = report.get("range") if isinstance(report.get("range"), dict) else {}
    lines = [
        "# Long Novel Agent Chapter Range Readiness",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Range: {range_info.get('start')} - {range_info.get('end')}",
        f"Draft dir: {report.get('draft_dir')}",
        f"File template: `{report.get('file_template')}`",
        f"Status: {report.get('status')}",
        f"Ready to present: {report.get('ready_to_present')}",
        f"Score: {report.get('score')}",
        f"Average score: {report.get('average_score')}",
        "",
        "## Summary",
        f"- Chapters: {summary.get('chapters', 0)}",
        f"- Ready: {summary.get('ready', 0)}",
        f"- Ready with notes: {summary.get('ready_with_notes', 0)}",
        f"- Review: {summary.get('review', 0)}",
        f"- Needs revision: {summary.get('needs_revision', 0)}",
        f"- Missing files: {summary.get('missing', 0)}",
        f"- Errors: {summary.get('errors', 0)}",
        f"- Problem chapters: {', '.join(str(item) for item in summary.get('problem_chapters', []) or []) or 'None'}",
        "",
        "## Chapters",
    ]
    chapters = report.get("chapters") if isinstance(report.get("chapters"), list) else []
    if not chapters:
        lines.append("- None")
    for row in chapters:
        if not isinstance(row, dict):
            continue
        lines.append(
            f"- Chapter {row.get('chapter')}: {row.get('status')} / score {row.get('score')} / ready {row.get('ready_to_present')} / `{row.get('file')}`"
        )
        plan = row.get("revision_plan") if isinstance(row.get("revision_plan"), list) else []
        if plan:
            short_plan = ", ".join(
                f"{step.get('group')}:{step.get('status')}({step.get('count')})"
                for step in plan
                if isinstance(step, dict)
            )
            if short_plan:
                lines.append(f"  Revision plan: {short_plan}")
    lines.extend(["", "## Problems"])
    problem_rows = [
        row
        for row in chapters
        if isinstance(row, dict)
        and (row.get("status") in {"missing", "error", "needs_revision", "review"} or not row.get("ready_to_present"))
    ]
    if not problem_rows:
        lines.append("- None")
    for row in problem_rows:
        if not isinstance(row, dict):
            continue
        lines.append(f"### Chapter {row.get('chapter')} ({row.get('status')})")
        must_fix = row.get("must_fix") if isinstance(row.get("must_fix"), list) else []
        review = row.get("review") if isinstance(row.get("review"), list) else []
        for label, items in (("Must fix", must_fix), ("Review", review)):
            lines.append(f"{label}:")
            if not items:
                lines.append("- None")
                continue
            for item in items:
                if not isinstance(item, dict):
                    continue
                lines.append(f"- {item.get('type')}: {item.get('message')}")
                if item.get("suggested_fix"):
                    lines.append(f"  Suggested fix: {item.get('suggested_fix')}")
        revision_plan = row.get("revision_plan") if isinstance(row.get("revision_plan"), list) else []
        if revision_plan:
            lines.append("Revision plan:")
            lines.extend(render_revision_plan(revision_plan))
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    lines.extend(["", "## Next"])
    status = str(report.get("status") or "")
    if status == "needs_files":
        lines.append("- Create missing draft files or pass --draft-dir / --file-template, then run this report again.")
    elif status == "needs_revision":
        lines.append("- Revise the listed chapters, then run this range report again.")
    elif status == "review":
        lines.append("- Ask the author to decide the review chapters before recording or presenting the range.")
    elif status == "ready_with_notes":
        lines.append("- The range has no blocking issue, but improvement notes should be considered before author acceptance.")
    else:
        lines.append("- If the author accepts these chapters, record each accepted chapter and create post-write proposals.")
    return "\n".join(lines).rstrip() + "\n"


def render_chapter_range_delivery_markdown(report: dict[str, Any]) -> str:
    range_info = report.get("range") if isinstance(report.get("range"), dict) else {}
    range_report = report.get("chapter_range_readiness") if isinstance(report.get("chapter_range_readiness"), dict) else {}
    range_summary = range_report.get("summary") if isinstance(range_report.get("summary"), dict) else {}
    handoff = report.get("handoff_range_report") if isinstance(report.get("handoff_range_report"), dict) else {}
    deliveries = report.get("chapter_deliveries") if isinstance(report.get("chapter_deliveries"), list) else []
    lines = [
        "# Long Novel Agent Chapter Range Delivery",
        "",
        f"Generated: {report.get('generated_at')}",
        f"Project: {report.get('project_dir')}",
        f"Range: {range_info.get('start')} - {range_info.get('end')}",
        f"Handoff chapter: {report.get('handoff_chapter')}",
        f"Status: {report.get('status')}",
        f"Ready to present: {report.get('ready_to_present')}",
        f"Read-only: {report.get('read_only')}",
        f"Writes project state: {report.get('writes_project_state')}",
        "",
        "## Range Readiness",
        f"- Status: {range_report.get('status')}",
        f"- Score: {range_report.get('score')}",
        f"- Average score: {range_report.get('average_score')}",
        f"- Chapters: {range_summary.get('chapters', 0)}",
        f"- Problem chapters: {', '.join(str(item) for item in range_summary.get('problem_chapters', []) or []) or 'None'}",
        "",
        "## Chapter Deliveries",
    ]
    if not deliveries:
        lines.append("- None")
    for item in deliveries:
        if not isinstance(item, dict):
            continue
        draft = item.get("draft") if isinstance(item.get("draft"), dict) else {}
        lines.append(
            f"- Chapter {item.get('chapter')}: status={item.get('status')}, ready={item.get('ready_to_present')}, text_units={draft.get('text_units') or 0}, file=`{item.get('file')}`"
        )
    errors = report.get("chapter_delivery_errors") if isinstance(report.get("chapter_delivery_errors"), list) else []
    if errors:
        lines.extend(["", "## Delivery Errors"])
        for item in errors:
            if isinstance(item, dict):
                lines.append(f"- Chapter {item.get('chapter')}: {item.get('error')}")
    lines.extend(
        [
            "",
            "## Handoff Range",
            f"- Status: {handoff.get('status')}",
            f"- Pending proposals: {report.get('pending_range_proposals_count', 0)}",
            f"- High-risk proposals: {report.get('high_risk_range_proposals_count', 0)}",
            "",
            "## Delivery Gates",
        ]
    )
    gates = report.get("delivery_gates") if isinstance(report.get("delivery_gates"), list) else []
    if gates:
        for gate in gates:
            if isinstance(gate, dict):
                lines.append(f"- {gate.get('id')}: status={gate.get('status')}, required={gate.get('required')}, passed={gate.get('passed')}")
    else:
        lines.append("- None")
    for title, key in (("Blockers", "blockers"), ("Review Items", "review_items"), ("Warnings", "warnings")):
        lines.extend(["", f"## {title}"])
        items = report.get(key) if isinstance(report.get(key), list) else []
        lines.extend(f"- {item}" for item in items or ["None"])
    lines.extend(["", "## Write Operations Not Performed"])
    operations = report.get("write_operations_not_performed") if isinstance(report.get("write_operations_not_performed"), list) else []
    lines.extend(f"- {item}" for item in operations or ["None"])
    lines.extend(["", "## Next Steps"])
    next_steps = report.get("next_steps") if isinstance(report.get("next_steps"), list) else []
    lines.extend(f"- {item}" for item in next_steps or ["None"])
    lines.extend(["", "## Recommended Commands"])
    commands = report.get("recommended_commands") if isinstance(report.get("recommended_commands"), dict) else {}
    if commands:
        for name, command in commands.items():
            lines.append(f"- {name}: `{command}`")
    else:
        lines.append("- None")
    return "\n".join(lines).rstrip() + "\n"


