def render_readiness_items(value: Any) -> list[str]:
    items = value if isinstance(value, list) else []
    if not items:
        return ["- None"]
    lines: list[str] = []
    for item in items:
        if not isinstance(item, dict):
            continue
        lines.append(f"- {item.get('type')}: {item.get('message')}")
        evidence = str(item.get("evidence") or "").strip()
        expected = str(item.get("expected") or "").strip()
        actual = str(item.get("actual") or "").strip()
        suggested = str(item.get("suggested_fix") or "").strip()
        if expected:
            lines.append(f"  - Expected: {expected}")
        if actual:
            lines.append(f"  - Actual: {actual}")
        if evidence:
            lines.append(f"  - Evidence: {evidence}")
        if suggested:
            lines.append(f"  - Suggested fix: {suggested}")
    return lines or ["- None"]


