def render_revision_plan(value: Any) -> list[str]:
    steps = value if isinstance(value, list) else []
    if not steps:
        return ["- None"]
    lines: list[str] = []
    for step in steps:
        if not isinstance(step, dict):
            continue
        issue_types = ", ".join(str(item) for item in step.get("issue_types", []) if str(item).strip()) or "unknown"
        lines.append(
            f"- {step.get('priority')}. {step.get('group')}: {step.get('status')} / {step.get('count')} issue(s) / {issue_types}"
        )
        message = str(step.get("message") or "").strip()
        if message:
            lines.append(f"  Message: {message}")
        contexts = step.get("fact_contexts") if isinstance(step.get("fact_contexts"), list) else []
        for context in contexts[:2]:
            if not isinstance(context, dict):
                continue
            expected = str(context.get("expected_text") or "").strip()
            if expected:
                lines.append(f"  Fact: {expected}")
        actions = step.get("suggested_actions") if isinstance(step.get("suggested_actions"), list) else []
        for action in actions[:3]:
            action_text = str(action or "").strip()
            if action_text:
                lines.append(f"  Action: {action_text}")
    return lines or ["- None"]


