def positive_int(value: str) -> int:
    parsed = int(value)
    if parsed <= 0:
        raise argparse.ArgumentTypeError("must be a positive integer")
    return parsed


def add_author_confirmation_argument(parser: argparse.ArgumentParser) -> None:
    parser.add_argument(
        "--author-confirmation",
        default="",
        help="Required for writer operations that change durable novel continuity state; use the author's approval text or decision note.",
    )


def add_write_session_guard_arguments(parser: argparse.ArgumentParser, *, include_context_hash: bool = False) -> None:
    parser.add_argument(
        "--expected-project-id",
        default="",
        help="Optional project_id from prepare-session; rejects the write if project_dir points to a different novel state.",
    )
    parser.add_argument(
        "--expected-state-sha256",
        default="",
        help="Optional .novel-agent state sha256 from prepare-session; rejects the write if durable state changed since that packet.",
    )
    if include_context_hash:
        parser.add_argument(
            "--expected-context-hash",
            default="",
            help="Optional target chapter context fingerprint from prepare-session; rejects the write if visible context changed.",
        )


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Long Novel Agent continuity CLI")
    sub = parser.add_subparsers(dest="command", required=True)

    init = sub.add_parser("init", help="Initialize .novel-agent state")
    init.add_argument("project_dir")
    init.add_argument("--title")
    init.add_argument("--target-chapters", type=positive_int)
    init.add_argument("--target-words", type=positive_int)
    init.add_argument("--force", action="store_true")

    init_wizard_parser = sub.add_parser("init-wizard", help="Plan or initialize a project with rules, source summary, and host agent metadata")
    init_wizard_parser.add_argument("project_dir")
    init_wizard_parser.add_argument("--title")
    init_wizard_parser.add_argument("--target-chapters", type=positive_int)
    init_wizard_parser.add_argument("--target-words", type=positive_int)
    init_wizard_parser.add_argument("--required", action="append", default=[])
    init_wizard_parser.add_argument("--forbidden", action="append", default=[])
    init_wizard_parser.add_argument("--future-marker", action="append", default=[])
    init_wizard_parser.add_argument("--rule-note", action="append", default=[])
    init_wizard_parser.add_argument("--style-note", default="")
    init_wizard_parser.add_argument("--source-summary", default="")
    init_wizard_parser.add_argument("--source-path", default="")
    init_wizard_parser.add_argument("--chapter-range", default="")
    init_wizard_parser.add_argument("--agent-id", default="")
    init_wizard_parser.add_argument("--platform", default="")
    init_wizard_parser.add_argument("--capabilities", default="")
    init_wizard_parser.add_argument("--agent-notes", default="")
    init_wizard_parser.add_argument("--import-gaoxia", action="store_true")
    init_wizard_parser.add_argument("--append-import", action="store_true")
    init_wizard_parser.add_argument("--dry-run", action="store_true")
    init_wizard_parser.add_argument("--force", action="store_true")

    quickstart = sub.add_parser("quickstart", help="Initialize or import a project, declare the host agent, prepare a chapter session, and run doctor")
    quickstart.add_argument("project_dir")
    quickstart.add_argument("--source", choices=sorted(QUICKSTART_SOURCES), default="auto", help="Use init, import-gaoxia, or auto-detect from project.json")
    quickstart.add_argument("--title")
    quickstart.add_argument("--target-chapters", type=positive_int)
    quickstart.add_argument("--target-words", type=positive_int)
    quickstart.add_argument("--required", action="append", default=[])
    quickstart.add_argument("--forbidden", action="append", default=[])
    quickstart.add_argument("--future-marker", action="append", default=[])
    quickstart.add_argument("--rule-note", action="append", default=[])
    quickstart.add_argument("--style-note", default="")
    quickstart.add_argument("--source-summary", default="")
    quickstart.add_argument("--source-path", default="")
    quickstart.add_argument("--chapter-range", default="")
    quickstart.add_argument("--agent-id", default="")
    quickstart.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="generic")
    quickstart.add_argument("--mode", choices=sorted(AGENT_TEMPLATE_MODES), default="writer")
    quickstart.add_argument("--capabilities", default="")
    quickstart.add_argument("--agent-notes", default="")
    quickstart.add_argument("--append-import", action="store_true")
    quickstart.add_argument("--chapter", type=positive_int)
    quickstart.add_argument("--install-config", default="", help="Optional MCP config file to inspect with doctor")
    quickstart.add_argument("--start-mcp-test", action="store_true", help="Ask doctor to start the configured or bundled MCP server")
    quickstart.add_argument("--summary-only", action="store_true", help="Return chapter context summary instead of full context")
    quickstart.add_argument("--dry-run", action="store_true")
    quickstart.add_argument("--force", action="store_true")
    quickstart.add_argument("--format", choices=["json", "markdown"], default="json")

    quickstart_wizard = sub.add_parser("quickstart-from-wizard", help="Read project-wizard.json and run quickstart dry-run or apply")
    quickstart_wizard.add_argument("project_dir", nargs="?")
    quickstart_wizard.add_argument("--answers", default="project-wizard.json", help="Path to a filled project-wizard.json file")
    quickstart_wizard.add_argument("--apply", action="store_true", help="Apply the wizard answers through quickstart; without this flag only dry-run is executed")
    quickstart_wizard.add_argument("--format", choices=["json", "markdown"], default="markdown")

    source_intake = sub.add_parser("source-intake", help="Dry-run or apply a filled source-intake.json file")
    source_intake.add_argument("project_dir")
    source_intake.add_argument("--intake", required=True, help="Path to source-intake.json generated by desktop-pack or filled by a desktop agent")
    source_intake.add_argument("--apply", action="store_true", help="Write enabled source, research, conflict, and fact entries into .novel-agent")
    source_intake.add_argument("--allow-low-quality", action="store_true", help="Allow applying source-intake reports whose quality level is empty or needs_revision after explicit author approval")
    source_intake.add_argument("--format", choices=["json", "markdown"], default="markdown")
    add_author_confirmation_argument(source_intake)
    add_write_session_guard_arguments(source_intake)

    source_intake_template_cmd = sub.add_parser("source-intake-template", help="Return a fillable source-intake.json template without writing files")
    source_intake_template_cmd.add_argument("project_dir")
    source_intake_template_cmd.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="codex")
    source_intake_template_cmd.add_argument("--mode", choices=["writer", "read-only"], default="read-only")
    source_intake_template_cmd.add_argument("--format", choices=["json", "markdown"], default="markdown")

    export_state = sub.add_parser("export-state", help="Export .novel-agent state as a portable zip package")
    export_state.add_argument("project_dir")
    export_state.add_argument("--output", default="")

    import_state = sub.add_parser("import-state", help="Import a .novel-agent portable zip package")
    import_state.add_argument("project_dir")
    import_state.add_argument("--package", required=True)
    import_state.add_argument("--force", action="store_true")

    agent_template = sub.add_parser("agent-template", help="Print host desktop agent workflow instructions")
    agent_template.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="generic")
    agent_template.add_argument("--mode", choices=sorted(AGENT_TEMPLATE_MODES), default="writer")
    agent_template.add_argument("--format", choices=["json", "markdown"], default="markdown")

    desktop_setup = sub.add_parser("desktop-setup", help="Build a local desktop agent setup guide for MCP, quickstart, and doctor")
    desktop_setup.add_argument("project_dir", nargs="?", default="/path/to/novel")
    desktop_setup.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="codex")
    desktop_setup.add_argument("--mode", choices=sorted(AGENT_TEMPLATE_MODES), default="read-only")
    desktop_setup.add_argument("--install-config", default="", help="Optional local MCP config path for doctor and quickstart commands")
    desktop_setup.add_argument("--install-target", default="", help="Optional skill install target directory to show in install commands")
    desktop_setup.add_argument("--tool-profile", choices=sorted(MCP_TOOL_PROFILES), default=DEFAULT_MCP_TOOL_PROFILE, help="MCP tool set to expose: core, writing, or full")
    desktop_setup.add_argument("--format", choices=["json", "markdown"], default="markdown")

    desktop_onboard = sub.add_parser("desktop-onboard", help="Build a plain-language onboarding guide for local desktop agents")
    desktop_onboard.add_argument("project_dir", nargs="?", default="/path/to/novel")
    desktop_onboard.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="codex")
    desktop_onboard.add_argument("--mode", choices=sorted(AGENT_TEMPLATE_MODES), default="read-only")
    desktop_onboard.add_argument("--install-config", default="", help="Optional local MCP config path")
    desktop_onboard.add_argument("--install-target", default="", help="Optional skill install target directory to show in install commands")
    desktop_onboard.add_argument("--tool-profile", choices=sorted(MCP_TOOL_PROFILES), default=DEFAULT_MCP_TOOL_PROFILE, help="MCP tool set to expose: core, writing, or full")
    desktop_onboard.add_argument("--source", choices=sorted(QUICKSTART_SOURCES), default="auto")
    desktop_onboard.add_argument("--chapter", type=positive_int)
    desktop_onboard.add_argument("--evidence-file", default="desktop-evidence.txt", help="Suggested text file for copied desktop client evidence")
    desktop_onboard.add_argument("--results-file", default="", help="Suggested results JSON filename")
    desktop_onboard.add_argument(
        "--write-guide",
        nargs="?",
        const="",
        default=None,
        metavar="PATH",
        help="Write the onboarding Markdown guide; defaults to long-novel-agent-onboarding.md inside the project directory",
    )
    desktop_onboard.add_argument("--force", action="store_true", help="Overwrite --write-guide if it already exists")
    desktop_onboard.add_argument("--format", choices=["json", "markdown"], default="markdown")

    desktop_bootstrap = sub.add_parser("desktop-bootstrap", help="Plan or execute local desktop-agent install, quickstart, and verification")
    desktop_bootstrap.add_argument("project_dir")
    desktop_bootstrap.add_argument("--platform", choices=sorted(AGENT_TEMPLATE_PLATFORMS), default="codex")
    desktop_bootstrap.add_argument("--mode", choices=sorted(AGENT_TEMPLATE_MODES), default="read-only")
    desktop_bootstrap.add_argument("--install-config", default="", help="Optional local MCP config path; Codex and Cursor can use known defaults")
    desktop_bootstrap.add_argument("--install-target", default="", help="Optional skill install target directory")
    desktop_bootstrap.add_argument("--tool-profile", choices=sorted(MCP_TOOL_PROFILES), default=DEFAULT_MCP_TOOL_PROFILE, help="MCP tool set to expose: core, writing, or full")
    desktop_bootstrap.add_argument("--source", choices=sorted(QUICKSTART_SOURCES), default="auto")
    desktop_bootstrap.add_argument("--chapter", type=positive_int)
    desktop_bootstrap.add_argument("--apply", action="store_true", help="Execute the planned install, quickstart, verification, and optional guide write")
    desktop_bootstrap.add_argument("--force", action="store_true", help="Pass force to install, quickstart, and guide overwrite")
    desktop_bootstrap.add_argument(
        "--write-guide",
        nargs="?",
        const="",
        default=None,
        metavar="PATH",
        help="With --apply, write the onboarding Markdown guide; defaults to long-novel-agent-onboarding.md inside the project directory",
    )
